                close: 'Close',
                dailyHabits: 'DAILY HABITS',
                focusAreas: 'FOCUS AREAS',
                special: 'SPECIAL',
                pinned: 'PINNED',
                editSchedule: 'Edit Schedule',
                importTasks: 'Import Tasks',
                templates: 'Templates',
                clearBlocks: 'Clear Blocks',
                resetDay: 'Reset Day',
                weeklyGoal: 'Weekly goal',
