        function savePraxePerson() {
            const name = (document.getElementById('pp-name')?.value || '').trim();
            if (!name) { document.getElementById('pp-name').focus(); return; }
            praxeData.people.push({
                id:    'prx_' + Date.now(),
                emoji: (document.getElementById('pp-emoji')?.value || '').trim() || '🎓',
                name,
                latim: (document.getElementById('pp-latim')?.value || '').trim(),
                role:  (document.getElementById('pp-role')?.value || '').trim(),
                note:  (document.getElementById('pp-note')?.value || '').trim(),
            });
            savePraxeData();
            ['pp-emoji','pp-name','pp-latim','pp-role','pp-note'].forEach(id => { const el = document.getElementById(id); if(el) el.value=''; });
            hidePraxeForm('person'); renderPraxePeople();
        }

        function removePraxePerson(i) {
            showConfirm({
                title: 'Remove person?',
                message: 'This will also delete all their dates, promises, and log entries.',
                confirmLabel: 'Remove', confirmColor: '#ef4444',
                onConfirm: () => { praxeData.people.splice(i,1); savePraxeData(); renderPraxePeople(); }
            });
        }

        // ── EVENTS ────────────────────────────────────────────────
        let _praxeEventFilter = 'all';

        function renderPraxeEvents() {
            const list = document.getElementById('praxe-events-list');
            if (!list) return;

            // Summary chips
            const sumEl = document.getElementById('praxe-event-summary');
            if (sumEl) {
                const cnt = { planned:0, confirmed:0, done:0, cancelled:0 };
                praxeData.events.forEach(e => { const s = e.status||'planned'; if (cnt[s]!==undefined) cnt[s]++; });
                const cRgb = { planned:'167,139,250', confirmed:'52,211,153', done:'96,165,250', cancelled:'248,113,113' };
                const cLbl = { planned:'📋 Planned', confirmed:'✅ Confirmed', done:'✓ Done', cancelled:'✗ Cancelled' };
                sumEl.innerHTML = Object.entries(cnt).filter(([,c])=>c>0).map(([s,c])=>
                    `<span style="font-size:0.72em;padding:3px 9px;border-radius:20px;background:rgba(${cRgb[s]},0.1);color:rgba(${cRgb[s]},0.9);border:1px solid rgba(${cRgb[s]},0.25);font-weight:700;">${cLbl[s]}: ${c}</span>`
                ).join('');
            }

            // Filter chips
            const filterEl = document.getElementById('praxe-event-filter-row');
            if (filterEl) {
                const fLbl = { all:'All', planned:'Planned', confirmed:'Confirmed', done:'Done', cancelled:'Cancelled' };
                filterEl.innerHTML = ['all','planned','confirmed','done','cancelled'].map(f =>
                    `<button onclick="_praxeEventFilter='${f}';renderPraxeEvents()" style="padding:4px 12px;border-radius:20px;border:1px solid ${_praxeEventFilter===f?'rgba(167,139,250,0.6)':'rgba(255,255,255,0.08)'};background:${_praxeEventFilter===f?'rgba(167,139,250,0.15)':'transparent'};color:${_praxeEventFilter===f?'#a78bfa':'#475569'};font-size:0.78em;font-weight:700;cursor:pointer;font-family:'Outfit',sans-serif;transition:all 0.15s;">${fLbl[f]}</button>`
                ).join('');
            }

            list.innerHTML = '';
            if (!praxeData.events.length) {
                list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No activities yet.</div>';
                updatePraxeStats(); return;
            }
            const withOrig = praxeData.events.map((e,i) => ({...e, _orig:i}));
            const toRender = _praxeEventFilter === 'all' ? withOrig : withOrig.filter(e => (e.status||'planned') === _praxeEventFilter);
            if (!toRender.length) {
                list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No activities match this filter.</div>';
                updatePraxeStats(); return;
            }
            // Sort by date ascending (undated last)
            const sorted = toRender.sort((a,b) => {
                if (!a.date && !b.date) return 0;
                if (!a.date) return 1;
                if (!b.date) return -1;
                return new Date(a.date) - new Date(b.date);
            });
            const statusLabels = { planned:'📋 Planned', confirmed:'✅ Confirmed', done:'✓ Done', cancelled:'✗ Cancelled' };
            sorted.forEach(ev => {
                const card = document.createElement('div');
                const s = ev.status || 'planned';
                card.className = 'praxe-event-card status-' + s;
                const safeN = escHtml(ev.name).replace(/'/g,"\\'");
                const safeDate = ev.date ? formatDate(ev.date) : '';
                card.innerHTML = `
                    <div class="praxe-event-header">
                        <div>
                            <div class="praxe-event-name">${escHtml(ev.name)}</div>
                            <div class="praxe-event-meta" style="margin-top:5px;">
                                ${ev.date ? `<span class="praxe-event-date">📅 ${safeDate}</span>` : ''}
                                <span class="praxe-event-status ${s}">${statusLabels[s]}</span>
                            </div>
                        </div>
                        <div class="ev-btn-group" style="display:flex;gap:6px;flex-shrink:0;">
                            <button onclick="praxeAddEventTask('${ev.id}','${safeN}','${safeDate}')" data-tooltip="Push task" style="padding:5px 10px;border-radius:8px;border:1px solid rgba(167,139,250,0.3);background:rgba(167,139,250,0.07);color:#a78bfa;font-family:'Outfit',sans-serif;font-size:0.75em;font-weight:700;cursor:pointer;">📋</button>
                            <button class="house-delete-btn" onclick="removePraxeEvent(${ev._orig})" data-tooltip="Remove">🗑️</button>
                        </div>
                    </div>
                    ${ev.note ? `<div class="praxe-event-note">"${escHtml(ev.note)}"</div>` : ''}
                    <div class="praxe-event-actions">
                        ${['planned','confirmed','done','cancelled'].map(s2 =>
                            `<button class="praxe-status-btn ${s === s2 ? 'active-'+s2 : ''}" onclick="setPraxeEventStatus(${ev._orig},'${s2}')">${statusLabels[s2]}</button>`
                        ).join('')}
                    </div>`;

                // ── inject ✏️ edit button ──
                const btnGroup = card.querySelector('.ev-btn-group');
                const editBtn = document.createElement('button');
                editBtn.textContent = '✏️'; editBtn.title = 'Edit';
                editBtn.style.cssText = 'padding:5px 8px;border-radius:8px;border:1px solid rgba(167,139,250,0.2);background:rgba(167,139,250,0.05);font-size:0.78em;cursor:pointer;';
                btnGroup.insertBefore(editBtn, btnGroup.lastElementChild);

                // ── inline edit form ──
                const eForm = document.createElement('div');
                eForm.style.cssText = 'display:none;flex-direction:column;gap:8px;padding:9px 10px;margin-top:6px;background:rgba(167,139,250,0.05);border:1px solid rgba(167,139,250,0.2);border-radius:9px;';
                const eNameInp = document.createElement('input'); eNameInp.className='house-input'; eNameInp.placeholder='Activity name'; eNameInp.maxLength=80; eNameInp.value=ev.name||'';
                const eDateInp = document.createElement('input'); eDateInp.className='house-input'; eDateInp.type='date'; eDateInp.value=ev.date||''; eDateInp.style.cssText='flex:none;width:150px;';
                const eNoteInp = document.createElement('input'); eNoteInp.className='house-input'; eNoteInp.placeholder='Note (optional)'; eNoteInp.maxLength=120; eNoteInp.value=ev.note||'';
                const eRow1 = document.createElement('div'); eRow1.style.cssText='display:flex;gap:6px;flex-wrap:wrap;';
                eRow1.appendChild(eNameInp); eRow1.appendChild(eDateInp);
                const eSaveBtn = document.createElement('button'); eSaveBtn.className='house-save-btn'; eSaveBtn.style.background='linear-gradient(135deg,#a78bfa,#7c3aed)'; eSaveBtn.textContent='Save';
                eSaveBtn.onclick = () => {
                    const nm = eNameInp.value.trim(); if(!nm){eNameInp.focus();return;}
                    praxeData.events[ev._orig].name = nm;
                    praxeData.events[ev._orig].date = eDateInp.value||'';
                    praxeData.events[ev._orig].note = eNoteInp.value.trim();
                    savePraxeData(); renderPraxeEvents();
                };
                const eCancelBtn = document.createElement('button'); eCancelBtn.className='house-cancel-btn'; eCancelBtn.textContent='Cancel'; eCancelBtn.onclick=()=>{ eForm.style.display='none'; };
                const eBtnRow = document.createElement('div'); eBtnRow.style.cssText='display:flex;gap:6px;';
                eBtnRow.appendChild(eSaveBtn); eBtnRow.appendChild(eCancelBtn);
                eForm.appendChild(eRow1); eForm.appendChild(eNoteInp); eForm.appendChild(eBtnRow);
                editBtn.onclick = () => { eForm.style.display = eForm.style.display==='flex'?'none':'flex'; if(eForm.style.display==='flex') eNameInp.focus(); };
                card.appendChild(eForm);

                // ── subtasks section ──────────────────────────────────
                const subsSection = document.createElement('div');
                subsSection.style.cssText = 'margin-top:4px;';
                const evObj = praxeData.events[ev._orig];

                function rebuildEvSubs() {
                    subsSection.innerHTML = '';
                    const subs = evObj.subtasks || [];
                    if (subs.length) {
                        const subsDiv = document.createElement('div');
                        subsDiv.style.cssText = 'display:flex;flex-direction:column;gap:4px;padding:4px 0;';
                        subs.forEach((st, si) => {
                            const done = !!st.done;
                            const subRow = document.createElement('div');
                            subRow.style.cssText = 'display:flex;align-items:center;gap:8px;padding:5px 8px;background:rgba(255,255,255,0.03);border-radius:7px;border:1px solid rgba(255,255,255,0.06);cursor:pointer;transition:background 0.15s;';
                            subRow.addEventListener('mouseenter', () => subRow.style.background = 'rgba(255,255,255,0.06)');
                            subRow.addEventListener('mouseleave', () => subRow.style.background = 'rgba(255,255,255,0.03)');

                            const chkBtn = document.createElement('button');
                            chkBtn.style.cssText = 'width:16px;height:16px;min-width:16px;border-radius:4px;border:1.5px solid;flex-shrink:0;cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:0.55em;font-weight:900;transition:all 0.15s;'
                                + (done ? 'background:#a78bfa;border-color:#a78bfa;color:#000;' : 'background:transparent;border-color:rgba(255,255,255,0.2);color:transparent;');
                            chkBtn.textContent = '✓';

                            const lbl = document.createElement('span');
                            lbl.style.cssText = 'font-size:0.8em;flex:1;color:' + (done ? '#475569' : '#94a3b8') + ';' + (done ? 'text-decoration:line-through;' : '');
                            lbl.textContent = st.text;

                            const editInp = document.createElement('input');
                            editInp.className = 'house-input';
                            editInp.value = st.text; editInp.maxLength = 100;
                            editInp.style.cssText = 'display:none;flex:1;font-size:0.8em;padding:3px 7px;';
                            editInp.addEventListener('click', e => e.stopPropagation());

                            const editSubBtn = document.createElement('button');
                            editSubBtn.textContent = '✏️'; editSubBtn.title = 'Edit';
                            editSubBtn.className = 'compact-edit-btn';
                            editSubBtn.addEventListener('click', e => {
                                e.stopPropagation();
                                if (editInp.style.display === 'none') { lbl.style.display = 'none'; editInp.style.display = 'flex'; editInp.focus(); editInp.select(); }
                                else { lbl.style.display = ''; editInp.style.display = 'none'; }
                            });

                            function saveSubEdit() {
                                const newText = editInp.value.trim(); if (!newText) { editInp.focus(); return; }
                                evObj.subtasks[si].text = newText; savePraxeData(); rebuildEvSubs();
                            }
                            editInp.addEventListener('keydown', e => {
                                if (e.key === 'Enter') { e.preventDefault(); saveSubEdit(); }
                                if (e.key === 'Escape') { editInp.style.display = 'none'; lbl.style.display = ''; }
                            });
                            editInp.addEventListener('blur', () => {
                                const newText = editInp.value.trim();
                                if (newText && newText !== st.text) saveSubEdit();
                                else { editInp.style.display = 'none'; lbl.style.display = ''; }
                            });

                            const delSubBtn = document.createElement('button');
                            delSubBtn.textContent = '✕'; delSubBtn.title = 'Remove step';
                            delSubBtn.style.cssText = 'background:none;border:none;color:#475569;font-size:0.75em;cursor:pointer;padding:2px 4px;flex-shrink:0;transition:color 0.15s;';
                            delSubBtn.addEventListener('mouseover', () => delSubBtn.style.color = '#f87171');
                            delSubBtn.addEventListener('mouseout',  () => delSubBtn.style.color = '#475569');
                            delSubBtn.addEventListener('click', e => { e.stopPropagation(); evObj.subtasks.splice(si, 1); savePraxeData(); rebuildEvSubs(); });

                            subRow.addEventListener('click', e => {
                                e.stopPropagation();
                                if (e.target.tagName === 'INPUT') return;
                                evObj.subtasks[si].done = !evObj.subtasks[si].done; savePraxeData(); rebuildEvSubs();
                            });

                            subRow.appendChild(chkBtn); subRow.appendChild(lbl); subRow.appendChild(editInp);
                            subRow.appendChild(editSubBtn); subRow.appendChild(delSubBtn);
                            subsDiv.appendChild(subRow);
                        });
                        subsSection.appendChild(subsDiv);
                    }
                    // add-step row (always visible)
                    const addRow = document.createElement('div');
                    addRow.style.cssText = 'display:flex;gap:6px;margin-top:4px;';
                    const addInp = document.createElement('input');
                    addInp.className = 'house-input'; addInp.placeholder = 'Add preparation step...'; addInp.maxLength = 100;
                    addInp.style.cssText = 'flex:1;font-size:0.8em;padding:4px 8px;';
                    const addBtn = document.createElement('button');
                    addBtn.textContent = '＋';
                    addBtn.style.cssText = 'padding:4px 12px;border-radius:8px;border:1px solid rgba(167,139,250,0.3);background:rgba(167,139,250,0.1);color:#a78bfa;font-size:0.8em;font-weight:700;cursor:pointer;flex-shrink:0;';
                    function doAddStep() {
                        const text = addInp.value.trim(); if (!text) { addInp.focus(); return; }
                        if (!evObj.subtasks) evObj.subtasks = [];
                        evObj.subtasks.push({ id: 'evst_' + Date.now() + '_' + Math.random().toString(36).slice(2), text, done: false }); savePraxeData(); rebuildEvSubs();
                    }
                    addInp.addEventListener('keydown', e => { if (e.key === 'Enter') { e.preventDefault(); doAddStep(); } });
                    addBtn.addEventListener('click', e => { e.stopPropagation(); doAddStep(); });
                    addRow.appendChild(addInp); addRow.appendChild(addBtn);
                    subsSection.appendChild(addRow);
                }
                rebuildEvSubs();
                card.appendChild(subsSection);
                list.appendChild(card);
            });
            updatePraxeStats();
        }

        function savePraxeEvent() {
            const name = (document.getElementById('pe-name')?.value || '').trim();
            if (!name) { document.getElementById('pe-name').focus(); return; }
            praxeData.events.push({
                id: 'pev_' + Date.now(),
                name,
                date: document.getElementById('pe-date')?.value || '',
                note: (document.getElementById('pe-note')?.value || '').trim(),
                status: 'planned',
                subtasks: _praxeFormSubtasks.length ? _praxeFormSubtasks.map(s => ({...s})) : [],
            });
            _praxeFormSubtasks = [];
            savePraxeData();
            ['pe-name','pe-date','pe-note','pe-subtask-inp'].forEach(id => { const el = document.getElementById(id); if(el) el.value=''; });
            hidePraxeForm('event'); renderPraxeEvents();
        }

        function removePraxeEvent(i) {
            showConfirm({
                title: 'Remove activity?',
                message: 'This activity will be permanently deleted.',
                confirmLabel: 'Remove', confirmColor: '#ef4444',
                onConfirm: () => { praxeData.events.splice(i,1); savePraxeData(); renderPraxeEvents(); }
            });
        }
        function setPraxeEventStatus(i, s)   { praxeData.events[i].status = s; savePraxeData(); renderPraxeEvents(); }

        // ── NOTES ─────────────────────────────────────────────────
        function renderPraxeNotes() {
            const list = document.getElementById('praxe-notes-list');
            if (!list) return;
            list.innerHTML = '';
            if (!praxeData.notes.length) {
                list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No notes yet.</div>';
                return;
            }
            [...praxeData.notes].reverse().forEach((n, i) => {
                const origIdx = praxeData.notes.length - 1 - i;

                // wrapper so edit form sits below the card row
                const wrap = document.createElement('div');

                const card = document.createElement('div');
                card.className = 'praxe-note-card';
                const safeT = escHtml(n.text).replace(/'/g,"\\'");
                card.innerHTML = `
                    <div class="praxe-note-dot"></div>
                    <div class="praxe-note-body">
                        <div class="praxe-note-text">${escHtml(n.text)}</div>
                        ${n.tag ? `<div class="praxe-note-tag"># ${escHtml(n.tag)}</div>` : ''}
                    </div>
                    <button onclick="praxeQuickTask('📝','${safeT}','')" data-tooltip="Push to tasks" style="padding:5px 10px;border-radius:8px;border:1px solid rgba(167,139,250,0.3);background:rgba(167,139,250,0.07);color:#a78bfa;font-family:'Outfit',sans-serif;font-size:0.75em;font-weight:700;cursor:pointer;flex-shrink:0;">📋</button>`;

                // ✏️ edit button
                const editBtn = document.createElement('button');
                editBtn.textContent = '✏️'; editBtn.title = 'Edit';
                editBtn.style.cssText = 'padding:5px 8px;border-radius:8px;border:1px solid rgba(167,139,250,0.2);background:rgba(167,139,250,0.05);font-size:0.78em;cursor:pointer;flex-shrink:0;';
                card.appendChild(editBtn);

                // ✕ delete button
                const delBtn = document.createElement('button');
                delBtn.className = 'house-delete-btn'; delBtn.setAttribute('data-tooltip','Remove'); delBtn.textContent = '🗑️';
                delBtn.onclick = () => removePraxeNote(origIdx);
                card.appendChild(delBtn);

                // ── inline edit form ──
                const eForm = document.createElement('div');
                eForm.style.cssText = 'display:none;flex-direction:column;gap:8px;padding:9px 10px;margin-top:4px;background:rgba(167,139,250,0.05);border:1px solid rgba(167,139,250,0.2);border-radius:9px;';
                const eTextInp = document.createElement('input'); eTextInp.className='house-input'; eTextInp.placeholder='Note text'; eTextInp.maxLength=200; eTextInp.value=n.text||'';
                const eTagInp  = document.createElement('input'); eTagInp.className='house-input';  eTagInp.placeholder='Tag (optional)'; eTagInp.maxLength=40; eTagInp.value=n.tag||''; eTagInp.style.cssText='flex:none;width:140px;';
                const eRow1 = document.createElement('div'); eRow1.style.cssText='display:flex;gap:6px;flex-wrap:wrap;';
                eRow1.appendChild(eTextInp); eRow1.appendChild(eTagInp);
                const eSaveBtn = document.createElement('button'); eSaveBtn.className='house-save-btn'; eSaveBtn.style.background='linear-gradient(135deg,#a78bfa,#7c3aed)'; eSaveBtn.textContent='Save';
                eSaveBtn.onclick = () => {
                    const txt = eTextInp.value.trim(); if(!txt){eTextInp.focus();return;}
                    praxeData.notes[origIdx].text = txt;
                    praxeData.notes[origIdx].tag  = eTagInp.value.trim();
                    savePraxeData(); renderPraxeNotes();
                };
                const eCancelBtn = document.createElement('button'); eCancelBtn.className='house-cancel-btn'; eCancelBtn.textContent='Cancel'; eCancelBtn.onclick=()=>{ eForm.style.display='none'; };
                const eBtnRow = document.createElement('div'); eBtnRow.style.cssText='display:flex;gap:6px;';
                eBtnRow.appendChild(eSaveBtn); eBtnRow.appendChild(eCancelBtn);
                eForm.appendChild(eRow1); eForm.appendChild(eBtnRow);
                editBtn.onclick = () => { eForm.style.display = eForm.style.display==='flex'?'none':'flex'; if(eForm.style.display==='flex') eTextInp.focus(); };

                wrap.appendChild(card); wrap.appendChild(eForm);
                list.appendChild(wrap);
            });
        }

        function savePraxeNote() {
            const text = (document.getElementById('pn-text')?.value || '').trim();
            if (!text) { document.getElementById('pn-text').focus(); return; }
            praxeData.notes.push({ text, tag: (document.getElementById('pn-tag')?.value || '').trim() });
            savePraxeData();
            ['pn-text','pn-tag'].forEach(id => { const el = document.getElementById(id); if(el) el.value=''; });
            hidePraxeForm('note'); renderPraxeNotes();
        }

        function removePraxeNote(i) {
            showConfirm({
                title: 'Remove note?',
                message: 'This note will be permanently deleted.',
                confirmLabel: 'Remove', confirmColor: '#ef4444',
                onConfirm: () => { praxeData.notes.splice(i,1); savePraxeData(); renderPraxeNotes(); }
            });
        }

        // ── TASKS → migrated to gTasksAll['praxe'] + renderGTasks ─

        // ── FORM HELPERS ──────────────────────────────────────────
        function showPraxeForm(type) {
            const form = document.getElementById('praxe-form-' + type);
            if (!form) return;
            form.classList.add('visible');
            const first = form.querySelector('input');
            if (first) first.focus();
        }
        function hidePraxeForm(type) {
            const form = document.getElementById('praxe-form-' + type);
            if (form) form.classList.remove('visible');
            if (type === 'event') { _praxeFormSubtasks = []; _renderPraxeFormSubtasks(); }
        }

        function initPraxeKeyShortcuts() {
            const map = { 'pp-note':'person', 'pe-note':'event', 'pn-tag':'note' };
            const saves = { person:savePraxePerson, event:savePraxeEvent, note:savePraxeNote };
            Object.keys(map).forEach(id => {
                const el = document.getElementById(id);
                if (!el) return;
                el.addEventListener('keydown', e => {
                    if (e.key === 'Enter') saves[map[id]]();
                    if (e.key === 'Escape') hidePraxeForm(map[id]);
                });
            });
        }

        // ════════════════════════════════════════════════════════
        //  GENERIC SECTION TASKS MODULE
        //  Handles tasks for all simple resp-sections that don't
        //  have their own dedicated module.
        // ════════════════════════════════════════════════════════

        let gTasksAll = loadData('gTasksAll');
        const IMP_SECTIONS = ['pills','imp-work','finance','b','organize','music'];

        const saveGTasksAll = () => saveData('gTasksAll', gTasksAll);

        let _pendingInventoryRefillCleanup = null;

        function _setLinkedGroupedTaskCollapsed(sid, rawId, collapsed) {
            let gtaskChanged = false;
            if (gTasksAll[sid]) {
                const sourceTask = gTasksAll[sid].find(t => String(t.id) === String(rawId));
                if (sourceTask && sourceTask.collapsed !== collapsed) {
                    sourceTask.collapsed = collapsed;
                    gtaskChanged = true;
                }
            }
            if (gtaskChanged) saveGTasksAll();

            const schedKey = 'gtask-' + sid + '-' + rawId;
            let schedChanged = false;
            schedBlocks.forEach(block => {
                block.tasks.forEach(task => {
                    if (task.id === schedKey && task.collapsed !== collapsed) {
                        task.collapsed = collapsed;
                        schedChanged = true;
                    }
                });
            });
            if (schedChanged) saveSchedBlocks();

            if (gtaskChanged) renderGTasks(sid);
            if (schedChanged) renderSchedule();
        }

        function toggleGroupedTaskCollapse(sid, rawId) {
            const task = (gTasksAll[sid] || []).find(t => String(t.id) === String(rawId));
            if (!task) return;
            _setLinkedGroupedTaskCollapsed(sid, rawId, !task.collapsed);
        }

        function _syncGroupedTaskSubtaskStateToSchedule(sid, rawId, subIdx, done) {
            const schedKey = 'gtask-' + sid + '-' + rawId;
            let schedChanged = false;
            schedBlocks.forEach(block => {
                block.tasks.forEach(task => {
                    if (task.id === schedKey && Array.isArray(task.subtasks) && task.subtasks[subIdx] !== undefined) {
                        task.subtasks[subIdx].done = done;
                        task.done = task.subtasks.every(s => s.done);
                        if (task.done) tasks[task.id] = true;
                        else delete tasks[task.id];
                        schedChanged = true;
                    }
                });
            });
            if (schedChanged) {
                saveSchedBlocks();
                localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
                renderSchedule();
            }
        }

        // Push a renamed task's text/emoji into any schedule blocks that already imported it
        function _syncGroupedTaskTextToSchedule(sid, rawId, newText, emoji) {
            const schedKey = 'gtask-' + sid + '-' + rawId;
            const fullText = (emoji ? emoji + ' ' : '') + (newText || '');
            let schedChanged = false;
            schedBlocks.forEach(block => {
                block.tasks.forEach(task => {
                    if (task.id !== schedKey) return;
                    if (task.text !== fullText) { task.text = fullText; schedChanged = true; }
                    if (emoji !== undefined && task.emoji !== emoji) { task.emoji = emoji; schedChanged = true; }
                });
            });
            if (schedChanged) {
                saveSchedBlocks();
                renderSchedule();
            }
        }

        function toggleScheduleGroupedTaskCollapse(taskId) {
            const match = String(taskId || '').match(/^gtask-([^-]+)-(.+)$/);
            if (!match) return;
            const [, sid, rawId] = match;
            const sourceTask = (gTasksAll[sid] || []).find(t => String(t.id) === String(rawId));
            if (sourceTask) {
                _setLinkedGroupedTaskCollapsed(sid, rawId, !sourceTask.collapsed);
                return;
            }
            let changed = false;
            schedBlocks.forEach(block => {
                block.tasks.forEach(task => {
                    if (task.id === taskId) {
                        task.collapsed = !task.collapsed;
                        changed = true;
                    }
                });
            });
            if (changed) {
                saveSchedBlocks();
                renderSchedule();
            }
        }

        // ── shared gtask modal state ──────────────────────────────────
        let _gtmSid    = null;
        let _gtmColor  = '#60a5fa';

        function renderGTasks(sid) {
            const list = document.getElementById('gtask-list-' + sid);
            if (!list) return;
            list.innerHTML = '';
            const arr = gTasksAll[sid] || [];
            if (!arr.length) {
                list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No tasks yet.</div>';
                return;
            }
            const btn = document.querySelector(
                `#resp-section-${sid} .house-add-trigger, #imp-section-${sid} .house-add-trigger`
            );
            const accent = btn ? btn.style.color : '#60a5fa';
            arr.forEach((t, i) => {
                const hasSubtasks = !!(t.subtasks && t.subtasks.length);
                const isCollapsed = !!t.collapsed;
                const taskAccent = t.accentColor || accent;
                const row = document.createElement('div');
                row.className = 'house-task-item' + (t.done ? ' done' : '');
                row.style.borderLeftColor = t.done ? '#22c55e' : taskAccent;
                row.setAttribute('data-tidx', i);
                if (hasSubtasks) {
                    row.style.cursor = 'default';
                    row.style.flexDirection = 'column';
                    row.style.alignItems = 'stretch';
                }

                // Drag handle
                const taskDragHandle = document.createElement('div');
                taskDragHandle.className = 'dnd-handle dnd-task-handle';
                taskDragHandle.title = 'Drag to reorder';
                taskDragHandle.innerHTML = '&#8942;&#8942;';

                const label = (t.emoji ? t.emoji + ' ' : '') + (t.title || t.text || '');
                const notesHtml = (!hasSubtasks && t.notes)
                    ? `<div style="color:#64748b;font-size:0.82em;margin-top:2px;">${escHtml(t.notes)}</div>` : '';

                // ── Header row ───────────────────────────────────────────────
                const headerDiv = document.createElement('div');
                headerDiv.className = 'd-row-8w';
                headerDiv.appendChild(taskDragHandle);

                if (hasSubtasks) {
                    // Progress badge — click to check/uncheck all subtasks
                    const doneCount = t.subtasks.filter(s => s.done).length;
                    const prog = document.createElement('div');
                    prog.className = 'gtask-prog-' + sid + '-' + i;
                    prog.style.cssText = 'width:22px;height:22px;min-width:22px;border-radius:6px;flex-shrink:0;'
                        + 'border:2.5px solid ' + taskAccent + ';'
                        + 'display:flex;align-items:center;justify-content:center;'
                        + 'font-size:0.55em;font-weight:900;transition:all 0.2s;cursor:pointer;'
                        + (t.done ? 'background:' + taskAccent + ';color:#000;' : 'color:' + taskAccent + ';background:transparent;');
                    prog.textContent = t.done ? '✓' : doneCount + '/' + t.subtasks.length;
                    prog.title = t.done ? 'Uncheck all' : 'Check all';
                    prog.addEventListener('click', (e) => {
                        e.stopPropagation();
                        const allDone = t.subtasks.every(s => s.done);
                        const newState = !allDone;

                        // Intercept: lost task being UNCHECKED via prog — offer to revert item status
                        if (sid === 'lost' && !newState && t.done && t.linkedItemIdx !== undefined && t.linkedItemIdx !== null) {
                            const _pli = lostData.items[t.linkedItemIdx];
                            if (_pli && (_pli.status === 'found' || _pli.status === 'replaced')) {
                                function _doProgUncheck() {
                                    t.subtasks.forEach(s => s.done = false);
                                    t.done = false;
                                    saveGTasksAll();
                                    const _psk = 'gtask-' + sid + '-' + t.id;
                                    delete tasks[_psk];
                                    localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
                                    document.querySelectorAll('.task-item[data-task="' + _psk + '"]').forEach(el => el.classList.remove('checked'));
                                    renderGTasks(sid); updateSummaryPills(); updateProgress();
                                    try { updateRespMenuBadges(); } catch(e) {}
                                }
                                showConfirm({
                                    icon: '↩️', title: 'Revert item?',
                                    message: `Uncheck — also mark <strong>${t.linkedItemName || _pli.name}</strong> as still searching?`,
                                    confirmLabel: '🔍 Yes, still searching', confirmColor: '#fbbf24',
                                    cancelLabel: 'Just uncheck',
                                    onConfirm() { _doProgUncheck(); setLostItemStatus(t.linkedItemIdx, 'searching'); },
                                    onCancel()  { _doProgUncheck(); }
                                });
                                return;
                            }
                        }

                        // Intercept: lost tasks with a linked item being completed — ask found/replaced
                        if (sid === 'lost' && newState && t.linkedItemIdx !== undefined && t.linkedItemIdx !== null) {
                            t.subtasks.forEach((s, si) => {
                                s.done = true;
                                if (t.groupRef && typeof _setOrgGroupSubDone === 'function') _setOrgGroupSubDone(t.groupRef, si, true);
                            });
                            t.done = true;
                            saveGTasksAll();
                            const _sk = 'gtask-' + sid + '-' + t.id;
                            tasks[_sk] = true;
                            localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
                            document.querySelectorAll('.task-item[data-task="' + _sk + '"]').forEach(el => el.classList.add('checked'));
                            _lostTaskComplete(t, sid, i);
                            return;
                        }

                        t.subtasks.forEach((s, si) => {
                            s.done = newState;
                            // Sync back to org group source
                            if (t.groupRef && typeof _setOrgGroupSubDone === 'function') {
                                _setOrgGroupSubDone(t.groupRef, si, newState);
                            }
                        });
                        t.done = newState;
                        row.classList.toggle('done', newState);
                        row.style.borderLeftColor = newState ? '#22c55e' : taskAccent;
                        prog.textContent = newState ? '✓' : '0/' + t.subtasks.length;
                        prog.style.background = newState ? taskAccent : 'transparent';
                        prog.style.color = newState ? '#000' : taskAccent;
                        prog.title = newState ? 'Uncheck all' : 'Check all';
                        saveGTasksAll();
                        // Sync praxe event status + subtasks
                        if (sid === 'praxe' && t.linkedPraxeEventId) {
                            const _pEv = praxeData.events.find(e => e.id === t.linkedPraxeEventId);
                            if (_pEv) {
                                _pEv.status = newState ? 'done' : 'planned';
                                if (_pEv.subtasks) _pEv.subtasks.forEach(ps => ps.done = newState);
                                savePraxeData(); renderPraxeEvents();
                            }
                        }
                        // Sync to schedule
                        const schedKey = 'gtask-' + sid + '-' + t.id;
                        if (newState) tasks[schedKey] = true; else delete tasks[schedKey];
                        localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
                        document.querySelectorAll('.task-item[data-task="' + schedKey + '"]').forEach(el => {
                            el.classList.toggle('checked', newState);
                        });
                        // Rebuild subtask rows via full re-render
                        renderGTasks(sid);
                        updateSummaryPills(); updateProgress();
                        try { updateRespMenuBadges(); } catch(e) {}
                    });
                    headerDiv.appendChild(prog);
                } else {
                    const chk = document.createElement('div');
                    chk.className = 'house-task-check';
                    if (t.done) { chk.style.background = taskAccent; chk.style.borderColor = taskAccent; }
                    chk.addEventListener('click', () => toggleGTask(sid, i));
                    headerDiv.appendChild(chk);
                }

                const textWrap = document.createElement('div');
                textWrap.className = 'flex-1';
                const textSpan = document.createElement('span');
                textSpan.className = 'house-task-text';
                textSpan.textContent = label;
                textSpan.contentEditable = 'true';
                textSpan.spellcheck = false;
                textSpan.style.outline = 'none';
                textSpan.style.cursor = 'text';
                textSpan.addEventListener('click', e => e.stopPropagation());
                textSpan.addEventListener('keydown', e => { if (e.key === 'Enter') { e.preventDefault(); textSpan.blur(); } });
                textSpan.addEventListener('blur', () => {
                    let raw = textSpan.textContent.trim();
                    if (!raw) { textSpan.textContent = label; return; }
                    // Strip leading emoji (keep separate emoji field) to avoid it being duplicated on next render
                    if (t.emoji && raw.startsWith(t.emoji + ' ')) raw = raw.slice(t.emoji.length + 1).trim();
                    if (!raw) { textSpan.textContent = label; return; }
                    t.text = raw; t.title = raw;
                    saveGTasksAll();
                    _syncGroupedTaskTextToSchedule(sid, t.id, raw, t.emoji);
                    // Sync name back to source (org group, gym session, etc.)
                    if (t.groupRef && t.groupRef.isGym) {
                        const sess = gym123Data && gym123Data.sessions.find(s => s.id === t.groupRef.sessionId);
                        if (sess) { sess.name = raw; saveGym123Data(); renderGymSessions(); }
                    } else if (t.groupRef && t.groupRef.isMA) {
                        const disc = maData && maData.disciplines.find(d => d.id === t.groupRef.disciplineId);
                        if (disc) { disc.name = raw; saveMAData(); renderMADisciplines(); }
                    } else if (t.groupRef && !t.groupRef.isWork && typeof _setOrgGroupTitle === 'function') {
                        _setOrgGroupTitle(t.groupRef, raw);
                    }
                });
                if (!hasSubtasks) {
                    textSpan.addEventListener('mousedown', e => {
                        // only toggle if not clicking to edit (double-click or already focused)
                        if (document.activeElement !== textSpan) { e.preventDefault(); toggleGTask(sid, i); }
                    });
                }
                textWrap.appendChild(textSpan);
                if (!hasSubtasks && t.notes) {
                    const notesEl = document.createElement('div');
                    notesEl.style.cssText = 'color:#64748b;font-size:0.8em;margin-top:2px;line-height:1.4;';
                    notesEl.textContent = t.notes;
                    textWrap.appendChild(notesEl);
                }
                headerDiv.appendChild(textWrap);

                if (hasSubtasks) {
                    const collapseBtn = document.createElement('button');
                    collapseBtn.title = isCollapsed ? 'Expand subtasks' : 'Minimize subtasks';
                    collapseBtn.textContent = isCollapsed ? '▸' : '▾';
                    collapseBtn.style.cssText = 'background:none;border:none;color:#64748b;font-size:0.95em;'
                        + 'cursor:pointer;padding:2px 4px;flex-shrink:0;transition:color 0.15s;';
                    collapseBtn.addEventListener('click', (e) => {
                        e.stopPropagation();
                        toggleGroupedTaskCollapse(sid, t.id);
                    });
                    headerDiv.appendChild(collapseBtn);
                }

                const isCompletedBuyTask = sid === 'pills' && t.done && /(?:^|\s)Buy\s+.+/i.test(t.text || '');
                if (!isCompletedBuyTask) {
                    // ── Edit button ──────────────────────────────────────
                    const editBtn = document.createElement('button');
                    editBtn.title = 'Edit task';
                    editBtn.textContent = '✏️';
                    editBtn.className = 'house-edit-btn';
                    editBtn.addEventListener('click', (e) => {
                        e.stopPropagation();
                        const existing = row.querySelector('._gtask-edit-form');
                        if (existing) { existing.remove(); if (!hasSubtasks) { row.style.borderRadius = ''; row.style.flexDirection = ''; row.style.alignItems = ''; } return; }
                        if (!hasSubtasks) {
                            row.style.borderRadius = '12px 12px 0 0';
                            row.style.flexDirection = 'column';
                            row.style.alignItems = 'stretch';
                        }
                        const form = document.createElement('div');
                        form.className = '_gtask-edit-form';
                        form.style.cssText = hasSubtasks
                            ? 'display:flex;flex-direction:column;gap:8px;padding:10px 12px;margin-top:8px;margin-bottom:2px;background:rgba(2,8,23,0.5);border:1px solid rgba(255,255,255,0.06);border-radius:10px;'
                            : 'display:flex;flex-direction:column;gap:8px;padding:10px 12px 12px 12px;margin-top:0;background:rgba(2,8,23,0.5);border-top:1px solid rgba(255,255,255,0.06);border-radius:0 0 12px 12px;';
                        const inpStyle = 'width:100%;box-sizing:border-box;background:rgba(255,255,255,0.05);border:1.5px solid rgba(255,255,255,0.1);border-radius:9px;padding:8px 11px;color:#e2e8f0;font-family:\'Outfit\',sans-serif;font-size:0.84em;outline:none;transition:border-color 0.15s;';
                        const txtInp = document.createElement('input');
                        txtInp.type = 'text';
                        txtInp.value = t.text || t.title || '';
                        txtInp.placeholder = 'Task name';
                        txtInp.style.cssText = inpStyle;
                        txtInp.addEventListener('focus', () => txtInp.style.borderColor = 'rgba(96,165,250,0.5)');
                        txtInp.addEventListener('blur',  () => txtInp.style.borderColor = 'rgba(255,255,255,0.1)');
                        const notesInp = document.createElement('input');
                        notesInp.type = 'text';
                        notesInp.value = t.notes || '';
                        notesInp.placeholder = 'Notes (optional)';
                        notesInp.style.cssText = inpStyle;
                        notesInp.addEventListener('focus', () => notesInp.style.borderColor = 'rgba(96,165,250,0.5)');
                        notesInp.addEventListener('blur',  () => notesInp.style.borderColor = 'rgba(255,255,255,0.1)');
                        const btnRow = document.createElement('div');
                        btnRow.style.cssText = 'display:flex;gap:6px;justify-content:flex-end;margin-top:2px;';
                        const saveBtn = document.createElement('button');
                        saveBtn.textContent = '✓ Save';
                        saveBtn.style.cssText = 'padding:6px 16px;border-radius:9px;border:none;background:rgba(96,165,250,0.2);color:#60a5fa;font-size:0.78em;font-weight:800;cursor:pointer;font-family:\'Outfit\',sans-serif;transition:background 0.15s;';
                        saveBtn.addEventListener('mouseover', () => saveBtn.style.background = 'rgba(96,165,250,0.35)');
                        saveBtn.addEventListener('mouseout',  () => saveBtn.style.background = 'rgba(96,165,250,0.2)');
                        const cancelBtn = document.createElement('button');
                        cancelBtn.textContent = 'Cancel';
                        cancelBtn.style.cssText = 'padding:6px 14px;border-radius:9px;border:1px solid rgba(255,255,255,0.08);background:transparent;color:#475569;font-size:0.78em;cursor:pointer;font-family:\'Outfit\',sans-serif;transition:color 0.15s;';
                        cancelBtn.addEventListener('mouseover', () => cancelBtn.style.color = '#94a3b8');
                        cancelBtn.addEventListener('mouseout',  () => cancelBtn.style.color = '#475569');
                        cancelBtn.addEventListener('click', (e) => { e.stopPropagation(); form.remove(); if (!hasSubtasks) { row.style.borderRadius = ''; row.style.flexDirection = ''; row.style.alignItems = ''; } });
                        saveBtn.addEventListener('click', (e) => {
                            e.stopPropagation();
                            const newText  = txtInp.value.trim();
                            const newNotes = notesInp.value.trim();
                            if (!newText) { txtInp.focus(); return; }
                            t.text = newText; t.title = newText; t.notes = newNotes;
                            saveGTasksAll();
                            _syncGroupedTaskTextToSchedule(sid, t.id, newText, t.emoji);
                            // Sync back to source for special tasks
                            if (t.groupRef && t.groupRef.isWork && typeof workProjects !== 'undefined') {
                                const wp = workProjects.find(p => p.id === t.groupRef.projectId);
                                if (wp) { wp.name = newText; if (typeof saveWorkProjects === 'function') { saveWorkProjects(); renderWorkProjects(); } }
                            } else if (t.linkedType === 'feature' && typeof projectsData !== 'undefined') {
                                projectsData.projects.forEach(p => { const f=(p.features||[]).find(x=>x.id===t.linkedId); if(f){f.title=newText;t.linkedTitle=newText;} });
                                if (typeof saveProjectsData === 'function') { saveProjectsData(); if(typeof renderUABacklog==='function') renderUABacklog(); }
                            } else if (t.linkedType === 'bug' && typeof projectsData !== 'undefined') {
                                projectsData.projects.forEach(p => { const b=(p.bugs||[]).find(x=>x.id===t.linkedId); if(b){b.desc=newText;t.linkedTitle=newText;} });
                                if (typeof saveProjectsData === 'function') { saveProjectsData(); if(typeof renderUABugs==='function') renderUABugs(); }
                            }
                            if (!hasSubtasks) row.style.borderRadius = '';
                            renderGTasks(sid);
                        });
                        const closeForm = () => { form.remove(); if (!hasSubtasks) { row.style.borderRadius = ''; row.style.flexDirection = ''; row.style.alignItems = ''; } };
                        txtInp.addEventListener('keydown', e => { if (e.key === 'Enter') { e.preventDefault(); saveBtn.click(); } if (e.key === 'Escape') closeForm(); });
                        notesInp.addEventListener('keydown', e => { if (e.key === 'Enter') { e.preventDefault(); saveBtn.click(); } if (e.key === 'Escape') closeForm(); });
                        btnRow.appendChild(cancelBtn); btnRow.appendChild(saveBtn);
                        form.appendChild(txtInp); form.appendChild(notesInp); form.appendChild(btnRow);
                        headerDiv.insertAdjacentElement('afterend', form);
                        txtInp.focus(); txtInp.select();
                    });
                    headerDiv.appendChild(editBtn);
                    // ── Delete button ────────────────────────────────────
                    const delBtn = document.createElement('button');
                    delBtn.className = 'house-delete-btn';
                    delBtn.title = 'Remove';
                    delBtn.textContent = '🗑️';
                    delBtn.addEventListener('click', (e) => { e.stopPropagation(); removeGTask(sid, i); });
                    headerDiv.appendChild(delBtn);
                }

                row.appendChild(headerDiv);

                if (sid === 'pills' && t.done && /(?:^|\s)Buy\s+.+/i.test(t.text || '')) {
                    const liquidBuyTask = liquidsInventory.some(p =>
                        String(t.text || '').toLowerCase().includes(`buy ${String((p && p.name) || '').trim().toLowerCase()}`)
                    );
                    const refillBtn = document.createElement('button');
                    refillBtn.textContent = liquidBuyTask ? '🧴 Refill' : '📦 Refill';
                    refillBtn.style.cssText = 'margin-top:10px;margin-left:36px;align-self:flex-start;'
                        + 'background:rgba(56,189,248,0.1);border:1px solid rgba(56,189,248,0.28);color:#7dd3fc;'
                        + 'border-radius:10px;padding:7px 12px;cursor:pointer;font-family:\'Outfit\',sans-serif;'
                        + 'font-size:0.75em;font-weight:800;transition:all 0.15s;';
                    refillBtn.addEventListener('click', (e) => {
                        e.stopPropagation();
                        showConfirm({
                            title: liquidBuyTask ? '🧴 Refill Liquid?' : '📦 Refill Pills?',
                            message: 'This opens the refill dialog. After you save the refill, this completed Today\'s Task will be removed.',
                            confirmLabel: 'Open Refill',
                            confirmColor: '#38bdf8',
                            onConfirm: () => openInventoryRefillFromTask(t.text, { source: 'gtask', sid, index: i })
                        });
                    });
                    row.appendChild(refillBtn);
                }

                // ── Subtask rows ─────────────────────────────────────────────
                if (hasSubtasks) {
                    const subsDiv = document.createElement('div');
                    subsDiv.style.cssText = 'margin-top:8px;display:' + (isCollapsed ? 'none' : 'flex') + ';flex-direction:column;gap:5px;';

                    function rebuildSubs() {
                        subsDiv.innerHTML = '';
                        const progEl = row.querySelector('.gtask-prog-' + sid + '-' + i);
                        t.subtasks.forEach((s, si) => {
                            const done = !!s.done;
                            const chkStyle = done
                                ? 'background:' + taskAccent + ';border-color:' + taskAccent + ';color:#000;'
                                : 'background:transparent;border-color:rgba(255,255,255,0.2);color:transparent;';
                            const subRow = document.createElement('div');
                            subRow.style.cssText = 'display:flex;align-items:center;gap:8px;padding:5px 8px;'
                                + 'background:rgba(255,255,255,0.03);border-radius:7px;'
                                + 'border:1px solid rgba(255,255,255,0.06);cursor:pointer;transition:background 0.15s;';
                            subRow.addEventListener('mouseenter', () => subRow.style.background = 'rgba(255,255,255,0.06)');
                            subRow.addEventListener('mouseleave', () => subRow.style.background = 'rgba(255,255,255,0.03)');
                            subRow.addEventListener('click', (e) => {
                                e.stopPropagation();
                                s.done = !s.done;
                                const newDone = s.done;
                                const allDone = t.subtasks.every(x => x.done);
                                t.done = allDone;
                                row.classList.toggle('done', allDone);
                                row.style.borderLeftColor = allDone ? '#22c55e' : taskAccent;
                                // Update progress badge
                                if (progEl) {
                                    const dc = t.subtasks.filter(x => x.done).length;
                                    progEl.textContent = allDone ? '✓' : dc + '/' + t.subtasks.length;
                                    progEl.style.background = allDone ? taskAccent : 'transparent';
                                    progEl.style.color = allDone ? '#000' : taskAccent;
                                }
                                saveGTasksAll();
                                // Sync praxe event subtask + status
                                if (sid === 'praxe' && t.linkedPraxeEventId && s.linkedEvSubId) {
                                    const _pEv = praxeData.events.find(e => e.id === t.linkedPraxeEventId);
                                    if (_pEv && _pEv.subtasks) {
                                        const _pSub = _pEv.subtasks.find(ps => ps.id === s.linkedEvSubId);
                                        if (_pSub) {
                                            _pSub.done = newDone;
                                            _pEv.status = allDone ? 'done' : (_pEv.status === 'done' ? 'planned' : _pEv.status);
                                            savePraxeData(); renderPraxeEvents();
                                        }
                                    }
                                }
                                _syncGroupedTaskSubtaskStateToSchedule(sid, t.id, si, newDone);
                                // Sync to org group or work project
                                if (t.groupRef && t.groupRef.isWork) {
                                    if (typeof _setWorkProjectSubDone === 'function') _setWorkProjectSubDone(t.groupRef, si, newDone);
                                } else if (t.groupRef && t.groupRef.isGym) {
                                    if (typeof _setGymSessionSubDone === 'function') _setGymSessionSubDone(t.groupRef, si, newDone);
                                } else if (t.groupRef && t.groupRef.isMA) {
                                    if (typeof _setMADisciplineSubDone === 'function') _setMADisciplineSubDone(t.groupRef, si, newDone);
                                } else if (typeof _setOrgGroupSubDone === 'function' && t.groupRef) {
                                    _setOrgGroupSubDone(t.groupRef, si, newDone);
                                }
                                // Sync schedule checked state
                                const schedKey = 'gtask-' + sid + '-' + t.id;
                                if (allDone) tasks[schedKey] = true; else delete tasks[schedKey];
                                localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
                                document.querySelectorAll('.task-item[data-task="' + schedKey + '"]').forEach(el => {
                                    el.classList.toggle('checked', allDone);
                                });
                                // ── Lost task: trigger found/replaced dialog when last step is checked ──
                                if (allDone && sid === 'lost' && t.linkedItemIdx !== undefined && t.linkedItemIdx !== null) {
                                    _lostTaskComplete(t, sid, i);
                                    return; // _lostTaskComplete will renderGTasks etc.
                                }
                                rebuildSubs();
                                updateSummaryPills(); updateProgress(); try { updateRespMenuBadges(); } catch(e) {}
                            });

                            const chkBtn = document.createElement('button');
                            chkBtn.style.cssText = 'width:16px;height:16px;min-width:16px;border-radius:4px;border:1.5px solid;'
                                + 'flex-shrink:0;cursor:pointer;display:flex;align-items:center;justify-content:center;'
                                + 'font-size:0.55em;font-weight:900;transition:all 0.15s;' + chkStyle;
                            chkBtn.textContent = '✓';
                            // Don't stopPropagation — let click bubble up to subRow handler

                            const lbl = document.createElement('span');
                            lbl.style.cssText = 'font-size:0.8em;flex:1;color:' + (done ? '#475569' : '#94a3b8') + ';'
                                + (done ? 'text-decoration:line-through;' : '');
                            lbl.textContent = s.text;

                            subRow.setAttribute('data-sub-idx', si);

                            const subHandle = document.createElement('span');
                            subHandle.className = 'sub-drag-handle';
                            subHandle.title = 'Drag to reorder';
                            subHandle.textContent = '⠿';

                            const delSubBtn = document.createElement('button');
                            delSubBtn.textContent = '✕';
                            delSubBtn.title = 'Remove';
                            delSubBtn.className = 'compact-del-btn';

                            delSubBtn.addEventListener('click', e => {
                                e.stopPropagation();
                                t.subtasks.splice(si, 1);
                                t.done = t.subtasks.length > 0 ? t.subtasks.every(x => x.done) : false;
                                saveGTasksAll();
                                if (t.groupRef && t.groupRef.isWork) _deleteTaskSubFromProject(t.groupRef, si);
                                // Update progress badge
                                if (progEl) {
                                    const dc = t.subtasks.filter(x => x.done).length;
                                    progEl.textContent = t.done ? '✓' : (t.subtasks.length ? dc + '/' + t.subtasks.length : '');
                                }
                                rebuildSubs();
                            });

                            subRow.appendChild(subHandle);
                            subRow.appendChild(chkBtn);
                            subRow.appendChild(lbl);
                            subRow.appendChild(delSubBtn);
                            subsDiv.appendChild(subRow);
                        });
                    }

                    rebuildSubs();
                    row.appendChild(subsDiv);
                }

                list.appendChild(row);
            });
            _initTaskListDnd(list, sid);
        }

        // Keep the Schedule checkbox state (and any duplicate DOM copies) in sync
        // with a gTasksAll['update-app'] task after its done state changes.
        function _uaSyncTaskToSchedule(sid, t) {
            const schedKey = 'gtask-' + sid + '-' + t.id;
            if (t.done) tasks[schedKey] = true; else delete tasks[schedKey];
            localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
            document.querySelectorAll('.task-item[data-task="' + schedKey + '"]').forEach(el => {
                el.classList.toggle('checked', !!t.done);
            });
        }

        // ── Linked task complete/uncomplete handlers (Projects ↔ Tasks) ──────
        function _uaTaskLinkedComplete(task, sid, taskIdx) {
            const curVer = (_projGet()||{}).version || '1.0.0';
            if (task.linkedType === 'feature') {
                showConfirm({
                    icon: '🎉', title: 'Feature shipped!',
                    message: `Log <strong>"${task.linkedTitle||task.text}"</strong> in the changelog?
                    <div style="margin-top:14px;padding:10px 12px;background:rgba(251,191,36,0.06);border:1px solid rgba(251,191,36,0.18);border-radius:10px;">
                        <div style="color:#94a3b8;font-size:0.78em;font-weight:700;margin-bottom:10px;">📦 VERSION BUMP from v${curVer}</div>
                        <div style="display:flex;flex-direction:column;gap:8px;">
                            <label style="display:flex;align-items:center;gap:10px;cursor:pointer;"><input type="radio" name="ua-vbump" value="patch" style="accent-color:#fbbf24;width:15px;height:15px;"> <span style="color:#e2e8f0;font-size:0.85em;">Patch &nbsp;<span style="color:#fbbf24;font-weight:800;">v${bumpVersion(curVer,'patch')}</span> <span style="color:#64748b;font-size:0.9em;">— small tweak</span></span></label>
                            <label style="display:flex;align-items:center;gap:10px;cursor:pointer;"><input type="radio" name="ua-vbump" value="minor" checked style="accent-color:#fbbf24;width:15px;height:15px;"> <span style="color:#e2e8f0;font-size:0.85em;">Minor &nbsp;<span style="color:#fbbf24;font-weight:800;">v${bumpVersion(curVer,'minor')}</span> <span style="color:#64748b;font-size:0.9em;">— new feature</span></span></label>
                            <label style="display:flex;align-items:center;gap:10px;cursor:pointer;"><input type="radio" name="ua-vbump" value="major" style="accent-color:#fbbf24;width:15px;height:15px;"> <span style="color:#e2e8f0;font-size:0.85em;">Major &nbsp;<span style="color:#fbbf24;font-weight:800;">v${bumpVersion(curVer,'major')}</span> <span style="color:#64748b;font-size:0.9em;">— big release</span></span></label>
                        </div>
                    </div>`,
                    confirmLabel: 'Log & Ship', confirmColor: '#34d399',
                    onConfirm() {
                        const bump = document.querySelector('input[name="ua-vbump"]:checked')?.value || 'minor';
                        const newVer = bumpVersion(curVer, bump);
                        const p2 = _projGet(); if (!p2) return;
                        p2.version = newVer;
                        const changeId = 'c' + Date.now();
                        if (!Array.isArray(p2.changelog)) p2.changelog = [];
                        p2.changelog.push({ id:changeId, type:'feature', version:'v'+newVer, desc:task.linkedTitle||task.text });
                        const featIdx = (p2.features||[]).findIndex(x => x.id === task.linkedId);
                        const snapshot = featIdx !== -1 ? {...p2.features[featIdx]} : null;
                        if (featIdx !== -1) p2.features.splice(featIdx, 1);
                        const t = gTasksAll[sid][taskIdx];
                        t.done = true; t.loggedChangeId = changeId; if (snapshot) t.linkedSnapshot = snapshot;
                        saveProjectsData(); saveGTasksAll();
                        renderUABacklog(); renderUAChangelog(); renderGTasks(sid); updateUAStats();
                        _uaSyncTaskToSchedule(sid, t);
                        updateSummaryPills(); updateProgress();
                        showToast('🚀 Logged! Now at v' + newVer, '#34d399');
                    },
                    onCancel() {
                        const t = gTasksAll[sid][taskIdx];
                        t.done = true; saveGTasksAll(); renderGTasks(sid);
                        _uaSyncTaskToSchedule(sid, t);
                        updateSummaryPills(); updateProgress();
                    }
                });
            } else if (task.linkedType === 'bug') {
                showConfirm({
                    icon: '🐛', title: 'Bug fixed!',
                    message: `Log <strong>"${task.linkedTitle||task.text}"</strong> under <span style="color:#fbbf24;font-weight:800;">v${curVer}</span> in the changelog and remove it?`,
                    confirmLabel: 'Log & Fix', confirmColor: '#34d399',
                    onConfirm() {
                        const p2 = _projGet(); if (!p2) return;
                        const changeId = 'c' + Date.now();
                        if (!Array.isArray(p2.changelog)) p2.changelog = [];
                        p2.changelog.push({ id:changeId, type:'fix', version:'v'+(p2.version||'1.0.0'), desc:task.linkedTitle||task.text });
                        const bugIdx = (p2.bugs||[]).findIndex(x => x.id === task.linkedId);
                        const snapshot = bugIdx !== -1 ? {...p2.bugs[bugIdx]} : null;
                        if (bugIdx !== -1) p2.bugs.splice(bugIdx, 1);
                        const t = gTasksAll[sid][taskIdx];
                        t.done = true; t.loggedChangeId = changeId; if (snapshot) t.linkedSnapshot = snapshot;
                        saveProjectsData(); saveGTasksAll();
                        renderUABugs(); renderUAChangelog(); renderGTasks(sid); updateUAStats();
                        _uaSyncTaskToSchedule(sid, t);
                        updateSummaryPills(); updateProgress();
                        showToast('✅ Bug fix logged!', '#34d399');
                    },
                    onCancel() {
                        const t = gTasksAll[sid][taskIdx];
                        t.done = true; saveGTasksAll(); renderGTasks(sid);
                        _uaSyncTaskToSchedule(sid, t);
                        updateSummaryPills(); updateProgress();
                    }
                });
            }
        }

        function _uaTaskLinkedUncomplete(task, sid, taskIdx) {
            showConfirm({
                icon: '↩️', title: 'Undo this entry?',
                message: `Uncheck the task and remove the changelog entry?${task.linkedSnapshot ? '<br><span style="color:#94a3b8;font-size:0.85em;">The '+task.linkedType+' will be restored to the list.</span>' : ''}`,
                confirmLabel: 'Reverse', confirmColor: '#f87171',
                onConfirm() {
                    const p2 = _projGet();
                    if (p2 && task.loggedChangeId) {
                        const cIdx = (p2.changelog||[]).findIndex(c => c.id === task.loggedChangeId);
                        if (cIdx !== -1) p2.changelog.splice(cIdx, 1);
                        if (task.linkedSnapshot) {
                            if (task.linkedType === 'feature') { if (!Array.isArray(p2.features)) p2.features=[]; p2.features.push(task.linkedSnapshot); }
                            else if (task.linkedType === 'bug') { if (!Array.isArray(p2.bugs)) p2.bugs=[]; p2.bugs.push(task.linkedSnapshot); }
                        }
                        saveProjectsData();
                        renderUAChangelog(); renderUABacklog(); renderUABugs(); updateUAStats();
                    }
                    const t = gTasksAll[sid][taskIdx];
                    t.done = false; delete t.loggedChangeId; delete t.linkedSnapshot;
                    saveGTasksAll(); renderGTasks(sid);
                    _uaSyncTaskToSchedule(sid, t);
                    updateSummaryPills(); updateProgress();
                    showToast('↩️ Reversed', '#f87171');
                },
                onCancel() {
                    const t = gTasksAll[sid][taskIdx];
                    t.done = true; saveGTasksAll(); renderGTasks(sid);
                    _uaSyncTaskToSchedule(sid, t);
                    updateSummaryPills(); updateProgress();
                }
            });
        }

        function _lostTaskComplete(task, sid, i) {
            const itemName = task.linkedItemName || 'the item';
            const idx = task.linkedItemIdx;

            function _syncSchedDone() {
                task.done = true; saveGTasksAll();
                const schedKey = 'gtask-' + sid + '-' + task.id;
                tasks[schedKey] = true;
                localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
                document.querySelectorAll('.task-item[data-task="' + schedKey + '"]').forEach(el => el.classList.add('checked'));
                renderGTasks(sid); updateSummaryPills(); updateProgress();
                try { updateRespMenuBadges(); } catch(e) {}
            }

            showConfirm({
                icon: '🔎',
                title: 'Task done — update item?',
                message: `Was <strong>${itemName}</strong> found or recovered?`,
                confirmLabel: '✅ Found it!',
                confirmColor: '#34d399',
                cancelLabel: '🔄 Got a replacement',
                onConfirm() {
                    _syncSchedDone();
                    if (idx !== null && idx !== undefined && lostData.items[idx]) {
                        setLostItemStatus(idx, 'found');
                    }
                    showToast('✅ Found! Item marked as found.', '#34d399');
                },
                onCancel() {
                    showConfirm({
                        icon: '🔄',
                        title: 'Replaced?',
                        message: `Mark <strong>${itemName}</strong> as replaced?`,
                        confirmLabel: '🔄 Yes, replaced',
                        confirmColor: '#60a5fa',
                        cancelLabel: '🔍 Still searching',
                        onConfirm() {
                            _syncSchedDone();
                            if (idx !== null && idx !== undefined && lostData.items[idx]) {
                                setLostItemStatus(idx, 'replaced');
                            }
                            showToast('🔄 Item marked as replaced.', '#60a5fa');
                        },
                        onCancel() {
                            // Still searching — mark task done, item stays active (no status change)
                            _syncSchedDone();
                        }
                    });
                }
            });
        }

        function toggleGTask(sid, i) {
            if (!gTasksAll[sid]) return;
            const task = gTasksAll[sid][i];
            const newDone = !task.done;

            // Intercept linked project tasks (feature/bug) — show modal instead
            if (sid === 'update-app' && task.linkedType && newDone && !task.loggedChangeId) {
                _uaTaskLinkedComplete(task, sid, i);
                return;
            }
            if (sid === 'update-app' && task.linkedType && !newDone && task.loggedChangeId) {
                _uaTaskLinkedUncomplete(task, sid, i);
                return;
            }

            // Intercept lost tasks with a linked item — completing: ask found/replaced
            if (sid === 'lost' && newDone && task.linkedItemIdx !== undefined && task.linkedItemIdx !== null) {
                _lostTaskComplete(task, sid, i);
                return;
            }
            // Intercept lost tasks with a linked item — unchecking: offer to revert item status
            if (sid === 'lost' && !newDone && task.linkedItemIdx !== undefined && task.linkedItemIdx !== null) {
                const _li = lostData.items[task.linkedItemIdx];
                if (_li && (_li.status === 'found' || _li.status === 'replaced')) {
                    function _doUncheck() {
                        gTasksAll[sid][i].done = false; saveGTasksAll(); renderGTasks(sid);
                        updateSummaryPills(); updateProgress();
                        const _sk = 'gtask-' + sid + '-' + task.id;
                        delete tasks[_sk];
                        localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
                        document.querySelectorAll('.task-item[data-task="' + _sk + '"]').forEach(el => el.classList.remove('checked'));
                    }
                    showConfirm({
                        icon: '↩️', title: 'Revert item?',
                        message: `Uncheck task — also mark <strong>${task.linkedItemName || _li.name}</strong> as still searching?`,
                        confirmLabel: '🔍 Yes, still searching', confirmColor: '#fbbf24',
                        cancelLabel: 'Just uncheck',
                        onConfirm() { _doUncheck(); setLostItemStatus(task.linkedItemIdx, 'searching'); },
                        onCancel()  { _doUncheck(); }
                    });
                    return;
                }
            }

            // Intercept family tasks linked to a promise — sync promise done state
            if (sid === 'family' && task.linkedFamPromiseMemberId && task.linkedFamPromiseText) {
                const _p = famData.promises.find(p => p.memberId === task.linkedFamPromiseMemberId && p.text === task.linkedFamPromiseText);
                if (_p) {
                    _p.done = newDone;
                    saveFamData();
                    renderFamMembers();
                    updateFamStats();
                }
            }

            // Intercept praxe tasks linked to an event — sync event status
            if (sid === 'praxe' && task.linkedPraxeEventId) {
                const _ev = praxeData.events.find(e => e.id === task.linkedPraxeEventId);
                if (_ev) {
                    _ev.status = newDone ? 'done' : 'planned';
                    savePraxeData();
                    renderPraxeEvents();
                }
            }

            gTasksAll[sid][i].done = newDone;
            saveGTasksAll();
            renderGTasks(sid);

            // Sync to schedule — imported tasks have id format: gtask-{sid}-{numericId}
            const schedKey = 'gtask-' + sid + '-' + task.id;
            if (newDone) tasks[schedKey] = true;
            else delete tasks[schedKey];
            localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
            document.querySelectorAll('.task-item[data-task="' + schedKey + '"]').forEach(el => {
                if (newDone) el.classList.add('checked');
                else el.classList.remove('checked');
            });

            // If this is a "Take X" pill task, adjust inventory
            if (sid === 'pills' && task.text && /Take .+/i.test(task.text)) {
                pillHandleTaskToggle(task.text, newDone);
            }
            if (sid === 'pills' && task.text && /Apply .+/i.test(task.text)) {
                liquidHandleTaskToggle(task.text, newDone);
            }
            // If this is a music practice task, handle streak
            if (sid === 'music' && task.text && /^Practice .+ today$/i.test(task.text)) {
                if (typeof musicHandleTaskToggle === 'function') musicHandleTaskToggle(newDone);
            }

            // Sync work project status when a work task is toggled
            if (sid === 'imp-work' && task.groupRef && task.groupRef.isWork) {
                if (typeof _syncWorkProjectStatus === 'function') _syncWorkProjectStatus(task.groupRef, newDone);
            }
            // Sync gym session weekDone when task is toggled
            if (sid === 'gym-1-2-3' && task.groupRef && task.groupRef.isGym) {
                const sess = typeof gym123Data !== 'undefined' && gym123Data.sessions
                    ? gym123Data.sessions.find(s => s.id === task.groupRef.sessionId)
                    : null;
                if (sess) {
                    sess.weekDone = newDone;
                    if (typeof saveGym123Data === 'function') saveGym123Data();
                    if (typeof renderGymSessions === 'function') renderGymSessions();
                }
            }
            // Sync MA discipline weekDone when task is toggled
            if (sid === 'martial-arts' && task.groupRef && task.groupRef.isMA) {
                const disc = typeof maData !== 'undefined' && maData.disciplines
                    ? maData.disciplines.find(d => d.id === task.groupRef.disciplineId)
                    : null;
                if (disc) {
                    disc.weekDone = newDone;
                    if (typeof saveMAData === 'function') saveMAData();
                    if (typeof renderMADisciplines === 'function') renderMADisciplines();
                }
            }
            updateSummaryPills();
            updateProgress();
        }

        function _doRemoveGTask(sid, i) {
            if (!gTasksAll[sid]) return;
            const task = gTasksAll[sid][i];
            // Revert linked work project to in-progress when its task is removed
            if (task && sid === 'imp-work' && task.groupRef && task.groupRef.isWork) {
                if (typeof _syncWorkProjectStatus === 'function') _syncWorkProjectStatus(task.groupRef, false);
            }
            // Revert linked praxe event to planned and reset its subtasks
            if (task && task.linkedPraxeEventId) {
                const _pEv = praxeData.events.find(e => e.id === task.linkedPraxeEventId);
                if (_pEv) {
                    _pEv.status = 'planned';
                    if (_pEv.subtasks) _pEv.subtasks.forEach(ps => ps.done = false);
                    savePraxeData(); renderPraxeEvents();
                }
            }
            gTasksAll[sid].splice(i, 1);
            saveGTasksAll();
            renderGTasks(sid);
            // Refresh any R slot showing this section
            try { ['r1','r2','r3'].forEach(slot => { if (rSlots && rSlots[slot] === sid) renderRTasks(slot); }); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e) {}
            if (task) {
                const schedKey = 'gtask-' + sid + '-' + task.id;
                let schedChanged = false;
                schedBlocks.forEach(b => {
                    const before = b.tasks.length;
                    b.tasks = b.tasks.filter(bt => bt.id !== schedKey);
                    if (b.tasks.length !== before) schedChanged = true;
                });
                if (schedChanged) {
                    saveSchedBlocks();
                    renderSchedule();
                }
                // Also clean up tasks map
                if (tasks[schedKey]) {
                    delete tasks[schedKey];
                    localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
                }
            }
        }

        function removeGTask(sid, i) {
            if (!gTasksAll[sid]) return;
            const task = gTasksAll[sid][i];
            // If this task has a logged changelog entry, offer to reverse everything
            if (sid === 'update-app' && task && task.loggedChangeId) {
                showConfirm({
                    icon: '🗑️', title: 'Remove task',
                    message: `Also remove the changelog entry and restore the <strong>${task.linkedType}</strong> to the list?`,
                    confirmLabel: 'Remove & Reverse', confirmColor: '#f87171',
                    onConfirm() {
                        const p2 = _projGet();
                        if (p2) {
                            const cIdx = (p2.changelog||[]).findIndex(c => c.id === task.loggedChangeId);
                            if (cIdx !== -1) p2.changelog.splice(cIdx, 1);
                            if (task.linkedSnapshot) {
                                if (task.linkedType === 'feature') { if (!Array.isArray(p2.features)) p2.features=[]; p2.features.push(task.linkedSnapshot); }
                                else if (task.linkedType === 'bug') { if (!Array.isArray(p2.bugs)) p2.bugs=[]; p2.bugs.push(task.linkedSnapshot); }
                            }
                            saveProjectsData();
                            renderUAChangelog(); renderUABacklog(); renderUABugs(); updateUAStats();
                        }
                        _doRemoveGTask(sid, i);
                        showToast('↩️ Reversed & removed', '#f87171');
                    },
                    onCancel() { _doRemoveGTask(sid, i); }
                });
                return;
            }
            _doRemoveGTask(sid, i);
        }

        function removeGTaskById(sid, rawId) {
            if (!gTasksAll[sid]) return;
            const idx = gTasksAll[sid].findIndex(t => String(t.id) === String(rawId));
            if (idx !== -1) removeGTask(sid, idx);
        }

        function showGTask(sid) {
            _gtmSid = sid;
            // Detect accent color from button
            const btn = document.querySelector(
                `#resp-section-${sid} .house-add-trigger, #imp-section-${sid} .house-add-trigger`
            );
            _gtmColor = btn ? btn.style.color : '#60a5fa';
            // Theme the modal
            const bar    = document.getElementById('gtask-modal-bar');
            const addBtn = document.getElementById('gtask-modal-add-btn');
            if (bar)    bar.style.background = _gtmColor;
            if (addBtn) {
                addBtn.style.background  = `linear-gradient(135deg,${_gtmColor},${_gtmColor}cc)`;
                addBtn.style.boxShadow   = `0 4px 14px ${_gtmColor}44`;
            }
            // Set icon from section heading
            const heading = document.querySelector(
                `#resp-section-${sid} .resp-detail-label, #imp-section-${sid} .imp-section-label`
            );
            const icon = document.getElementById('gtask-modal-icon');
            if (icon) icon.textContent = heading
                ? (heading.textContent.trim().match(/^\S+/)?.[0] || '✅') : '✅';
            // Clear inputs and show
            ['gtm-emoji','gtm-title','gtm-notes'].forEach(id => {
                const el = document.getElementById(id); if (el) el.value = '';
            });
            const ov = document.getElementById('gtask-modal-overlay');
            if (ov) { ov.style.display = 'flex'; document.body.style.overflow = 'hidden'; }
            setTimeout(() => {
                const el = document.getElementById('gtm-title'); if (el) el.focus();
            }, 80);
        }

        function hideGTask(sid) { _gtmCancel(); }

        function _gtmSave() {
            const emoji = (document.getElementById('gtm-emoji')?.value || '').trim();
            const title = (document.getElementById('gtm-title')?.value || '').trim();
            const notes = (document.getElementById('gtm-notes')?.value || '').trim();
            if (!title) { document.getElementById('gtm-title')?.focus(); return; }
            const sid = _gtmSid;
            if (!sid) return;
            if (!gTasksAll[sid]) gTasksAll[sid] = [];
            gTasksAll[sid].push({ id: Date.now(), emoji, text: title, notes, done: false });
            saveGTasksAll();
            _gtmCancel();
            renderGTasks(sid);
        }

        function _gtmCancel() {
            const ov = document.getElementById('gtask-modal-overlay');
            if (ov) ov.style.display = 'none';
            document.body.style.overflow = '';
            _gtmSid = null;
        }

        // saveGTask is now an alias (still called from initGenericTasks-era code)
        function saveGTask(sid) { _gtmSave(); }

        function initGenericTasks() {
            const GENERIC_SECTIONS = [
                'dermatologist','psychologist','guitar','saxophone','piano','ableton','martial-arts','streaming',
                'doutor-finan-as','invest','social-media','emulator','computer','phone',
                'calendar','update-app','lenses','room','travel-list'
            ];
            GENERIC_SECTIONS.forEach(sid => renderGTasks(sid));
            // Also render Important sections tasks
            IMP_SECTIONS.forEach(sid => renderGTasks(sid));
        }

        // ── INIT ──────────────────────────────────────────────────
        function initPraxeSection() {
            // One-time migration: clear old praxeData.tasks (don't copy — they were seeded defaults)
            if ((praxeData.tasks || []).length && !praxeData._migrated) {
                praxeData.tasks = [];
                praxeData._migrated = true;
                savePraxeData();
            }
            // v2: remove any stale migration-era tasks (e.g. "Prepare: Julgamento")
            if (!praxeData._v2clean) {
                if (gTasksAll['praxe']) {
                    const before = gTasksAll['praxe'].length;
                    gTasksAll['praxe'] = gTasksAll['praxe'].filter(t => !/julgamento/i.test(t.text || t.title || ''));
                    if (gTasksAll['praxe'].length !== before) saveGTasksAll();
                }
                praxeData._v2clean = true;
                savePraxeData();
            }
            // Ensure all events have stable IDs (needed for task linking)
            let eventsNeedSave = false;
            praxeData.events.forEach(e => {
                if (!e.id) { e.id = 'pev_' + Date.now() + '_' + Math.random().toString(36).slice(2); eventsNeedSave = true; }
                if (e.subtasks) e.subtasks.forEach(st => { if (!st.id) { st.id = 'evst_' + Date.now() + '_' + Math.random().toString(36).slice(2); eventsNeedSave = true; } });
            });
            if (eventsNeedSave) savePraxeData();
            renderPraxePeople();
            renderPraxeEvents();
            renderPraxeNotes();
            renderGTasks('praxe');
            initPraxeKeyShortcuts();
        }

        // ════════════════════════════════════════════════════════
        //  FAMILY MODULE
        // ════════════════════════════════════════════════════════

        let famData = loadData('famData');
        ensureArrays(famData, 'members', 'dates', 'promises', 'log', 'tasks');

        const saveFamData = () => saveData('famData', famData);

        // ── QUICK TASK PUSH ──────────────────────────────────────
        function famQuickTask(emoji, title, desc) {
            if (!gTasksAll['family']) gTasksAll['family'] = [];
            const already = gTasksAll['family'].find(t => (t.text === title || t.title === title) && !t.done);
            if (already) { toast('Task already exists'); return; }
            gTasksAll['family'].push({ id: Date.now(), emoji, text: title, notes: desc || '', done: false });
            saveGTasksAll();
            renderGTasks('family');
            toast('📌 Task added');
        }

        function famAddPromiseTask(mId, promise) {
            if (!gTasksAll['family']) gTasksAll['family'] = [];
            const title = promise.text;
            const already = gTasksAll['family'].find(t => t.linkedFamPromiseMemberId === mId && t.linkedFamPromiseText === title && !t.done);
            if (already) { showToast('Task already exists', '#f9a8d4'); return; }
            gTasksAll['family'].push({
                id: Date.now(),
                emoji: '🤝',
                text: title,
                notes: '',
                done: false,
                linkedFamPromiseMemberId: mId,
                linkedFamPromiseText: title,
            });
            saveGTasksAll();
            renderGTasks('family');
            showToast('📌 Promise task added', '#34d399');
        }

        // ── STATS ────────────────────────────────────────────────
        function updateFamStats() {
            const today = new Date(); today.setHours(0,0,0,0);
            const memberIds = new Set(famData.members.map(m => m.id).filter(Boolean));

            // Count upcoming: important dates + birthdays within 30 days
            let upcoming = famData.dates.filter(d => {
                if (!d.date) return false;
                const dt = new Date(d.date); dt.setFullYear(today.getFullYear());
                if (dt < today) dt.setFullYear(today.getFullYear() + 1);
                return (dt - today) / (1000*60*60*24) <= 30;
            }).length;
            famData.members.forEach(m => {
                if (!m.birthday) return;
                const dt = new Date(m.birthday); dt.setFullYear(today.getFullYear());
                if (dt < today) dt.setFullYear(today.getFullYear() + 1);
                if ((dt - today) / (1000*60*60*24) <= 30) upcoming++;
            });

            // Only count promises that belong to current members (avoid ghost data)
            const validPromises = famData.promises.filter(p => memberIds.has(p.memberId));
            const kept = validPromises.filter(p => p.done).length;

            const el = id => document.getElementById(id);
            if (el('fam-stat-members'))  el('fam-stat-members').textContent  = famData.members.length;
            if (el('fam-stat-upcoming')) el('fam-stat-upcoming').textContent = upcoming;
            if (el('fam-stat-promises')) el('fam-stat-promises').textContent = kept + '/' + validPromises.length;
        }

        // ── DATE BADGE LOGIC ────────────────────────────────────
        function dateBadge(dateStr) {
            if (!dateStr) return '';
            const today = new Date();
            today.setHours(0,0,0,0);
            const dt = new Date(dateStr);
            dt.setFullYear(today.getFullYear());
            if (dt < today) dt.setFullYear(today.getFullYear() + 1);
            const diff = Math.round((dt - today) / (1000*60*60*24));
            if (diff === 0) return '<span class="fam-date-badge today">🎉 Today!</span>';
            if (diff <= 7)  return `<span class="fam-date-badge soon">In ${diff}d</span>`;
            if (diff <= 30) return `<span class="fam-date-badge upcoming">In ${diff}d</span>`;
            return `<span class="fam-date-badge past">In ${diff}d</span>`;
        }

        function formatDate(dateStr) {
            if (!dateStr) return '';
            const [y, m, d] = dateStr.split('-');
            const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
            return `${d} ${months[parseInt(m)-1]}`;
        }

        // ── MEMBERS ─────────────────────────────────────────────
        let _famEditMemberId = null;

