        function cancelFamMemberEdit()  { _famEditMemberId = null; renderFamMembers(); }

        function saveFamMemberEdit(mId) {
            const m = famData.members.find(x => x.id === mId);
            if (!m) return;
            const name = (document.getElementById('fme-name-'+mId)?.value||'').trim();
            if (!name) { document.getElementById('fme-name-'+mId)?.focus(); return; }
            m.name  = name;
            m.emoji = (document.getElementById('fme-emoji-'+mId)?.value||'').trim() || '👤';
            m.role  = (document.getElementById('fme-role-'+mId)?.value||'').trim();
            m.note  = (document.getElementById('fme-note-'+mId)?.value||'').trim();
            saveFamData(); _famEditMemberId = null; renderFamMembers();
            showToast('✏️ Member updated', '#fb7185');
        }

        const FAM_BDAY_STEPS = [
            { emoji:'🎁', text:'Buy a gift' },
            { emoji:'🎉', text:'Plan celebration' },
            { emoji:'💌', text:'Write birthday message' },
            { emoji:'🎂', text:'Get birthday cake' },
            { emoji:'📱', text:'Call / video call' },
            { emoji:'🎊', text:'Plan a surprise' },
        ];

        let _famBdayPickerMemberId = null;

        function openFamBdayPicker(mId) {
            _famBdayPickerMemberId = mId;
            renderFamMembers();
        }

        function cancelFamBdayPicker() {
            _famBdayPickerMemberId = null;
            renderFamMembers();
        }

        function pushFamBdayPicker(mId) {
            const m = famData.members.find(x => x.id === mId);
            if (!m) return;
            const container = document.getElementById('fam-bday-picker-' + mId);
            if (!container) return;

            const selected = [];
            container.querySelectorAll('input[type="checkbox"]').forEach(cb => {
                if (cb.checked) {
                    const si = parseInt(cb.dataset.si, 10);
                    if (!isNaN(si) && FAM_BDAY_STEPS[si]) {
                        selected.push({ ...FAM_BDAY_STEPS[si], text: FAM_BDAY_STEPS[si].text + ' for ' + m.name });
                    }
                }
            });

            if (!selected.length) { showToast('Select at least one step', '#f87171'); return; }

            if (!gTasksAll['family']) gTasksAll['family'] = [];
            const taskTitle = m.name + "'s Birthday";
            const already = gTasksAll['family'].find(t => t.text === taskTitle && !t.done);
            if (already) { showToast('Birthday task already exists', '#f9a8d4'); _famBdayPickerMemberId = null; renderFamMembers(); return; }

            const subtasks = selected.map(s => ({
                id: 'fbs_' + Date.now() + '_' + Math.random().toString(36).slice(2),
                text: s.emoji + ' ' + s.text,
                done: false
            }));

            gTasksAll['family'].push({
                id: Date.now() + Math.random(),
                emoji: '🎂',
                text: taskTitle,
                notes: m.birthday ? formatDate(m.birthday) : '',
                done: false,
                subtasks,
                accentColor: '#f9a8d4',
            });
            saveGTasksAll();
            _famBdayPickerMemberId = null;
            renderGTasks('family');
            renderFamMembers();
            try { ['r1','r2','r3'].forEach(s=>{if(rSlots&&rSlots[s]==='family')renderRTasks(s);}); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e) {}
            showToast('🎂 Birthday task added with ' + subtasks.length + ' step' + (subtasks.length !== 1 ? 's' : ''), '#f9a8d4');
        }

