                const sec = (label, color) => {
                    const d = document.createElement('div');
                    d.innerHTML = `<div style="font-size:0.63em;font-weight:900;text-transform:uppercase;letter-spacing:0.7px;color:${color};margin-bottom:6px;">${label}</div>`;
                    return d;
                };
