        function saveFriMember() {
            const name = (document.getElementById('frm-name')?.value || '').trim();
            if (!name) { document.getElementById('frm-name').focus(); return; }
            friData.members.push({
                id:    'fri_' + Date.now(),
                emoji: (document.getElementById('frm-emoji')?.value || '').trim() || '👤',
                name,
                role:  (document.getElementById('frm-role')?.value  || '').trim(),
                note:  (document.getElementById('frm-note')?.value  || '').trim(),
            });
            saveFriData();
            ['frm-emoji','frm-name','frm-role','frm-note'].forEach(id => { const el = document.getElementById(id); if(el) el.value=''; });
            hideFriForm('member'); renderFriMembers();
        }

        function removeFriMember(i) {
            showConfirm({
                title: 'Remove friend?',
                message: 'This will also delete all their dates, promises, and log entries.',
                confirmLabel: 'Remove',
                onConfirm: () => { friData.members.splice(i,1); saveFriData(); renderFriMembers(); }
            });
        }

        // ── DATES ────────────────────────────────────────────────
        function renderFriDates() { renderFriMembers(); }

        function saveFriDate() {
            const label = (document.getElementById('frd-label')?.value || '').trim();
            if (!label) { document.getElementById('frd-label').focus(); return; }
            friData.dates.push({
                emoji: (document.getElementById('frd-emoji')?.value || '').trim(),
                label,
                date:  document.getElementById('frd-date')?.value  || '',
                type:  document.getElementById('frd-type')?.value  || 'birthday',
            });
            saveFriData();
            ['frd-emoji','frd-label','frd-date'].forEach(id => { const el = document.getElementById(id); if(el) el.value=''; });
            hideFriForm('date'); renderFriDates();
        }

        function removeFriDate(i) { friData.dates.splice(i,1); saveFriData(); renderFriDates(); }

        // ── PROMISES ────────────────────────────────────────────
        function renderFriPromises() { renderFriMembers(); }

        function saveFriPromise() {
            const text = (document.getElementById('frp-text')?.value || '').trim();
            if (!text) { document.getElementById('frp-text').focus(); return; }
            friData.promises.push({ text, who: (document.getElementById('frp-who')?.value||'').trim(), done: false });
            saveFriData();
            ['frp-text','frp-who'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
            hideFriForm('promise'); renderFriPromises();
        }

        function toggleFriPromise(i) { friData.promises[i].done = !friData.promises[i].done; saveFriData(); renderFriPromises(); }
        function removeFriPromise(i)  { friData.promises.splice(i,1); saveFriData(); renderFriPromises(); }

        // ── LOG ──────────────────────────────────────────────────
        function renderFriLog() { renderFriMembers(); }

        function saveFriLog() {
            const text = (document.getElementById('frl-text')?.value || '').trim();
            if (!text) { document.getElementById('frl-text').focus(); return; }
            const now = new Date();
            const date = now.toLocaleDateString('pt-PT', { day:'2-digit', month:'short', year:'numeric' });
            friData.log.push({ text, date });
            saveFriData();
            const el = document.getElementById('frl-text'); if(el) el.value='';
            hideFriForm('log'); renderFriLog();
        }

        function removeFriLog(i) { friData.log.splice(i,1); saveFriData(); renderFriLog(); }

        // ── TASKS → migrated to gTasksAll['friends'] + renderGTasks ─

        // ── FORM HELPERS ─────────────────────────────────────────
        function showFriForm(type) {
            const form = document.getElementById('fri-form-' + type);
            if (!form) return;
            form.classList.add('visible');
            const first = form.querySelector('input');
            if (first) first.focus();
        }
        function hideFriForm(type) {
            const form = document.getElementById('fri-form-' + type);
            if (form) form.classList.remove('visible');
        }

        function initFriKeyShortcuts() {
            const map = { 'frm-note':'member', 'frp-who':'promise', 'frl-text':'log' };
            const saves = { member:saveFriMember, promise:saveFriPromise, log:saveFriLog };
            Object.keys(map).forEach(id => {
                const el = document.getElementById(id);
                if (!el) return;
                el.addEventListener('keydown', e => {
                    if (e.key === 'Enter') saves[map[id]]();
                    if (e.key === 'Escape') hideFriForm(map[id]);
                });
            });
        }

        // ── INIT ─────────────────────────────────────────────────
        function initFriendsSection() {
            // One-time migration: friData.tasks -> gTasksAll['friends']
            if ((friData.tasks || []).length && !(gTasksAll['friends'] || []).length) {
                gTasksAll['friends'] = friData.tasks.map(t => ({
                    id: t.id || ('friqt_' + Date.now() + '_' + Math.random()),
                    emoji: t.emoji || '',
                    text: t.title || t.text || '',
                    notes: t.desc || '',
                    done: !!t.done
                }));
                saveGTasksAll();
            }
            renderFriMembers();
            renderGTasks('friends');
            initFriKeyShortcuts();
        }

        // ════════════════════════════════════════════════════════
        //  LOST MODULE
        // ════════════════════════════════════════════════════════

        // Category-smart recovery subtasks — used when pushing a missing item to tasks
        const LOST_RECOVERY_BY_CAT = {
            'Document': [
                { text: '🔍 Retrace — where did you last have it?' },
                { text: '👮 File a police report (needed for replacements)' },
                { text: '🪪 Visit national ID / passport authority' },
                { text: '📷 Bring ID photo + police report number' },
                { text: '🛡️ Check if insurance covers the loss' },
                { text: '📋 Update stored copies / emergency contacts' },
            ],
            'Card': [
                { text: '💳 Block card immediately via app or 24h hotline' },
                { text: '🔍 Check recent transactions for fraud' },
                { text: '🔒 Change online banking password' },
                { text: '🏦 Request replacement card at bank or app' },
                { text: '👮 File police report if theft suspected' },
                { text: '🛡️ Alert insurer if card covers purchase protection' },
            ],
            'Device': [
                { text: '📱 Activate Find My / Google Find My Device' },
                { text: '🔒 Remote lock the device immediately' },
                { text: '🔢 Note IMEI / serial number for police report' },
                { text: '👮 File police report with IMEI' },
                { text: '📵 Report IMEI to carrier to blacklist device' },
                { text: '🗑️ Remote wipe if sensitive data at risk' },
                { text: '🔑 Change passwords for accounts on device' },
                { text: '🛡️ Check device insurance / warranty coverage' },
            ],
            'Key': [
                { text: '🔍 Check all pockets, bags, usual spots' },
                { text: '📞 Contact building manager or landlord' },
                { text: '🔑 Call locksmith if access is urgent' },
                { text: '🚪 Consider rekeying if address was also lost' },
                { text: '🏢 Report to building security / concierge' },
                { text: '🔐 Get duplicate key made once found/replaced' },
            ],
            'Clothing': [
                { text: '🔍 Retrace steps — last place you had it' },
                { text: '🏢 Check lost & found at venues visited' },
                { text: '🚕 Contact taxi / Uber / transport lost & found' },
                { text: '📞 Call restaurant, gym, venue directly' },
                { text: '📋 File online lost property report if transport' },
            ],
            'Other': [
                { text: '🔍 Retrace steps carefully' },
                { text: '🏢 Check lost & found at places visited' },
                { text: '📞 Contact people you were with' },
                { text: '🚕 Check taxi / Uber / public transport lost & found' },
                { text: '👮 File police report if valuable or theft suspected' },
                { text: '🛡️ Check if home/travel insurance covers it' },
            ],
        };

        let lostData = loadData('lostData');
        ensureArrays(lostData, 'items', 'docs', 'tasks');
        if (!lostData.recovery) lostData.recovery = {};
        if (!lostData.activeIfs) lostData.activeIfs = [];

        const saveLostData = () => saveData('lostData', lostData);

        // ── STATS ────────────────────────────────────────────────
        function updateLostStats() {
            const missing   = lostData.items.filter(i => i.status === 'missing').length;
            const searching = lostData.items.filter(i => i.status === 'searching').length;
            const resolved  = lostData.items.filter(i => i.status === 'found' || i.status === 'replaced').length;
            const el = id => document.getElementById(id);
            if (el('lost-stat-missing'))   el('lost-stat-missing').textContent   = missing;
            if (el('lost-stat-searching')) el('lost-stat-searching').textContent = searching;
            if (el('lost-stat-resolved'))  el('lost-stat-resolved').textContent  = resolved;
        }

        // ── QUICK TASK PUSH ──────────────────────────────────────
        function lostQuickTask(emoji, title, desc) {
            if (!gTasksAll['lost']) gTasksAll['lost'] = [];
            const already = gTasksAll['lost'].find(t => (t.text || t.title) === title && !t.done);
            if (already) { toast('Task already exists'); return; }
            gTasksAll['lost'].push({ id: Date.now() + Math.random(), emoji, text: title, notes: desc || '', done: false, accentColor: '#fbbf24' });
            saveGTasksAll();
            renderGTasks('lost');
            try { ['r1','r2','r3'].forEach(slot => { if(rSlots&&rSlots[slot]==='lost') renderRTasks(slot); }); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e) {}
            toast('📌 Task added');
        }

        // ── MISSING ITEMS ────────────────────────────────────────
        function lostPushItemTask(i) {
            const item = lostData.items[i];
            if (!item) return;
            const title = 'Recover: ' + item.name;
            if (!gTasksAll['lost']) gTasksAll['lost'] = [];
            const already = gTasksAll['lost'].find(t => t.text === title && !t.done);
            if (already) { toast('Task already exists'); return; }
            const catSteps = LOST_RECOVERY_BY_CAT[item.cat] || LOST_RECOVERY_BY_CAT['Other'];
            const subtasks = catSteps.map(s => ({ id: 'ls_'+Date.now()+'_'+Math.random().toString(36).slice(2), text: s.text, done: false }));
            gTasksAll['lost'].push({
                id: Date.now() + Math.random(),
                emoji: CAT_EMOJI[item.cat] || '📦',
                text: title, notes: item.note || '',
                done: false, subtasks,
                accentColor: '#fbbf24',
                linkedItemIdx: i,
                linkedItemName: item.name,
            });
            saveGTasksAll();
            renderGTasks('lost');
            try { ['r1','r2','r3'].forEach(slot => { if(rSlots&&rSlots[slot]==='lost') renderRTasks(slot); }); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e) {}
            toast('📌 Recovery task added with ' + subtasks.length + ' steps');
        }

        const CAT_EMOJI = { Document:'📄', Key:'🔑', Card:'💳', Device:'📱', Clothing:'👕', Other:'📦' };
        const LOST_STATUS_CFG = {
            missing:   { label:'🔴 Missing',   c:'#f87171', bg:'rgba(248,113,113,0.1)', bd:'rgba(248,113,113,0.3)' },
            searching: { label:'🔍 Searching',  c:'#fbbf24', bg:'rgba(251,191,36,0.1)', bd:'rgba(251,191,36,0.3)' },
            found:     { label:'✅ Found',      c:'#34d399', bg:'rgba(52,211,153,0.1)',  bd:'rgba(52,211,153,0.3)' },
            replaced:  { label:'🔄 Replaced',   c:'#60a5fa', bg:'rgba(96,165,250,0.1)', bd:'rgba(96,165,250,0.3)' },
        };

        let _lostItemFilter = 'all';
        let _lostEditIdx   = -1;  // index of item currently being edited inline (-1 = none)
        let _lostPickerIdx = -1;  // index of item showing recovery-step picker (-1 = none)
        const _LOST_ITEM_FILTERS = [
            { id:'all',      label:'All' },
            { id:'active',   label:'Active',   match: s => s === 'missing' || s === 'searching' },
            { id:'found',    label:'Found',    match: s => s === 'found' },
            { id:'replaced', label:'Replaced', match: s => s === 'replaced' },
        ];
        function setLostItemFilter(id) { _lostItemFilter = id; renderLostItems(); }

        function _renderLostItemFilterRow() {
            const row = document.getElementById('lost-items-filter-row');
            if (!row) return;
            row.innerHTML = _LOST_ITEM_FILTERS.map(f =>
                '<button onclick="setLostItemFilter(\'' + f.id + '\')" style="padding:4px 10px;border-radius:20px;font-size:0.7em;font-weight:800;cursor:pointer;font-family:\'Outfit\',sans-serif;transition:all 0.15s;border:1px solid ' + (_lostItemFilter === f.id ? 'rgba(251,191,36,0.5)' : 'rgba(255,255,255,0.08)') + ';background:' + (_lostItemFilter === f.id ? 'rgba(251,191,36,0.12)' : 'transparent') + ';color:' + (_lostItemFilter === f.id ? '#fbbf24' : '#475569') + ';">' + f.label + '</button>'
            ).join('');
        }

        function _renderLostItemSummary() {
            const el = document.getElementById('lost-items-summary');
            if (!el || !lostData.items.length) { if (el) el.innerHTML = ''; return; }
            const missing   = lostData.items.filter(i => i.status === 'missing').length;
            const searching = lostData.items.filter(i => i.status === 'searching').length;
            const found     = lostData.items.filter(i => i.status === 'found').length;
            const replaced  = lostData.items.filter(i => i.status === 'replaced').length;
            el.innerHTML = [
                missing   ? '<span style="font-size:0.72em;font-weight:800;padding:3px 9px;border-radius:20px;background:rgba(248,113,113,0.1);color:#f87171;border:1px solid rgba(248,113,113,0.25);">🔴 ' + missing + ' Missing</span>'   : '',
                searching ? '<span style="font-size:0.72em;font-weight:800;padding:3px 9px;border-radius:20px;background:rgba(251,191,36,0.1);color:#fbbf24;border:1px solid rgba(251,191,36,0.25);">🔍 ' + searching + ' Searching</span>' : '',
                found     ? '<span style="font-size:0.72em;font-weight:800;padding:3px 9px;border-radius:20px;background:rgba(52,211,153,0.1);color:#34d399;border:1px solid rgba(52,211,153,0.25);">✅ ' + found + ' Found</span>'         : '',
                replaced  ? '<span style="font-size:0.72em;font-weight:800;padding:3px 9px;border-radius:20px;background:rgba(96,165,250,0.1);color:#60a5fa;border:1px solid rgba(96,165,250,0.25);">🔄 ' + replaced + ' Replaced</span>'   : '',
            ].filter(Boolean).join('');
        }

        function renderLostItems() {
            const list = document.getElementById('lost-items-list');
            if (!list) return;
            _renderLostItemFilterRow();
            _renderLostItemSummary();
            list.innerHTML = '';
            if (!lostData.items.length) {
                list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">Nothing logged yet. Add items below.</div>';
                updateLostStats(); return;
            }
            const filterDef = _LOST_ITEM_FILTERS.find(f => f.id === _lostItemFilter);
            const visible = lostData.items
                .map((item, i) => ({ item, i }))
                .filter(({ item }) => !filterDef || !filterDef.match || filterDef.match(item.status || 'missing'));
            if (!visible.length) {
                list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No items match this filter.</div>';
                updateLostStats(); return;
            }
            visible.forEach(({ item, i }) => {
                const s = item.status || 'missing';
                const st = LOST_STATUS_CFG[s] || LOST_STATUS_CFG.missing;
                const catEmoji = CAT_EMOJI[item.cat] || '📦';
                const steps = LOST_RECOVERY_BY_CAT[item.cat] || LOST_RECOVERY_BY_CAT['Other'];
                const card = document.createElement('div');
                card.style.cssText = `background:rgba(2,8,23,0.5);border:1.5px solid ${st.bd};border-radius:14px;overflow:hidden;transition:border-color 0.3s;`;

                if (_lostPickerIdx === i) {
                    // ── Recovery step picker ──
                    const cats2 = ['Document','Key','Card','Device','Clothing','Other'];
                    card.innerHTML = `
                        <div style="display:flex;flex-direction:column;gap:8px;padding:12px;">
                            <div style="font-size:0.7em;font-weight:900;text-transform:uppercase;letter-spacing:0.6px;color:#fbbf24;margin-bottom:2px;">📋 Choose recovery steps</div>
                            <div style="font-size:0.78em;color:#64748b;margin-bottom:2px;">Select the steps to add as subtasks:</div>
                            <div id="lost-picker-${i}" style="display:flex;flex-direction:column;gap:4px;">
                                ${steps.map((step, si) => `
                                    <label style="display:flex;align-items:center;gap:8px;cursor:pointer;padding:6px 8px;background:rgba(255,255,255,0.03);border-radius:7px;border:1px solid rgba(255,255,255,0.06);">
                                        <input type="checkbox" data-si="${si}" checked style="accent-color:#fbbf24;cursor:pointer;width:15px;height:15px;flex-shrink:0;">
                                        <span style="font-size:0.82em;color:#94a3b8;">${escHtml(step.text)}</span>
                                    </label>`).join('')}
                            </div>
                            <div style="display:flex;gap:6px;flex-wrap:wrap;margin-top:2px;">
                                <button onclick="pushLostPicker(${i})" style="flex:1;padding:7px;border-radius:10px;font-size:0.78em;font-weight:900;cursor:pointer;font-family:'Outfit',sans-serif;background:linear-gradient(135deg,#fbbf24,#f59e0b);border:none;color:#0f172a;">📌 Push task →</button>
                                <button onclick="cancelLostPicker()" style="padding:7px 14px;border-radius:10px;font-size:0.78em;font-weight:700;cursor:pointer;font-family:'Outfit',sans-serif;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.08);color:#64748b;">Cancel</button>
                            </div>
                        </div>`;

                } else if (_lostEditIdx === i) {
                    // ── Inline edit form ──
                    const cats = ['Document','Key','Card','Device','Clothing','Other'];
                    card.innerHTML = `
                        <div style="display:flex;flex-direction:column;gap:8px;padding:12px;">
                            <div style="font-size:0.7em;font-weight:900;text-transform:uppercase;letter-spacing:0.6px;color:#fbbf24;margin-bottom:2px;">✏️ Edit item</div>
                            <div style="display:flex;gap:8px;flex-wrap:wrap;">
                                <input id="lie-name-${i}" class="house-input" value="${escHtml(item.name)}" placeholder="Item name" maxlength="80" style="flex:2;min-width:160px;">
                                <select id="lie-cat-${i}" class="house-input" style="flex:1;min-width:120px;">
                                    ${cats.map(c => `<option value="${c}"${item.cat===c?' selected':''}>${CAT_EMOJI[c]||''} ${c}</option>`).join('')}
                                </select>
                            </div>
                            <input id="lie-note-${i}" class="house-input" value="${escHtml(item.note||'')}" placeholder="Notes — last seen, steps taken... (optional)" maxlength="160">
                            <div style="display:flex;gap:6px;flex-wrap:wrap;">
                                <button onclick="saveLostItemEdit(${i})" style="flex:1;padding:7px;border-radius:10px;font-size:0.78em;font-weight:900;cursor:pointer;font-family:'Outfit',sans-serif;background:linear-gradient(135deg,#fbbf24,#f59e0b);border:none;color:#0f172a;">Save changes</button>
                                <button onclick="cancelLostItemEdit()" style="padding:7px 14px;border-radius:10px;font-size:0.78em;font-weight:700;cursor:pointer;font-family:'Outfit',sans-serif;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.08);color:#64748b;">Cancel</button>
                            </div>
                        </div>`;
                    setTimeout(() => { const el = document.getElementById('lie-name-' + i); if (el) { el.focus(); el.select(); } }, 50);

                } else {
                    // ── Normal view ──
                    card.innerHTML = `
                        <div style="display:flex;align-items:flex-start;gap:8px;padding:12px 12px 8px;">
                            <div style="font-size:1.4em;flex-shrink:0;line-height:1;margin-top:1px;">${catEmoji}</div>
                            <div style="flex:1;min-width:0;">
                                <div style="font-weight:900;font-size:0.97em;color:#e2e8f0;">${escHtml(item.name)}</div>
                                <div style="display:flex;align-items:center;gap:6px;margin-top:4px;flex-wrap:wrap;">
                                    <span style="font-size:0.62em;font-weight:900;padding:2px 7px;border-radius:20px;background:${st.bg};color:${st.c};border:1px solid ${st.bd};">${st.label}</span>
                                    <span style="font-size:0.68em;color:#475569;font-weight:700;">${escHtml(item.cat)}</span>
                                </div>
                                ${item.note ? `<div style="font-size:0.78em;color:#64748b;margin-top:5px;font-style:italic;">"${escHtml(item.note)}"</div>` : ''}
                            </div>
                            <div style="display:flex;flex-direction:column;gap:4px;align-items:flex-end;flex-shrink:0;">
                                <button onclick="openLostPicker(${i})" data-tooltip="Choose recovery steps" style="padding:4px 9px;border-radius:8px;border:1px solid rgba(251,191,36,0.35);background:rgba(251,191,36,0.08);color:#fbbf24;font-family:'Outfit',sans-serif;font-size:0.72em;font-weight:800;cursor:pointer;white-space:nowrap;">📋 Recover</button>
                                <div style="display:flex;gap:4px;">
                                    <button onclick="openLostItemEdit(${i})" style="padding:3px 8px;border-radius:8px;border:1px solid rgba(129,140,248,0.3);background:rgba(129,140,248,0.07);color:#818cf8;font-family:'Outfit',sans-serif;font-size:0.72em;font-weight:800;cursor:pointer;">✏️</button>
                                    <button class="house-delete-btn" onclick="removeLostItem(${i})">🗑️</button>
                                </div>
                            </div>
                        </div>
                        <div style="padding:0 12px 8px;display:flex;flex-direction:column;gap:3px;">
                            <div style="font-size:0.65em;font-weight:900;text-transform:uppercase;letter-spacing:0.6px;color:#334155;margin-bottom:2px;">Recovery steps for this type</div>
                            ${steps.slice(0,3).map(r => `<div style="font-size:0.76em;color:#475569;">· ${r.text}</div>`).join('')}
                            ${steps.length > 3 ? `<div style="font-size:0.7em;color:#334155;font-style:italic;">+ ${steps.length - 3} more when pushed to tasks</div>` : ''}
                        </div>
                        <div style="display:flex;gap:5px;flex-wrap:wrap;padding:8px 10px;border-top:1px solid rgba(255,255,255,0.05);">
                            ${Object.keys(LOST_STATUS_CFG).map(s2 => `<button onclick="setLostItemStatus(${i},'${s2}')" style="padding:3px 8px;border-radius:20px;font-size:0.65em;font-weight:800;cursor:pointer;font-family:'Outfit',sans-serif;transition:all 0.15s;border:1px solid ${s===s2?LOST_STATUS_CFG[s2].bd:'rgba(255,255,255,0.07)'};background:${s===s2?LOST_STATUS_CFG[s2].bg:'transparent'};color:${s===s2?LOST_STATUS_CFG[s2].c:'#334155'};">${LOST_STATUS_CFG[s2].label}</button>`).join('')}
                        </div>`;
                }

                list.appendChild(card);
            });
            updateLostStats();
        }


        // ── STUBS for removed Lost features ─────────────────────
        function renderLostDocs() {}
        function saveLostDoc() {}
        function removeLostDoc() {}
        function cycleLostDocStatus() {}
        function renderLostRecovery() {}
        function resetLostRecovery() {}
        function toggleLostRecovery() {}
        function updateLostRecoveryProgress() {}

        function saveLostItem() {
            const name = (document.getElementById('li-name')?.value || '').trim();
            if (!name) { document.getElementById('li-name').focus(); return; }
            const cat  = document.getElementById('li-cat')?.value || 'Other';
            const note = (document.getElementById('li-note')?.value || '').trim();
            lostData.items.push({ name, cat, note, status: 'missing' });
            saveLostData();
            ['li-name','li-note'].forEach(id => { const el = document.getElementById(id); if(el) el.value = ''; });
            hideLostForm('item');
            renderLostItems();
        }

        function removeLostItem(i) {
            const item = lostData.items[i];
            if (!item) return;
            showConfirm({
                message: 'Remove "' + (item.name || 'item') + '"?',
                confirmLabel: 'Remove', cancelLabel: 'Cancel',
                onConfirm: () => { lostData.items.splice(i, 1); saveLostData(); renderLostItems(); }
            });
        }

        function openLostPicker(i) {
            _lostPickerIdx = i;
            _lostEditIdx = -1;
            renderLostItems();
        }

        function cancelLostPicker() {
            _lostPickerIdx = -1;
            renderLostItems();
        }

        function pushLostPicker(i) {
            const item = lostData.items[i];
            if (!item) return;
            const container = document.getElementById('lost-picker-' + i);
            if (!container) return;
            const catSteps = LOST_RECOVERY_BY_CAT[item.cat] || LOST_RECOVERY_BY_CAT['Other'];
            const selectedSteps = [];
            container.querySelectorAll('input[type="checkbox"]').forEach(cb => {
                if (cb.checked) {
                    const si = parseInt(cb.dataset.si, 10);
                    if (!isNaN(si) && catSteps[si]) selectedSteps.push(catSteps[si]);
                }
            });
            if (!selectedSteps.length) { showToast('Select at least one step', '#f87171'); return; }
            const title = 'Recover: ' + item.name;
            if (!gTasksAll['lost']) gTasksAll['lost'] = [];
            const already = gTasksAll['lost'].find(t => t.text === title && !t.done);
            if (already) { showToast('Recovery task already exists', '#fbbf24'); _lostPickerIdx = -1; renderLostItems(); return; }
            const subtasks = selectedSteps.map(s => ({ id: 'ls_'+Date.now()+'_'+Math.random().toString(36).slice(2), text: s.text, done: false }));
            gTasksAll['lost'].push({
                id: Date.now() + Math.random(),
                emoji: CAT_EMOJI[item.cat] || '📦',
                text: title, notes: item.note || '',
                done: false, subtasks,
                accentColor: '#fbbf24',
                linkedItemIdx: i,
                linkedItemName: item.name,
            });
            saveGTasksAll();
            _lostPickerIdx = -1;
            renderGTasks('lost');
            renderLostItems();
            try { ['r1','r2','r3'].forEach(slot => { if(rSlots&&rSlots[slot]==='lost') renderRTasks(slot); }); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e) {}
            showToast('📌 Recovery task added with ' + subtasks.length + ' step' + (subtasks.length !== 1 ? 's' : ''), '#fbbf24');
        }

        function openLostItemEdit(i) {
            _lostEditIdx = i;
            _lostPickerIdx = -1;
            renderLostItems();
        }

        function cancelLostItemEdit() {
            _lostEditIdx = -1;
            renderLostItems();
        }

        function saveLostItemEdit(i) {
            const item = lostData.items[i];
            if (!item) return;
            const name = (document.getElementById('lie-name-' + i)?.value || '').trim();
            if (!name) { document.getElementById('lie-name-' + i)?.focus(); return; }
            const cat  = document.getElementById('lie-cat-' + i)?.value || item.cat || 'Other';
            const note = (document.getElementById('lie-note-' + i)?.value || '').trim();
            lostData.items[i] = { ...item, name, cat, note };
            saveLostData();
            _lostEditIdx = -1;
            renderLostItems();
            showToast('✏️ Item updated', '#fbbf24');
        }

        function setLostItemStatus(i, status) {
            const prev = lostData.items[i] && lostData.items[i].status;
            lostData.items[i].status = status;
            saveLostData();
            renderLostItems();
            if (status === 'found' && prev !== 'found')     showToast('✅ Great news — item marked as found!', '#34d399');
            else if (status === 'replaced' && prev !== 'replaced') showToast('🔄 Item marked as replaced', '#60a5fa');
        }

        // ── DOCUMENTS ────────────────────────────────────────────
        function cycleLostDocStatus(i) {
            const cycle = ['ok', 'missing', 'expired'];
            const cur = lostData.docs[i].status || 'ok';
            lostData.docs[i].status = cycle[(cycle.indexOf(cur) + 1) % cycle.length];
            saveLostData(); renderLostDocs();
        }

        function renderLostDocs() {
            const list = document.getElementById('lost-docs-list');
            if (!list) return;
            list.innerHTML = '';
            if (!lostData.docs.length) {
                list.innerHTML = '<div style="color:#475569; font-size:0.88em; padding:8px 2px;">No documents yet.</div>';
                return;
            }
            const statusMap = {
                ok:      { cls:'ok',      label:'✅ OK',      color:'#34d399', border:'rgba(52,211,153,0.4)',  bg:'rgba(52,211,153,0.08)'  },
                missing: { cls:'missing', label:'🔴 Missing', color:'#f87171', border:'rgba(239,68,68,0.4)',   bg:'rgba(239,68,68,0.08)'   },
                expired: { cls:'expired', label:'🟡 Expired', color:'#fbbf24', border:'rgba(251,191,36,0.4)',  bg:'rgba(251,191,36,0.08)'  },
            };
            lostData.docs.forEach((doc, i) => {
                const st = statusMap[doc.status] || statusMap.ok;
                const safeN = escHtml(doc.name).replace(/'/g,"\\'");
                const row = document.createElement('div');
                row.className = 'lost-doc-row';
                row.innerHTML = `
                    <div class="lost-doc-icon">${escHtml(doc.emoji || '📄')}</div>
                    <div class="lost-doc-body">
                        <div class="lost-doc-name">${escHtml(doc.name)}</div>
                        ${doc.ref ? `<div class="lost-doc-info">${escHtml(doc.ref)}</div>` : ''}
                    </div>
                    <button onclick="cycleLostDocStatus(${i})" data-tooltip="Tap to change status" style="padding:5px 10px;border-radius:8px;border:1px solid ${st.border};background:${st.bg};color:${st.color};font-family:'Outfit',sans-serif;font-size:0.75em;font-weight:800;cursor:pointer;flex-shrink:0;white-space:nowrap;transition:all 0.15s;">${st.label}</button>
                    <button onclick="lostQuickTask('🪪','Replace: ${safeN}','')" data-tooltip="Add task" style="padding:5px 10px;border-radius:8px;border:1px solid rgba(251,191,36,0.3);background:rgba(251,191,36,0.07);color:#fbbf24;font-family:'Outfit',sans-serif;font-size:0.75em;font-weight:700;cursor:pointer;flex-shrink:0;">📋</button>
                    <button class="house-delete-btn" onclick="removeLostDoc(${i})" data-tooltip="Remove">🗑️</button>`;
                list.appendChild(row);
            });
        }

        function saveLostDoc() {
            const name = (document.getElementById('ld-name')?.value || '').trim();
            if (!name) { document.getElementById('ld-name').focus(); return; }
            const emoji  = (document.getElementById('ld-emoji')?.value  || '').trim() || '📄';
            const ref    = (document.getElementById('ld-ref')?.value    || '').trim();
            const status = document.getElementById('ld-status')?.value || 'ok';
            lostData.docs.push({ emoji, name, ref, status });
            saveLostData();
            ['ld-emoji','ld-name','ld-ref'].forEach(id => { const el = document.getElementById(id); if(el) el.value = ''; });
            hideLostForm('doc');
            renderLostDocs();
        }

        function removeLostDoc(i) {
            lostData.docs.splice(i, 1); saveLostData(); renderLostDocs();
        }

        // ── RECOVERY CHECKLIST ───────────────────────────────────
        const LOST_CAT_COLORS = {
            'First Response': { color:'#38bdf8', border:'rgba(56,189,248,0.5)',  bg:'rgba(56,189,248,0.08)'  },
            'If Financial':   { color:'#f87171', border:'rgba(239,68,68,0.5)',   bg:'rgba(239,68,68,0.08)'   },
            'If Device':      { color:'#a78bfa', border:'rgba(167,139,250,0.5)', bg:'rgba(167,139,250,0.08)' },
            'Official Steps': { color:'#fbbf24', border:'rgba(251,191,36,0.5)',  bg:'rgba(251,191,36,0.08)'  },
            'Follow Up':      { color:'#34d399', border:'rgba(52,211,153,0.5)',  bg:'rgba(52,211,153,0.08)'  },
        };

        // "If" categories that must be toggled on to appear
        const LOST_IF_CATS = ['If Financial', 'If Device'];

        function toggleLostIf(cat) {
            if (!lostData.activeIfs) lostData.activeIfs = [];
            const idx = lostData.activeIfs.indexOf(cat);
            if (idx >= 0) lostData.activeIfs.splice(idx, 1);
            else lostData.activeIfs.push(cat);
            saveLostData();
            renderLostRecovery();
        }

        function renderLostRecovery() {
            const wrap = document.getElementById('lost-recovery-checklist');
            if (!wrap) return;
            wrap.innerHTML = '';
            if (!lostData.activeIfs) lostData.activeIfs = [];

            // ── "If" scenario toggles ─────────────────────────
            const ifToggleDiv = document.createElement('div');
            ifToggleDiv.style.cssText = 'margin-bottom:14px;';
            ifToggleDiv.innerHTML = '<div style="font-size:0.75em;font-weight:800;color:#475569;text-transform:uppercase;letter-spacing:0.8px;margin-bottom:8px;">What applies to your situation?</div>';
            const ifRow = document.createElement('div');
            ifRow.className = 'd-wrap-8';
            LOST_IF_CATS.forEach(cat => {
                const col = LOST_CAT_COLORS[cat];
                const active = lostData.activeIfs.includes(cat);
                const btn = document.createElement('button');
                btn.style.cssText = `padding:7px 14px;border-radius:20px;border:1px solid ${active ? col.border : 'rgba(255,255,255,0.1)'};background:${active ? col.bg : 'rgba(255,255,255,0.03)'};color:${active ? col.color : '#475569'};font-family:'Outfit',sans-serif;font-size:0.82em;font-weight:800;cursor:pointer;transition:all 0.15s;`;
                btn.textContent = (active ? '✓ ' : '+ ') + cat;
                btn.onclick = () => toggleLostIf(cat);
                ifRow.appendChild(btn);
            });
            ifToggleDiv.appendChild(ifRow);
            wrap.appendChild(ifToggleDiv);

            // ── Item picker ────────────────────────────────────
            const activeItems = lostData.items.filter(it => it.status === 'missing' || it.status === 'searching');
            if (activeItems.length) {
                const pickerDiv = document.createElement('div');
                pickerDiv.style.cssText = 'display:flex;align-items:center;gap:8px;margin-bottom:14px;flex-wrap:wrap;';
                pickerDiv.innerHTML = `<span style="font-size:0.78em;color:#475569;font-weight:700;">Link steps to:</span>
                    <select id="lost-recovery-item-select" style="background:rgba(2,8,23,0.6);border:1px solid rgba(251,191,36,0.25);border-radius:8px;color:#e2e8f0;font-family:'Outfit',sans-serif;font-size:0.8em;padding:5px 8px;outline:none;cursor:pointer;">
                        <option value="">— none —</option>
                        ${activeItems.map(it => `<option value="${escHtml(it.name)}">${escHtml(it.name)}</option>`).join('')}
                    </select>`;
                wrap.appendChild(pickerDiv);
            }

            // ── Build step groups ──────────────────────────────
            const groups = {};
            const catOrder = [];
            LOST_RECOVERY_STEPS.forEach(step => {
                if (!groups[step.cat]) { groups[step.cat] = []; catOrder.push(step.cat); }
                groups[step.cat].push(step);
            });

            const visibleCats = catOrder.filter(cat =>
                !LOST_IF_CATS.includes(cat) || lostData.activeIfs.includes(cat)
            );

            visibleCats.forEach(cat => {
                const col = LOST_CAT_COLORS[cat] || { color:'#fbbf24', border:'rgba(251,191,36,0.5)', bg:'rgba(251,191,36,0.08)' };
                const catDiv = document.createElement('div');
                catDiv.style.marginBottom = '14px';
                const catLabel = document.createElement('div');
                catLabel.style.cssText = `font-size:0.72em;font-weight:800;color:${col.color};text-transform:uppercase;letter-spacing:0.8px;margin-bottom:8px;`;
                catLabel.textContent = cat;
                catDiv.appendChild(catLabel);
                const list = document.createElement('div');
                list.className = 'd-col-6';
                groups[cat].forEach(step => {
                    const checked = !!lostData.recovery[step.id];
                    const el = document.createElement('div');
                    el.style.cssText = `display:flex;align-items:center;gap:10px;padding:10px 12px;border-radius:11px;transition:all 0.15s;border:1px solid ${checked ? col.border : 'rgba(255,255,255,0.05)'};background:${checked ? col.bg : 'rgba(2,8,23,0.3)'};`;
                    const cbDiv = document.createElement('div');
                    cbDiv.style.cssText = `width:20px;height:20px;border-radius:6px;border:2px solid ${checked ? col.color : 'rgba(255,255,255,0.15)'};background:${checked ? col.color : 'transparent'};flex-shrink:0;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:900;color:#000;cursor:pointer;transition:all 0.2s;`;
                    cbDiv.textContent = checked ? '✓' : '';
                    cbDiv.onclick = () => toggleLostRecovery(step.id);
                    const textSpan = document.createElement('span');
                    textSpan.style.cssText = `flex:1;font-size:0.87em;color:${checked ? col.color : '#cbd5e1'};font-weight:${checked ? '700' : '600'};text-decoration:${checked ? 'line-through' : 'none'};cursor:pointer;`;
                    textSpan.textContent = (step.emoji ? step.emoji + ' ' : '') + step.text;
                    textSpan.onclick = () => toggleLostRecovery(step.id);
                    const pushBtn = document.createElement('button');
                    pushBtn.title = 'Push to tasks';
                    pushBtn.style.cssText = "padding:4px 8px;border-radius:7px;border:1px solid rgba(251,191,36,0.3);background:rgba(251,191,36,0.07);color:#fbbf24;font-size:0.72em;font-weight:700;cursor:pointer;flex-shrink:0;font-family:'Outfit',sans-serif;";
                    pushBtn.textContent = '📋';
                    pushBtn.onclick = (e) => {
                        e.stopPropagation();
                        const sel = document.getElementById('lost-recovery-item-select');
                        const itemName = sel ? sel.value : '';
                        const title = itemName ? `${step.text} — ${itemName}` : step.text;
                        lostQuickTask(step.emoji || '📋', title, itemName ? `For: ${itemName}` : '');
                    };
                    el.appendChild(cbDiv);
                    el.appendChild(textSpan);
                    el.appendChild(pushBtn);
                    list.appendChild(el);
                });
                catDiv.appendChild(list);
                wrap.appendChild(catDiv);
            });

            // ── Push all unchecked visible steps ───────────────
            const visibleSteps = LOST_RECOVERY_STEPS.filter(s => visibleCats.includes(s.cat));
            const unchecked = visibleSteps.filter(s => !lostData.recovery[s.id]);
            if (unchecked.length) {
                const pushAllBtn = document.createElement('button');
                pushAllBtn.style.cssText = "display:flex;align-items:center;justify-content:center;gap:7px;width:100%;margin-top:4px;background:rgba(255,255,255,0.03);border:1px dashed rgba(251,191,36,0.25);color:#475569;border-radius:12px;padding:10px;cursor:pointer;font-size:0.83em;font-weight:700;font-family:'Outfit',sans-serif;transition:all 0.15s;";
                pushAllBtn.textContent = `📋 Push ${unchecked.length} unchecked steps to Tasks`;
                pushAllBtn.onmouseover = () => { pushAllBtn.style.background='rgba(251,191,36,0.07)'; pushAllBtn.style.color='#fbbf24'; pushAllBtn.style.borderColor='rgba(251,191,36,0.4)'; };
                pushAllBtn.onmouseout  = () => { pushAllBtn.style.background='rgba(255,255,255,0.03)'; pushAllBtn.style.color='#475569'; pushAllBtn.style.borderColor='rgba(251,191,36,0.25)'; };
                pushAllBtn.onclick = () => {
                    const sel = document.getElementById('lost-recovery-item-select');
                    const itemName = sel ? sel.value : '';
                    let added = 0;
                    unchecked.forEach(s => {
                        const title = itemName ? `${s.text} — ${itemName}` : s.text;
                        const already = (lostData.tasks || []).find(t => t.title === title && !t.done);
                        if (!already) {
                            lostData.tasks.push({ id:'lqt_'+Date.now()+'_'+Math.random(), emoji:s.emoji||'📋', title, desc:itemName?`For: ${itemName}`:'' });
                            added++;
                        }
                    });
                    saveLostData(); renderGTasks('lost'); try{['r1','r2','r3'].forEach(slot=>{if(rSlots&&rSlots[slot]==='lost')renderRTasks(slot);});}catch(e){} void(renderLostTasks);
                    toast(`📌 ${added} task${added!==1?'s':''} added`);
                };
                wrap.appendChild(pushAllBtn);
            }

            updateLostRecoveryProgress();
        }

        function toggleLostRecovery(id) {
            lostData.recovery[id] = !lostData.recovery[id];
            saveLostData();
            renderLostRecovery();
        }

        function updateLostRecoveryProgress() {
            if (!lostData.activeIfs) lostData.activeIfs = [];
            const visibleCats = Object.keys(LOST_CAT_COLORS).filter(cat =>
                !LOST_IF_CATS.includes(cat) || lostData.activeIfs.includes(cat)
            );
            const visible = LOST_RECOVERY_STEPS.filter(s => visibleCats.includes(s.cat));
            const total = visible.length;
            const done  = visible.filter(s => lostData.recovery[s.id]).length;
            const fill  = document.getElementById('lost-recovery-fill');
            if (fill) fill.style.width = (total ? Math.round((done/total)*100) : 0) + '%';
        }

        function resetLostRecovery() {
            if (!confirm('Reset recovery checklist?')) return;
            lostData.recovery = {}; lostData.activeIfs = []; saveLostData(); renderLostRecovery();
        }

        // ── TASKS ────────────────────────────────────────────────
        function renderLostTasks() {
            renderGTasks('lost');
            try { ['r1','r2','r3'].forEach(slot => { if(rSlots&&rSlots[slot]==='lost') renderRTasks(slot); }); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e) {}
        }

        function saveLostTask() {
    const emoji = (document.getElementById('lt-emoji')?.value || '').trim();
    const title = (document.getElementById('lt-title')?.value || '').trim();
    const desc  = (document.getElementById('lt-desc')?.value || '').trim();
    if (!title) { document.getElementById('lt-title')?.focus(); return; }

    // Linked item
    const linkedSel = document.getElementById('lt-linked-item');
    const linkedIdxRaw = linkedSel ? linkedSel.value : '';
    const linkedItemIdx = linkedIdxRaw !== '' ? parseInt(linkedIdxRaw, 10) : null;
    const linkedItem = linkedItemIdx !== null ? (lostData.items[linkedItemIdx] || null) : null;

    let id = makeTaskIdFromTitle(title);
    const used = new Set((lostData.tasks || []).map(function(x){ return x.id; }));
    if (used.has(id)) id = id + '_' + Date.now();

    const gId = Date.now() + Math.random();
    lostData.tasks = lostData.tasks || [];
    if (!gTasksAll['lost']) gTasksAll['lost'] = [];

    const gTask = { id: gId, emoji, text: title, notes: desc || (linkedItem ? 'For: ' + linkedItem.name : ''), done: false, accentColor: '#fbbf24' };
    if (linkedItemIdx !== null) {
        gTask.linkedItemIdx = linkedItemIdx;
        gTask.linkedItemName = linkedItem ? linkedItem.name : '';
    }
    gTasksAll['lost'].push(gTask);
    saveGTasksAll();

    const ldTask = { id, gId, emoji, title, desc };
    if (linkedItemIdx !== null) { ldTask.linkedItemIdx = linkedItemIdx; ldTask.linkedItemName = linkedItem ? linkedItem.name : ''; }
    lostData.tasks.push(ldTask);
    saveLostData();

    ['lt-emoji','lt-title','lt-desc'].forEach(function(i){ const el=document.getElementById(i); if(el) el.value=''; });
    if (linkedSel) linkedSel.value = '';
    hideLostForm('task');
    renderLostTasks();
}

        function toggleLostTask(i) {
            lostData.tasks[i].done = !lostData.tasks[i].done; saveLostData(); renderLostTasks();
        }

        function removeLostTask(taskId) {
    lostData.tasks = (lostData.tasks || []).filter(function(t){ return t.id !== taskId; });
    saveLostData();
    renderLostTasks();
}

        // ── FORM HELPERS ────────────────────────────────────────
        function showLostForm(type) {
            const form = document.getElementById('lost-form-' + type);
            if (!form) return;
            form.classList.add('visible');

            // Populate linked-item dropdown when opening the task form
            if (type === 'task') {
                const sel = document.getElementById('lt-linked-item');
                if (sel) {
                    sel.innerHTML = '<option value="">🔗 Link to a missing item (optional)</option>';
                    const active = (lostData.items || [])
                        .map((it, idx) => ({ it, idx }))
                        .filter(({ it }) => it.status === 'missing' || it.status === 'searching');
                    active.forEach(({ it, idx }) => {
                        const o = document.createElement('option');
                        o.value = idx;
                        const badge = it.status === 'searching' ? '🔍' : '❓';
                        o.textContent = badge + ' ' + it.name + (it.cat ? ' (' + it.cat + ')' : '');
                        sel.appendChild(o);
                    });
                    if (!active.length) {
                        const o = document.createElement('option');
                        o.value = ''; o.disabled = true;
                        o.textContent = '— No active missing items —';
                        sel.appendChild(o);
                    }
                }
            }

            const first = form.querySelector('input');
            if (first) first.focus();
        }

        function hideLostForm(type) {
            const form = document.getElementById('lost-form-' + type);
            if (form) form.classList.remove('visible');
        }

        function initLostKeyShortcuts() {
            const map = { 'li-note': 'item', 'ld-ref': 'doc', 'lt-title': 'task' };
            const saves = { item: saveLostItem, doc: saveLostDoc, task: saveLostTask };
            Object.keys(map).forEach(id => {
                const el = document.getElementById(id);
                if (!el) return;
                el.addEventListener('keydown', e => {
                    if (e.key === 'Enter') saves[map[id]]();
                    if (e.key === 'Escape') hideLostForm(map[id]);
                });
            });
        }

        // ── INIT ─────────────────────────────────────────────────
        function initLostSection() {
            renderLostItems();
            renderLostDocs();
            renderLostRecovery();
            renderLostTasks();
            initLostKeyShortcuts();
        }

        // Visit checklist — grouped task cards
        const HOUSE_VISIT_GROUPS = [
            { id:'vg-space',     emoji:'🛋️', label:'Space & Feel', color:'#38bdf8', bg:'rgba(56,189,248,0.08)', border:'rgba(56,189,248,0.2)', items:[
                { id:'vc-light',    emoji:'☀️',  text:'Natural light',         hint:'Check at different times — morning vs afternoon' },
                { id:'vc-noise',    emoji:'🔊',  text:'Noise level',            hint:'Listen for street, neighbours, building sounds' },
                { id:'vc-size',     emoji:'📐',  text:'Room sizes & layout',    hint:'Will your furniture fit? Check proportions' },
                { id:'vc-storage',  emoji:'🗄️',  text:'Storage space',          hint:'Wardrobes, cupboards, attic, basement' },
                { id:'vc-ceiling',  emoji:'📏',  text:'Ceiling height',         hint:'Low ceilings can feel oppressive' },
                { id:'vc-smell',    emoji:'👃',  text:'Smell & air quality',    hint:'Mould, damp, pet odours, old smell' },
            ]},
            { id:'vg-utilities', emoji:'⚡', label:'Utilities', color:'#fbbf24', bg:'rgba(251,191,36,0.08)', border:'rgba(251,191,36,0.2)', items:[
                { id:'vc-water',    emoji:'🚿',  text:'Water pressure',         hint:'Run the shower and taps' },
                { id:'vc-hot-water',emoji:'🔥',  text:'Hot water',              hint:'How fast? Tank or combi boiler?' },
                { id:'vc-heating',  emoji:'❄️',  text:'Heating / AC',           hint:'Type, age, coverage of all rooms' },
                { id:'vc-outlets',  emoji:'🔌',  text:'Power outlets',          hint:'Enough per room? Check kitchen especially' },
                { id:'vc-internet', emoji:'📡',  text:'Internet / fiber',       hint:'Ask provider — is fiber available at this address?' },
                { id:'vc-laundry',  emoji:'🫧',  text:'Washing machine space',  hint:'Hookup available? Where does it go?' },
            ]},
            { id:'vg-condition', emoji:'🔍', label:'Condition', color:'#f87171', bg:'rgba(248,113,113,0.08)', border:'rgba(248,113,113,0.2)', items:[
                { id:'vc-windows',  emoji:'🪟',  text:'Windows & seals',        hint:'Check for drafts, condensation, easy to open' },
                { id:'vc-walls',    emoji:'🧱',  text:'Walls & ceiling',        hint:'Damp patches, cracks, peeling paint' },
                { id:'vc-floors',   emoji:'🪵',  text:'Floors',                 hint:'Creaks, damage, cold, uneven' },
                { id:'vc-kitchen',  emoji:'🍳',  text:'Kitchen & appliances',   hint:'Oven, hob, extractor — test them' },
                { id:'vc-bathroom', emoji:'🚽',  text:'Bathroom',               hint:'Flush, grout condition, mould, ventilation' },
                { id:'vc-doors',    emoji:'🚪',  text:'Doors & locks',          hint:'All close properly, locks work' },
            ]},
            { id:'vg-location',  emoji:'📍', label:'Location', color:'#4ade80', bg:'rgba(74,222,128,0.08)', border:'rgba(74,222,128,0.2)', items:[
                { id:'vc-commute',  emoji:'🚇',  text:'Commute time',           hint:'Test the actual route at rush hour' },
                { id:'vc-transport',emoji:'🚌',  text:'Public transport',       hint:'Nearest bus/metro — how far to walk?' },
                { id:'vc-parking',  emoji:'🅿️',  text:'Parking',               hint:'Included? Street parking available nearby?' },
                { id:'vc-supermarket',emoji:'🛒', text:'Supermarket nearby',   hint:'Walk or drive? How long?' },
                { id:'vc-safety',   emoji:'🔒',  text:'Area safety',            hint:'Walk around at different times of day' },
                { id:'vc-green',    emoji:'🌳',  text:'Green space / parks',    hint:'For walking, running, relaxing' },
            ]},
            { id:'vg-admin',     emoji:'📋', label:'Admin & Legal', color:'#a78bfa', bg:'rgba(167,139,250,0.08)', border:'rgba(167,139,250,0.2)', items:[
                { id:'vc-contract', emoji:'📄',  text:'Contract type & length', hint:'Fixed term? Min stay? Break clause?' },
                { id:'vc-bills',    emoji:'💡',  text:'Bills included?',        hint:'Water, electricity, gas, condo fees' },
                { id:'vc-deposit',  emoji:'💰',  text:'Deposit amount',         hint:'How many months? Returnable? Conditions?' },
                { id:'vc-pets',     emoji:'🐾',  text:'Pet policy',             hint:'Explicit written permission in contract' },
                { id:'vc-landlord', emoji:'👤',  text:'Landlord/agency',        hint:'Responsive? Professional? Check reviews' },
                { id:'vc-available',emoji:'📅',  text:'Available date',         hint:'Matches your move-in timeline?' },
            ]},
        ];
        // Flat list for backward compat
        const HOUSE_VISIT_CHECKLIST_ITEMS = HOUSE_VISIT_GROUPS.flatMap(g => g.items.map(it => ({ ...it, cat: g.label })));

        let houseData = {};
        try {
            houseData = JSON.parse(localStorage.getItem('houseData') || '{}') || {};
        } catch(e) { houseData = {}; }

        // Defaults
        if (!houseData.criteriaList) {
            // Migrate old single criteria to list
            if (houseData.criteria && Object.keys(houseData.criteria).some(k => houseData.criteria[k])) {
                const c = houseData.criteria;
                houseData.criteriaList = [{ id:'crit_migrated', name:'My Criteria', budgetMax:c.budgetMax||'', budgetMin:c.budgetMin||'', type:c.type||'', rooms:c.rooms||'', zones:c.zones||'', commute:c.commute||'', furnished:'', parking:'', pets:'', sizeMin:'', sizeMax:'', notes:'' }];
            } else {
                houseData.criteriaList = [];
            }
        }
        ensureArrays(houseData, 'listings', 'contacts', 'tasks');
        if (!houseData.visitCheck)    houseData.visitCheck    = {};
        if (!houseData.criteriaOpen)  houseData.criteriaOpen  = {};

        const saveHouseData = () => saveData('houseData', houseData);

        // Quick-push a task from listings/areas/contacts — deduplicates by title
        function houseQuickTask(emoji, title, desc) {
            if (!gTasksAll['house']) gTasksAll['house'] = [];
            const already = gTasksAll['house'].find(t => (t.text || t.title) === title && !t.done);
            if (already) { toast('Task already exists'); return; }
            gTasksAll['house'].push({ id: Date.now() + Math.random(), emoji, text: title, notes: desc || '', done: false, accentColor: '#38bdf8' });
            saveGTasksAll();
            renderGTasks('house');
            toast('📌 Task added');
        }

        function pushHouseListingToTasks(idx) {
            const l = houseData.listings[idx];
            if (!l) return;
            if (!gTasksAll['house']) gTasksAll['house'] = [];
            // Pick task label based on current status
            const statusTasks = {
                interested: { emoji: '🔍', verb: 'Research' },
                scheduled:  { emoji: '📅', verb: 'Visit' },
                visited:    { emoji: '📝', verb: 'Evaluate' },
                offer:      { emoji: '📄', verb: 'Make offer on' },
                rejected:   { emoji: '❌', verb: 'Close out' },
            };
            const st = statusTasks[l.status || 'interested'] || { emoji: '🏠', verb: 'Check' };
            const taskTitle = st.verb + ': ' + l.name;
            const already = gTasksAll['house'].find(t => (t.text || t.title) === taskTitle && !t.done);
            if (already) { toast('📋 Task already exists'); return; }
            // Build subtasks from what's known about the listing
            const subtasks = [];
            if ((l.status || 'interested') === 'interested' || l.status === 'scheduled') {
                subtasks.push({ id: 'hl_visit_' + Date.now(), text: '📅 Schedule a visit', done: false });
            }
            if (l.link) subtasks.push({ id: 'hl_link_' + Date.now() + 1, text: '🔗 Review listing page', done: false });
            const contactName = _listingContactName ? _listingContactName(l.contactId) : null;
            if (contactName) subtasks.push({ id: 'hl_contact_' + Date.now() + 2, text: '📞 Contact ' + contactName, done: false });
            if (l.pros || l.cons) subtasks.push({ id: 'hl_eval_' + Date.now() + 3, text: '⚖️ Weigh pros & cons', done: false });
            subtasks.push({ id: 'hl_decide_' + Date.now() + 4, text: '✅ Make a decision', done: false });
            // Build a short info note
            const noteParts = [];
            if (l.price) noteParts.push('€' + l.price + (l.intent === 'buy' ? '' : '/mo'));
            if (l.size)  noteParts.push(l.size + 'm²');
            if (l.zone)  noteParts.push('📍' + l.zone);
            gTasksAll['house'].push({
                id: Date.now() + Math.random(),
                emoji: st.emoji,
                text: taskTitle,
                notes: noteParts.join(' · '),
                done: false,
                accentColor: '#38bdf8',
                subtasks: subtasks.length ? subtasks : undefined,
            });
            saveGTasksAll();
            renderGTasks('house');
            toast('📋 "' + taskTitle + '" added to Tasks');
        }

        // ── CRITERIA (multi-set) ────────────────────────────────
        function addHouseCriteria() {
            houseData.criteriaList.push({
                id: 'crit_' + Date.now(), name: 'New Criteria Set',
                intent: 'rent',
                budgetMax: '', downPayment: '',
                type: '', rooms: '', zones: '', commute: '',
                sizeMin: '', sizeMax: '',
                furnished: '', parking: '', pets: '',
                condition: '', energyMin: '', floorPref: '',
                elevator: '', transport: '', storage: '',
                needBalcony: '', needGarden: '', needTerrace: '',
                sunExposure: '', notes: ''
            });
            saveHouseData(); renderHouseCriteria();
        }

        function removeHouseCriteria(idx) {
            showConfirm({ title: 'Delete criteria set', message: `Delete "<strong>${houseData.criteriaList[idx]?.name || 'this set'}</strong>"?`, confirmLabel: 'Delete', onConfirm: () => {
                houseData.criteriaList.splice(idx, 1);
                saveHouseData(); renderHouseCriteria();
            }});
        }

        function pushHouseCriteriaToTasks(idx) {
            const c = houseData.criteriaList[idx];
            if (!c) return;
            if (!gTasksAll['house']) gTasksAll['house'] = [];
            const taskTitle = 'Research: ' + (c.name || 'Criteria Set');
            const already = gTasksAll['house'].find(t => (t.text || t.title) === taskTitle && !t.done);
            if (already) { toast('📋 Task already exists'); return; }

            const isBuy = c.intent === 'buy';
            const subtasks = [];

            // Search portals
            subtasks.push({ id: 'hcr_s1_' + Date.now(),     text: '🔎 Search listings on portals (Idealista, Imovirtual, OLX)', done: false });

            // Zone-specific steps
            if (c.zones) {
                const zones = c.zones.split(',').map(z => z.trim()).filter(Boolean);
                zones.slice(0, 2).forEach((z, i) => {
                    subtasks.push({ id: 'hcr_z' + i + '_' + Date.now(), text: '📍 Check zone in person: ' + z, done: false });
                });
            }

            // Budget check
            if (c.budgetMax) subtasks.push({ id: 'hcr_b_' + Date.now(), text: '💰 Confirm budget fits: ≤€' + c.budgetMax + (isBuy ? '' : '/mo'), done: false });

            // Must-haves reminder
            const mustHaves = [];
            if (c.furnished === 'yes') mustHaves.push('furnished');
            if (c.parking === 'yes')   mustHaves.push('parking');
            if (c.pets === 'yes')      mustHaves.push('pets OK');
            if (c.elevator === 'yes')  mustHaves.push('elevator');
            if (mustHaves.length)      subtasks.push({ id: 'hcr_m_' + Date.now(), text: '✅ Verify must-haves: ' + mustHaves.join(', '), done: false });

            subtasks.push({ id: 'hcr_e_' + Date.now(), text: '⭐ Shortlist best matches & add to Listings', done: false });

            // Build note from key criteria
            const noteParts = [];
            if (c.type)      noteParts.push(c.type);
            if (c.budgetMax) noteParts.push('≤€' + c.budgetMax + (isBuy ? '' : '/mo'));
            if (c.rooms)     noteParts.push('T' + c.rooms + '+');
            if (c.zones)     noteParts.push('📍' + c.zones.split(',')[0].trim());

            gTasksAll['house'].push({
                id: Date.now() + Math.random(),
                emoji: '🔍',
                text: taskTitle,
                notes: noteParts.join(' · '),
                done: false,
                accentColor: isBuy ? '#a78bfa' : '#38bdf8',
                subtasks,
            });
            saveGTasksAll();
            renderGTasks('house');
            toast('📋 "' + taskTitle + '" added to Tasks');
        }

        function renderHouseCriteria() {
            const list = document.getElementById('house-criteria-list');
            if (!list) return;
            list.innerHTML = '';
            if (!houseData.criteriaList.length) {
                list.innerHTML = '<div style="color:#475569;font-size:0.85em;padding:8px 2px;">No criteria yet. Add a set to define what you\'re looking for.</div>';
                return;
            }

            const TYPE_OPTS_RENT = ['','apartment','studio','house','room','T0','T1','T2','T3','T3+'];
            const TYPE_OPTS_BUY  = ['','apartment','studio','house','villa','townhouse','T0','T1','T2','T3','T3+','land'];

            houseData.criteriaList.forEach((c, idx) => {
                // Ensure new fields exist on old saved data
                if (!c.intent) c.intent = 'rent';

                const isBuy = c.intent === 'buy';
                const accent = isBuy ? '#a78bfa' : '#38bdf8';

                const card = document.createElement('div');
                card.style.cssText = `background:rgba(56,189,248,0.04);border:1.5px solid ${accent}28;border-radius:13px;overflow:hidden;`;

                // ── Header ──────────────────────────────────────────
                const header = document.createElement('div');
                header.style.cssText = `display:flex;align-items:center;gap:8px;padding:10px 12px;cursor:pointer;background:${accent}08;`;
                header.onclick = () => {
                    const b = card.querySelector('.hcrit-body');
                    if (!b) return;
                    const opening = b.style.display === 'none';
                    b.style.display = opening ? 'flex' : 'none';
                    houseData.criteriaOpen[c.id] = opening;
                    saveHouseData();
                };

                const nameEl = document.createElement('div');
                nameEl.contentEditable = 'true'; nameEl.spellcheck = false;
                nameEl.style.cssText = `flex:1;font-weight:800;font-size:0.9em;color:${accent};outline:none;`;
                nameEl.textContent = c.name || 'Criteria Set';
                nameEl.onclick = e => e.stopPropagation();
                nameEl.onblur = () => { c.name = nameEl.textContent.trim() || 'Criteria Set'; saveHouseData(); };

                const intentBadge = document.createElement('span');
                intentBadge.style.cssText = `font-size:0.65em;font-weight:800;padding:2px 8px;border-radius:20px;background:${accent}18;border:1px solid ${accent}44;color:${accent};flex-shrink:0;`;
                intentBadge.textContent = isBuy ? '🏠 Buy' : '🔑 Rent';

                const summaryEl = document.createElement('div');
                summaryEl.style.cssText = 'font-size:0.68em;color:#475569;flex-shrink:0;';
                const parts = [];
                if (c.type) parts.push(c.type);
                if (c.budgetMax) parts.push('≤' + c.budgetMax + (isBuy ? '€' : '€/mo'));
                if (c.zones) parts.push(c.zones.split(',')[0].trim());
                summaryEl.textContent = parts.join(' · ') || 'tap to expand';

                const pushBtn = document.createElement('button');
                pushBtn.onclick = e => { e.stopPropagation(); pushHouseCriteriaToTasks(idx); };
                pushBtn.style.cssText = 'background:none;border:none;color:#475569;font-size:0.85em;cursor:pointer;padding:2px 5px;flex-shrink:0;transition:color 0.15s;opacity:0.55;';
                pushBtn.textContent = '📋';
                pushBtn.title = 'Add research task for this criteria set';
                pushBtn.onmouseover = () => { pushBtn.style.opacity = '1'; pushBtn.style.color = accent; };
                pushBtn.onmouseout  = () => { pushBtn.style.opacity = '0.55'; pushBtn.style.color = '#475569'; };

                const delBtn = document.createElement('button');
                delBtn.onclick = e => { e.stopPropagation(); removeHouseCriteria(idx); };
                delBtn.style.cssText = 'background:none;border:none;color:#475569;font-size:0.85em;cursor:pointer;padding:2px 4px;flex-shrink:0;transition:color 0.15s;';
                delBtn.textContent = '✕';
                delBtn.onmouseover = () => delBtn.style.color = '#f87171';
                delBtn.onmouseout  = () => delBtn.style.color = '#475569';

                header.appendChild(nameEl); header.appendChild(intentBadge); header.appendChild(summaryEl); header.appendChild(pushBtn); header.appendChild(delBtn);
                card.appendChild(header);

                // ── Body ─────────────────────────────────────────────
                const body = document.createElement('div');
                body.className = 'hcrit-body';
                const _critOpen = !!houseData.criteriaOpen[c.id];
                body.style.cssText = `display:${_critOpen ? 'flex' : 'none'};padding:12px;flex-direction:column;gap:10px;`;

                // helpers
                const fld = (placeholder, field, type = 'text') => {
                    const inp = document.createElement('input');
                    inp.className = 'house-input'; inp.type = type;
                    inp.placeholder = placeholder; inp.value = c[field] || '';
                    inp.style.flex = '1';
                    inp.oninput = () => { c[field] = inp.value; saveHouseData(); };
                    return inp;
                };
                const selFld = (field, options) => {
                    const s = document.createElement('select');
                    s.className = 'house-input'; s.style.flex = '1';
                    s.innerHTML = options.map(([v, l]) => `<option value="${v}">${l}</option>`).join('');
                    s.value = c[field] || '';
                    s.onchange = () => { c[field] = s.value; saveHouseData(); renderHouseCriteria(); };
                    return s;
                };
                const tog = (field, label, color) => {
                    const col = color || accent;
                    const active = c[field] === 'yes';
                    const btn = document.createElement('button');
                    btn.type = 'button';
                    btn.style.cssText = `padding:5px 11px;border-radius:20px;font-size:0.75em;font-weight:800;cursor:pointer;font-family:'Outfit',sans-serif;transition:all 0.15s;border:1.5px solid ${active ? col + '80' : 'rgba(255,255,255,0.1)'};background:${active ? col + '25' : 'rgba(255,255,255,0.03)'};color:${active ? col : '#475569'};`;
                    btn.textContent = label;
                    btn.onclick = () => { c[field] = active ? '' : 'yes'; saveHouseData(); renderHouseCriteria(); };
                    return btn;
                };
                const row = (...els) => { const d = document.createElement('div'); d.className = 'd-wrap-8'; els.forEach(e => d.appendChild(e)); return d; };
                const label = (txt) => { const d = document.createElement('div'); d.style.cssText = 'font-size:0.72em;font-weight:700;color:#475569;width:100%;margin-bottom:-4px;'; d.textContent = txt; return d; };

                // ── Intent toggle ────────────────────────────────────
                const intentRow = document.createElement('div');
                intentRow.style.cssText = 'display:flex;gap:6px;';
                ['rent', 'buy'].forEach(v => {
                    const active = (c.intent || 'rent') === v;
                    const col = v === 'buy' ? '#a78bfa' : '#38bdf8';
                    const b = document.createElement('button');
                    b.type = 'button';
                    b.style.cssText = `flex:1;padding:7px 10px;border-radius:10px;font-size:0.8em;font-weight:800;cursor:pointer;font-family:'Outfit',sans-serif;transition:all 0.15s;border:1.5px solid ${active ? col + '80' : 'rgba(255,255,255,0.1)'};background:${active ? col + '20' : 'rgba(255,255,255,0.03)'};color:${active ? col : '#475569'};`;
                    b.textContent = v === 'rent' ? '🔑 Rent' : '🏠 Buy';
                    b.onclick = () => { c.intent = v; saveHouseData(); renderHouseCriteria(); };
                    intentRow.appendChild(b);
                });
                body.appendChild(intentRow);

                // helper: input with always-visible unit badge on the right
                const fldU = (placeholder, field, unit, type = 'text') => {
                    const wrap = document.createElement('div');
                    wrap.style.cssText = 'position:relative;flex:1;display:flex;align-items:center;min-width:70px;';
                    const inp = document.createElement('input');
                    inp.className = 'house-input'; inp.type = type;
                    inp.placeholder = placeholder; inp.value = c[field] || '';
                    if (unit) inp.style.paddingRight = '36px';
                    inp.oninput = () => { c[field] = inp.value; saveHouseData(); };
                    wrap.appendChild(inp);
                    if (unit) {
                        const badge = document.createElement('span');
                        badge.style.cssText = 'position:absolute;right:8px;font-size:0.65em;font-weight:800;color:#475569;pointer-events:none;user-select:none;white-space:nowrap;';
                        badge.textContent = unit;
                        wrap.appendChild(badge);
                    }
                    return wrap;
                };

                // helper: section label with a dim hint
                const secLabel = (icon, title, hint) => {
                    const d = document.createElement('div');
                    d.style.cssText = 'width:100%;display:flex;align-items:baseline;gap:5px;margin-bottom:-2px;margin-top:2px;';
                    d.innerHTML = `<span style="font-size:0.65em;font-weight:900;color:#64748b;text-transform:uppercase;letter-spacing:0.07em;">${icon} ${title}</span>`
                                + (hint ? `<span style="font-size:0.62em;color:#475569;font-style:italic;">${hint}</span>` : '');
                    return d;
                };

                // ── Budget ───────────────────────────────────────────
                if (isBuy) {
                    body.appendChild(secLabel('💰', 'Budget', 'max purchase price · down payment you can put upfront'));
                    body.appendChild(row(fldU('Max price', 'budgetMax', '€', 'number'), fldU('Down payment', 'downPayment', '€', 'number')));
                } else {
                    body.appendChild(secLabel('💰', 'Budget', 'maximum you want to pay per month'));
                    body.appendChild(row(fldU('Max rent', 'budgetMax', '€/mo', 'number')));
                }

                // ── Property ─────────────────────────────────────────
                const typeOpts = (isBuy ? TYPE_OPTS_BUY : TYPE_OPTS_RENT).map(v => [v, v || 'Any type']);
                body.appendChild(secLabel('🏠', 'Property', 'type · minimum bedrooms · size range'));
                body.appendChild(row(
                    selFld('type', typeOpts),
                    fldU('Min rooms', 'rooms', 'T min', 'number'),
                    fldU('Min size', 'sizeMin', 'm²', 'number'),
                    fldU('Max size', 'sizeMax', 'm²', 'number')
                ));

                // ── Location ─────────────────────────────────────────
                body.appendChild(secLabel('📍', 'Location', 'areas to search · max travel time to your main destination'));
                body.appendChild(row(fld('Zones, e.g. Porto, Gaia', 'zones'), fldU('Max commute', 'commute', 'min', 'number')));

                // ── Condition / Energy / Floor ────────────────────────
                body.appendChild(secLabel('🔍', 'Filters', 'building state · energy certificate (A=low bills, G=high bills) · floor level'));
                body.appendChild(row(
                    selFld('condition',  [['','Any condition'],  ['new','🏗️ New build'],['used','🏘️ Used'],['renovate','🔧 To renovate']]),
                    selFld('energyMin',  [['','Any energy rating'],['A','⚡ A (best)'],['B','⚡ B'],['C','⚡ C']]),
                    selFld('floorPref',  [['','Any floor'],['ground','🌿 Ground floor'],['upper','🏢 Upper floors']])
                ));

                // ── Must-haves ────────────────────────────────────────
                body.appendChild(secLabel('✅', 'Must-haves', 'toggle on anything the place must have'));
                const togRow = document.createElement('div');
                togRow.className = 'd-wrap-8';
                const togsMain = [];
                if (!isBuy) togsMain.push(['furnished', '🛋️ Furnished']);
                togsMain.push(
                    ['parking',    '🚗 Parking'],
                    ['pets',       '🐾 Pets OK'],
                    ['elevator',   '🛗 Elevator'],
                    ['transport',  '🚇 Near transport'],
                    ['storage',    '📦 Storage/Garage'],
                    ['sunExposure','☀️ South-facing']
                );
                togsMain.forEach(([f, l]) => togRow.appendChild(tog(f, l)));
                body.appendChild(togRow);
                // South-facing explanation
                const sfHint = document.createElement('div');
                sfHint.style.cssText = 'font-size:0.62em;color:#475569;font-style:italic;width:100%;margin-top:-2px;';
                sfHint.textContent = '☀️ South-facing = main windows face south → direct sunlight all day, warmer in winter';
                body.appendChild(sfHint);

                // ── Outdoor space ─────────────────────────────────────
                body.appendChild(secLabel('🌿', 'Outdoor space', 'must have at least one of these'));
                const outdoorRow = document.createElement('div');
                outdoorRow.className = 'd-wrap-8';
                [['needBalcony','🪴 Balcony'],['needGarden','🌳 Garden'],['needTerrace','🌞 Terrace']].forEach(([f, l]) => outdoorRow.appendChild(tog(f, l, '#4ade80')));
                body.appendChild(outdoorRow);

                // ── Notes ─────────────────────────────────────────────
                body.appendChild(secLabel('📝', 'Notes / dealbreakers', 'anything else that matters — e.g. no ground floor, must have natural light'));
                const notesInp = fld('Write your dealbreakers here…', 'notes');
                notesInp.style.cssText = 'width:100%;box-sizing:border-box;flex:none;';
                body.appendChild(notesInp);

                card.appendChild(body);
                list.appendChild(card);
            });
        }

        function initHouseCriteria() { renderHouseCriteria(); }

        // ── LISTINGS ────────────────────────────────────────────
        const LISTING_STATUS = {
            interested:  { label:'👀 Interested',  color:'#38bdf8', bg:'rgba(56,189,248,0.1)'  },
            favourite:   { label:'⭐ Favourite',   color:'#fbbf24', bg:'rgba(251,191,36,0.1)'  },
            visited:     { label:'🏃 Visited',     color:'#4ade80', bg:'rgba(74,222,128,0.1)'  },
            negotiating: { label:'🤝 Negotiating', color:'#a78bfa', bg:'rgba(167,139,250,0.1)' },
            contacted:   { label:'📞 Contacted',   color:'#818cf8', bg:'rgba(129,140,248,0.1)' },
            rejected:    { label:'✗ Rejected',    color:'#64748b', bg:'rgba(100,116,139,0.1)' },
        };

        function _listingContactName(contactId) {
            if (!contactId) return null;
            const c = (houseData.contacts||[]).find(c => c.id === contactId);
            return c ? (c.name + (c.role ? ' · ' + c.role : '')) : null;
        }

        let _editListingIdx = null;

        function openListingEdit(i) {
            _editListingIdx = (_editListingIdx === i) ? null : i;
            renderHouseListings();
        }

        function saveListingEdit(i) {
            const l = houseData.listings[i];
            if (!l) return;
            const gv  = id => (document.getElementById('hle-' + id)?.value || '').trim();
            const gn  = id => document.getElementById('hle-' + id)?.value || '';
            let intent = l.intent || 'rent';
            document.querySelectorAll('.hle-intent-btn').forEach(b => { if (b.dataset.active === 'true') intent = b.dataset.val; });
            const name = gv('name'); if (!name) { document.getElementById('hle-name')?.focus(); return; }
            l.name      = name;
            l.intent    = intent;
            l.type      = gv('type');
            l.price     = gn('price');
            l.size      = gn('size');
            l.rooms     = gn('rooms');
            l.zone      = gv('zone');
            l.floor     = gv('floor');
            l.link      = gv('link');
            l.contactId = document.getElementById('hle-contact')?.value || '';
            l.pros      = gv('pros');
            l.cons      = gv('cons');
            l.notes     = gv('notes');
            saveHouseData();
            _editListingIdx = null;
            renderHouseListings();
        }

        function toggleHleIntent(val) {
            document.querySelectorAll('.hle-intent-btn').forEach(b => {
                const active = b.dataset.val === val;
                b.dataset.active = active ? 'true' : 'false';
                const isBuy = b.dataset.val === 'buy';
                b.style.background  = active ? (isBuy ? 'rgba(167,139,250,0.15)' : 'rgba(56,189,248,0.15)') : 'rgba(255,255,255,0.03)';
                b.style.borderColor = active ? (isBuy ? 'rgba(167,139,250,0.5)'  : 'rgba(56,189,248,0.45)') : 'rgba(255,255,255,0.08)';
                b.style.color       = active ? (isBuy ? '#a78bfa' : '#38bdf8') : '#475569';
            });
            const priceEl = document.getElementById('hle-price');
            if (priceEl) priceEl.placeholder = val === 'buy' ? 'Price (€)' : 'Price (€/mo)';
        }

        let _houseListingFilter = 'all';
        const _HOUSE_LISTING_FILTERS = [
            { id:'all',       label:'All' },
            { id:'active',    label:'Active',    match: s => ['interested','favourite','contacted','negotiating'].includes(s) },
            { id:'favourite', label:'⭐ Fav',    match: s => s === 'favourite' },
            { id:'visited',   label:'Visited',   match: s => s === 'visited' },
            { id:'rejected',  label:'Rejected',  match: s => s === 'rejected' },
        ];
        function setHouseListingFilter(id) { _houseListingFilter = id; renderHouseListings(); }

        function _renderHouseListingFilterRow() {
            const row = document.getElementById('house-listings-filter-row');
            if (!row) return;
            row.innerHTML = _HOUSE_LISTING_FILTERS.map(f => {
                const active = _houseListingFilter === f.id;
                return '<button onclick="setHouseListingFilter(\'' + f.id + '\')" style="font-size:0.62em;font-weight:800;padding:3px 9px;border-radius:20px;cursor:pointer;font-family:\'Outfit\',sans-serif;transition:all 0.15s;'
                    + (active ? 'background:rgba(56,189,248,0.18);border:1px solid rgba(56,189,248,0.45);color:#38bdf8;'
                              : 'background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.08);color:#475569;')
                    + '">' + f.label + '</button>';
            }).join('');
        }

        function _renderHouseListingSummary() {
            const el = document.getElementById('house-listings-summary');
            if (!el || !houseData.listings.length) { if (el) el.innerHTML = ''; return; }
            const counts = {};
            houseData.listings.forEach(l => { const s = l.status||'interested'; counts[s] = (counts[s]||0) + 1; });
            el.innerHTML = Object.entries(LISTING_STATUS)
                .filter(([k]) => counts[k])
                .map(([k, s]) => '<span style="font-size:0.62em;font-weight:800;padding:3px 9px;border-radius:20px;background:' + s.bg + ';border:1px solid ' + s.color + '44;color:' + s.color + ';">' + s.label + ' ' + counts[k] + '</span>')
                .join('');
        }

        function renderHouseListings() {
            const list = document.getElementById('house-listings-list');
            if (!list) return;
            _renderHouseListingFilterRow();
            _renderHouseListingSummary();
            list.innerHTML = '';
            const filterDef = _HOUSE_LISTING_FILTERS.find(f => f.id === _houseListingFilter);
            const visible = houseData.listings
                .map((l, i) => ({ l, i }))
                .filter(({ l }) => !filterDef || !filterDef.match || filterDef.match(l.status || 'interested'));
            if (!houseData.listings.length) {
                list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No listings yet.</div>';
                updateHouseStats(); return;
            }
            if (!visible.length) {
                list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No listings match this filter.</div>';
                updateHouseStats(); return;
            }
            visible.forEach(({ l, i }) => {
                const st = LISTING_STATUS[l.status||'interested'] || LISTING_STATUS.interested;
                const contactName = _listingContactName(l.contactId);
                const isBuy = l.intent === 'buy';
                const card = document.createElement('div');
                card.style.cssText = `background:rgba(2,8,23,0.5);border:1.5px solid ${st.color}44;border-radius:14px;overflow:hidden;`;

                // Rating stars (1-5)
                const rating = parseInt(l.rating) || 0;
                const ratingHtml = rating ? `<span style="font-size:0.82em;letter-spacing:1px;color:#fbbf24;">${'★'.repeat(rating)}${'☆'.repeat(5-rating)}</span>` : '';

                // Intent badge
                const intentBadge = l.intent ? `<span style="font-size:0.62em;font-weight:800;padding:2px 6px;border-radius:20px;background:${isBuy?'rgba(167,139,250,0.12)':'rgba(56,189,248,0.1)'};border:1px solid ${isBuy?'rgba(167,139,250,0.4)':'rgba(56,189,248,0.3)'};color:${isBuy?'#a78bfa':'#38bdf8'};">${isBuy?'🏠 Buy':'🔑 Rent'}</span>` : '';

                const chips = [
                    intentBadge,
                    l.type   ? `<span style="font-size:0.7em;color:#94a3b8;background:rgba(255,255,255,0.05);padding:2px 7px;border-radius:20px;">${escHtml(l.type)}</span>` : '',
                    l.price  ? `<span style="font-size:0.7em;font-weight:800;color:${st.color};background:${st.bg};padding:2px 7px;border-radius:20px;">€${escHtml(l.price)}${isBuy?'':'/mo'}</span>` : '',
                    l.size   ? `<span style="font-size:0.7em;color:#94a3b8;background:rgba(255,255,255,0.05);padding:2px 7px;border-radius:20px;">${escHtml(l.size)}m²</span>` : '',
                    l.rooms  ? `<span style="font-size:0.7em;color:#94a3b8;background:rgba(255,255,255,0.05);padding:2px 7px;border-radius:20px;">${escHtml(l.rooms)} rm</span>` : '',
                    l.zone   ? `<span style="font-size:0.7em;color:#94a3b8;background:rgba(255,255,255,0.05);padding:2px 7px;border-radius:20px;">📍${escHtml(l.zone)}</span>` : '',
                    l.floor  ? `<span style="font-size:0.7em;color:#94a3b8;background:rgba(255,255,255,0.05);padding:2px 7px;border-radius:20px;">Fl.${escHtml(l.floor)}</span>` : '',
                ].filter(Boolean).join('');

                const safeListingName = escHtml(l.name).replace(/'/g, "\\'");
                card.innerHTML = `
                    <div style="display:flex;align-items:flex-start;gap:8px;padding:12px 12px 8px;">
                        <div style="flex:1;min-width:0;">
                            <div style="display:flex;align-items:center;gap:6px;margin-bottom:5px;flex-wrap:wrap;">
                                <span style="font-weight:900;font-size:0.92em;color:#e2e8f0;">${escHtml(l.name)}</span>
                                ${ratingHtml}
                            </div>
                            <div style="display:flex;flex-wrap:wrap;gap:4px;">${chips}</div>
                            ${contactName ? `<div style="font-size:0.75em;color:#a78bfa;margin-top:5px;">👤 ${escHtml(contactName)}</div>` : ''}
                        </div>
                        <div style="display:flex;gap:4px;flex-shrink:0;">
                            <button onclick="houseStartVisit('${safeListingName}')" title="Start visit checklist for this listing" style="background:rgba(56,189,248,0.08);border:1px solid rgba(56,189,248,0.25);color:#38bdf8;border-radius:8px;padding:4px 8px;font-size:0.7em;font-weight:800;cursor:pointer;font-family:'Outfit',sans-serif;">✅</button>
                            <button onclick="pushHouseListingToTasks(${i})" title="Push to Tasks" style="background:rgba(56,189,248,0.06);border:1px solid rgba(56,189,248,0.2);color:#38bdf8;border-radius:8px;padding:4px 8px;font-size:0.7em;font-weight:800;cursor:pointer;font-family:'Outfit',sans-serif;opacity:0.65;transition:opacity 0.15s;" onmouseover="this.style.opacity='1'" onmouseout="this.style.opacity='0.65'">📋</button>
                            <button onclick="openListingEdit(${i})" title="Edit listing" style="background:${_editListingIdx===i?'rgba(251,191,36,0.15)':'rgba(255,255,255,0.04)'};border:1px solid ${_editListingIdx===i?'rgba(251,191,36,0.4)':'rgba(255,255,255,0.1)'};color:${_editListingIdx===i?'#fbbf24':'#64748b'};border-radius:8px;padding:4px 8px;font-size:0.7em;font-weight:800;cursor:pointer;font-family:'Outfit',sans-serif;">✏️</button>
                            <button class="house-delete-btn" onclick="removeHouseListing(${i})">🗑️</button>
                        </div>
                    </div>
                    ${(l.pros||l.cons) ? `<div style="display:flex;gap:6px;padding:0 12px 8px;flex-wrap:wrap;">
                        ${l.pros?`<div style="flex:1;min-width:80px;font-size:0.72em;color:#4ade80;background:rgba(74,222,128,0.06);border:1px solid rgba(74,222,128,0.15);border-radius:8px;padding:4px 8px;">✅ ${escHtml(l.pros)}</div>`:''}
                        ${l.cons?`<div style="flex:1;min-width:80px;font-size:0.72em;color:#f87171;background:rgba(248,113,113,0.06);border:1px solid rgba(248,113,113,0.15);border-radius:8px;padding:4px 8px;">❌ ${escHtml(l.cons)}</div>`:''}
                    </div>` : ''}
                    ${l.link ? `<div style="padding:0 12px 8px;"><a href="${escHtml(l.link)}" target="_blank" rel="noopener" style="font-size:0.75em;color:#38bdf8;text-decoration:none;">🔗 Open listing ↗</a></div>` : ''}
                    ${l.notes ? `<div style="padding:0 12px 8px;font-size:0.75em;color:#64748b;font-style:italic;">"${escHtml(l.notes)}"</div>` : ''}
                    <div style="display:flex;flex-wrap:wrap;gap:4px;padding:8px 12px;border-top:1px solid rgba(255,255,255,0.04);">
                        ${Object.entries(LISTING_STATUS).map(([key,s]) => {
                            const active = (l.status||'interested')===key;
                            return `<button onclick="setListingStatus(${i},'${key}')" style="padding:3px 8px;border-radius:20px;font-size:0.68em;font-weight:800;cursor:pointer;font-family:'Outfit',sans-serif;border:1.5px solid ${active?s.color+'80':'rgba(255,255,255,0.08)'};background:${active?s.bg:'transparent'};color:${active?s.color:'#475569'};">${s.label}</button>`;
                        }).join('')}
                        <div style="flex:1;display:flex;justify-content:flex-end;align-items:center;gap:2px;">
                            ${[1,2,3,4,5].map(n => `<button onclick="setListingRating(${i},${n})" title="${n} star${n>1?'s':''}" style="background:none;border:none;cursor:pointer;font-size:1em;color:${rating>=n?'#fbbf24':'#334155'};padding:1px 2px;line-height:1;">${rating>=n?'★':'☆'}</button>`).join('')}
                        </div>
                    </div>`;
                // ── Inline edit form ───────────────────────────────
                if (_editListingIdx === i) {
                    const contactOpts = (houseData.contacts||[]).map(c =>
                        `<option value="${c.id}"${l.contactId===c.id?' selected':''}>${escHtml(c.name+(c.role?' — '+c.role:''))}</option>`
                    ).join('');
                    const inp = (id, placeholder, val, type='text') =>
                        `<input class="house-input" id="hle-${id}" type="${type}" placeholder="${placeholder}" value="${escHtml(String(val||''))}" style="flex:1;min-width:90px;">`;
                    const intentBuy = l.intent === 'buy';
                    const btnBase = 'font-size:0.72em;font-weight:900;padding:4px 10px;border-radius:20px;cursor:pointer;font-family:\'Outfit\',sans-serif;transition:all 0.15s;';
                    const editForm = document.createElement('div');
                    editForm.style.cssText = 'padding:10px 12px 12px;border-top:1px solid rgba(255,255,255,0.06);display:flex;flex-direction:column;gap:7px;';
                    editForm.innerHTML = `
                        <div style="font-size:0.7em;font-weight:800;color:#fbbf24;margin-bottom:2px;">✏️ Edit listing</div>
                        <input class="house-input" id="hle-name" placeholder="Name / Address" value="${escHtml(l.name||'')}" maxlength="80">
                        <div style="display:flex;gap:6px;flex-wrap:wrap;align-items:center;">
                            <div style="display:flex;gap:5px;">
                                <button class="hle-intent-btn" data-val="rent" data-active="${!intentBuy}" onclick="toggleHleIntent('rent')"
                                    style="${btnBase}background:${!intentBuy?'rgba(56,189,248,0.15)':'rgba(255,255,255,0.03)'};border:1px solid ${!intentBuy?'rgba(56,189,248,0.45)':'rgba(255,255,255,0.08)'};color:${!intentBuy?'#38bdf8':'#475569'};">🔑 Rent</button>
                                <button class="hle-intent-btn" data-val="buy" data-active="${intentBuy}" onclick="toggleHleIntent('buy')"
                                    style="${btnBase}background:${intentBuy?'rgba(167,139,250,0.15)':'rgba(255,255,255,0.03)'};border:1px solid ${intentBuy?'rgba(167,139,250,0.5)':'rgba(255,255,255,0.08)'};color:${intentBuy?'#a78bfa':'#475569'};">🏠 Buy</button>
                            </div>
                            <select class="house-input" id="hle-type" style="flex:1;min-width:110px;">
                                <option value="">Type…</option>
                                ${['Apartment','House','Studio','Room','Villa','Townhouse','Land'].map(t=>`<option value="${t}"${l.type===t?' selected':''}>${t}</option>`).join('')}
                            </select>
                        </div>
                        <div style="display:flex;gap:6px;flex-wrap:wrap;">
                            ${inp('price','Price',l.price,'number')}
                            ${inp('size','Size (m²)',l.size,'number')}
                            ${inp('rooms','Rooms',l.rooms,'number')}
                        </div>
                        <div style="display:flex;gap:6px;flex-wrap:wrap;">
                            ${inp('zone','Zone / Neighbourhood',l.zone)}
                            ${inp('floor','Floor',l.floor)}
                        </div>
                        <div style="display:flex;gap:6px;flex-wrap:wrap;">
                            ${inp('link','URL',l.link)}
                            <select class="house-input" id="hle-contact" style="flex:1;min-width:120px;">
                                <option value="">No contact</option>${contactOpts}
                            </select>
                        </div>
                        <div style="display:flex;gap:6px;flex-wrap:wrap;">
                            ${inp('pros','Pros',l.pros)}
                            ${inp('cons','Cons',l.cons)}
                        </div>
                        ${inp('notes','Notes',l.notes)}
                        <div style="display:flex;gap:6px;margin-top:2px;">
                            <button onclick="saveListingEdit(${i})" style="flex:1;padding:7px;border-radius:10px;font-size:0.78em;font-weight:900;cursor:pointer;font-family:'Outfit',sans-serif;background:linear-gradient(135deg,#fbbf24,#f59e0b);border:none;color:#0f172a;">Save changes</button>
                            <button onclick="openListingEdit(${i})" style="padding:7px 14px;border-radius:10px;font-size:0.78em;font-weight:700;cursor:pointer;font-family:'Outfit',sans-serif;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.08);color:#64748b;">Cancel</button>
                        </div>`;
                    card.appendChild(editForm);
                }

                list.appendChild(card);
            });
            updateHouseStats();
        }

        function _populateListingContactDropdown() {
            const sel = document.getElementById('hl-contact');
            if (!sel) return;
            const cur = sel.value;
            sel.innerHTML = '<option value="">No contact linked</option>';
            (houseData.contacts||[]).forEach(c => {
                const opt = document.createElement('option');
                opt.value = c.id; opt.textContent = c.name + (c.role ? ' — '+c.role : '');
                sel.appendChild(opt);
            });
            if (cur) sel.value = cur;
        }

        function _setHouseListingField(id, value) {
            const el = document.getElementById(id);
            if (!el || value === undefined || value === null || value === '') return;
            el.value = String(value).trim();
        }

        function _setHouseListingIntent(intent) {
            const wanted = intent === 'buy' ? 'buy' : 'rent';
            document.querySelectorAll('#hl-intent-btn').forEach(b => {
                const active = b.dataset.val === wanted;
                b.dataset.active = active ? 'true' : 'false';
                _styleHlIntentBtn(b, active);
            });
            const priceEl = document.getElementById('hl-price');
            if (priceEl) priceEl.placeholder = wanted === 'buy' ? 'Price (€)' : 'Price (€/mo)';
        }

        function _cleanListingUrl(raw) {
            const m = String(raw || '').match(/https?:\/\/[^\s<>"']+/i);
            if (!m) return '';
            try {
                const u = new URL(m[0]);
                ['fbclid', 'utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content'].forEach(k => u.searchParams.delete(k));
                return u.toString();
            } catch(e) {
                return m[0];
            }
        }

        function _titleFromListingUrl(url) {
            if (!url) return '';
            try {
                const u = new URL(url);
                const last = u.pathname.split('/').filter(Boolean).pop() || '';
                const clean = last.replace(/^ID[^-]*$/i, '').replace(/-ID[^-]+$/i, '').replace(/\.[a-z0-9]+$/i, '');
                return clean
                    .split('-')
                    .filter(Boolean)
                    .map(w => w.length <= 3 && /^t\d/i.test(w) ? w.toUpperCase() : w.charAt(0).toUpperCase() + w.slice(1))
                    .join(' ')
                    .trim();
            } catch(e) {
                return '';
            }
        }

        function _parseHouseListingText(raw) {
            const text = String(raw || '').replace(/\u00a0/g, ' ').replace(/[ \t]+/g, ' ').trim();
            const url  = _cleanListingUrl(text);
            const data = { link: url };

            // STRATEGY 1: Structured label:value (AI/Claude/ChatGPT output)
            const allLines = text.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
            const structLines = allLines.filter(l => /^[-•*]?\s*\*{0,2}[^:*\n]{2,45}\*{0,2}\s*:\s*.{1,}/.test(l));
            if (structLines.length >= 2) {
                structLines.forEach(line => {
                    const m = line.match(/^[-•*]?\s*\*{0,2}([^:*\n]{2,45}?)\*{0,2}\s*:\s*(.+)$/);
                    if (!m) return;
                    const key = m[1].trim().toLowerCase();
                    const val = m[2].replace(/\*+/g, '').replace(/\s*\([^)]*\)/g, '').trim();
                    if (!val) return;
                    if (/\b(price|pre[cç]o|valor|rent|aluguer|arrendamento|sale price)\b/.test(key)) {
                        const nums = val.replace(/[^\d]/g, '');
                        if (nums) data.price = nums;
                        if (/month|m[eê]s|\/mo|alug|arren/i.test(val + line)) data.intent = 'rent';
                        else if (/compra|venda|sale|buy/i.test(val + line))          data.intent = 'buy';
                        else if (nums && parseInt(nums) > 50000)                      data.intent = 'buy';
                        else data.intent = 'rent';
                    } else if (/\b(size|[áa]rea|m[\u00b2]|metros|sqm|square)\b/.test(key)) {
                        const n = val.match(/(\d{2,5})/)?.[1]; if (n && !data.size) data.size = n;
                    } else if (/\b(rooms?|quartos?|tipolog|bedrooms?)\b/.test(key)) {
                        const t = val.match(/T\s*(\d)/i)?.[1] || val.match(/(\d+)/)?.[1]; if (t && !data.rooms) data.rooms = t;
                    } else if (/\b(floor|andar)\b/.test(key)) {
                        if (!data.floor) data.floor = val.replace(/^\d+\s*-\s*/, '').trim();
                    } else if (/\b(location|zone?|city|cidade|localiz|address|endere|zona|neighbourhood|bairro)\b/.test(key)) {
                        if (!data.zone) { const parts = val.split(',').map(p=>p.trim()).filter(Boolean); data.zone = parts.slice(-2).join(', '); }
                    } else if (/\b(type|tipo|property\s*type)\b/.test(key)) {
                        if (!data.type) data.type = _mapImportPropertyType(val);
                    } else if (/\b(title|name|nome|t[ií]tulo)\b/.test(key)) {
                        if (!data.name) data.name = val;
                    } else if (/\b(energy|energia|certif|rating|classifica)\b/.test(key)) {
                        const r = val.match(/\b([A-G])\b/)?.[1]; if (r) data._energy = r;
                    } else if (/\b(condition|condi[cç]|features?|caracter|notes?)\b/.test(key)) {
                        if (!data._extraNotes) data._extraNotes = val;
                    }
                });
            }

            // STRATEGY 2: Smart URL slug
            if (url && !data.name) {
                const slug = (() => { try { return new URL(url).pathname.split('/').filter(Boolean).pop() || ''; } catch(e) { return ''; } })();
                if (slug) {
                    const parts = slug.replace(/-?ID[a-z0-9]+$/i, '').split('-').filter(Boolean);
                    if (!data.rooms) { const t = parts.find(p => /^t\d$/i.test(p)); if (t) data.rooms = t.replace(/t/i,''); }
                    const CITIES = ['porto','lisboa','gaia','matosinhos','braga','coimbra','aveiro','faro','almada','cascais','oeiras','sintra','maia','gondomar','campanha','bonfim','cedofeita','paranhos','ramalde','boavista'];
                    if (!data.zone) { const c = parts.find(p => CITIES.includes(p.toLowerCase())); if (c) data.zone = c.charAt(0).toUpperCase()+c.slice(1); }
                    if (!data.floor) {
                        if (parts.some(p => /^[uú]ltimo$/i.test(p)))       data.floor = 'Top floor';
                        else if (parts.some(p => /^r[\/\-]?c$/i.test(p)))     data.floor = 'Ground floor';
                        else { const fi = parts.findIndex(p => /^andar$/i.test(p)); if (fi>0 && /^\d+$/.test(parts[fi-1])) data.floor = parts[fi-1]+'º'; }
                    }
                    data.name = _titleFromListingUrl(url);
                    const sf = []; const sl = slug.toLowerCase();
                    if (/renovad|remodelad/.test(sl)) sf.push('Renovated');
                    if (/elevador/.test(sl))           sf.push('Elevator');
                    if (/garagem|garage/.test(sl))     sf.push('Parking');
                    if (/varanda/.test(sl))            sf.push('Balcony');
                    if (/terra[cç]o/.test(sl))        sf.push('Terrace');
                    if (sf.length) data._slugNotes = sf.join(' · ');
                }
            }

            // STRATEGY 3: Regex scan of full text
            if (!data.price) { const pm = text.match(/(?:€\s*)?(\d{1,3}(?:[ .]\d{3})+|\d{3,7})(?:\s*€)?(?:\s*\/\s*m[eê]s|\s*\/\s*month|\s*mensais|\s*\/mo)?/i); if (pm) data.price = pm[1].replace(/[ .]/g,''); }
            if (!data.intent) {
                if      (/comprar|venda|vende-se|\bbuy\b|pre[cç]o de venda/i.test(text)) data.intent = 'buy';
                else if (data.price && parseInt(data.price) > 50000)                      data.intent = 'buy';
                else                                                                        data.intent = 'rent';
            }
            if (!data.size)  { const sm = text.match(/(\d{2,4})\s*(?:m[\u00b2]|m2|metros quadrados|sqm)\b/i); if (sm) data.size = sm[1]; }
            if (!data.rooms) { const rm = text.match(/\bT\s*([0-9])\+?\b/i) || text.match(/(\d+)\s*(?:quartos?|bedrooms?|rooms?)\b/i); if (rm) data.rooms = rm[1]; }
            if (!data.type) {
                if      (/\b(t0|studio|est[uú]dio)\b/i.test(text))             data.type = 'Studio';
                else if (/\b(apartamento|apartment|andar|flat)\b/i.test(text))   data.type = 'Apartment';
                else if (/\b(moradia|house|casa)\b/i.test(text))                 data.type = 'House';
                else if (/\b(villa|vivenda)\b/i.test(text))                      data.type = 'Villa';
                else if (/\b(quarto|room)\b/i.test(text))                        data.type = 'Room';
                else if (/\b(terreno|land)\b/i.test(text))                       data.type = 'Land';
            }
            if (!data.floor) { const fm = text.match(/(?:^|\s)(\d+)[\u00baª]?\s*(?:andar|floor)\b/i) || text.match(/\b(r\/c|rés-do-chão|ground floor|ultimo andar|último andar|top floor)\b/i); if (fm) data.floor = fm[1] || fm[0].trim(); }
            if (!data.zone) { const zm = text.match(/\b(?:em|in|zona de|freguesia de)\s+([A-ZÁÉÍÓÚÂÊÔÃÕÇ][\wÀ-ÿ' -]{2,45})(?:[,.\n]|$)/) || text.match(/\b(Porto|Lisboa|Gaia|Matosinhos|Campan[h\u00e3]+|Bonfim|Cedofeita|Paranhos|Maia|Gondomar|Cascais|Oeiras|Almada|Braga|Coimbra|Aveiro|Faro)\b/i); if (zm) data.zone = (zm[1]||zm[0]).trim(); }
            if (!data.name) { const tl = allLines.find(l => l.length>=8 && l.length<=100 && !/^https?:\/\//i.test(l) && !/cookie|contactar|telefone|an[uú]ncio|whatsapp/i.test(l)); data.name = tl || _titleFromListingUrl(url); }

            // Notes: merge all hints
            const noteSet = new Set();
            if (data._energy)     noteSet.add('Energy ' + data._energy);
            if (data._extraNotes) data._extraNotes.split(/[,·]/).map(n=>n.trim()).filter(Boolean).forEach(n=>noteSet.add(n));
            if (data._slugNotes)  data._slugNotes.split(' · ').forEach(n=>noteSet.add(n));
            if (/renovad[oa]|remodelad[oa]/i.test(text))            noteSet.add('Renovated');
            if (/elevador|lift|elevator/i.test(text))                noteSet.add('Elevator');
            if (/garagem|garage|parking|estacionamento/i.test(text)) noteSet.add('Parking');
            if (/varanda|balcony/i.test(text))                       noteSet.add('Balcony');
            if (/terra[cç]o|terrace/i.test(text))              noteSet.add('Terrace');
            if (/metro|esta[cç][ãa]o|comboio/i.test(text))noteSet.add('Near transport');
            if (/piscina|swimming pool/i.test(text))                 noteSet.add('Pool');
            if (/jardim|garden/i.test(text))                         noteSet.add('Garden');
            if (noteSet.size) data.notes = [...noteSet].join(' · ');
            delete data._energy; delete data._extraNotes; delete data._slugNotes;
            return data;
        }

        function analyzeHouseListingPaste() {
            const src = document.getElementById('hl-import-text');
            const hint = document.getElementById('hl-import-hint');
            const raw = (src?.value || '').trim();
            if (!raw) { src?.focus(); return; }
            const data = _parseHouseListingText(raw);
            _setHouseListingIntent(data.intent);
            _setHouseListingField('hl-name', data.name);
            _setHouseListingField('hl-type', data.type);
            _setHouseListingField('hl-price', data.price);
            _setHouseListingField('hl-size', data.size);
            _setHouseListingField('hl-rooms', data.rooms);
            _setHouseListingField('hl-zone', data.zone);
            _setHouseListingField('hl-floor', data.floor);
            _setHouseListingField('hl-link', data.link);
            _setHouseListingField('hl-notes', data.notes);
            if (hint) {
                const filled = ['name','type','price','size','rooms','zone','floor','link','notes'].filter(k => data[k]).length;
                hint.textContent = filled ? `Filled ${filled} field${filled === 1 ? '' : 's'}. Check before saving.` : 'I could not read much from that text. Paste more of the listing page.';
                hint.style.color = filled ? '#38bdf8' : '#fbbf24';
            }
        }

        function clearHouseListingPaste() {
            const src = document.getElementById('hl-import-text');
            const hint = document.getElementById('hl-import-hint');
            if (src) src.value = '';
            if (hint) {
                hint.textContent = 'Paste a URL to fetch, or paste copied listing text to parse.';
                hint.style.color = '#64748b';
            }
        }

        function copyListingAIPrompt() {
            const prompt = [
                'Extract info from the real estate listing I will share and reply ONLY in this exact format (key: value, one per line). Omit any field you are not sure about — do not guess.',
                '',
                'Name: [property name or full address]',
                'Type: [Apartment / House / Studio / Villa / Townhouse / Room / Land]',
                'Price: [number + €/month for rent, e.g. 850 €/month — OR use "Sale price: 250000 €" if it is for sale]',
                'Size: [area in m², number only, e.g. 75]',
                'Rooms: [number of bedrooms, e.g. 2]',
                'Floor: [floor number or label, e.g. 3, Ground floor, Top floor]',
                'Zone: [neighbourhood, city, e.g. Bonfim, Porto]',
                'Energy: [energy certificate letter only: A / B / C / D / E / F / G]',
                'Notes: [2–3 key highlights, comma-separated]',
                '',
                'No intro sentence, no explanation — just the list above.',
                '',
                '--- LISTING BELOW (paste text or URL) ---',
                ''
            ].join('\n');

            const btn = document.getElementById('hl-ai-prompt-btn');
            const hint = document.getElementById('hl-import-hint');

            navigator.clipboard.writeText(prompt).then(() => {
                if (btn) { btn.textContent = '✓ Copied!'; setTimeout(() => { btn.textContent = '🤖 Copy AI Prompt'; }, 2200); }
                if (hint) { hint.textContent = 'Prompt copied! Paste it into Claude or ChatGPT, add the listing, then paste the reply back here → Fill from text.'; hint.style.color = '#34d399'; setTimeout(() => { hint.textContent = 'Paste URL → Fetch · Paste text or AI reply → Fill from text'; hint.style.color = '#64748b'; }, 5000); }
            }).catch(() => {
                // Fallback for browsers that block clipboard
                const ta = document.createElement('textarea');
                ta.value = prompt;
                ta.style.cssText = 'position:fixed;top:-999px;left:-999px;opacity:0;';
                document.body.appendChild(ta);
                ta.select();
                document.execCommand('copy');
                document.body.removeChild(ta);
                if (btn) { btn.textContent = '✓ Copied!'; setTimeout(() => { btn.textContent = '🤖 Copy AI Prompt'; }, 2200); }
                if (hint) { hint.textContent = 'Prompt copied! Paste into Claude or ChatGPT with your listing, then paste the reply here → Fill from text.'; hint.style.color = '#34d399'; setTimeout(() => { hint.textContent = 'Paste URL → Fetch · Paste text or AI reply → Fill from text'; hint.style.color = '#64748b'; }, 5000); }
            });
        }

        // ── URL FETCH IMPORT ────────────────────────────────────
        function _mapImportPropertyType(raw) {
            const t = (raw || '').toLowerCase();
            if (t.includes('apartment') || t.includes('flat') || t.includes('apartamento') || t.includes('andar')) return 'Apartment';
            if (t.includes('studio') || t.includes('estudio') || t.includes('t0')) return 'Studio';
            if (t.includes('villa') || t.includes('vivenda')) return 'Villa';
            if (t.includes('townhouse') || t.includes('moradia em banda')) return 'Townhouse';
            if (t.includes('house') || t.includes('moradia') || t.includes('casa')) return 'House';
            if (t.includes('land') || t.includes('terreno')) return 'Land';
            if (t.includes('room') || t.includes('quarto')) return 'Room';
            return '';
        }

        function _parseImportNextData(nd) {
            const pp = nd?.props?.pageProps;
            if (!pp) return null;
            const ad = pp.ad || pp.listing || pp.property || pp.data?.ad || pp.adDetails || pp.propertyDetails;
            if (!ad) return null;
            const price = ad.price?.value ?? ad.totalPrice?.value ?? ad.rentPrice?.value ?? ad.priceValue ?? '';
            const transaction = (ad.transaction || ad.transactionType || ad.offerType || '').toUpperCase();
            const isBuy = transaction === 'SELL' || transaction === 'SALE' || transaction === 'FOR_SALE' || transaction === 'COMPRA';
            const rooms = ad.roomsNumber ?? ad.rooms ?? ad.numberOfRooms ?? '';
            const titleRaw = ad.title || ad.name || '';
            const roomsFromTitle = (!rooms && titleRaw) ? (titleRaw.match(/T(\d)/i)?.[1] || '') : '';
            return {
                name:   titleRaw,
                price:  String(price),
                rooms:  String(rooms || roomsFromTitle),
                size:   String(ad.areaInSquareMeters ?? ad.area ?? ad.floorArea ?? ad.usableArea ?? ''),
                zone:   ad.location?.address?.city || ad.location?.city || ad.address?.city || ad.city || '',
                floor:  String(ad.floor ?? ad.floorNumber ?? ''),
                type:   _mapImportPropertyType(ad.property?.type || ad.propertyType || ad.type || titleRaw),
                intent: isBuy ? 'buy' : 'rent',
            };
        }

        function _parseImportLdJson(ld) {
            const arr = Array.isArray(ld) ? ld : [ld];
            for (const item of arr) {
                const type = String(item['@type'] || '').toLowerCase();
                if (!type) continue;
                const isProperty = ['apartment','house','residence','realestatelisting','singlefamilyresidence','accommodation','product'].some(t => type.includes(t));
                if (!isProperty) continue;
                const price = item.offers?.price ?? item.price ?? '';
                return {
                    name:   item.name || '',
                    price:  String(price).replace(/[^\d.]/g, ''),
                    rooms:  String(item.numberOfRooms || ''),
                    size:   String(item.floorSize?.value || item.floorArea || ''),
                    zone:   item.address?.addressLocality || item.address?.addressRegion || '',
                    floor:  '',
                    type:   _mapImportPropertyType(String(item['@type'] || '')),
                    intent: 'rent',
                };
            }
            return null;
        }

        function _parseImportMetaTags(doc) {
            const og   = p => doc.querySelector(`meta[property="${p}"]`)?.getAttribute('content') || '';
            const meta = n => doc.querySelector(`meta[name="${n}"]`)?.getAttribute('content') || '';
            const title = og('og:title') || doc.title || meta('title') || '';
            const desc  = og('og:description') || meta('description') || '';
            if (!title && !desc) return null;
            const combined = title + ' ' + desc;
            const priceMatch = combined.match(/[\d\s.]+\s*€(?:\s*\/\s*m[eê]s)?/i);
            const priceStr   = priceMatch ? priceMatch[0].replace(/[^\d]/g, '') : '';
            const isBuyHint  = /vend|compra|sale|buy|sell/i.test(combined);
            const isRentHint = /arren|alug|rent|m[eê]s/i.test(combined);
            const roomsMatch = combined.match(/T\s*(\d)/i)?.[1] || combined.match(/(\d+)\s*(?:quart|room|bed)/i)?.[1] || '';
            const sizeMatch  = combined.match(/(\d+)\s*m²/i)?.[1] || '';
            return {
                name:   title.replace(/\s*[|\-–]\s*.+$/, '').trim(),
                price:  priceStr,
                rooms:  roomsMatch,
                size:   sizeMatch,
                zone:   '',
                floor:  '',
                type:   _mapImportPropertyType(combined),
                intent: isBuyHint && !isRentHint ? 'buy' : 'rent',
            };
        }

        async function _fetchListingData(url) {
            const PROXY = 'https://api.allorigins.win/get?url=';
            const controller = new AbortController();
            const tid = setTimeout(() => controller.abort(), 12000);
            try {
                const resp = await fetch(PROXY + encodeURIComponent(url), { signal: controller.signal });
                if (!resp.ok) return null;
                const data = await resp.json();
                const html = data.contents;
                if (!html) return null;

                const parser = new DOMParser();
                const doc = parser.parseFromString(html, 'text/html');

                // 1 — Next.js embedded JSON (imovirtual, idealista, olx, etc.)
                const nextEl = doc.getElementById('__NEXT_DATA__');
                if (nextEl) {
                    try {
                        const result = _parseImportNextData(JSON.parse(nextEl.textContent));
                        if (result?.name) return result;
                    } catch(e) {}
                }

                // 2 — JSON-LD structured data
                for (const s of doc.querySelectorAll('script[type="application/ld+json"]')) {
                    try {
                        const result = _parseImportLdJson(JSON.parse(s.textContent));
                        if (result?.name) return result;
                    } catch(e) {}
                }

                // 3 — OG / meta tags (last resort)
                const metaResult = _parseImportMetaTags(doc);
                if (metaResult?.name) return metaResult;

                return null;
            } finally {
                clearTimeout(tid);
            }
        }

        async function importListingFromUrl() {
            const src  = document.getElementById('hl-import-text');
            const hint = document.getElementById('hl-import-hint');
            const btn  = document.getElementById('hl-fetch-btn');
            const raw  = (src?.value || '').trim();
            if (!raw) { src?.focus(); return; }

            // Extract and clean URL from pasted text
            const url = _cleanListingUrl(raw);
            if (!url) {
                if (hint) { hint.textContent = 'No URL found — use "Fill from text" to parse copied text.'; hint.style.color = '#fbbf24'; }
                return;
            }

            if (btn) { btn.textContent = '⏳'; btn.disabled = true; }
            if (hint) { hint.textContent = 'Fetching listing…'; hint.style.color = '#94a3b8'; }

            try {
                const result = await _fetchListingData(url);

                // Always save the clean URL to the link field
                _setHouseListingField('hl-link', url);

                if (result) {
                    _setHouseListingIntent(result.intent);
                    _setHouseListingField('hl-name',  result.name);
                    _setHouseListingField('hl-type',  result.type);
                    _setHouseListingField('hl-price', result.price);
                    _setHouseListingField('hl-size',  result.size);
                    _setHouseListingField('hl-rooms', result.rooms);
                    _setHouseListingField('hl-zone',  result.zone);
                    _setHouseListingField('hl-floor', result.floor);
                    if (src) src.value = '';
                    const filled = ['name','type','price','size','rooms','zone','floor'].filter(k => result[k]).length;
                    if (hint) { hint.textContent = `Fetched! ${filled} field${filled===1?'':'s'} filled — review before saving.`; hint.style.color = '#4ade80'; }
                } else {
                    // Fallback: try text parse of the URL slug
                    const slugData = _parseHouseListingText(raw);
                    _setHouseListingIntent(slugData.intent);
                    _setHouseListingField('hl-name',  slugData.name || _titleFromListingUrl(url));
                    _setHouseListingField('hl-type',  slugData.type);
                    _setHouseListingField('hl-price', slugData.price);
                    _setHouseListingField('hl-rooms', slugData.rooms);
                    _setHouseListingField('hl-zone',  slugData.zone);
                    if (src) src.value = '';
                    if (hint) { hint.textContent = 'Fetch blocked by site — extracted what I could from the URL. Fill in the rest manually.'; hint.style.color = '#fbbf24'; }
                }
            } catch(e) {
                _setHouseListingField('hl-link', url);
                if (src) src.value = '';
                if (hint) { hint.textContent = 'Network error — URL saved. Fill in the details manually.'; hint.style.color = '#f87171'; }
            } finally {
                if (btn) { btn.textContent = '🌐 Fetch URL'; btn.disabled = false; }
            }
        }

        function saveHouseListing() {
            const name = (document.getElementById('hl-name')?.value || '').trim();
            if (!name) { document.getElementById('hl-name')?.focus(); return; }
            const intentBtns = document.querySelectorAll('#hl-intent-btn');
            let intent = 'rent';
            intentBtns.forEach(b => { if (b.dataset.active === 'true') intent = b.dataset.val; });
            houseData.listings.push({
                name,
                intent,
                type:      (document.getElementById('hl-type')?.value  || '').trim(),
                price:     document.getElementById('hl-price')?.value || '',
                size:      document.getElementById('hl-size')?.value  || '',
                rooms:     document.getElementById('hl-rooms')?.value || '',
                zone:      (document.getElementById('hl-zone')?.value  || '').trim(),
                floor:     (document.getElementById('hl-floor')?.value || '').trim(),
                link:      (document.getElementById('hl-link')?.value  || '').trim(),
                contactId: document.getElementById('hl-contact')?.value || '',
                pros:      (document.getElementById('hl-pros')?.value  || '').trim(),
                cons:      (document.getElementById('hl-cons')?.value  || '').trim(),
                notes:     (document.getElementById('hl-notes')?.value || '').trim(),
                rating:    0,
                status:    'interested'
            });
            saveHouseData();
            ['hl-name','hl-price','hl-size','hl-rooms','hl-zone','hl-floor','hl-link','hl-pros','hl-cons','hl-notes'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});
            const sel=document.getElementById('hl-contact'); if(sel) sel.value='';
            const typeEl=document.getElementById('hl-type'); if(typeEl) typeEl.value='';
            // Reset intent buttons back to rent
            document.querySelectorAll('#hl-intent-btn').forEach(b => {
                const active = b.dataset.val === 'rent';
                b.dataset.active = active ? 'true' : 'false';
                _styleHlIntentBtn(b, active);
            });
            hideHouseForm('listing'); renderHouseListings();
        }

        function _styleHlIntentBtn(btn, active) {
            const isBuy = btn.dataset.val === 'buy';
            btn.style.background    = active ? (isBuy ? 'rgba(167,139,250,0.15)' : 'rgba(56,189,248,0.15)') : 'rgba(255,255,255,0.03)';
            btn.style.borderColor   = active ? (isBuy ? 'rgba(167,139,250,0.5)'  : 'rgba(56,189,248,0.45)') : 'rgba(255,255,255,0.08)';
            btn.style.color         = active ? (isBuy ? '#a78bfa' : '#38bdf8') : '#475569';
            btn.style.fontWeight    = active ? '900' : '600';
        }

        function toggleHlIntent(val) {
            document.querySelectorAll('#hl-intent-btn').forEach(b => {
                const active = b.dataset.val === val;
                b.dataset.active = active ? 'true' : 'false';
                _styleHlIntentBtn(b, active);
            });
            // Adjust price placeholder
            const priceEl = document.getElementById('hl-price');
            if (priceEl) priceEl.placeholder = val === 'buy' ? 'Price (€)' : 'Price (€/mo)';
        }

