            const total = HOUSE_VISIT_CHECKLIST_ITEMS.length;
            const done  = HOUSE_VISIT_CHECKLIST_ITEMS.filter(i => houseData.visitCheck[i.id]).length;
            const pct   = total ? Math.round((done/total)*100) : 0;
