        function _renderHouseTasksLegacy() {
    const ul = document.getElementById('house-tasks-ul');
    if (!ul) return;

    // Migrate legacy tasks ({text, done}) -> {id, emoji, title, desc}
    try {
        houseData.tasks = (houseData.tasks || []).map(function(t){
            if (t && typeof t === 'object' && ('title' in t)) return t;
            const title = (t && t.text) ? String(t.text) : String(t || '');
            const id = makeTaskIdFromTitle(title) + '_' + (t && t.id ? t.id : Date.now());
            return { id, emoji:'', title:title, desc:'' };
        });
    } catch(e) {}

    ul.innerHTML = '';
    if (!(houseData.tasks || []).length) {
        ul.innerHTML = '<li style="color:#475569; font-size:0.88em; padding:8px 2px; list-style:none;">No tasks yet.</li>';
        return;
    }

    const _hAccent = '#38bdf8';

    (houseData.tasks || []).forEach(function(t) {
        const hasSubtasks = !!(t.subtasks && t.subtasks.length);
        const globalKey = 'resp-house-' + t.id;
        const isDone = hasSubtasks ? !!t.done : !!(tasks && tasks[globalKey]);

        const item = document.createElement('li');
        item.className = 'house-task-item resp-task-item' + (isDone ? ' done' : '');
        item.setAttribute('data-resp', 'house');
        item.setAttribute('data-rtask', t.id);
        item.style.listStyle = 'none';
        item.style.borderLeftColor = isDone ? '#22c55e' : _hAccent;
        if (hasSubtasks) {
            item.style.flexDirection = 'column';
            item.style.alignItems = 'stretch';
            item.style.cursor = 'default';
        }

        // Header row
        const headerDiv = document.createElement('div');
        headerDiv.style.cssText = 'display:flex;align-items:center;gap:8px;flex:1;min-width:0;';

        if (hasSubtasks) {
            const doneCount = t.subtasks.filter(function(s){ return s.done; }).length;
            const prog = document.createElement('div');
            prog.style.cssText = 'width:22px;height:22px;min-width:22px;border-radius:6px;flex-shrink:0;'
                + 'border:2.5px solid ' + _hAccent + ';'
                + 'display:flex;align-items:center;justify-content:center;'
                + 'font-size:0.55em;font-weight:900;transition:all 0.2s;'
                + (isDone ? 'background:' + _hAccent + ';color:#000;' : 'color:' + _hAccent + ';background:transparent;');
            prog.textContent = isDone ? '✓' : doneCount + '/' + t.subtasks.length;
            headerDiv.appendChild(prog);
        } else {
            const chk = document.createElement('div');
            chk.className = 'house-task-check';
            headerDiv.appendChild(chk);
        }

        const textWrap = document.createElement('div');
        textWrap.style.cssText = 'flex:1;min-width:0;';
        const textSpan = document.createElement('span');
        textSpan.className = 'house-task-text';
        textSpan.textContent = (t.emoji ? t.emoji + ' ' : '') + (t.title || 'Task');
        textWrap.appendChild(textSpan);
        if (t.desc) {
            const descEl = document.createElement('div');
            descEl.style.cssText = 'color:#64748b;font-size:0.82em;margin-top:2px;';
            descEl.textContent = t.desc;
            textWrap.appendChild(descEl);
        }
        headerDiv.appendChild(textWrap);

        const del = document.createElement('button');
        del.className = 'house-delete-btn';
        del.title = 'Remove';
        del.textContent = '🗑️';
        del.style.marginLeft = 'auto';
        del.onclick = function(ev) {
            ev.stopPropagation();
            removeHouseTask(t.id);
        };
        headerDiv.appendChild(del);

        item.appendChild(headerDiv);

        if (hasSubtasks) {
            const subList = document.createElement('div');
            subList.style.cssText = 'display:flex;flex-direction:column;gap:4px;margin-top:8px;padding-top:8px;border-top:1px solid rgba(255,255,255,0.06);';
            t.subtasks.forEach(function(s, si) {
                const subRow = document.createElement('div');
                subRow.style.cssText = 'display:flex;align-items:center;gap:8px;padding:3px 0;cursor:pointer;';
                subRow.onclick = function(e) {
                    e.stopPropagation();
                    _toggleHouseSubtask(t.id, si);
                };

                const subChk = document.createElement('div');
                subChk.style.cssText = 'width:14px;height:14px;min-width:14px;border-radius:4px;flex-shrink:0;transition:all 0.15s;'
                    + 'display:flex;align-items:center;justify-content:center;'
                    + 'border:2px solid ' + (s.done ? '#22c55e' : 'rgba(56,189,248,0.4)') + ';'
                    + 'background:' + (s.done ? '#22c55e' : 'transparent') + ';';
                if (s.done) subChk.innerHTML = '<span style="color:#000;font-size:9px;font-weight:900;line-height:1;">✓</span>';

                const subTxt = document.createElement('span');
                subTxt.style.cssText = 'font-size:0.82em;font-weight:600;'
                    + (s.done ? 'color:#475569;text-decoration:line-through;' : 'color:#94a3b8;');
                subTxt.textContent = s.text;

                subRow.appendChild(subChk);
                subRow.appendChild(subTxt);
                subList.appendChild(subRow);
            });
            item.appendChild(subList);
        }

        ul.appendChild(item);
    });

    initRespTaskState();
    // Tasks with subtasks manage their own done state — suppress schedule-sync click
    (houseData.tasks || []).forEach(function(t) {
        if (!(t.subtasks && t.subtasks.length)) return;
        const el = ul.querySelector('[data-rtask="' + t.id + '"]');
        if (el) el.onclick = null;
    });
    try {
        ['r1','r2','r3'].forEach(function(slot){ if (rSlots && rSlots[slot] === 'house') renderRTasks(slot); });
        bindScheduleRTasks();
        updateSummaryPills();
        updateProgress();
    } catch(e) {}
}

        function _toggleHouseSubtask(taskId, subIdx) {
    const task = (houseData.tasks || []).find(function(t){ return t.id === taskId; });
    if (!task || !task.subtasks || task.subtasks[subIdx] === undefined) return;
    task.subtasks[subIdx].done = !task.subtasks[subIdx].done;
    task.done = task.subtasks.every(function(s){ return s.done; });
    saveHouseData();
    renderHouseTasks();
}

        function saveHouseTask() { showGTask('house'); }
        function toggleHouseTask() {}
        function removeHouseTask() {}

        // ── STATS ───────────────────────────────────────────────
        function updateHouseStats() {
            const elListings  = document.getElementById('house-stat-listings');
            const elVisited   = document.getElementById('house-stat-visited');
            const elContacts  = document.getElementById('house-stat-contacts');
            const elTasks     = document.getElementById('house-stat-tasks');
            if (elListings)  elListings.textContent  = houseData.listings.length;
            if (elVisited)   elVisited.textContent   = houseData.listings.filter(l => l.status === 'visited').length;
            if (elContacts)  elContacts.textContent  = (houseData.contacts || []).length;
            const houseTasks = gTasksAll['house'] || [];
            if (elTasks)     elTasks.textContent     = houseTasks.filter(t => t.done).length + '/' + houseTasks.length;
        }

        // ── FORM HELPERS ────────────────────────────────────────
        function showHouseForm(type) {
            const form = document.getElementById('house-form-' + type);
            if (!form) return;
            form.classList.add('visible');
            const first = form.querySelector('input');
            if (first) first.focus();
        }

        function hideHouseForm(type) {
            const form = document.getElementById('house-form-' + type);
            if (form) form.classList.remove('visible');
        }

        // ── UTILITY ─────────────────────────────────────────────
        function escHtml(str) {
            return String(str || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
        }

        // ── ENTER KEY SHORTCUTS ─────────────────────────────────
        function initHouseKeyShortcuts() {
            const map = { 'hl-notes':'listing', 'hco-email':'contact' };
            const saves = { listing: saveHouseListing, contact: saveHouseContact };
            Object.keys(map).forEach(id => {
                const el = document.getElementById(id);
                if (!el) return;
                el.addEventListener('keydown', e => {
                    if (e.key === 'Enter') saves[map[id]]();
                    if (e.key === 'Escape') hideHouseForm(map[id]);
                });
            });
        }

        // ── STUBS for removed features ────────────────────────────
        function renderHouseAreas() {}   // Areas section removed
        function saveHouseArea() {}
        function removeHouseArea() {}

        // ── INIT ─────────────────────────────────────────────────
        function initHouseSection() {
            // One-time migration: houseData.tasks -> gTasksAll['house']
            if (!(gTasksAll['house'] || []).length && (houseData.tasks || []).length) {
                gTasksAll['house'] = houseData.tasks.map(function(t) {
                    return {
                        id: Date.now() + Math.random(),
                        emoji: t.emoji || '',
                        text: t.title || t.text || 'Task',
                        notes: t.desc || '',
                        done: !!t.done,
                        accentColor: '#38bdf8',
                        subtasks: t.subtasks || []
                    };
                });
                saveGTasksAll();
            }
            renderHouseCriteria();
            renderHouseContacts();   // contacts first so listing dropdown is populated
            renderHouseListings();
            renderVisitChecklist();
            renderGTasks('house');
            initHouseKeyShortcuts();
        }
        // Storage: { catId: [{ id, emoji, name }] }
        let customRespItems = loadData('customRespItems');

        const saveCustomRespItems = () => saveData('customRespItems', customRespItems);

        function slugify(text) {
            return 'custom-' + text.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '') + '-' + Date.now();
        }

        function renderCustomItems(catId) {
            const container = document.getElementById('custom-items-' + catId);
            if (!container) return;
            container.innerHTML = '';
            const items = customRespItems[catId] || [];
            items.forEach(item => {
                const row = document.createElement('div');
                row.className = 'resp-item-row';

                const div = document.createElement('div');
                div.className = 'resp-item resp-item-custom';
                div.onclick = () => openRespSection(item.id);
                div.innerHTML = `<span class="resp-item-label"><strong>${item.emoji || '📌'} ${item.name}</strong></span><span class="resp-item-arrow">›</span>`;

                const delBtn = document.createElement('button');
                delBtn.className = 'resp-delete-btn';
                delBtn.title = 'Remove';
                delBtn.textContent = '✕';
                delBtn.onclick = (e) => {
                    e.stopPropagation();
                    removeCustomRespItem(catId, item.id);
                };

                row.appendChild(div);
                row.appendChild(delBtn);
                container.appendChild(row);

                // Ensure a dynamic section exists for this item
                ensureDynamicRespSection(item.id, item.emoji + ' ' + item.name);
            });

            // Update category count badge
            updateCatCount(catId);
        }

        function ensureDynamicRespSection(id, title) {
            if (document.getElementById('resp-section-' + id)) return;
            const div = document.createElement('div');
            div.id = 'resp-section-' + id;
            div.className = 'summary important-page';
            div.style.display = 'none';
            div.innerHTML = `
                <button class="back-btn" onclick="backToRespMenu()">⬅️ Back</button>

                <div class="resp-detail-card" style="border-color:rgba(99,102,241,0.25); background:linear-gradient(135deg,rgba(2,8,23,0.7),rgba(99,102,241,0.06));">
                    <div class="resp-detail-label" style="color:#818cf8;">📋 ${title}</div>
                    <div class="resp-detail-text" style="line-height:1.7;">Custom responsibility. Use the tasks below to track action items for this area.</div>
                </div>

                <div class="resp-detail-card" style="border-color:rgba(99,102,241,0.18);">
                    <div class="resp-detail-label">📌 Tasks</div>
                    <div class="resp-detail-text" style="margin-bottom:12px;">Add, check off, and remove tasks for this responsibility.</div>
                    <div id="gtask-list-${id}" style="display:flex; flex-direction:column; gap:8px;"></div>
                    <button class="house-add-trigger" style="color:#818cf8; border-color:rgba(99,102,241,0.3);" onclick="showGTask('${id}')">＋ Add task</button>

                </div>`;
            // Insert it inside the container (after the last resp-section)
            const container = document.querySelector('#responsabilidades .container');
            if (container) container.appendChild(div);
            // Render any existing tasks for this dynamic section
            renderGTasks(id);
        }

        function saveNewRespItem(catId) {
            const emojiInput = document.getElementById('add-emoji-' + catId);
            const nameInput = document.getElementById('add-name-' + catId);
            if (!emojiInput || !nameInput) return;

            const name = nameInput.value.trim();
            if (!name) {
                nameInput.focus();
                nameInput.style.borderColor = '#ef4444';
                setTimeout(() => nameInput.style.borderColor = '', 1500);
                return;
            }

            const emoji = emojiInput.value.trim() || '📌';
            const id = slugify(name);

            if (!customRespItems[catId]) customRespItems[catId] = [];
            customRespItems[catId].push({ id, emoji, name });
            saveCustomRespItems();

            emojiInput.value = '';
            nameInput.value = '';
            hideAddForm(catId);
            renderCustomItems(catId);
            // Refresh R-slot selects so the new item appears
            ['r1','r2','r3'].forEach(slot => populateRSelect(slot));
            showToast('✅ Added: ' + emoji + ' ' + name);
        }

        function removeCustomRespItem(catId, itemId) {
            if (!customRespItems[catId]) return;
            customRespItems[catId] = customRespItems[catId].filter(i => i.id !== itemId);
            saveCustomRespItems();
            renderCustomItems(catId);
            // Remove dynamic section if it exists
            const el = document.getElementById('resp-section-' + itemId);
            if (el) el.remove();
            // Refresh R-slot selects
            ['r1','r2','r3'].forEach(slot => populateRSelect(slot));
        }

        function showAddForm(catId) {
            const form = document.getElementById('add-form-' + catId);
            if (form) {
                form.classList.add('visible');
                const nameInput = document.getElementById('add-name-' + catId);
                if (nameInput) nameInput.focus();
            }
        }

        function hideAddForm(catId) {
            const form = document.getElementById('add-form-' + catId);
            if (form) form.classList.remove('visible');
        }

        function initCustomRespItems() {
            const cats = ['home-life','personal','health-fitness','hobbies','professional','tech-digital','education','others'];
            cats.forEach(catId => renderCustomItems(catId));
            // Enter key to save in each form
            cats.forEach(catId => {
                const input = document.getElementById('add-name-' + catId);
                if (input) input.addEventListener('keydown', e => {
                    if (e.key === 'Enter') saveNewRespItem(catId);
                    if (e.key === 'Escape') hideAddForm(catId);
                });
            });
        }

        // ─── CATEGORY COLLAPSE ───────────────────────────────────────────────────
        let catCollapsed = loadData('catCollapsed');

        function toggleCat(headerEl) {
            const catDiv = headerEl.closest('.resp-category');
            if (!catDiv) return;
            const catId = catDiv.getAttribute('data-cat');
            const isCollapsed = catDiv.classList.toggle('collapsed');
            catCollapsed[catId] = isCollapsed;
            localStorage.setItem('catCollapsed', JSON.stringify(catCollapsed));
        }

        function initCatCollapsed() {
            document.querySelectorAll('.resp-category[data-cat]').forEach(div => {
                const catId = div.getAttribute('data-cat');
                if (catCollapsed[catId]) div.classList.add('collapsed');
            });
        }

        function updateCatCount(catId) {
            const catDiv = document.querySelector(`.resp-category[data-cat="${catId}"]`);
            if (!catDiv) return;
            const countEl = catDiv.querySelector('.resp-cat-count');
            if (!countEl) return;
            // Count built-in + custom
            const builtIn = catDiv.querySelectorAll('.resp-list-wrap > .resp-item-row').length;
            const custom = (customRespItems[catId] || []).length;
            countEl.textContent = builtIn + custom;
        }

        function getAllRespOptions() {
            // Collect built-in items from the Responsibilities menu
            const items = document.querySelectorAll('#resp-menu .resp-item[onclick]');
            const options = [];
            items.forEach(el => {
                const onclick = el.getAttribute('onclick') || '';
                const m = onclick.match(/openRespSection\('([^']+)'\)/);
                if (!m) return;
                const id = m[1];
                const label = el.querySelector('.resp-item-label');
                const title = (label ? label.textContent : el.textContent || '').trim();
                options.push({ id, title });
            });
            // Include custom items
            Object.values(customRespItems).forEach(catItems => {
                catItems.forEach(item => {
                    if (!options.find(o => o.id === item.id)) {
                        options.push({ id: item.id, title: (item.emoji || '') + ' ' + item.name });
                    }
                });
            });
            // (no hardcoded defaults — all responsibilities come from the menu)
            // Stable sort by title
            options.sort((a, b) => a.title.localeCompare(b.title));
            return options;
        }

        function getRespMeta(respId) {
            if (!respId || respId === 'none') {
                return { title: 'Empty', desc: 'No responsibility selected. Choose one from the dropdown above.', emoji: '📌', color: '#475569' };
            }
            const section = document.getElementById('resp-section-' + respId);
            if (!section) {
                return { title: respId, desc: 'No description found yet.', emoji: '📋', color: '#818cf8' };
            }

            // Title & emoji & color: use first .resp-detail-card .resp-detail-label (new-style)
            let title = '', emoji = '📋', color = '#818cf8';
            const firstCard = section.querySelector('.resp-detail-card');
            const labelEl = firstCard ? firstCard.querySelector('.resp-detail-label') : null;
            if (labelEl) {
                const raw = (labelEl.textContent || '').trim();
                // Split on first letter to get emoji prefix
                const splitIdx = raw.search(/[A-Za-z0-9\u00C0-\u024F]/);
                if (splitIdx > 0) {
                    emoji = raw.slice(0, splitIdx).trim() || '📋';
                    title = raw.slice(splitIdx).trim();
                } else {
                    title = raw;
                }
                if (labelEl.style && labelEl.style.color) color = labelEl.style.color;
            }
            // Fallback: legacy h2
            if (!title) {
                const h2 = section.querySelector('h2');
                const raw = h2 ? h2.textContent.trim() : respId;
                title = raw.replace(/^[^A-Za-z0-9]+/, '').trim() || respId;
            }

            // Always override title/emoji with the canonical menu label so section-level
            // sub-panels (e.g. "Gym" inside Fitness) don't pollute the display name.
            const menuOpt = getAllRespOptions().find(o => o.id === respId);
            if (menuOpt && menuOpt.title) {
                const mRaw = menuOpt.title.trim();
                const mSplit = mRaw.search(/[A-Za-z0-9À-ɏ]/);
                if (mSplit > 0) {
                    emoji = mRaw.slice(0, mSplit).trim() || emoji;
                    title = mRaw.slice(mSplit).trim() || title;
                } else if (mRaw) {
                    title = mRaw || title;
                }
            }

            // Description: first .resp-detail-text in first card (new-style)
            let desc = '';
            const firstTextEl = firstCard ? firstCard.querySelector('.resp-detail-text') : null;
            if (firstTextEl) desc = (firstTextEl.textContent || '').trim();
            // Fallback: legacy p "Description:"
            if (!desc) {
                const legacyP = Array.from(section.querySelectorAll('p')).find(x => (x.textContent || '').includes('Description:'));
                if (legacyP) desc = (legacyP.textContent || '').replace('Description:', '').trim();
            }
            if (!desc) desc = 'No description available.';

            return { title, desc, emoji, color };
        }

        function populateRSelect(slot) {
            const anchor = document.getElementById(slot + '-select');
            if (!anchor) return;

            const options = getAllRespOptions();
            const allOptions = [{ id: 'none', title: '— None —' }, ...options.filter(o => o.id !== 'none')];

            // Validate current value
            if (!allOptions.find(o => o.id === rSlots[slot])) {
                rSlots[slot] = 'none';
                saveRSlots();
            }

            // Build or reuse the custom search wrapper
            let wrap = document.getElementById(slot + '-search-wrap');
            if (!wrap) {
                wrap = document.createElement('div');
                wrap.id = slot + '-search-wrap';
                wrap.style.cssText = 'position:relative;';
                anchor.parentNode.replaceChild(wrap, anchor);
            }

            const curOpt = allOptions.find(o => o.id === rSlots[slot]) || allOptions[0];
            const curLabel = curOpt.id === 'none' ? '' : curOpt.title;

            wrap.innerHTML = `
                <input id="${slot}-search-input" type="text"
                    placeholder="Type to search…"
                    autocomplete="off" autocorrect="off" autocapitalize="off" spellcheck="false"
                    value="${escapeHtml(curLabel)}"
                    style="width:100%;box-sizing:border-box;background:#0a0f1e;color:#e2e8f0;
                           border:2px solid rgba(129,140,248,0.3);border-radius:12px;
                           padding:12px 14px;font-weight:700;font-size:1em;
                           font-family:'Outfit',sans-serif;outline:none;
                           transition:border-color 0.2s ease;"
                    onfocus="this.style.borderColor='#818cf8';_rSearchOpen('${slot}')"
                    onblur="this.style.borderColor='rgba(129,140,248,0.3)'"
                    oninput="_rSearchFilter('${slot}',this.value)">
                <div id="${slot}-search-dd"
                    style="display:none;position:absolute;top:calc(100% + 6px);left:0;right:0;
                           z-index:9999;max-height:220px;overflow-y:auto;
                           background:#0a0f1e;border:2px solid rgba(129,140,248,0.35);
                           border-radius:12px;box-shadow:0 10px 36px rgba(0,0,0,0.65);">
                </div>`;
            _rSearchBuildList(slot, allOptions, '');
        }

        function _rSearchAllOpts() {
            const options = getAllRespOptions();
            return [{ id: 'none', title: '— None —' }, ...options.filter(o => o.id !== 'none')];
        }

        function _rSearchBuildList(slot, opts, query) {
            const dd = document.getElementById(slot + '-search-dd');
            if (!dd) return;
            const q = (query || '').toLowerCase().trim();
            const list = q ? opts.filter(o => o.title.toLowerCase().includes(q)) : opts;
            const cur = rSlots[slot] || 'none';
            dd.innerHTML = list.length
                ? list.map(opt => {
                    const active = opt.id === cur;
                    return `<div
                        onmousedown="_rSearchPick('${slot}','${opt.id}')"
                        style="padding:11px 14px;cursor:pointer;font-size:0.9em;font-weight:700;
                               font-family:'Outfit',sans-serif;
                               color:${active ? '#818cf8' : '#e2e8f0'};
                               background:${active ? 'rgba(129,140,248,0.12)' : 'transparent'};
                               transition:background 0.1s;"
                        onmouseover="this.style.background='rgba(129,140,248,0.1)'"
                        onmouseout="this.style.background='${active ? 'rgba(129,140,248,0.12)' : 'transparent'}'">
                        ${escapeHtml(opt.title)}
                    </div>`;
                  }).join('')
                : `<div style="padding:11px 14px;color:#475569;font-size:0.85em;font-family:'Outfit',sans-serif;">No results</div>`;
        }

        function _rSearchOpen(slot) {
            const dd = document.getElementById(slot + '-search-dd');
            const inp = document.getElementById(slot + '-search-input');
            if (!dd || !inp) return;
            _rSearchBuildList(slot, _rSearchAllOpts(), inp.value);
            dd.style.display = 'block';
            // Scroll selected item into view
            setTimeout(() => {
                const active = dd.querySelector('[style*="rgba(129,140,248,0.12)"]');
                if (active) active.scrollIntoView({ block: 'nearest' });
            }, 30);
        }

        function _rSearchFilter(slot, query) {
            const dd = document.getElementById(slot + '-search-dd');
            if (dd) dd.style.display = 'block';
            _rSearchBuildList(slot, _rSearchAllOpts(), query);
        }

        function _rSearchPick(slot, id) {
            rSlots[slot] = id;
            saveRSlots();
            const opt = _rSearchAllOpts().find(o => o.id === id);
            const inp = document.getElementById(slot + '-search-input');
            const dd  = document.getElementById(slot + '-search-dd');
            if (inp) inp.value = opt && opt.id !== 'none' ? opt.title : '';
            if (dd)  dd.style.display = 'none';
            renderRSection(slot);
            bindScheduleRTasks();
            updateSummaryPills();
            updateProgress();
        }

        function updateRLabels() {
            ['r1','r2','r3'].forEach(slot => {
                const meta = getRespMeta(rSlots[slot]);
                const hasResp = rSlots[slot] && rSlots[slot] !== 'none';
                // Update the label text inside the card (never overwrite the whole card)
                const labelEl = document.getElementById('imp-' + slot + '-label');
                if (labelEl) {
                    const rawLabel = hasResp
                        ? (meta.emoji ? meta.emoji + ' ' + meta.title : meta.title)
                        : 'Empty';
                    labelEl.textContent = _translateText(rawLabel);
                    labelEl.style.color = hasResp ? '#e2e8f0' : '#475569';
                }
                // Dim the slot badge if nothing assigned
                const slotEl = document.querySelector('#summary-pill-' + slot + ' .imp-r-slot');
                if (slotEl) slotEl.style.opacity = hasResp ? '1' : '0.4';
            });
        }

        function renderRSection(slot) {
            const respId = rSlots[slot];
            const meta = getRespMeta(respId);

            // ── Update description card ──
            const titleEl = document.getElementById(slot + '-title');
            const descEl  = document.getElementById(slot + '-desc');
            if (titleEl) {
                titleEl.textContent = meta.emoji + ' ' + meta.title;
                titleEl.style.color = meta.color || '#818cf8';
            }
            if (descEl) descEl.textContent = meta.desc;

            // ── Update section desc card border/bg color ──
            const descCard = document.querySelector('#imp-section-' + slot + ' .imp-desc-card');
            if (descCard && meta.color) {
                // parse hex → rgba
                const c = meta.color.replace('#','');
                let r=99,g=102,b=241;
                if (c.length===6){r=parseInt(c.slice(0,2),16);g=parseInt(c.slice(2,4),16);b=parseInt(c.slice(4,6),16);}
                descCard.style.borderColor = 'rgba('+r+','+g+','+b+',0.3)';
                descCard.style.background  = 'linear-gradient(135deg,rgba(2,8,23,0.7),rgba('+r+','+g+','+b+',0.08))';
            }

            // ── Update select card border color ──
            const selCard = document.querySelector('#imp-section-' + slot + ' .imp-section-card');
            if (selCard && meta.color) {
                const c = meta.color.replace('#','');
                let r=99,g=102,b=241;
                if (c.length===6){r=parseInt(c.slice(0,2),16);g=parseInt(c.slice(2,4),16);b=parseInt(c.slice(4,6),16);}
                selCard.style.borderColor = 'rgba('+r+','+g+','+b+',0.2)';
            }

            // ── Update "Go to" button color ──
            const goBtn = document.getElementById('r-go-btn-' + slot);
            if (goBtn && meta.color) {
                goBtn.style.background = 'linear-gradient(135deg,' + meta.color + ',' + meta.color + 'bb)';
            }

            renderRTasks(slot);
            updateRTaskCount(slot);
            updateRLabels();
        }

        function updateRTaskCount(slot) {
            const badge = document.getElementById('r-task-badge-' + slot);
            if (!badge) return;
            const wrap = document.getElementById(slot + '-tasks');
            if (!wrap) { badge.style.display = 'none'; return; }
            const items = wrap.querySelectorAll('.task-item');
            const done  = wrap.querySelectorAll('.task-item.checked');
            if (items.length === 0) {
                badge.textContent = 'No tasks';
                badge.style.background = 'rgba(71,85,105,0.4)';
                badge.style.color = '#475569';
            } else {
                badge.textContent = done.length + '/' + items.length + ' done';
                badge.style.background = done.length === items.length
                    ? 'rgba(34,197,94,0.15)' : 'rgba(129,140,248,0.12)';
                badge.style.color = done.length === items.length ? '#22c55e' : '#818cf8';
            }
            badge.style.display = 'inline-block';
        }
        function goToSelectedResp(slot) {
            const respId = rSlots[slot];
            if (!respId || respId === 'none') return;
            _respOriginRSlot = slot; // remember which R-slot to return to
            // Close the R overlay first so Responsibilities section is visible
            document.querySelectorAll('.imp-section-overlay').forEach(el => el.style.display = 'none');
            document.body.style.overflow = '';
            // Restore schedule toolbar + FAB now that the overlay is gone
            const schedTb = document.getElementById('sched-toolbar');
            if (schedTb) schedTb.style.display = '';
            const schedFab = document.getElementById('sched-fab-wrap');
            if (schedFab) schedFab.style.display = '';
            openRespSection(respId);
        }

        // Build one <li> for the R-slot task list, with full subtask support
        // (progress badge, expand/collapse, per-subtask toggle + sync to source).
        function _buildRTaskLi(t, sid, slot) {
            const globalKey = 'gtask-' + sid + '-' + t.id;
            const hasSubtasks = !!(t.subtasks && t.subtasks.length > 0);
            const taskAccent = t.accentColor || '#fbbf24';

            const li = document.createElement('li');
            li.className = 'task-item' + (t.done ? ' checked' : '');
            li.setAttribute('data-task', globalKey);
            li.setAttribute('data-summary', slot);

            if (hasSubtasks) {
                // Main item NOT directly clickable — auto-checked only
                li.style.cursor = 'default';
                li.style.flexDirection = 'column';
                li.style.alignItems = 'stretch';
                li.style.gap = '0';
            } else {
                li.onclick = function() {
                    if (sid === 'update-app' && t.linkedType) {
                        toggleGTask(sid, gTasksAll[sid].indexOf(t));
                    } else {
                        toggleTask(li);
                    }
                };
            }

            // ── Header row ──────────────────────────────────────────
            const header = document.createElement('div');
            header.style.cssText = 'display:flex;align-items:center;gap:10px;' + (hasSubtasks ? 'cursor:pointer;' : 'pointer-events:none;');

            let chevron = null;
            const progEl = document.createElement('div');
            if (hasSubtasks) {
                const doneCount = t.subtasks.filter(function(s){ return s.done; }).length;
                progEl.style.cssText = 'width:26px;height:26px;border-radius:8px;flex-shrink:0;'
                    + 'border:3px solid ' + taskAccent + ';'
                    + 'display:flex;align-items:center;justify-content:center;'
                    + 'font-size:0.6em;font-weight:900;transition:all 0.2s;'
                    + (t.done ? 'background:' + taskAccent + ';color:#000;' : 'color:' + taskAccent + ';background:transparent;');
                progEl.textContent = t.done ? '✓' : doneCount + '/' + t.subtasks.length;
            } else {
                progEl.className = 'task-checkbox';
            }
            header.appendChild(progEl);

            const textCol2 = document.createElement('div');
            textCol2.style.cssText = 'flex:1;min-width:0;display:flex;flex-direction:column;gap:2px;';
            const mainDiv = document.createElement('div');
            mainDiv.className = 'task-main';
            mainDiv.textContent = (t.emoji ? t.emoji + ' ' : '') + (t.title || t.text || '');
            textCol2.appendChild(mainDiv);
            const descText = t.desc || t.notes || '';
            if (descText && !hasSubtasks) {
                const descEl = document.createElement('div');
                descEl.style.cssText = 'color:#64748b;font-size:0.8em;line-height:1.4;';
                descEl.textContent = descText;
                textCol2.appendChild(descEl);
            }
            header.appendChild(textCol2);
            if (hasSubtasks) {
                chevron = document.createElement('div');
                chevron.style.cssText = 'font-size:0.7em;color:#475569;transition:transform 0.2s;flex-shrink:0;'
                    + (t.collapsed ? '' : 'transform:rotate(180deg);');
                chevron.textContent = '▼';
                header.appendChild(chevron);
            }
            li.appendChild(header);

            // ── Subtask rows ────────────────────────────────────────
            if (hasSubtasks) {
                const subsWrap = document.createElement('div');
                subsWrap.style.cssText = 'display:flex;flex-direction:column;gap:5px;margin-top:10px;'
                    + (t.collapsed ? 'display:none;' : '');

                function buildSubs() {
                    subsWrap.innerHTML = '';
                    t.subtasks.forEach(function(s, si) {
                        const done = !!s.done;
                        const row = document.createElement('div');
                        row.style.cssText = 'display:flex;align-items:center;gap:8px;padding:6px 8px;'
                            + 'background:rgba(255,255,255,0.03);border-radius:7px;'
                            + 'border:1px solid rgba(255,255,255,0.07);cursor:pointer;transition:background 0.15s;';
                        row.addEventListener('mouseenter', function(){ row.style.background='rgba(255,255,255,0.06)'; });
                        row.addEventListener('mouseleave', function(){ row.style.background='rgba(255,255,255,0.03)'; });
                        row.addEventListener('click', function(e) {
                            e.stopPropagation();
                            s.done = !s.done;
                            const newDone = s.done;
                            const allDone = t.subtasks.every(function(x){ return x.done; });
                            t.done = allDone;
                            if (typeof saveGTasksAll === 'function') saveGTasksAll();

                            li.classList.toggle('checked', allDone);
                            progEl.textContent = allDone ? '✓' : t.subtasks.filter(function(x){ return x.done; }).length + '/' + t.subtasks.length;
                            progEl.style.background = allDone ? taskAccent : 'transparent';
                            progEl.style.color      = allDone ? '#000' : taskAccent;

                            buildSubs();

                            if (typeof renderGTasks === 'function') renderGTasks(sid);

                            if (t.groupRef && t.groupRef.isWork) {
                                if (typeof _setWorkProjectSubDone === 'function') _setWorkProjectSubDone(t.groupRef, si, newDone);
                            } else if (t.groupRef && t.groupRef.isGym) {
                                if (typeof _setGymSessionSubDone === 'function') _setGymSessionSubDone(t.groupRef, si, newDone);
                            } else if (t.groupRef && t.groupRef.isMA) {
                                if (typeof _setMADisciplineSubDone === 'function') _setMADisciplineSubDone(t.groupRef, si, newDone);
                            } else if (t.groupRef && typeof _setOrgGroupSubDone === 'function') {
                                _setOrgGroupSubDone(t.groupRef, si, newDone);
                            }

                            updateSummaryPills(); updateProgress();
                        });

                        const chkEl = document.createElement('div');
                        chkEl.style.cssText = 'width:15px;height:15px;min-width:15px;border-radius:4px;'
                            + 'border:1.5px solid ' + (done ? taskAccent : 'rgba(255,255,255,0.25)') + ';'
                            + 'background:' + (done ? taskAccent : 'transparent') + ';'
                            + 'display:flex;align-items:center;justify-content:center;'
                            + 'font-size:0.55em;font-weight:900;color:#000;flex-shrink:0;';
                        chkEl.textContent = done ? '✓' : '';

                        const lblEl = document.createElement('span');
                        lblEl.style.cssText = 'font-size:0.82em;color:' + (done ? '#475569' : '#94a3b8') + ';'
                            + (done ? 'text-decoration:line-through;' : '');
                        lblEl.textContent = s.text;

                        row.appendChild(chkEl);
                        row.appendChild(lblEl);
                        subsWrap.appendChild(row);
                    });
                }

                header.addEventListener('click', function(e) {
                    e.stopPropagation();
                    t.collapsed = !t.collapsed;
                    if (typeof saveGTasksAll === 'function') saveGTasksAll();
                    subsWrap.style.display = t.collapsed ? 'none' : 'flex';
                    chevron.style.transform = t.collapsed ? '' : 'rotate(180deg)';
                });

                buildSubs();
                _wireSubDnd(subsWrap,
                    () => t.subtasks,
                    () => { saveGTasksAll(); buildSubs(); }
                );
                li.appendChild(subsWrap);
            }

            return li;
        }

        function renderRTasks(slot) {
            const wrap = document.getElementById(slot + '-tasks');
            if (!wrap) return;

            const respId = rSlots[slot];
            if (!respId || respId === 'none') {
                wrap.innerHTML = '<p style="color:#475569; font-size:0.88em; padding:4px 0;">Choose a responsibility above to see its tasks here.</p>';
                updateSummaryPills();
                return;
            }

            // ── Special case: health is a consolidated section — aggregate all 5 sub-sections ──
            if (respId === 'health') {
                const HEALTH_SIDS = ['general-doctor','dentist','ophthalmologist','dermatologist','psychologist'];
                const allHealthTasks = [];
                HEALTH_SIDS.forEach(sid => {
                    (gTasksAll[sid] || []).forEach(t => { allHealthTasks.push({ t, sid }); });
                });
                if (allHealthTasks.length > 0) {
                    const ul = document.createElement('ul');
                    ul.className = 'task-list';
                    allHealthTasks.forEach(({ t, sid }) => {
                        ul.appendChild(_buildRTaskLi(t, sid, slot));
                    });
                    wrap.innerHTML = '';
                    wrap.appendChild(ul);
                    updateSummaryPills();
                } else {
                    wrap.innerHTML = '<p style="color:#475569;font-size:0.88em;padding:4px 0;">No tasks yet. Add tasks inside the health sub-sections.</p>';
                }
                return;
            }

            // ── Special case: fitness aggregates gym + martial-arts ──
            if (respId === 'fitness') {
                const FITNESS_SIDS = ['gym-1-2-3', 'martial-arts'];
                const allFitnessTasks = [];
                FITNESS_SIDS.forEach(sid => {
                    (gTasksAll[sid] || []).forEach(t => { allFitnessTasks.push({ t, sid }); });
                });
                if (allFitnessTasks.length > 0) {
                    const ul = document.createElement('ul');
                    ul.className = 'task-list';
                    allFitnessTasks.forEach(({ t, sid }) => {
                        ul.appendChild(_buildRTaskLi(t, sid, slot));
                    });
                    wrap.innerHTML = '';
                    wrap.appendChild(ul);
                    updateSummaryPills();
                } else {
                    wrap.innerHTML = '<p style="color:#475569;font-size:0.88em;padding:4px 0;">No tasks yet. Add tasks inside the Gym or Martial Arts sections.</p>';
                }
                return;
            }

            // ── Try 1: direct module data lookup (sections whose tasks live in a module object, NOT gTasksAll) ──
            // NOTE: sections migrated to gTasksAll are intentionally excluded here so they fall through to Try 2.
            const MODULE_DATA_MAP = {
                'dermatologist': typeof dermData !== 'undefined' ? dermData.tasks : null,
                'psychologist':  typeof psyData  !== 'undefined' ? psyData.tasks  : null,
                'streaming':     typeof streamingData !== 'undefined' ? streamingData.tasks : null,
                'invest':        typeof investData !== 'undefined' ? investData.tasks : null,
                'social-media':  typeof socialData !== 'undefined' ? socialData.tasks : null,
                'emulator':      typeof emuData  !== 'undefined' ? emuData.tasks  : null,
                'computer':      typeof pcData   !== 'undefined' ? pcData.tasks   : null,
                'phone':         typeof phoneData !== 'undefined' ? phoneData.tasks : null,
                'calendar':      typeof calData  !== 'undefined' ? calData.tasks  : null,
                'update-app':    null, // fully managed via gTasksAll — falls through to Try 2
                'lenses':        typeof lensData !== 'undefined' ? lensData.tasks : null,
                'room':          typeof roomData !== 'undefined' ? roomData.tasks : null,
                'travel-list':   typeof travelData !== 'undefined' ? travelData.tasks : null,
                // Sections below are fully on gTasksAll — handled by Try 2:
                // house, lost, family, friends, praxe, shopping, look,
                // dentist, ophthalmologist, general-doctor, martial-arts,
                // guitar, saxophone, piano, ableton (→ music), gym-1-2-3
            };

            const moduleTasks = MODULE_DATA_MAP[respId];
            if (moduleTasks && moduleTasks.length > 0) {
                const ul = document.createElement('ul');
                ul.className = 'task-list';
                moduleTasks.forEach(function(t) {
                    const globalKey = 'resp-' + respId + '-' + t.id;
                    const title = (t.emoji ? t.emoji + ' ' : '') + (t.title || t.text || '');
                    const desc = t.desc || t.notes || '';
                    const li = document.createElement('li');
                    li.className = 'task-item';
                    li.setAttribute('data-task', globalKey);
                    li.setAttribute('data-summary', slot);
                    li.onclick = function(){ toggleTask(li); };
                    const cb = document.createElement('div');
                    cb.className = 'task-checkbox';
                    const textCol = document.createElement('div');
                    textCol.style.cssText = 'flex:1;min-width:0;display:flex;flex-direction:column;gap:2px;';
                    const main = document.createElement('div');
                    main.className = 'task-main';
                    main.textContent = title;
                    textCol.appendChild(main);
                    if (desc) {
                        const dEl = document.createElement('div');
                        dEl.style.cssText = 'color:#64748b;font-size:0.8em;line-height:1.4;';
                        dEl.textContent = desc;
                        textCol.appendChild(dEl);
                    }
                    li.appendChild(cb);
                    li.appendChild(textCol);
                    if (tasks && tasks[globalKey]) li.classList.add('checked');
                    ul.appendChild(li);
                });
                wrap.innerHTML = '';
                wrap.appendChild(ul);
                updateSummaryPills();
                return;
            }

            // ── Try 2: gTasksAll (generic sections — guitar, saxophone, room, organize, etc.) ──
            if (typeof gTasksAll !== 'undefined' && gTasksAll[respId] && gTasksAll[respId].length > 0) {
                const ul = document.createElement('ul');
                ul.className = 'task-list';
                gTasksAll[respId].forEach(function(t) {
                    ul.appendChild(_buildRTaskLi(t, respId, slot));
                });
                wrap.innerHTML = '';
                wrap.appendChild(ul);
                updateSummaryPills();
                return;
            }

            // ── No tasks found ──
            wrap.innerHTML = '<p style="color:#475569; font-size:0.88em; padding:4px 0;">No tasks yet. Add tasks inside the responsibility section.</p>';
            updateSummaryPills();
        }



        function bindScheduleRTasks() {
            // Any schedule task with data-sched-slot / data-sched-rtask will be dynamically linked
            // to the currently selected responsibility in that R slot.
            const schedItems = document.querySelectorAll('li.task-item[data-sched-slot][data-sched-rtask]');
            schedItems.forEach(li => {
                const slot = li.getAttribute('data-sched-slot');
                const rtask = li.getAttribute('data-sched-rtask');
                const respId = rSlots && rSlots[slot] ? rSlots[slot] : null;
                if (!slot || !rtask || !respId || respId === 'none') return;

                const globalKey = `resp-${respId}-${rtask}`;
                li.setAttribute('data-task', globalKey);
                li.setAttribute('data-summary', slot);

                // Reflect checked state
                if (tasks && tasks[globalKey]) li.classList.add('checked');
                else li.classList.remove('checked');
            });

            updateSummaryPills();
            updateProgress();
        }
function initRSlotsUI() {
            ['r1','r2','r3'].forEach(slot => {
                populateRSelect(slot);
                const select = document.getElementById(slot + '-select');
                if (select) {
                    select.addEventListener('change', () => {
                        rSlots[slot] = select.value;
                        saveRSlots();
                        renderRSection(slot);
                        bindScheduleRTasks();
                        // Summary pills completion depends on tasks; keep UI updated
                        updateSummaryPills();
                        updateProgress();
                    });
                }
                renderRSection(slot);
                updateRTaskCount(slot);
            });
        }



        // Object to hold completion state of each summary. This is computed on the fly and not persisted.
        let summaryDone = {};

        // Initialize tasks with empty set (no tasks done by default)
        // Ensure that `tasks` only contains keys that correspond to actual task IDs in the document.
        if (Object.keys(tasks).length === 0) {
            tasks = {};
            localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
        }



        // -----------------------------
        // Responsibilities: tasks + gym weekly sessions
        // -----------------------------
        let respTasks = {};
        try {
            respTasks = JSON.parse(localStorage.getItem('respTasks') || '{}') || {};
        } catch (e) {
            respTasks = {};
        }

        function toggleRespTask(element) {
            const respId = element.getAttribute('data-resp') || 'unknown';
            const taskId = element.getAttribute('data-rtask') || 'unknown_task';

            const isChecked = element.classList.contains('checked');
            const newState = !isChecked;

            // sync duplicates for same resp+task
            document.querySelectorAll(`.resp-task-item[data-resp="${respId}"][data-rtask="${taskId}"]`).forEach(function(item){
                if (newState) item.classList.add('checked');
                else item.classList.remove('checked');
            });

            if (!respTasks[respId]) respTasks[respId] = {};
            respTasks[respId][taskId] = newState;
            localStorage.setItem('respTasks', JSON.stringify(respTasks));
        }

        function initRespTaskState() {
            document.querySelectorAll('.resp-task-item[data-resp][data-rtask]').forEach(function(el){
                const respId = el.getAttribute('data-resp');
                const taskId = el.getAttribute('data-rtask');
                const globalKey = `resp-${respId}-${taskId}`;

                el.setAttribute('data-task', globalKey);
                // Responsibilities tasks behave like Important/Schedule tasks (shared state)
                el.onclick = function(){ toggleTask(el); };

                if (tasks && tasks[globalKey]) {
                    el.classList.add('checked');
                } else {
                    el.classList.remove('checked');
                }
            });
        }

        let gymWeeklySessions = [];
        try {
            gymWeeklySessions = JSON.parse(localStorage.getItem('gymWeeklySessions') || '[]') || [];
        } catch (e) {
            gymWeeklySessions = [];
        }
        // Dentist: appointments (add / remove)
// ════════════════════════════════════════════════════════
//  DENTIST MODULE — v2
//  (Appointments + Routine + Kit + Log + Tasks)
// ════════════════════════════════════════════════════════

let __dentistFirstLoad = false;
let dentistData = {};
try {
    const _raw = localStorage.getItem('dentistData');
    __dentistFirstLoad = (_raw === null);
    dentistData = JSON.parse(_raw || '{}') || {};
} catch(e) { __dentistFirstLoad = true; dentistData = {}; }

// ── shape guards & migrations
ensureArrays(dentistData, 'appts', 'routine', 'kit', 'log', 'tasks');
if (typeof dentistData.routineState !== 'object' || !dentistData.routineState) dentistData.routineState = {};
// migrate old dentistAppointments to appts
if (!dentistData.appts.length) {
    try {
        const oldAppts = JSON.parse(localStorage.getItem('dentistAppointments') || '[]') || [];
        if (oldAppts.length) {
            dentistData.appts = oldAppts.map(a => ({ id:'a'+Date.now()+Math.random(), type:'checkup', when: a.date||'', where: a.title||'', notes:'' }));
        }
    } catch(e) {}
}
// migrate old routineState into items if routine is empty
if (!dentistData.routine.length) {
    dentistData.routine = [
        { id:'brush_am',  emoji:'🪥', label:'Brush (morning)' },
        { id:'floss',     emoji:'🧵', label:'Floss' },
        { id:'brush_pm',  emoji:'🪥', label:'Brush (night)' },
        { id:'mouthwash', emoji:'💧', label:'Mouthwash' },
    ];
}
// remap old {title} shape → {label}
dentistData.routine = dentistData.routine.map(r => ({ ...r, label: r.label || r.title || 'Step' }));

if (!dentistData.kit.length && __dentistFirstLoad) {
    dentistData.kit = [
        { key:'toothbrush',  emoji:'🪥', label:'Toothbrush (replace every 3 mo)',  done:false },
        { key:'toothpaste',  emoji:'🧴', label:'Toothpaste',                        done:false },
        { key:'floss',       emoji:'🧵', label:'Floss / floss picks',               done:false },
        { key:'mouthwash',   emoji:'💧', label:'Mouthwash',                         done:false },
        { key:'tongue',      emoji:'👅', label:'Tongue scraper',                    done:false },
    ];
}
if (!dentistData.tasks.length && __dentistFirstLoad) {
    dentistData.tasks = [
        { id:'dent_book', emoji:'📅', title:'Book cleaning', desc:'Schedule the next visit (call / online booking).' },
    ];
}
dentistData._seeded = true;

const saveDentistData = () => saveData('dentistData', dentistData);
saveDentistData();

// ── form helpers
function showDentistForm(kind){
    const el = document.getElementById('dentist-form-' + kind);
    if (!el) return;
    el.classList.add('visible');
    const f = el.querySelector('input,textarea,select');
    if (f) setTimeout(() => f.focus(), 60);
}
function hideDentistForm(kind){
    const el = document.getElementById('dentist-form-' + kind);
    if (el) el.classList.remove('visible');
}

// ── STATS
function updateDentistStats(){
    const g = id => document.getElementById(id);
    if (g('dent-stat-appts')) g('dent-stat-appts').textContent = dentistData.appts.length;
    const rDone = dentistData.routine.filter(r => dentistData.routineState[r.id]).length;
    const rPct  = dentistData.routine.length ? Math.round((rDone/dentistData.routine.length)*100) : 0;
    if (g('dent-stat-routine')) g('dent-stat-routine').textContent = rPct + '%';
    const kDone = dentistData.kit.filter(k => k.done).length;
    const kPct  = dentistData.kit.length ? Math.round((kDone/dentistData.kit.length)*100) : 0;
    if (g('dent-stat-kit'))  g('dent-stat-kit').textContent  = kPct + '%';
    if (g('dent-stat-log'))  g('dent-stat-log').textContent  = dentistData.log.length;
}

// ── APPOINTMENT TYPE MAP
const DENT_APPT_TYPE = {
    cleaning:    { emoji:'🪥', label:'Cleaning',     color:'#34d399' },
    checkup:     { emoji:'🦷', label:'Check-up',     color:'#60a5fa' },
    treatment:   { emoji:'💉', label:'Treatment',    color:'#f87171' },
    whitening:   { emoji:'✨', label:'Whitening',    color:'#fbbf24' },
    orthodontic: { emoji:'🧲', label:'Orthodontic',  color:'#a78bfa' },
    followup:    { emoji:'🔄', label:'Follow-up',    color:'#38bdf8' },
    other:       { emoji:'⚙️', label:'Other',        color:'#94a3b8' },
};

// ── APPOINTMENTS
function renderDentistAppts(){
    const list = document.getElementById('dent-appt-list');
    if (!list) return;
    list.innerHTML = '';
    if (!dentistData.appts.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No appointments yet — add your next one.</div>';
        updateDentistStats(); return;
    }
    dentistData.appts.forEach((a, i) => {
        const t = DENT_APPT_TYPE[a.type] || DENT_APPT_TYPE.other;
        const row = document.createElement('div');
        row.style.cssText = 'display:flex;align-items:flex-start;gap:10px;padding:12px 14px;border-radius:13px;background:rgba(96,165,250,0.05);border:1px solid rgba(96,165,250,0.15);';

        const icon = document.createElement('div');
        icon.className = 'icon-xl';
        icon.textContent = t.emoji;

        const body = document.createElement('div');
        body.className = 'flex-1';

        const topRow = document.createElement('div');
        topRow.className = 'd-row-7w';

        const typeTag = document.createElement('span');
        typeTag.style.cssText = colorTag(t.color) + ';white-space:nowrap';
        typeTag.textContent = t.label;
        topRow.appendChild(typeTag);

        const whenDisplay = (() => {
            if (a.date) {
                try {
                    const d = new Date(a.date + 'T00:00:00');
                    const fmt = d.toLocaleDateString(undefined, { weekday:'short', month:'short', day:'numeric' });
                    return fmt + (a.time ? ' ' + a.time : '');
                } catch(e) { return a.when || ''; }
            }
            return a.when || '';
        })();
        if (whenDisplay) {
            const wb = document.createElement('span');
            wb.style.cssText = 'font-size:0.7em;font-weight:800;padding:2px 7px;border-radius:99px;background:rgba(96,165,250,0.1);color:#60a5fa;border:1px solid rgba(96,165,250,0.2);white-space:nowrap;';
            wb.textContent = '📅 ' + whenDisplay;
            topRow.appendChild(wb);
        }
        if (a.where) {
            const we = document.createElement('span');
            we.className = 'item-label';
            we.textContent = a.where;
            topRow.appendChild(we);
        }
        body.appendChild(topRow);
        if (a.notes) {
            const n = document.createElement('div');
            n.className = 'text-muted';
            n.textContent = a.notes;
            body.appendChild(n);
        }

        const right = document.createElement('div');
        right.className = 'd-flex-gs0';

        const pushBtn = document.createElement('button');
        pushBtn.title = 'Push to tasks';
        pushBtn.className='pill pill-sky';
        pushBtn.textContent = '📋';
        pushBtn.onclick = e => { e.stopPropagation(); dentistQuickTask(t.emoji, (a.where||t.label) + (a.when?' — '+a.when:''), a.notes||''); };

        const editBtn = document.createElement('button');
        editBtn.title = 'Edit'; editBtn.textContent = '✎';
        editBtn.style.cssText = 'padding:5px 9px;border-radius:8px;border:1px solid rgba(255,255,255,0.1);background:rgba(255,255,255,0.04);color:#94a3b8;font-size:0.82em;font-weight:700;cursor:pointer;';
        editBtn.onclick = e => {
            e.stopPropagation();
            row.innerHTML = '';
            row.style.flexDirection = 'column';
            row.style.gap = '8px';
            const makeSelect = (val) => {
                const s = document.createElement('select'); s.className = 'house-input'; s.style.cssText = 'flex:1;min-width:130px;font-size:0.85em;';
                Object.entries(DENT_APPT_TYPE).forEach(([k,v]) => { const o = document.createElement('option'); o.value=k; o.textContent=v.emoji+' '+v.label; if(k===val)o.selected=true; s.appendChild(o); });
                return s;
            };
            const makeInput = (val, ph, maxl, type) => { const inp = document.createElement('input'); inp.className='house-input'; inp.value=val; if(ph) inp.placeholder=ph; inp.maxLength=maxl||60; inp.style.cssText='flex:1;font-size:0.85em;'; if(type) inp.type=type; return inp; };
            const r1 = document.createElement('div'); r1.className='d-row-7w-no-mb';
            const selType = makeSelect(a.type);
            const inpDate = makeInput(a.date||'', '', 20, 'date');
            const inpTime = makeInput(a.time||'', '', 10, 'time');
            inpDate.style.minWidth='130px'; inpTime.style.minWidth='100px';
            r1.appendChild(selType); r1.appendChild(inpDate); r1.appendChild(inpTime);
            const r2 = document.createElement('div'); r2.className='d-row-7w-no-mb';
            const inpWhere = makeInput(a.where, 'Clinic / dentist name', 50);
            const inpNotes = makeInput(a.notes, 'Notes (optional)', 100);
            r2.appendChild(inpWhere); r2.appendChild(inpNotes);
            const r3 = document.createElement('div'); r3.style.cssText='display:flex;gap:7px;';
            const saveBtn2 = document.createElement('button'); saveBtn2.className='house-save-btn'; saveBtn2.style.cssText='background:linear-gradient(135deg,#60a5fa,#3b82f6);font-size:0.85em;padding:8px 16px;'; saveBtn2.textContent='Save';
            saveBtn2.onclick = () => {
                a.type=selType.value; a.date=inpDate.value; a.time=inpTime.value;
                a.when=[a.date,a.time].filter(Boolean).join(' ');
                a.where=inpWhere.value.trim(); a.notes=inpNotes.value.trim();
                saveDentistData(); renderDentistAppts();
            };
            const cancelBtn2 = document.createElement('button'); cancelBtn2.className='house-cancel-btn'; cancelBtn2.style.cssText='font-size:0.85em;padding:8px 14px;'; cancelBtn2.textContent='Cancel';
            cancelBtn2.onclick = () => renderDentistAppts();
            r3.appendChild(saveBtn2); r3.appendChild(cancelBtn2);
            row.appendChild(r1); row.appendChild(r2); row.appendChild(r3);
            inpDate.focus();
        };

        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️'; delBtn.title = 'Remove';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove appointment?', message: 'Delete this appointment? This cannot be undone.', confirmLabel: 'Remove', onConfirm: () => { dentistData.appts.splice(i,1); saveDentistData(); renderDentistAppts(); } }); };

        right.appendChild(pushBtn); right.appendChild(editBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateDentistStats();
}

function saveDentistAppt(){
    const type  = document.getElementById('dent-appt-type')?.value || 'checkup';
    const date  = (document.getElementById('dent-appt-date')?.value || '').trim();
    const time  = (document.getElementById('dent-appt-time')?.value || '').trim();
    const where = (document.getElementById('dent-appt-where')?.value || '').trim();
    const notes = (document.getElementById('dent-appt-notes')?.value || '').trim();
    if (!date && !where) { document.getElementById('dent-appt-date')?.focus(); return; }
    const when = [date, time].filter(Boolean).join(' ');
    dentistData.appts.push({ id:'a'+Date.now(), type, when, date, time, where, notes });
    saveDentistData();
    ['dent-appt-date','dent-appt-time','dent-appt-where','dent-appt-notes'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});
    hideDentistForm('appt'); renderDentistAppts();
}

// ── DAILY ROUTINE
function renderDentistRoutine(){
    const list = document.getElementById('dent-routine-list');
    if (!list) return;
    list.innerHTML = '';
    const total = dentistData.routine.length;
    const done  = dentistData.routine.filter(r => dentistData.routineState[r.id]).length;
    const pct   = total ? Math.round((done/total)*100) : 0;
    const bar   = document.getElementById('dent-routine-bar');  if (bar)   bar.style.width   = pct + '%';
    const pctEl = document.getElementById('dent-routine-pct');  if (pctEl) pctEl.textContent = pct + '%';

    dentistData.routine.forEach((item, i) => {
        const isDone = !!dentistData.routineState[item.id];
        const row = document.createElement('div');
        row.className = `ir ${isDone ? 'ir-g' : ''}`;

        const emojiEl = document.createElement('div');
        emojiEl.className = 'icon-26';
        emojiEl.textContent = item.emoji || '🪥';

        const cb = document.createElement('div');
        cb.style.cssText = chk('#34d399',isDone);
        cb.textContent = isDone ? '✓' : '';

        const labelEl = document.createElement('div');
        labelEl.className = `done-label done-g ${isDone ? 'done' : ''}`;
        labelEl.textContent = item.label;

        const toggle = () => { dentistData.routineState[item.id] = !isDone; saveDentistData(); renderDentistRoutine(); updateDentistStats(); };
        [row, cb, labelEl].forEach(el => el.onclick = toggle);

        const delBtn = document.createElement('button');
        delBtn.className = 'mini-btn';
        delBtn.textContent = '✕';
        delBtn.onmouseover = () => { delBtn.style.color='#f87171'; delBtn.style.borderColor='rgba(248,113,113,0.3)'; };
        delBtn.onmouseout  = () => { delBtn.style.color='#475569'; delBtn.style.borderColor='rgba(255,255,255,0.07)'; };
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove step?', message: 'Delete this routine step?', confirmLabel: 'Remove', onConfirm: () => { dentistData.routine.splice(i,1); delete dentistData.routineState[item.id]; saveDentistData(); renderDentistRoutine(); updateDentistStats(); } }); };

        row.appendChild(emojiEl); row.appendChild(cb); row.appendChild(labelEl); row.appendChild(delBtn);
        list.appendChild(row);
    });
    updateDentistStats();
}

function saveDentistRoutineItem(){
    const emoji = (document.getElementById('dr-emoji')?.value || '').trim() || '🪥';
    const label = (document.getElementById('dr-title')?.value || '').trim();
    if (!label) { document.getElementById('dr-title')?.focus(); return; }
    const id = 'r_' + Date.now();
    dentistData.routine.push({ id, emoji, label });
    saveDentistData();
    ['dr-emoji','dr-title'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});
    hideDentistForm('routine'); renderDentistRoutine(); updateDentistStats();
}

function resetDentistRoutine(){
    dentistData.routineState = {};
    saveDentistData(); renderDentistRoutine(); updateDentistStats();
    toast('🔄 Routine reset');
}

// ── KIT & SUPPLIES
function renderDentistKit(){
    const list = document.getElementById('dent-kit-list');
    if (!list) return;
    list.innerHTML = '';
    const total = dentistData.kit.length;
    const done  = dentistData.kit.filter(k => k.done).length;
    const pct   = total ? Math.round((done/total)*100) : 0;
    const bar   = document.getElementById('dent-kit-bar');  if (bar)   bar.style.width   = pct + '%';
    const pctEl = document.getElementById('dent-kit-pct');  if (pctEl) pctEl.textContent = pct + '%';

    if (!total) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No kit items yet.</div>';
        updateDentistStats(); return;
    }
    dentistData.kit.forEach((k, i) => {
        const row = document.createElement('div');
        row.className = `ir ${k.done ? 'ir-y' : ''}`;

        const emojiEl = document.createElement('div');
        emojiEl.className = 'icon-26';
        emojiEl.textContent = k.emoji || '🧴';

        const cb = document.createElement('div');
        cb.style.cssText = chk('#fbbf24',k.done);
        cb.textContent = k.done ? '✓' : '';

        const labelEl = document.createElement('div');
        labelEl.className = `done-label done-y ${k.done ? 'done' : ''}`;
        labelEl.textContent = k.label;

        const toggle = () => { dentistData.kit[i].done = !k.done; saveDentistData(); renderDentistKit(); updateDentistStats(); };
        [row, cb, labelEl].forEach(el => el.onclick = toggle);

        const delBtn = document.createElement('button');
        delBtn.className = 'mini-btn';
        delBtn.textContent = '✕';
        delBtn.onmouseover = () => { delBtn.style.color='#f87171'; delBtn.style.borderColor='rgba(248,113,113,0.3)'; };
        delBtn.onmouseout  = () => { delBtn.style.color='#475569'; delBtn.style.borderColor='rgba(255,255,255,0.07)'; };
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove item?', message: 'Delete this kit item?', confirmLabel: 'Remove', onConfirm: () => { dentistData.kit.splice(i,1); saveDentistData(); renderDentistKit(); updateDentistStats(); } }); };

        row.appendChild(emojiEl); row.appendChild(cb); row.appendChild(labelEl); row.appendChild(delBtn);
        list.appendChild(row);
    });
    updateDentistStats();
}

function saveDentistKitItem(){
    const emoji = (document.getElementById('dk-emoji')?.value || '').trim() || '🧴';
    const label = (document.getElementById('dk-label')?.value || '').trim();
    if (!label) { document.getElementById('dk-label')?.focus(); return; }
    dentistData.kit.push({ key:'k'+Date.now(), emoji, label, done:false });
    saveDentistData();
    ['dk-emoji','dk-label'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});
    hideDentistForm('kit'); renderDentistKit(); updateDentistStats();
}

function resetDentistKit(){
    dentistData.kit.forEach(k => k.done = false);
    saveDentistData(); renderDentistKit(); updateDentistStats();
    toast('🔄 Kit reset');
}

// ── DENTAL LOG
const DENT_LOG_TYPE = {
    pain:        { emoji:'🤕', label:'Pain / sensitivity', color:'#f87171' },
    question:    { emoji:'❓', label:'Question for dentist', color:'#60a5fa' },
    aftercare:   { emoji:'🩹', label:'Aftercare reminder',  color:'#34d399' },
    observation: { emoji:'👁️', label:'Observation',         color:'#a78bfa' },
    note:        { emoji:'📝', label:'Note',                color:'#94a3b8' },
};

function renderDentistLog(){
    const list = document.getElementById('dent-log-list');
    if (!list) return;
    list.innerHTML = '';
    if (!dentistData.log.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No entries yet. Log pain, questions, or reminders for your next visit.</div>';
        updateDentistStats(); return;
    }
    [...dentistData.log].reverse().forEach((e, revIdx) => {
        const realIdx = dentistData.log.length - 1 - revIdx;
        const t = DENT_LOG_TYPE[e.type] || DENT_LOG_TYPE.note;
        const row = document.createElement('div');
        row.className = 'card-p';

        const icon = document.createElement('div');
        icon.className = 'icon-lg';
        icon.textContent = t.emoji;

        const body = document.createElement('div');
        body.className = 'flex-1';

        const topRow = document.createElement('div');
        topRow.className = 'd-row-7w';

        const typeTag = document.createElement('span');
        typeTag.style.cssText = colorTag(t.color);
        typeTag.textContent = t.label;
        topRow.appendChild(typeTag);

        if (e.date) {
            const db = document.createElement('span');
            db.className = 'meta-dim';
            try {
                const d = new Date(e.date + 'T00:00:00');
                db.textContent = '📅 ' + d.toLocaleDateString(undefined, { weekday:'short', month:'short', day:'numeric' });
            } catch(_) { db.textContent = '📅 ' + e.date; }
            topRow.appendChild(db);
        }
        body.appendChild(topRow);

        if (e.text) {
            const textEl = document.createElement('div');
            textEl.className = 'note-text';
            textEl.textContent = e.text;
            body.appendChild(textEl);
        }

        const right = document.createElement('div');
        right.className = 'd-flex-gs0';

        const pushBtn = document.createElement('button');
        pushBtn.title = 'Push to tasks';
        pushBtn.className = 'pill pill-p';
        pushBtn.textContent = '📋';
        pushBtn.onclick = ev => { ev.stopPropagation(); dentistQuickTask(t.emoji, t.label+(e.date?' — '+e.date:''), e.text?.slice(0,40)||''); };

        const editLogBtn = document.createElement('button');
        editLogBtn.title = 'Edit'; editLogBtn.textContent = '✎';
        editLogBtn.style.cssText = 'padding:5px 9px;border-radius:8px;border:1px solid rgba(255,255,255,0.1);background:rgba(255,255,255,0.04);color:#94a3b8;font-size:0.82em;font-weight:700;cursor:pointer;';
        editLogBtn.onclick = ev => {
            ev.stopPropagation();
            row.innerHTML = '';
            row.style.flexDirection = 'column';
            row.style.gap = '8px';
            const makeSelect = (val) => {
                const s = document.createElement('select'); s.className='house-input'; s.style.cssText='flex:1;font-size:0.85em;';
                Object.entries(DENT_LOG_TYPE).forEach(([k,v]) => { const o=document.createElement('option'); o.value=k; o.textContent=v.emoji+' '+v.label; if(k===val)o.selected=true; s.appendChild(o); });
                return s;
            };
            const r1 = document.createElement('div'); r1.className='d-row-7w-no-mb';
            const selType = makeSelect(e.type);
            const inpDate = document.createElement('input'); inpDate.className='house-input'; inpDate.type='date'; inpDate.value=e.date||''; inpDate.style.cssText='flex:1;min-width:130px;font-size:0.85em;';
            r1.appendChild(selType); r1.appendChild(inpDate);
            const ta = document.createElement('textarea'); ta.className='house-input'; ta.value=e.text||''; ta.maxLength=400; ta.style.cssText='width:100%;min-height:60px;resize:vertical;font-size:0.85em;line-height:1.5;box-sizing:border-box;';
            const r3 = document.createElement('div'); r3.style.cssText='display:flex;gap:7px;';
            const saveBtn2 = document.createElement('button'); saveBtn2.className='house-save-btn'; saveBtn2.style.cssText='background:linear-gradient(135deg,#c084fc,#a855f7);font-size:0.85em;padding:8px 16px;'; saveBtn2.textContent='Save';
            saveBtn2.onclick = () => {
                e.type=selType.value; e.date=inpDate.value.trim(); e.text=ta.value.trim();
                saveDentistData(); renderDentistLog(); updateDentistStats();
            };
            const cancelBtn2 = document.createElement('button'); cancelBtn2.className='house-cancel-btn'; cancelBtn2.style.cssText='font-size:0.85em;padding:8px 14px;'; cancelBtn2.textContent='Cancel';
            cancelBtn2.onclick = () => renderDentistLog();
            r3.appendChild(saveBtn2); r3.appendChild(cancelBtn2);
            row.appendChild(r1); row.appendChild(ta); row.appendChild(r3);
            ta.focus();
        };

        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️'; delBtn.title = 'Remove';
        delBtn.onclick = ev => { ev.stopPropagation(); showConfirm({ title: 'Remove log entry?', message: 'Delete this log entry?', confirmLabel: 'Remove', onConfirm: () => { dentistData.log.splice(realIdx,1); saveDentistData(); renderDentistLog(); updateDentistStats(); } }); };

        right.appendChild(pushBtn); right.appendChild(editLogBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateDentistStats();
}

function saveDentistLog(){
    const type = document.getElementById('dl-type')?.value || 'note';
    const date = (document.getElementById('dl-date')?.value || '').trim();
    const text = (document.getElementById('dl-text')?.value || '').trim();
    if (!text) { document.getElementById('dl-text')?.focus(); return; }
    dentistData.log.push({ id:'l'+Date.now(), type, date, text });
    saveDentistData();
    ['dl-date','dl-text'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});
    hideDentistForm('log'); renderDentistLog(); updateDentistStats();
}

// ── QUICK TASK
function dentistQuickTask(emoji, title, desc){
    if (!gTasksAll['dentist']) gTasksAll['dentist'] = [];
    const already = gTasksAll['dentist'].find(t => (t.text === title || t.title === title) && !t.done);
    if (already) { toast('Task already exists'); return; }
    gTasksAll['dentist'].push({ id: 'dqt_' + Date.now(), emoji, text: title, notes: desc || '', done: false, accentColor: '#60a5fa' });
    saveGTasksAll(); renderDentistTasks();
    toast('📌 Task added');
}

// ── TASKS
function renderDentistTasks(){
    renderGTasks('dentist');
    try { ['r1','r2','r3'].forEach(slot=>{if(rSlots&&(rSlots[slot]==='dentist'||rSlots[slot]==='health'))renderRTasks(slot);}); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e){}
}

function saveDentistTask(){ hideDentistForm('task'); showGTask('dentist'); }
function removeDentistTask() { renderDentistTasks(); }

function initDentistSection(){
    if (!document.getElementById('resp-section-dentist')) return;
    // One-time migration from dentistData.tasks → gTasksAll['dentist']
    if ((dentistData.tasks || []).length && !(gTasksAll['dentist'] || []).length) {
        gTasksAll['dentist'] = dentistData.tasks.map(t => ({
            id: t.id || ('dqt_' + Date.now() + '_' + Math.random()),
            emoji: t.emoji || '',
            text: t.title || t.text || '',
            notes: t.desc || '',
            done: !!t.done,
            accentColor: '#60a5fa'
        }));
        saveGTasksAll();
    }
    renderDentistAppts();
    renderDentistRoutine();
    renderDentistKit();
    renderDentistLog();
    renderDentistTasks();
    updateDentistStats();
}


// ════════════════════════════════════════════════════════
//  OPHTHALMOLOGIST MODULE (Appointments + Checklist + Rx + Notes + Tasks)
// ════════════════════════════════════════════════════════


// ════════════════════════════════════════════════════════
//  OPHTHALMOLOGIST MODULE — v2 (Stats + Appts + Habits + Rx + Log + Tasks)
// ════════════════════════════════════════════════════════

let __ophFirstLoad = false;
let ophthalmologistData = {};
try {
    const raw = localStorage.getItem('ophthalmologistData');
    __ophFirstLoad = (raw === null);
    ophthalmologistData = JSON.parse(raw || '{}') || {};
} catch(e) {
    __ophFirstLoad = true;
    ophthalmologistData = {};
}

// ── data shape guards
ensureArrays(ophthalmologistData, 'appts', 'habits', 'log', 'tasks');
if (!ophthalmologistData.rx) ophthalmologistData.rx = {};
if (typeof ophthalmologistData.rx.glasses  !== 'string') ophthalmologistData.rx.glasses  = '';
if (typeof ophthalmologistData.rx.contacts !== 'string') ophthalmologistData.rx.contacts = '';
if (typeof ophthalmologistData.rx.drops    !== 'string') ophthalmologistData.rx.drops    = '';
if (typeof ophthalmologistData.rx.next     !== 'string') ophthalmologistData.rx.next     = '';
if (typeof ophthalmologistData._seeded === 'undefined') ophthalmologistData._seeded = false;

// ── migrate old checklist → habits
if (!ophthalmologistData._seeded) {
    const old = ophthalmologistData.checklist;
    if (Array.isArray(old) && old.length) {
        ophthalmologistData.habits = old.map(item => ({
            key: item.key || ('h_' + Date.now() + Math.random()),
            emoji: '👁️',
            label: item.label || '',
            done: !!item.done
        }));
    }
    delete ophthalmologistData.checklist;
    delete ophthalmologistData.notes;
    ophthalmologistData._seeded = true;
}

// ── seed default habits on first load
if (__ophFirstLoad && !ophthalmologistData.habits.length) {
    ophthalmologistData.habits = [
        { key:'breaks',   emoji:'🖥️', label:'20-20-20 screen breaks',        done:false },
        { key:'drops',    emoji:'💧', label:'Use eye drops (if needed)',       done:false },
        { key:'clean',    emoji:'🧼', label:'Clean glasses / lenses',          done:false },
        { key:'sleep',    emoji:'😴', label:'Sleep & hydration check',          done:false },
        { key:'outdoor',  emoji:'☀️', label:'Get daylight / outdoor time',     done:false },
    ];
}

const saveOphthalmologistData = () => saveData('ophthalmologistData', ophthalmologistData);

// ── stat chips
function updateOphStats(){
    const now = new Date();
    const upcoming = (ophthalmologistData.appts || []).filter(a => {
        if (!a.when) return true;
        const d = new Date(a.when); return isNaN(d) || d >= now;
    }).length;
    const total = (ophthalmologistData.habits || []).length;
    const done  = (ophthalmologistData.habits || []).filter(h => h.done).length;
    const pct   = total ? Math.round(done / total * 100) : 0;
    const rxFilled = [ophthalmologistData.rx.glasses, ophthalmologistData.rx.contacts,
                      ophthalmologistData.rx.drops, ophthalmologistData.rx.next].filter(v => v && v.trim()).length;
    const logCount = (ophthalmologistData.log || []).length;

    const el = id => document.getElementById(id);
    if (el('oph-stat-appts')) el('oph-stat-appts').textContent = upcoming;
    if (el('oph-stat-habits')) el('oph-stat-habits').textContent = pct + '%';
    if (el('oph-stat-rx'))    el('oph-stat-rx').textContent    = rxFilled + '/4';
    if (el('oph-stat-log'))   el('oph-stat-log').textContent   = logCount;
}

// ── form show/hide
function showOphForm(kind){
    const el = document.getElementById('oph-form-' + kind);
    if (el) el.style.display = 'block';
}
function hideOphForm(kind){
    const el = document.getElementById('oph-form-' + kind);
    if (el) el.style.display = 'none';
}

// ── appointment type map
const OPH_APPT_TYPE = {
    exam:     { emoji:'👁️',  label:'Eye exam',         color:'#38bdf8', bg:'rgba(56,189,248,0.12)'  },
    contacts: { emoji:'🩹',  label:'Contact fitting',   color:'#34d399', bg:'rgba(52,211,153,0.12)'  },
    glasses:  { emoji:'👓',  label:'Glasses / order',   color:'#fbbf24', bg:'rgba(251,191,36,0.12)'  },
    surgery:  { emoji:'🩺',  label:'Procedure',         color:'#f87171', bg:'rgba(248,113,113,0.12)' },
    followup: { emoji:'🔄',  label:'Follow-up',         color:'#a78bfa', bg:'rgba(167,139,250,0.12)' },
    other:    { emoji:'⚙️',  label:'Other',             color:'#94a3b8', bg:'rgba(148,163,184,0.1)'  },
};

// ── render appointments
function renderOphAppts(){
    const list = document.getElementById('oph-appt-list');
    if (!list) return;
    list.innerHTML = '';

    if (!ophthalmologistData.appts.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No appointments yet.</div>';
        updateOphStats(); return;
    }

    const sorted = [...ophthalmologistData.appts].reverse();
    sorted.forEach(appt => {
        const t = OPH_APPT_TYPE[appt.type] || OPH_APPT_TYPE.other;
        const row = document.createElement('div');
        row.style.cssText = `display:flex;align-items:flex-start;gap:10px;padding:11px 13px;border-radius:12px;border:1px solid ${t.bg};background:rgba(2,8,23,0.35);`;

        const badge = document.createElement('span');
        badge.style.cssText = `font-size:0.68em;font-weight:800;padding:3px 9px;border-radius:99px;background:${t.bg};color:${t.color};border:1px solid ${t.color}33;flex-shrink:0;margin-top:2px;white-space:nowrap;`;
        badge.textContent = t.emoji + ' ' + t.label;

        const info = document.createElement('div');
        info.className = 'flex-1';

        const title = document.createElement('div');
        title.className = 'item-label';
        title.textContent = appt.when || '—';

        info.appendChild(title);
        if (appt.place) {
            const sub = document.createElement('div');
            sub.style.cssText = 'font-size:0.78em;color:#64748b;margin-top:2px;';
            sub.textContent = '📍 ' + appt.place;
            info.appendChild(sub);
        }
        if (appt.notes) {
            const notes = document.createElement('div');
            notes.style.cssText = 'font-size:0.78em;color:#64748b;margin-top:2px;font-style:italic;';
            notes.textContent = appt.notes;
            info.appendChild(notes);
        }

        const taskBtn = document.createElement('button');
        taskBtn.title = 'Push to tasks';
        taskBtn.className = 'pill pill-b';
        taskBtn.textContent = '📋';
        taskBtn.onclick = e => { e.stopPropagation(); ophQuickTask('👁️', (appt.when||'Appt') + (appt.place ? ' @ '+appt.place : ''), 'Eye appointment'); };

        const del = document.createElement('button');
        del.className = 'mini-btn';
        del.textContent = '✕';
        del.onmouseover = () => { del.style.color='#f87171'; del.style.borderColor='rgba(248,113,113,0.3)'; };
        del.onmouseout  = () => { del.style.color='#475569'; del.style.borderColor='rgba(255,255,255,0.07)'; };
        del.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove appointment?', message: 'Delete this appointment? This cannot be undone.', confirmLabel: 'Remove', onConfirm: () => { ophthalmologistData.appts = ophthalmologistData.appts.filter(a => a.id !== appt.id); saveOphthalmologistData(); renderOphAppts(); } }); };

        row.appendChild(badge); row.appendChild(info); row.appendChild(taskBtn); row.appendChild(del);
        list.appendChild(row);
    });
    updateOphStats();
}

function saveOphAppt(){
    const type  = document.getElementById('oph-appt-type')?.value || 'other';
    const date  = (document.getElementById('oph-appt-date')?.value || '').trim();
    const time  = (document.getElementById('oph-appt-time')?.value || '').trim();
    const when  = [date, time].filter(Boolean).join(' ');
    const place = (document.getElementById('oph-appt-place')?.value || '').trim();
    const notes = (document.getElementById('oph-appt-notes')?.value || '').trim();
    if (!date && !place) { document.getElementById('oph-appt-date')?.focus(); return; }

    ophthalmologistData.appts.push({ id:'a'+Date.now(), type, when, date, time, place, notes });
    saveOphthalmologistData();
    ['oph-appt-type','oph-appt-date','oph-appt-time','oph-appt-place','oph-appt-notes'].forEach(id => {
        const el = document.getElementById(id); if (el) el.value = el.tagName === 'SELECT' ? el.options[0].value : '';
    });
    hideOphForm('appt');
    renderOphAppts();
}

// ── render habits
function renderOphHabits(){
    const list = document.getElementById('oph-habits-list');
    if (!list) return;
    list.innerHTML = '';

    const total = (ophthalmologistData.habits || []).length;
    const done  = (ophthalmologistData.habits || []).filter(h => h.done).length;
    const pct   = total ? Math.round(done / total * 100) : 0;

    const pctEl = document.getElementById('oph-habits-pct');
    const bar   = document.getElementById('oph-habits-bar');
    if (pctEl) pctEl.textContent = pct + '%';
    if (bar)   bar.style.width   = pct + '%';

    (ophthalmologistData.habits || []).forEach((item, i) => {
        const row = document.createElement('div');
        row.className = `ir ${item.done ? 'ir-g' : ''}`;

        const emojiEl = document.createElement('div');
        emojiEl.className = 'icon-26';
        emojiEl.textContent = item.emoji || '👁️';

        const cb = document.createElement('div');
        cb.style.cssText = chk('#34d399', item.done);
        cb.textContent = item.done ? '✓' : '';

        const label = document.createElement('span');
        label.className = `done-label done-g ${item.done ? 'done' : ''}`;
        label.textContent = item.label;

        const toggle = () => {
            ophthalmologistData.habits[i].done = !ophthalmologistData.habits[i].done;
            saveOphthalmologistData(); renderOphHabits(); updateOphStats();
        };
        row.onclick = toggle;

        const del = document.createElement('button');
        del.className = 'mini-btn';
        del.textContent = '✕';
        del.onmouseover = () => { del.style.color='#f87171'; del.style.borderColor='rgba(248,113,113,0.3)'; };
        del.onmouseout  = () => { del.style.color='#475569'; del.style.borderColor='rgba(255,255,255,0.07)'; };
        del.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove habit?', message: 'Delete this eye-care habit?', confirmLabel: 'Remove', onConfirm: () => { ophthalmologistData.habits.splice(i,1); saveOphthalmologistData(); renderOphHabits(); updateOphStats(); } }); };

        row.appendChild(emojiEl); row.appendChild(cb); row.appendChild(label); row.appendChild(del);
        list.appendChild(row);
    });
    updateOphStats();
}

function saveOphHabit(){
    const emoji = (document.getElementById('oph-h-emoji')?.value || '').trim() || '👁️';
    const label = (document.getElementById('oph-h-label')?.value || '').trim();
    if (!label) { document.getElementById('oph-h-label')?.focus(); return; }
    ophthalmologistData.habits.push({ key:'h_'+Date.now(), emoji, label, done:false });
    saveOphthalmologistData();
    ['oph-h-emoji','oph-h-label'].forEach(id => { const el = document.getElementById(id); if(el) el.value = ''; });
    hideOphForm('habit');
    renderOphHabits();
}

function resetOphHabits(){
    ophthalmologistData.habits.forEach(h => h.done = false);
    saveOphthalmologistData(); renderOphHabits(); updateOphStats();
}

// ── Rx autosave
function initOphRx(){
    const ids = { 'oph-rx-glasses':'glasses', 'oph-rx-contacts':'contacts', 'oph-rx-drops':'drops', 'oph-rx-next':'next' };
    Object.entries(ids).forEach(([elId, key]) => {
        const el = document.getElementById(elId);
        if (!el) return;
        el.value = ophthalmologistData.rx[key] || '';
        el.addEventListener('input', () => {
            ophthalmologistData.rx[key] = el.value || '';
            saveOphthalmologistData(); updateOphStats();
        }, { passive:true });
    });
}

