        const del = document.createElement('button');
        del.style.cssText = 'width:22px;height:22px;border-radius:5px;border:1px solid rgba(255,255,255,0.07);background:rgba(255,255,255,0.03);color:#475569;font-size:0.75em;cursor:pointer;display:flex;align-items:center;justify-content:center;';
        del.textContent = '✕';
        del.onmouseover = () => { del.style.color='#f87171'; };
        del.onmouseout  = () => { del.style.color='#475569'; };
        del.onclick = () => { showConfirm({ title: 'Remove log entry?', message: 'Delete this log entry?', confirmLabel: 'Remove', onConfirm: () => { ophthalmologistData.log = ophthalmologistData.log.filter(l => l.id !== entry.id); saveOphthalmologistData(); renderOphLog(); } }); };

        header.appendChild(badge); header.appendChild(dateEl); header.appendChild(taskBtn); header.appendChild(del);

        const text = document.createElement('div');
        text.style.cssText = 'font-size:0.85em;color:#cbd5e1;line-height:1.55;';
