function saveOphLog(){
    const type = document.getElementById('oph-l-type')?.value || 'note';
    const date = (document.getElementById('oph-l-date')?.value || '').trim();
    const text = (document.getElementById('oph-l-text')?.value || '').trim();
    if (!text) { document.getElementById('oph-l-text')?.focus(); return; }

    ophthalmologistData.log.push({ id:'l'+Date.now(), type, date, text });
    saveOphthalmologistData();
    const tEl = document.getElementById('oph-l-type'); if(tEl) tEl.value = tEl.options[0].value;
    ['oph-l-date','oph-l-text'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideOphForm('log');
    renderOphLog();
}

// ── quick task helper
function ophQuickTask(emoji, title, context){
    if (!gTasksAll['ophthalmologist']) gTasksAll['ophthalmologist'] = [];
    const already = gTasksAll['ophthalmologist'].find(t => (t.text === title || t.title === title) && !t.done);
    if (already) { toast('Task already exists'); return; }
    gTasksAll['ophthalmologist'].push({ id: 't' + Date.now(), emoji, text: title, notes: context || '', done: false, accentColor: '#38bdf8' });
    saveGTasksAll(); renderOphTasks();
    toast('📌 Task added');
}

// ── tasks
function renderOphTasks(){
    renderGTasks('ophthalmologist');
    try { ['r1','r2','r3'].forEach(slot=>{if(rSlots&&(rSlots[slot]==='ophthalmologist'||rSlots[slot]==='health'))renderRTasks(slot);}); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e){}
}

function saveOphTask(){ hideOphForm('task'); showGTask('ophthalmologist'); }
function removeOphTask() { renderOphTasks(); }

function initOphthalmologistSection(){
    // One-time migration from ophthalmologistData.tasks → gTasksAll['ophthalmologist']
    if ((ophthalmologistData.tasks || []).length && !(gTasksAll['ophthalmologist'] || []).length) {
        gTasksAll['ophthalmologist'] = ophthalmologistData.tasks.map(t => ({
            id: t.id || ('t' + Date.now() + '_' + Math.random()),
            emoji: t.emoji || '',
            text: t.title || t.text || '',
            notes: t.desc || '',
            done: !!t.done,
            accentColor: '#38bdf8'
        }));
        saveGTasksAll();
    }
    renderOphAppts();
    renderOphHabits();
    initOphRx();
    renderOphLog();
    renderOphTasks();
    updateOphStats();
}

