// ── WEEKLY GOAL selector
function renderGymGoalRow(){
    const row = document.getElementById('gym-goal-row');
    if (!row) return;
    row.innerHTML = '';
    [0,1,2,3,4,5].forEach(n => {
        const b = document.createElement('button');
        b.type = 'button';
        const active = gym123Data.weeklyGoal === n;
        b.style.cssText = `width:28px;height:28px;border-radius:8px;font-size:0.8em;font-weight:900;cursor:pointer;transition:all 0.15s;border:1px solid ${active?'rgba(34,197,94,0.5)':'rgba(255,255,255,0.08)'};background:${active?'rgba(34,197,94,0.18)':'rgba(255,255,255,0.03)'};color:${active?'#22c55e':'#475569'};`;
        b.textContent = n + 'x';
        b.onclick = () => { gym123Data.weeklyGoal = n; saveGym123Data(); renderGymGoalRow(); updateGymStats(); };
        row.appendChild(b);
    });
}

