// ── Track which sessions are expanded across re-renders
const _gymExpanded = {};

// ── SESSIONS LIST
function renderGymSessions(){
    const list = document.getElementById('gym-sessions-list');
    if (!list) return;
    list.innerHTML = '';

    if (!gym123Data.sessions.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:6px 2px;">No sessions yet. Add your first one below.</div>';
        return;
    }

    gym123Data.sessions.forEach((s, i) => {
        // Migrate legacy plan text -> subtasks
        if (!s.subtasks && s.plan && s.plan.trim()) {
            s.subtasks = s.plan.split(/\n|\//).map(t => t.trim()).filter(Boolean).map(t => ({ id:'st'+Date.now()+Math.random().toString(36).slice(2), text:t, done:false }));
            delete s.plan;
            saveGym123Data();
        }
        if (!s.subtasks) s.subtasks = [];

        const doneCount = s.subtasks.filter(st => st.done).length;

        const wrap = document.createElement('div');
        wrap.style.cssText = `border-radius:14px;overflow:hidden;border:1px solid ${s.weekDone?'rgba(34,197,94,0.4)':'rgba(255,255,255,0.07)'};background:${s.weekDone?'rgba(34,197,94,0.07)':'rgba(2,8,23,0.4)'};transition:all 0.2s;`;

        // ── header row
        const head = document.createElement('div');
        head.style.cssText = 'display:flex;align-items:center;gap:10px;padding:12px 14px;cursor:pointer;';

        const emojiEl = document.createElement('div');
        emojiEl.style.cssText = 'font-size:1.4em;flex-shrink:0;width:30px;text-align:center;';
        emojiEl.textContent = s.emoji || '💪';

        const nameEl = document.createElement('div');
        nameEl.style.cssText = `flex:1;font-weight:800;font-size:0.93em;color:${s.weekDone?'#22c55e':'#e2e8f0'};`;
        nameEl.textContent = s.name || 'Session';

        const right = document.createElement('div');
        right.className = 'd-flex-ai-gs0';

        // subtask progress badge
        if (s.subtasks.length) {
            const badge = document.createElement('span');
            badge.style.cssText = 'font-size:0.7em;font-weight:800;padding:2px 7px;border-radius:99px;background:rgba(34,197,94,0.1);color:#22c55e;border:1px solid rgba(34,197,94,0.2);white-space:nowrap;';
            badge.textContent = doneCount + '/' + s.subtasks.length;
            right.appendChild(badge);
        }

        // done toggle
        const doneBtn = document.createElement('button');
        doneBtn.type = 'button';
        doneBtn.title = s.weekDone ? 'Mark as not done' : 'Mark done this week';
        doneBtn.style.cssText = `padding:5px 12px;border-radius:8px;font-size:0.78em;font-weight:800;cursor:pointer;transition:all 0.15s;border:1px solid ${s.weekDone?'rgba(34,197,94,0.5)':'rgba(255,255,255,0.12)'};background:${s.weekDone?'rgba(34,197,94,0.15)':'rgba(255,255,255,0.04)'};color:${s.weekDone?'#22c55e':'#64748b'};`;
        doneBtn.textContent = s.weekDone ? '✓ Done' : '○ Done';
        doneBtn.onclick = e => { e.stopPropagation(); gym123Data.sessions[i].weekDone = !s.weekDone; saveGym123Data(); renderGymSessions(); updateGymStats(); };

        // expand toggle button
        const expandBtn = document.createElement('button');
        expandBtn.type = 'button';
        expandBtn.style.cssText = 'width:24px;height:24px;border-radius:6px;border:1px solid rgba(255,255,255,0.07);background:rgba(255,255,255,0.03);color:#475569;font-size:0.75em;cursor:pointer;transition:all 0.15s;display:flex;align-items:center;justify-content:center;';
        expandBtn.textContent = '▾';

        // delete
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️'; delBtn.title = 'Delete session';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Delete session?', message: 'Delete "' + s.name + '"? This cannot be undone.', confirmLabel: 'Delete', onConfirm: () => { gym123Data.sessions.splice(i,1); saveGym123Data(); renderGymSessions(); updateGymStats(); } }); };

        // push whole session as task with exercises as subtasks
        const pushBtn = document.createElement('button');
        pushBtn.type = 'button';
        pushBtn.title = 'Push session to tasks';
        pushBtn.style.cssText = 'padding:5px 9px;border-radius:8px;font-size:0.72em;font-weight:700;cursor:pointer;transition:all 0.15s;border:1px solid rgba(34,197,94,0.3);background:rgba(34,197,94,0.07);color:#22c55e;';
        pushBtn.textContent = '📋';
        pushBtn.onclick = e => { e.stopPropagation(); gymPushSession(s); };

        // edit name
        const editBtn = document.createElement('button');
        editBtn.type = 'button';
        editBtn.title = 'Edit session name';
        editBtn.style.cssText = 'width:24px;height:24px;border-radius:6px;border:1px solid rgba(255,255,255,0.07);background:rgba(255,255,255,0.03);color:#475569;font-size:0.8em;cursor:pointer;transition:all 0.15s;display:flex;align-items:center;justify-content:center;';
        editBtn.textContent = '✎';
        editBtn.onclick = e => {
            e.stopPropagation();
            const input = document.createElement('input');
            input.value = s.name;
            input.style.cssText = 'flex:1;min-width:0;background:transparent;border:none;border-bottom:1px solid #22c55e;color:#e2e8f0;font-weight:800;font-size:0.93em;outline:none;padding:2px 0;';
            nameEl.replaceWith(input);
            input.focus(); input.select();
            const commit = () => {
                const v = input.value.trim();
                if (v) { s.name = v; saveGym123Data(); }
                renderGymSessions();
            };
            input.addEventListener('blur', commit);
            input.addEventListener('keydown', e2 => {
                if (e2.key === 'Enter') { e2.preventDefault(); input.blur(); }
                if (e2.key === 'Escape') { input.removeEventListener('blur', commit); renderGymSessions(); }
            });
        };

        // duplicate
        const dupBtn = document.createElement('button');
        dupBtn.type = 'button';
        dupBtn.title = 'Duplicate session';
        dupBtn.style.cssText = 'width:24px;height:24px;border-radius:6px;border:1px solid rgba(255,255,255,0.07);background:rgba(255,255,255,0.03);color:#475569;font-size:0.8em;cursor:pointer;transition:all 0.15s;display:flex;align-items:center;justify-content:center;';
        dupBtn.textContent = '⧉';
        dupBtn.onclick = e => {
            e.stopPropagation();
            const copy = JSON.parse(JSON.stringify(s));
            copy.id = 's' + Date.now();
            copy.name = s.name + ' (copy)';
            copy.weekDone = false;
            copy.subtasks = (s.subtasks || []).map(st => ({ ...st, id: 'st' + Date.now() + Math.random().toString(36).slice(2), done: false }));
            gym123Data.sessions.splice(i + 1, 0, copy);
            saveGym123Data(); renderGymSessions(); updateGymStats();
        };

        right.appendChild(pushBtn); right.appendChild(doneBtn); right.appendChild(editBtn); right.appendChild(dupBtn); right.appendChild(expandBtn); right.appendChild(delBtn);
        head.appendChild(emojiEl); head.appendChild(nameEl); head.appendChild(right);

        // ── subtask body (collapsible)
        const planBody = document.createElement('div');
        planBody.style.cssText = 'display:none;padding:0 14px 14px;';

        // subtask list container
        const stList = document.createElement('div');
        stList.style.cssText = 'display:flex;flex-direction:column;gap:6px;margin-bottom:10px;';

        const renderSubtasks = () => {
            stList.innerHTML = '';
            if (!s.subtasks.length) {
                stList.innerHTML = '<div style="color:#334155;font-size:0.82em;font-style:italic;padding:4px 2px;">No exercises yet. Add one below.</div>';
                return;
            }
            s.subtasks.forEach((st) => {
                const stRow = document.createElement('div');
                stRow.style.cssText = `display:flex;align-items:center;gap:8px;padding:8px 10px;border-radius:9px;background:${st.done?'rgba(34,197,94,0.06)':'rgba(255,255,255,0.03)'};border:1px solid ${st.done?'rgba(34,197,94,0.2)':'rgba(255,255,255,0.06)'};cursor:pointer;transition:all 0.15s;`;
                stRow.setAttribute('data-sub-idx', s.subtasks.indexOf(st));

                const stCb = document.createElement('div');
                stCb.style.cssText = `width:18px;height:18px;border-radius:5px;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:900;color:#000;transition:all 0.2s;border:2px solid ${st.done?'#22c55e':'rgba(255,255,255,0.2)'};background:${st.done?'#22c55e':'transparent'};`;
                stCb.textContent = st.done ? '✓' : '';

                const stText = document.createElement('span');
                stText.style.cssText = `flex:1;font-size:0.85em;font-weight:600;color:${st.done?'#475569':'#cbd5e1'};text-decoration:${st.done?'line-through':'none'};`;
                stText.textContent = st.text;

                const stEdit = document.createElement('button');
                stEdit.style.cssText = 'width:20px;height:20px;border-radius:5px;border:none;background:none;color:#334155;font-size:0.8em;cursor:pointer;flex-shrink:0;display:flex;align-items:center;justify-content:center;transition:color 0.15s;';
                stEdit.textContent = '✎';
                stEdit.onmouseover = () => stEdit.style.color = '#60a5fa';
                stEdit.onmouseout  = () => stEdit.style.color = '#334155';
                stEdit.onclick = e => {
                    e.stopPropagation();
                    const inp = document.createElement('input');
                    inp.value = st.text;
                    inp.style.cssText = 'flex:1;background:transparent;border:none;border-bottom:1px solid #60a5fa;color:#e2e8f0;font-size:0.85em;font-weight:600;outline:none;padding:2px 0;min-width:0;';
                    stText.replaceWith(inp);
                    stRow.style.cursor = 'default';
                    stRow.onclick = null;
                    stCb.onclick = null;
                    inp.focus(); inp.select();
                    const commit = () => {
                        const v = inp.value.trim();
                        if (v && v !== st.text) {
                            st.text = v;
                            saveGym123Data();
                            _syncGymSubtaskText(s.id, st.id, v);
                        }
                        renderGymSessions();
                    };
                    inp.addEventListener('blur', commit);
                    inp.addEventListener('keydown', e2 => {
                        if (e2.key === 'Enter') { e2.preventDefault(); inp.blur(); }
                        if (e2.key === 'Escape') { inp.removeEventListener('blur', commit); renderGymSessions(); }
                    });
                };

                const stDel = document.createElement('button');
                stDel.style.cssText = 'width:20px;height:20px;border-radius:5px;border:none;background:none;color:#334155;font-size:0.75em;cursor:pointer;flex-shrink:0;display:flex;align-items:center;justify-content:center;transition:color 0.15s;';
                stDel.textContent = '✕';
                stDel.onmouseover = () => stDel.style.color = '#f87171';
                stDel.onmouseout  = () => stDel.style.color = '#334155';
                stDel.onclick = e => { e.stopPropagation(); removeGymSubtask(s.id, st.id); };

                stRow.onclick = () => {
                    toggleGymSubtask(s.id, st.id);
                    const freshSt = (gym123Data.sessions.find(ss=>ss.id===s.id)?.subtasks||[]).find(x=>x.id===st.id);
                    if (freshSt) _syncGymSessionSubToTask(s.id, st.id, freshSt.done);
                };
                stCb.onclick = e => {
                    e.stopPropagation();
                    toggleGymSubtask(s.id, st.id);
                    const freshSt = (gym123Data.sessions.find(ss=>ss.id===s.id)?.subtasks||[]).find(x=>x.id===st.id);
                    if (freshSt) _syncGymSessionSubToTask(s.id, st.id, freshSt.done);
                };

                const stHandle = document.createElement('span');
                stHandle.className = 'sub-drag-handle';
                stHandle.title = 'Drag to reorder';
                stHandle.textContent = '⠿';

                stRow.appendChild(stHandle); stRow.appendChild(stCb); stRow.appendChild(stText); stRow.appendChild(stEdit); stRow.appendChild(stDel);
                stList.appendChild(stRow);
            });
        };
        renderSubtasks();
        // Wire subtask DnD
        _wireSubDnd(stList,
            () => s.subtasks,
            () => { saveGym123Data(); renderGymSessions(); }
        );
        planBody.appendChild(stList);

        // add subtask input row
        const addRow = document.createElement('div');
        addRow.style.cssText = 'display:flex;gap:6px;';
        const stInput = document.createElement('input');
        stInput.className = 'house-input';
        stInput.placeholder = 'Add exercise (e.g. Bench 4×8)';
        stInput.maxLength = 80;
        stInput.style.cssText = 'flex:1;font-size:0.85em;padding:7px 10px;';
        const stAddBtn = document.createElement('button');
        stAddBtn.className = 'house-save-btn';
        stAddBtn.style.background = 'linear-gradient(135deg,#22c55e,#16a34a)';
        stAddBtn.style.cssText += ';padding:7px 16px;font-size:0.88em;flex-shrink:0;';
        stAddBtn.textContent = '＋';
        const doAdd = () => { addGymSubtask(s.id, stInput.value); stInput.value = ''; };
        stAddBtn.onclick = e => { e.stopPropagation(); doAdd(); };
        stInput.addEventListener('keydown', e => { if (e.key === 'Enter') { e.preventDefault(); doAdd(); } });
        addRow.appendChild(stInput); addRow.appendChild(stAddBtn);
        planBody.appendChild(addRow);

        // expand toggle logic — persisted across re-renders
        planBody.style.display = _gymExpanded[s.id] ? 'block' : 'none';
        expandBtn.textContent = _gymExpanded[s.id] ? '▴' : '▾';
        const toggleExpand = () => {
            _gymExpanded[s.id] = !_gymExpanded[s.id];
            planBody.style.display = _gymExpanded[s.id] ? 'block' : 'none';
            expandBtn.textContent = _gymExpanded[s.id] ? '▴' : '▾';
        };
        head.onclick = toggleExpand;
        expandBtn.onclick = e => { e.stopPropagation(); toggleExpand(); };

        wrap.appendChild(head); wrap.appendChild(planBody);
        list.appendChild(wrap);
    });
    updateGymStats();
}

// ── SAVE SESSION
function saveGymSession(){
    const name = (document.getElementById('gs-name')?.value || '').trim();
    if (!name) { document.getElementById('gs-name')?.focus(); return; }
    const emoji = (document.getElementById('gs-emoji')?.value || '').trim() || '💪';
    gym123Data.sessions.push({ id:'s'+Date.now(), emoji, name, subtasks:[], weekDone:false });
    saveGym123Data();
    ['gs-emoji','gs-name'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideGymForm('session'); renderGymSessions(); updateGymStats();
}

// ── SUBTASKS
function addGymSubtask(sessionId, text) {
    text = (text || '').trim();
    if (!text) return;
    const s = gym123Data.sessions.find(s => s.id === sessionId);
    if (!s) return;
    if (!s.subtasks) s.subtasks = [];
    s.subtasks.push({ id: 'st' + Date.now() + Math.random().toString(36).slice(2), text, done: false });
    saveGym123Data(); renderGymSessions();
}

function toggleGymSubtask(sessionId, subtaskId) {
    const s = gym123Data.sessions.find(s => s.id === sessionId);
    if (!s || !s.subtasks) return;
    const st = s.subtasks.find(st => st.id === subtaskId);
    if (!st) return;
    st.done = !st.done;
    if (s.subtasks.length > 0) s.weekDone = s.subtasks.every(x => x.done);
    saveGym123Data(); renderGymSessions(); updateGymStats();
}

function removeGymSubtask(sessionId, subtaskId) {
    const s = gym123Data.sessions.find(s => s.id === sessionId);
    if (!s || !s.subtasks) return;
    s.subtasks = s.subtasks.filter(st => st.id !== subtaskId);
    saveGym123Data(); renderGymSessions();
}

function moveGymSubtask(sessionId, subtaskId, dir) {
    const s = gym123Data.sessions.find(s => s.id === sessionId);
    if (!s || !s.subtasks) return;
    const idx = s.subtasks.findIndex(st => st.id === subtaskId);
    const newIdx = idx + dir;
    if (newIdx < 0 || newIdx >= s.subtasks.length) return;
    [s.subtasks[idx], s.subtasks[newIdx]] = [s.subtasks[newIdx], s.subtasks[idx]];
    saveGym123Data(); renderGymSessions();
}

// ── RESET WEEK
function resetGymWeek(){
    showConfirm({ title: 'Reset week?', message: 'Clear all session check-marks for this week?', confirmLabel: 'Reset', onConfirm: _doResetGymWeek });
}
function _doResetGymWeek(){
    const done = gym123Data.sessions.filter(s => s.weekDone).length;
    const goal = gym123Data.weeklyGoal ?? 3;
    const sd   = gym123Data.weekStreakData || { lastWeek:'', streak:0 };
    const currentWeek = _gymCurrentWeekKey();

    if (done >= goal) {
        // Met goal this week — increment streak (only once per week)
        if (sd.lastWeek !== currentWeek) {
            sd.streak = (sd.streak || 0) + 1;
            sd.lastWeek = currentWeek;
        }
        toast('🔥 Streak: ' + sd.streak + ' week' + (sd.streak === 1 ? '' : 's') + '! Keep it up!');
    } else {
        // Missed goal — break streak
        if (sd.streak > 0) {
            sd.streak = 0;
            sd.lastWeek = '';
            toast('💔 Streak reset — missed the weekly goal (' + done + '/' + goal + ')');
        } else {
            toast('🔄 Week reset');
        }
    }

    gym123Data.weekStreakData = sd;
    gym123Data.sessions.forEach(s => s.weekDone = false);
    saveGym123Data(); renderGymSessions(); updateGymStats();
}

// ── STATS
function _gymCurrentWeekKey(){
    // ISO week, Monday-based: "2026-W13"
    const d = new Date();
    const day = d.getDay() || 7; // Mon=1 … Sun=7
    d.setDate(d.getDate() + 4 - day); // shift to Thursday of this week
    const yearStart = new Date(d.getFullYear(), 0, 1);
    const week = Math.ceil(((d - yearStart) / 86400000 + 1) / 7);
    return d.getFullYear() + '-W' + String(week).padStart(2, '0');
}

function updateGymStats(){
    const g = id => document.getElementById(id);
    const done  = gym123Data.sessions.filter(s => s.weekDone).length;
    const goal  = gym123Data.weeklyGoal ?? 3;

    // Auto-increment streak as soon as goal is met, once per week
    if (done >= goal) {
        const sd = gym123Data.weekStreakData || { lastWeek:'', streak:0 };
        const currentWeek = _gymCurrentWeekKey();
        if (sd.lastWeek !== currentWeek) {
            sd.streak = (sd.streak || 0) + 1;
            sd.lastWeek = currentWeek;
            gym123Data.weekStreakData = sd;
            saveGym123Data();
            toast('🔥 Weekly goal hit! Streak: ' + sd.streak + ' week' + (sd.streak === 1 ? '' : 's') + '!');
        }
    }

    if (g('gym-stat-week'))   g('gym-stat-week').textContent   = done + '/' + goal;
    if (g('gym-stat-streak')) g('gym-stat-streak').textContent = _gymCalcStreak();
    if (g('gym-stat-total'))  g('gym-stat-total').textContent  = gym123Data.sessions.length;
}

function _gymCalcStreak(){
    try { return (gym123Data.weekStreakData && gym123Data.weekStreakData.streak) || 0; } catch(e) { return 0; }
}

// ── QUICK TASK
function gymPushSession(s) {
    if (!gTasksAll['gym-1-2-3']) gTasksAll['gym-1-2-3'] = [];
    // Don't add if already present and not done
    if (gTasksAll['gym-1-2-3'].some(t => t.groupRef && t.groupRef.sessionId === s.id && !t.done)) {
        toast('Session already in tasks'); return;
    }
    const subtasks = (s.subtasks || []).map(st => ({ id: st.id, text: st.text, done: !!st.done }));
    gTasksAll['gym-1-2-3'].push({
        id: Date.now() + Math.random(),
        emoji: s.emoji || '💪',
        text: s.name || 'Session',
        notes: '',
        done: false,
        subtasks: subtasks.length ? subtasks : null,
        accentColor: '#22c55e',
        groupRef: { sessionId: s.id, isGym: true }
    });
    saveGTasksAll();
    renderGTasks('gym-1-2-3');
    try { ['r1','r2','r3'].forEach(slot => { if(rSlots&&rSlots[slot]==='gym-1-2-3') renderRTasks(slot); }); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e) {}
    toast('📌 Session added with ' + (subtasks.length || 0) + ' exercises');
}


function _setGymSessionSubDone(groupRef, subIdx, done) {
    if (!groupRef || !groupRef.sessionId) return;
    const s = gym123Data.sessions.find(s => s.id === groupRef.sessionId);
    if (!s || !s.subtasks) return;
    // Try matching by id first (subtasks were copied with original ids)
    const gTask = (gTasksAll['gym-1-2-3'] || []).find(t => t.groupRef && t.groupRef.sessionId === groupRef.sessionId);
    const subtaskId = gTask && gTask.subtasks && gTask.subtasks[subIdx] ? gTask.subtasks[subIdx].id : null;
    const st = subtaskId ? s.subtasks.find(x => x.id === subtaskId) : s.subtasks[subIdx];
    if (st) {
        st.done = done;
        if (s.subtasks.length > 0) s.weekDone = s.subtasks.every(x => x.done);
        saveGym123Data();
        renderGymSessions(); updateGymStats();
    }
}

function _syncGymSessionSubToTask(sessionId, subtaskId, done) {
    const arr = gTasksAll['gym-1-2-3'] || [];
    let changed = false;
    arr.forEach(t => {
        if (!t.groupRef || t.groupRef.sessionId !== sessionId || !t.subtasks) return;
        const sub = t.subtasks.find(s => s.id === subtaskId);
        if (sub) { sub.done = done; t.done = t.subtasks.every(s => s.done); changed = true; }
    });
    if (changed) {
        saveGTasksAll();
        renderGTasks('gym-1-2-3');
        // Also update schedule block tasks with this session
        schedBlocks.forEach(block => {
            block.tasks.forEach(task => {
                const m = String(task.id||'').match(/^gtask-gym-1-2-3-(.+)$/);
                if (!m) return;
                const gTask = (gTasksAll['gym-1-2-3']||[]).find(t => String(t.id) === m[1]);
                if (!gTask) return;
                if (gTask.subtasks) task.subtasks = gTask.subtasks.map(s=>({id:s.id,text:s.text,done:s.done}));
                task.done = gTask.done;
            });
        });
        saveSchedBlocks();
        renderSchedule();
    }
}

function _syncGymSubtaskText(sessionId, subtaskId, newText) {
    // Sync text to gTasksAll
    const arr = gTasksAll['gym-1-2-3'] || [];
    arr.forEach(t => {
        if (!t.groupRef || t.groupRef.sessionId !== sessionId || !t.subtasks) return;
        const sub = t.subtasks.find(s => s.id === subtaskId);
        if (sub) sub.text = newText;
    });
    saveGTasksAll();
    renderGTasks('gym-1-2-3');
    // Sync to schedule blocks
    schedBlocks.forEach(block => {
        block.tasks.forEach(task => {
            const m = String(task.id||'').match(/^gtask-gym-1-2-3-(.+)$/);
            if (!m) return;
            const gTask = (gTasksAll['gym-1-2-3']||[]).find(t => String(t.id) === m[1]);
            if (!gTask || !gTask.subtasks) return;
            if (gTask.subtasks) task.subtasks = gTask.subtasks.map(s=>({id:s.id,text:s.text,done:s.done}));
        });
    });
    saveSchedBlocks();
    renderSchedule();
    try { ['r1','r2','r3'].forEach(slot => { if(rSlots&&rSlots[slot]==='gym-1-2-3') renderRTasks(slot); }); } catch(e) {}
}

function gymQuickTask(emoji, title, desc){
    if (!gTasksAll['gym-1-2-3']) gTasksAll['gym-1-2-3'] = [];
    const already = gTasksAll['gym-1-2-3'].find(t => (t.text === title || t.title === title) && !t.done);
    if (already) { toast('Task already exists'); return; }
    gTasksAll['gym-1-2-3'].push({ id: 'gqt_' + Date.now(), emoji, text: title, notes: desc || '', done: false, accentColor: '#22c55e' });
    saveGTasksAll(); renderGymTasks();
    toast('📌 Task added');
}

// ── LOG escape helper (kept for potential legacy data safety)
function gymEsc(s) {
    try { return (typeof escHtml==='function') ? escHtml(String(s)) : String(s).replace(/[&<>"']/g, c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
    catch(e){ return String(s); }
}

// ── TASKS
function ensureGymTaskDefaults(){
    if (gym123Data._seeded) return;
    if (!gym123Data.tasks.length) gym123Data.tasks = [{ id:'gym_session', emoji:'🏋️', title:'Gym Session', desc:'Train + log the session.' }];
    gym123Data._seeded = true; saveGym123Data();
}

function renderGymTasks(){
    renderGTasks('gym-1-2-3');
    try { ['r1','r2','r3'].forEach(slot => { if(rSlots&&rSlots[slot]==='gym-1-2-3') renderRTasks(slot); }); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e) {}
}

function gymAddTask() { showGTask('gym-1-2-3'); }

function saveGymTask(){ hideGymForm('task'); showGTask('gym-1-2-3'); }
function removeGymTask() { renderGymTasks(); }

function initGymSection(){
    if (!document.getElementById('fitness-panel-gym')) return;
    // One-time migration from gym123Data.tasks → gTasksAll['gym-1-2-3']
    if ((gym123Data.tasks || []).length) {
        if (!(gTasksAll['gym-1-2-3'] || []).length) {
            gTasksAll['gym-1-2-3'] = gym123Data.tasks.map(t => ({
                id: t.id || ('gqt_' + Date.now() + '_' + Math.random()),
                emoji: t.emoji || '',
                text: t.title || t.text || '',
                notes: t.desc || '',
                done: !!t.done,
                accentColor: '#22c55e'
            }));
            saveGTasksAll();
        }
        gym123Data.tasks = []; saveGym123Data();
    }
    renderGymGoalRow();
    renderGymSessions();
    renderGymTasks();
    updateGymStats();
}



// ════════════════════════════════════════════════════════
//  GENERAL DOCTOR MODULE (Appointments + Checklist + Notes + Tasks)
// ════════════════════════════════════════════════════════

let __gdFirstLoad = false;
// ════════════════════════════════════════════════════════
//  GENERAL DOCTOR MODULE — v2
//  (Appointments + Habits + Meds + Health Log + Tasks)
// ════════════════════════════════════════════════════════

let generalDoctorData = {};
try {
    const raw = localStorage.getItem('generalDoctorData');
    __gdFirstLoad = (raw === null);
    generalDoctorData = JSON.parse(raw || '{}') || {};
} catch(e) {
    __gdFirstLoad = true;
    generalDoctorData = {};
}

// ── data shape guards
ensureArrays(generalDoctorData, 'appts', 'habits', 'meds', 'log', 'tasks');
// migrate old checklist → habits
if (!generalDoctorData.habits.length && Array.isArray(generalDoctorData.checklist) && generalDoctorData.checklist.length) {
    generalDoctorData.habits = generalDoctorData.checklist.map(c => ({ key: c.key||('h'+Math.random()), emoji:'✅', label: c.label, done: c.done||false }));
}
if (!generalDoctorData._seeded) generalDoctorData._seeded = false;

// ── seed defaults once
if (!generalDoctorData.habits.length && !generalDoctorData._seeded) {
    generalDoctorData.habits = [
        { key:'water',    emoji:'💧', label:'Hydration target hit',                done:false },
        { key:'sleep',    emoji:'😴', label:'Sleep consistency (same bedtime)',     done:false },
        { key:'symptoms', emoji:'📋', label:'Log any symptoms / pain',             done:false },
        { key:'followup', emoji:'🔄', label:'Check pending results / referrals',   done:false },
        { key:'steps',    emoji:'🚶', label:'Light movement / walk',               done:false },
    ];
}
if (!generalDoctorData.tasks.length && !generalDoctorData._seeded) {
    generalDoctorData.tasks = [
        { id:'gd_checkup', emoji:'🩺', title:'Book check-up', desc:'Call / online booking (date + clinic).' },
    ];
}
generalDoctorData._seeded = true;

const saveGeneralDoctorData = () => saveData('generalDoctorData', generalDoctorData);
saveGeneralDoctorData();

// ── form helpers
function showGDForm(kind){
    const el = document.getElementById('gd-form-' + kind);
    if (!el) return;
    el.classList.add('visible');
    const f = el.querySelector('input,textarea,select');
    if (f) setTimeout(() => f.focus(), 60);
}
function hideGDForm(kind){
    const el = document.getElementById('gd-form-' + kind);
    if (el) el.classList.remove('visible');
}

// ── STATS
function updateGDStats(){
    const g = id => document.getElementById(id);
    if (g('gd-stat-appts'))  g('gd-stat-appts').textContent  = generalDoctorData.appts.length;
    const hDone  = generalDoctorData.habits.filter(h => h.done).length;
    const hTotal = generalDoctorData.habits.length;
    const hPct   = hTotal ? Math.round((hDone/hTotal)*100) : 0;
    if (g('gd-stat-health')) g('gd-stat-health').textContent = hPct + '%';
    if (g('gd-stat-meds'))   g('gd-stat-meds').textContent   = generalDoctorData.meds.length;
    if (g('gd-stat-notes'))  g('gd-stat-notes').textContent  = generalDoctorData.log.length;
}

// ── APPOINTMENT TYPE MAP
const GD_APPT_TYPE = {
    checkup:    { emoji:'🩺', label:'Check-up',    color:'#38bdf8' },
    blood:      { emoji:'🧪', label:'Blood test',  color:'#f87171' },
    specialist: { emoji:'📋', label:'Specialist',  color:'#a78bfa' },
    followup:   { emoji:'🔄', label:'Follow-up',   color:'#34d399' },
    other:      { emoji:'⚙️', label:'Other',       color:'#94a3b8' },
};

// ── APPOINTMENTS
function renderGDAppts(){
    const list = document.getElementById('gd-appt-list');
    if (!list) return;
    list.innerHTML = '';
    if (!generalDoctorData.appts.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No appointments yet — add your next one.</div>';
        updateGDStats(); return;
    }
    generalDoctorData.appts.forEach((a, i) => {
        const t = GD_APPT_TYPE[a.type] || GD_APPT_TYPE.other;
        const row = document.createElement('div');
        row.style.cssText = `display:flex;align-items:flex-start;gap:10px;padding:12px 14px;border-radius:13px;background:rgba(56,189,248,0.05);border:1px solid rgba(56,189,248,0.15);`;

        const icon = document.createElement('div');
        icon.className = 'icon-xl';
        icon.textContent = t.emoji;

        const body = document.createElement('div');
        body.className = 'flex-1';

        const topRow = document.createElement('div');
        topRow.className = 'd-row-7w';

        const typeTag = document.createElement('span');
        typeTag.style.cssText = colorTag(t.color) + ';white-space:nowrap';
        typeTag.textContent = t.label;
        topRow.appendChild(typeTag);

        if (a.when) {
            const whenBadge = document.createElement('span');
            whenBadge.style.cssText = 'font-size:0.7em;font-weight:800;padding:2px 7px;border-radius:99px;background:rgba(56,189,248,0.1);color:#38bdf8;border:1px solid rgba(56,189,248,0.2);white-space:nowrap;';
            whenBadge.textContent = '📅 ' + a.when;
            topRow.appendChild(whenBadge);
        }
        if (a.where) {
            const whereEl = document.createElement('span');
            whereEl.className = 'item-label';
            whereEl.textContent = a.where;
            topRow.appendChild(whereEl);
        }
        body.appendChild(topRow);

        if (a.notes) {
            const notesEl = document.createElement('div');
            notesEl.className = 'text-muted';
            notesEl.textContent = a.notes;
            body.appendChild(notesEl);
        }

        const right = document.createElement('div');
        right.className = 'd-flex-gs0';

        const pushBtn = document.createElement('button');
        pushBtn.title = 'Push to tasks';
        pushBtn.className = 'pill pill-b';
        pushBtn.textContent = '📋';
        pushBtn.onclick = e => { e.stopPropagation(); gdQuickTask(t.emoji, (a.where||t.label) + (a.when ? ' — ' + a.when : ''), a.notes||''); };

        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️'; delBtn.title = 'Remove';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove appointment?', message: 'Delete this appointment? This cannot be undone.', confirmLabel: 'Remove', onConfirm: () => { generalDoctorData.appts.splice(i,1); saveGeneralDoctorData(); renderGDAppts(); } }); };

        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateGDStats();
}

function saveGDAppt(){
    const type  = document.getElementById('gd-appt-type')?.value || 'other';
    const date  = (document.getElementById('gd-appt-date')?.value  || '').trim();
    const time  = (document.getElementById('gd-appt-time')?.value  || '').trim();
    const when  = [date, time].filter(Boolean).join(' ');
    const where = (document.getElementById('gd-appt-where')?.value || '').trim();
    const notes = (document.getElementById('gd-appt-notes')?.value || '').trim();
    if (!date && !where) { document.getElementById('gd-appt-date')?.focus(); return; }
    generalDoctorData.appts.push({ id:'a'+Date.now(), type, when, date, time, where, notes });
    saveGeneralDoctorData();
    ['gd-appt-date','gd-appt-time','gd-appt-where','gd-appt-notes'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideGDForm('appt'); renderGDAppts();
}

// ── HEALTH HABITS
function renderGDHabits(){
    const list = document.getElementById('gd-health-list');
    if (!list) return;
    list.innerHTML = '';
    const total = generalDoctorData.habits.length;
    const done  = generalDoctorData.habits.filter(h => h.done).length;
    const pct   = total ? Math.round((done/total)*100) : 0;
    const bar   = document.getElementById('gd-health-bar');   if (bar)   bar.style.width   = pct + '%';
    const pctEl = document.getElementById('gd-health-pct');   if (pctEl) pctEl.textContent = pct + '%';

    generalDoctorData.habits.forEach((h, i) => {
        const row = document.createElement('div');
        row.className = `ir ${h.done ? 'ir-g' : ''}`;

        const emojiEl = document.createElement('div');
        emojiEl.className = 'icon-26';
        emojiEl.textContent = h.emoji || '✅';

        const cb = document.createElement('div');
        cb.style.cssText = chk('#34d399',h.done);
        cb.textContent = h.done ? '✓' : '';

        const labelEl = document.createElement('div');
        labelEl.className = `done-label done-g ${h.done ? 'done' : ''}`;
        labelEl.textContent = h.label;

        const toggle = () => { generalDoctorData.habits[i].done = !h.done; saveGeneralDoctorData(); renderGDHabits(); updateGDStats(); };
        [row, cb, labelEl].forEach(el => el.onclick = toggle);

        const pushBtn = document.createElement('button');
        pushBtn.className = 'pill pill-g';
        pushBtn.textContent = '📋'; pushBtn.title = 'Push to tasks';
        pushBtn.onclick = e => { e.stopPropagation(); gdQuickTask(h.emoji||'✅', h.label, 'Daily health habit'); };

        const delBtn = document.createElement('button');
        delBtn.className = 'mini-btn';
        delBtn.textContent = '✕';
        delBtn.onmouseover = () => { delBtn.style.color='#f87171'; delBtn.style.borderColor='rgba(248,113,113,0.3)'; };
        delBtn.onmouseout  = () => { delBtn.style.color='#475569'; delBtn.style.borderColor='rgba(255,255,255,0.07)'; };
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove habit?', message: 'Delete this health habit?', confirmLabel: 'Remove', onConfirm: () => { generalDoctorData.habits.splice(i,1); saveGeneralDoctorData(); renderGDHabits(); updateGDStats(); } }); };

        row.appendChild(emojiEl); row.appendChild(cb); row.appendChild(labelEl); row.appendChild(pushBtn); row.appendChild(delBtn);
        list.appendChild(row);
    });
    updateGDStats();
}

function saveGDHabit(){
    const emoji = (document.getElementById('gdh-emoji')?.value || '').trim() || '✅';
    const label = (document.getElementById('gdh-label')?.value || '').trim();
    if (!label) { document.getElementById('gdh-label')?.focus(); return; }
    generalDoctorData.habits.push({ key:'h'+Date.now(), emoji, label, done:false });
    saveGeneralDoctorData();
    ['gdh-emoji','gdh-label'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideGDForm('habit'); renderGDHabits(); updateGDStats();
}

function resetGDHabits(){
    generalDoctorData.habits.forEach(h => h.done = false);
    saveGeneralDoctorData(); renderGDHabits(); updateGDStats();
    toast('🔄 Habits reset');
}

// ── MEDICATIONS
function renderGDMeds(){
    const list = document.getElementById('gd-meds-list');
    if (!list) return;
    list.innerHTML = '';
    if (!generalDoctorData.meds.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No medications added yet.</div>';
        updateGDStats(); return;
    }
    generalDoctorData.meds.forEach((m, i) => {
        const row = document.createElement('div');
        row.className = `ir ${m.taken ? 'ir-y' : ''}`;

        const emojiEl = document.createElement('div');
        emojiEl.className = 'icon-26';
        emojiEl.textContent = m.emoji || '💊';

        const cb = document.createElement('div');
        cb.style.cssText = chk('#fbbf24',m.taken);
        cb.textContent = m.taken ? '✓' : '';

        const body = document.createElement('div');
        body.className = 'flex-1';
        const nameEl = document.createElement('div');
        nameEl.style.cssText = `font-size:0.87em;font-weight:${m.taken?700:600};color:${m.taken?'#fbbf24':'#cbd5e1'};text-decoration:${m.taken?'line-through':'none'};`;
        nameEl.textContent = m.name;
        body.appendChild(nameEl);
        if (m.freq) {
            const freqEl = document.createElement('div');
            freqEl.style.cssText = 'margin-top:3px;';
            freqEl.innerHTML = `<span style="font-size:0.68em;font-weight:800;padding:2px 7px;border-radius:99px;background:rgba(251,191,36,0.1);color:#fbbf24;border:1px solid rgba(251,191,36,0.2);text-transform:uppercase;letter-spacing:0.6px;">${m.freq}</span>`;
            body.appendChild(freqEl);
        }

        const toggle = () => { generalDoctorData.meds[i].taken = !m.taken; saveGeneralDoctorData(); renderGDMeds(); };
        [row, cb, body].forEach(el => el.onclick = toggle);

        const delBtn = document.createElement('button');
        delBtn.className = 'mini-btn';
        delBtn.textContent = '✕';
        delBtn.onmouseover = () => { delBtn.style.color='#f87171'; delBtn.style.borderColor='rgba(248,113,113,0.3)'; };
        delBtn.onmouseout  = () => { delBtn.style.color='#475569'; delBtn.style.borderColor='rgba(255,255,255,0.07)'; };
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove medication?', message: 'Delete this medication?', confirmLabel: 'Remove', onConfirm: () => { generalDoctorData.meds.splice(i,1); saveGeneralDoctorData(); renderGDMeds(); updateGDStats(); } }); };

        row.appendChild(emojiEl); row.appendChild(cb); row.appendChild(body); row.appendChild(delBtn);
        list.appendChild(row);
    });
    updateGDStats();
}

function saveGDMed(){
    const emoji = (document.getElementById('gdm-emoji')?.value || '').trim() || '💊';
    const name  = (document.getElementById('gdm-name')?.value  || '').trim();
    const freq  = (document.getElementById('gdm-freq')?.value  || '').trim();
    if (!name) { document.getElementById('gdm-name')?.focus(); return; }
    generalDoctorData.meds.push({ key:'m'+Date.now(), emoji, name, freq, taken:false });
    saveGeneralDoctorData();
    ['gdm-emoji','gdm-name','gdm-freq'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideGDForm('med'); renderGDMeds(); updateGDStats();
}

function resetGDMeds(){
    generalDoctorData.meds.forEach(m => m.taken = false);
    saveGeneralDoctorData(); renderGDMeds();
    toast('🔄 Meds reset');
}

// ── HEALTH LOG
const GD_LOG_TYPE = {
    symptom:  { emoji:'🤒', label:'Symptom',   color:'#f87171' },
    result:   { emoji:'🧪', label:'Result',     color:'#34d399' },
    question: { emoji:'❓', label:'Question',   color:'#38bdf8' },
    measure:  { emoji:'📏', label:'Measure',    color:'#a78bfa' },
    note:     { emoji:'📝', label:'Note',       color:'#94a3b8' },
};

function renderGDLog(){
    const list = document.getElementById('gd-log-list');
    if (!list) return;
    list.innerHTML = '';
    if (!generalDoctorData.log.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No entries yet. Log symptoms, results, or questions for your next visit.</div>';
        updateGDStats(); return;
    }
    [...generalDoctorData.log].reverse().forEach((e, revIdx) => {
        const realIdx = generalDoctorData.log.length - 1 - revIdx;
        const t = GD_LOG_TYPE[e.type] || GD_LOG_TYPE.note;
        const row = document.createElement('div');
        row.className = 'card-p';

        const icon = document.createElement('div');
        icon.className = 'icon-lg';
        icon.textContent = t.emoji;

        const body = document.createElement('div');
        body.className = 'flex-1';

        const topRow = document.createElement('div');
        topRow.className = 'd-row-7w';

        const typeTag = document.createElement('span');
        typeTag.style.cssText = colorTag(t.color);
        typeTag.textContent = t.label;
        topRow.appendChild(typeTag);

        if (e.date) {
            const dateBadge = document.createElement('span');
            dateBadge.className = 'meta-dim';
            dateBadge.textContent = '📅 ' + e.date;
            topRow.appendChild(dateBadge);
        }
        body.appendChild(topRow);

        if (e.text) {
            const textEl = document.createElement('div');
            textEl.className = 'note-text';
            textEl.textContent = e.text;
            body.appendChild(textEl);
        }

        const right = document.createElement('div');
        right.className = 'd-flex-gs0';

        const pushBtn = document.createElement('button');
        pushBtn.title = 'Push to tasks';
        pushBtn.className = 'pill pill-p';
        pushBtn.textContent = '📋';
        pushBtn.onclick = ev => { ev.stopPropagation(); gdQuickTask(t.emoji, t.label + (e.date?' — '+e.date:''), e.text?.slice(0,40)||''); };

        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️'; delBtn.title = 'Remove';
        delBtn.onclick = ev => { ev.stopPropagation(); showConfirm({ title: 'Remove log entry?', message: 'Delete this log entry?', confirmLabel: 'Remove', onConfirm: () => { generalDoctorData.log.splice(realIdx,1); saveGeneralDoctorData(); renderGDLog(); updateGDStats(); } }); };

        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateGDStats();
}

function saveGDLog(){
    const type = document.getElementById('gdl-type')?.value || 'note';
    const date = (document.getElementById('gdl-date')?.value || '').trim();
    const text = (document.getElementById('gdl-text')?.value || '').trim();
    if (!text) { document.getElementById('gdl-text')?.focus(); return; }
    generalDoctorData.log.push({ id:'l'+Date.now(), type, date, text });
    saveGeneralDoctorData();
    ['gdl-date','gdl-text'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideGDForm('log'); renderGDLog(); updateGDStats();
}

// ── QUICK TASK
function gdQuickTask(emoji, title, desc){
    if (!gTasksAll['general-doctor']) gTasksAll['general-doctor'] = [];
    const already = gTasksAll['general-doctor'].find(t => (t.text === title || t.title === title) && !t.done);
    if (already) { toast('Task already exists'); return; }
    gTasksAll['general-doctor'].push({ id: 'gdqt_' + Date.now(), emoji, text: title, notes: desc || '', done: false, accentColor: '#38bdf8' });
    saveGTasksAll(); renderGDTasks();
    toast('📌 Task added');
}

// ── TASKS
function renderGDTasks(){
    renderGTasks('general-doctor');
    try { ['r1','r2','r3'].forEach(slot => { if(rSlots&&(rSlots[slot]==='general-doctor'||rSlots[slot]==='health')) renderRTasks(slot); }); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e) {}
}

function saveGDTask(){ hideGDForm('task'); showGTask('general-doctor'); }
function removeGDTask() { renderGDTasks(); }

function initGeneralDoctorSection(){
    if (!document.getElementById('resp-section-general-doctor')) return;
    // One-time migration from generalDoctorData.tasks → gTasksAll['general-doctor']
    if ((generalDoctorData.tasks || []).length && !(gTasksAll['general-doctor'] || []).length) {
        gTasksAll['general-doctor'] = generalDoctorData.tasks.map(t => ({
            id: t.id || ('gdqt_' + Date.now() + '_' + Math.random()),
            emoji: t.emoji || '',
            text: t.title || t.text || '',
            notes: t.desc || '',
            done: !!t.done,
            accentColor: '#38bdf8'
        }));
        saveGTasksAll();
    }
    renderGDAppts();
    renderGDHabits();
    renderGDMeds();
    renderGDLog();
    renderGDTasks();
    updateGDStats();
}


// ════════════════════════════════════════════════════════
// ════════════════════════════════════════════════════════
        //  RESPONSIBILITY MENU BADGES
        // ════════════════════════════════════════════════════════
        function updateRespMenuBadges() {
            const sources = {
                'house':          typeof houseData    !== 'undefined' ? houseData.tasks    : [],
                'lost':           typeof lostData     !== 'undefined' ? lostData.tasks     : [],
                'family':         typeof famData      !== 'undefined' ? famData.tasks      : [],
                'praxe':          typeof praxeData    !== 'undefined' ? praxeData.tasks    : [],
                'look':           typeof lookData     !== 'undefined' ? lookData.tasks     : [],
                'shopping':       typeof shoppingData !== 'undefined' ? shoppingData.tasks : [],
                'gym-1-2-3':      typeof gTasksAll    !== 'undefined' ? (gTasksAll['gym-1-2-3'] || []) : [],
                'martial-arts':   typeof gTasksAll    !== 'undefined' ? (gTasksAll['martial-arts'] || []) : [],
                'fitness':        typeof gTasksAll    !== 'undefined' ? [...(gTasksAll['gym-1-2-3']||[]), ...(gTasksAll['martial-arts']||[])] : [],
                'health':         [
                    ...(typeof generalDoctorData !== 'undefined' ? (generalDoctorData.tasks || []) : []),
                    ...(typeof dentistData       !== 'undefined' ? (dentistData.tasks       || []) : []),
                    ...(typeof ophthalmologistData !== 'undefined' ? (ophthalmologistData.tasks || []) : []),
                    ...(typeof dermData          !== 'undefined' ? (dermData.tasks          || []) : []),
                    ...(typeof psyData           !== 'undefined' ? (psyData.tasks           || []) : []),
                ],
                'guitar':         typeof guitarData   !== 'undefined' ? guitarData.tasks   : [],
                'saxophone':      typeof saxData      !== 'undefined' ? saxData.tasks      : [],
                'piano':          typeof pianoData    !== 'undefined' ? pianoData.tasks    : [],
                'ableton':        typeof abletonData  !== 'undefined' ? abletonData.tasks  : [],
                'streaming':      typeof streamingData!== 'undefined' ? streamingData.tasks: [],
                'invest':         typeof investData   !== 'undefined' ? investData.tasks   : [],
                'social-media':   typeof socialData   !== 'undefined' ? socialData.tasks   : [],
                'emulator':       typeof emuData      !== 'undefined' ? emuData.tasks      : [],
                'computer':       typeof pcData       !== 'undefined' ? pcData.tasks       : [],
                'phone':          typeof phoneData    !== 'undefined' ? phoneData.tasks     : [],
                'calendar':       typeof calData      !== 'undefined' ? calData.tasks      : [],
                'update-app':     [], // managed via gTasksAll, not uaData legacy
                'lenses':         typeof lensData     !== 'undefined' ? lensData.tasks     : [],
                'room':           typeof roomData     !== 'undefined' ? roomData.tasks      : [],
                'travel-list':    typeof travelData   !== 'undefined' ? travelData.tasks   : [],
            };
            Object.entries(sources).forEach(([sid, taskArr]) => {
                const el = document.getElementById('ribadge-' + sid);
                if (!el) return;
                const arr = taskArr || [];
                if (!arr.length) { el.style.display = 'none'; return; }
                let done = 0;
                arr.forEach(t => {
                    const k1 = 'resp-' + sid + '-' + t.id;
                    const k2 = 'gtask-' + sid + '-' + t.id;
                    if ((typeof tasks !== 'undefined' && (tasks[k1] || tasks[k2])) || t.done) done++;
                });
                const total = arr.length;
                el.textContent = done + '/' + total;
                el.style.display = '';
                el.className = 'resp-item-badge' + (done === total ? ' all-done' : done > 0 ? ' has-done' : '');
            });
        }

        //  TRAVEL LIST MODULE
// ════════════════════════════════════════════════════════

let travelData = loadData('travelData');

ensureArrays(travelData, 'destinations', 'packing', 'habits', 'log', 'tasks');
if (!travelData._seeded) travelData._seeded = false;

if (!travelData.packing.length && !travelData._seeded) {
    travelData.packing = [
        { key:'passport',  emoji:'🛂', label:'Passport / ID',                   done:false },
        { key:'adapter',   emoji:'🔌', label:'Travel adapter',                   done:false },
        { key:'chargers',  emoji:'🔋', label:'Phone & device chargers',          done:false },
        { key:'clothes',   emoji:'👕', label:'Clothes for all days + 1 extra',   done:false },
        { key:'toiletries',emoji:'🧴', label:'Toiletries bag',                   done:false },
        { key:'meds',      emoji:'💊', label:'Medications / first aid',          done:false },
        { key:'insurance', emoji:'📋', label:'Travel insurance / booking docs',  done:false },
        { key:'cash',      emoji:'💵', label:'Local currency / card',            done:false },
    ];
}
if (!travelData.habits.length && !travelData._seeded) {
    travelData.habits = [
        { key:'visa',    emoji:'📋', label:'Check visa requirements',          done:false },
        { key:'flights', emoji:'✈️', label:'Search and compare flights',       done:false },
        { key:'hotel',   emoji:'🏨', label:'Book accommodation',               done:false },
        { key:'budget',  emoji:'💰', label:'Set and review trip budget',       done:false },
        { key:'notify',  emoji:'📞', label:'Notify bank of travel dates',      done:false },
    ];
}
if (!travelData.tasks.length && !travelData._seeded) {
    travelData.tasks = [
        { id:'trv_plan', emoji:'✈️', title:'Start planning next trip', desc:'Pick a destination and research.' },
    ];
}
travelData._seeded = true;

const saveTravelData = () => saveData('travelData', travelData);
saveTravelData();

function showTRVForm(kind) {
    const el = document.getElementById('trv-form-' + kind);
    if (!el) return;
    el.classList.add('visible');
    const f = el.querySelector('input,textarea,select');
    if (f) setTimeout(() => f.focus(), 60);
}
function hideTRVForm(kind) {
    const el = document.getElementById('trv-form-' + kind);
    if (el) el.classList.remove('visible');
}

// ── STATS
function updateTRVStats() {
    const g = id => document.getElementById(id);
    if (g('trv-stat-dest')) g('trv-stat-dest').textContent = travelData.destinations.length;
    const pDone = travelData.packing.filter(p => p.done).length;
    const pPct  = travelData.packing.length ? Math.round((pDone/travelData.packing.length)*100) : 0;
    if (g('trv-stat-pack')) g('trv-stat-pack').textContent = pPct + '%';
    const hDone = travelData.habits.filter(h => h.done).length;
    const hPct  = travelData.habits.length ? Math.round((hDone/travelData.habits.length)*100) : 0;
    if (g('trv-stat-habits')) g('trv-stat-habits').textContent = hPct + '%';
    if (g('trv-stat-log'))    g('trv-stat-log').textContent    = travelData.log.length;
}

// ── DESTINATION STATUS MAP
const TRV_DEST_STATUS = {
    dream:   { emoji:'🌟', label:'Dream trip', color:'#22d3ee' },
    planned: { emoji:'📋', label:'Planned',    color:'#a78bfa' },
    booked:  { emoji:'✅', label:'Booked',     color:'#34d399' },
    done:    { emoji:'🏆', label:'Been there', color:'#fbbf24' },
};

// ── DESTINATIONS
function renderTRVDestinations() {
    const list = document.getElementById('trv-dest-list');
    if (!list) return;
    list.innerHTML = '';
    if (!travelData.destinations.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No destinations yet — add places you want to visit.</div>';
        updateTRVStats(); return;
    }
    travelData.destinations.forEach((d, i) => {
        const st = TRV_DEST_STATUS[d.type || 'dream'] || TRV_DEST_STATUS.dream;
        const row = document.createElement('div');
        row.style.cssText = irColorFs(st.color);

        const icon = document.createElement('div');
        icon.style.cssText = 'font-size:1.6em;flex-shrink:0;padding-top:1px;';
        icon.textContent = d.flag || '🌍';

        const body = document.createElement('div');
        body.className = 'flex-1';
        const nameEl = document.createElement('div');
        nameEl.style.cssText = 'font-size:0.92em;font-weight:800;color:#e2e8f0;margin-bottom:5px;';
        nameEl.textContent = d.name;
        body.appendChild(nameEl);

        const meta = document.createElement('div');
        meta.className='d-row-6-fc';
        const stBadge = document.createElement('span');
        stBadge.style.cssText = colorTagSm(st.color);
        stBadge.textContent = st.emoji + ' ' + st.label;
        meta.appendChild(stBadge);
        if (d.when) {
            const wb = document.createElement('span');
            wb.style.cssText = 'font-size:0.7em;font-weight:700;padding:2px 6px;border-radius:99px;background:rgba(34,211,238,0.1);color:#22d3ee;border:1px solid rgba(34,211,238,0.2);';
            wb.textContent = '📅 ' + d.when;
            meta.appendChild(wb);
        }
        if (d.budget) {
            const bb = document.createElement('span');
            bb.style.cssText = 'font-size:0.7em;font-weight:700;padding:2px 6px;border-radius:99px;background:rgba(52,211,153,0.1);color:#34d399;border:1px solid rgba(52,211,153,0.2);';
            bb.textContent = '💰 ' + d.budget;
            meta.appendChild(bb);
        }
        body.appendChild(meta);
        if (d.notes) {
            const ne = document.createElement('div');
            ne.style.cssText = 'color:#64748b;font-size:0.78em;margin-top:5px;line-height:1.4;';
            ne.textContent = d.notes;
            body.appendChild(ne);
        }

        const nextType = { dream:'planned', planned:'booked', booked:'done', done:'dream' };
        row.onclick = () => { travelData.destinations[i].type = nextType[d.type||'dream']; saveTravelData(); renderTRVDestinations(); updateTRVStats(); };

        const right = document.createElement('div');
        right.className = 'd-flex-gs0';
        const pushBtn = document.createElement('button');
        pushBtn.className='pill pill-c';
        pushBtn.textContent = '📋'; pushBtn.title = 'Push to tasks';
        pushBtn.onclick = e => { e.stopPropagation(); trvQuickTask(d.flag||'✈️', 'Plan trip to '+d.name, d.when||''); };
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title:'Remove destination', message:`Remove "<strong>${d.name}</strong>"?`, confirmLabel:'Remove', onConfirm(){ travelData.destinations.splice(i,1); saveTravelData(); renderTRVDestinations(); updateTRVStats(); } }); };
        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateTRVStats();
}

function saveTRVDest() {
    const flag   = (document.getElementById('trvd-flag')?.value   || '').trim() || '🌍';
    const name   = (document.getElementById('trvd-name')?.value   || '').trim();
    const type   = document.getElementById('trvd-type')?.value    || 'dream';
    const when   = (document.getElementById('trvd-when')?.value   || '').trim();
    const budget = (document.getElementById('trvd-budget')?.value || '').trim();
    const notes  = (document.getElementById('trvd-notes')?.value  || '').trim();
    if (!name) { document.getElementById('trvd-name')?.focus(); return; }
    travelData.destinations.push({ id:'d'+Date.now(), flag, name, type, when, budget, notes });
    saveTravelData();
    ['trvd-flag','trvd-name','trvd-when','trvd-budget','trvd-notes'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideTRVForm('dest'); renderTRVDestinations(); updateTRVStats();
}

// ── PACKING CHECKLIST
function renderTRVPacking() {
    const list = document.getElementById('trv-pack-list');
    if (!list) return;
    list.innerHTML = '';
    const total = travelData.packing.length;
    const done  = travelData.packing.filter(p => p.done).length;
    const pct   = total ? Math.round((done/total)*100) : 0;
    const bar   = document.getElementById('trv-pack-bar'); if (bar) bar.style.width = pct + '%';
    const pctEl = document.getElementById('trv-pack-pct'); if (pctEl) pctEl.textContent = pct + '%';
    travelData.packing.forEach((h, i) => {
        const row = document.createElement('div');
        row.className = `ir ${h.done ? 'ir-g' : ''}`;
        const emojiEl = document.createElement('div');
        emojiEl.className = 'icon-26';
        emojiEl.textContent = h.emoji || '🧳';
        const cb = document.createElement('div');
        cb.style.cssText = chk('#34d399',h.done);
        cb.textContent = h.done ? '✓' : '';
        const labelEl = document.createElement('div');
        labelEl.className = `done-label done-g ${h.done ? 'done' : ''}`;
        labelEl.textContent = h.label;
        const toggle = () => { travelData.packing[i].done = !h.done; saveTravelData(); renderTRVPacking(); updateTRVStats(); };
        [row, cb, labelEl].forEach(el => el.onclick = toggle);
        const delBtn = document.createElement('button');
        delBtn.className = 'mini-btn';
        delBtn.textContent = '✕';
        delBtn.onmouseover = () => { delBtn.style.color='#f87171'; delBtn.style.borderColor='rgba(248,113,113,0.3)'; };
        delBtn.onmouseout  = () => { delBtn.style.color='#475569'; delBtn.style.borderColor='rgba(255,255,255,0.07)'; };
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title:'Remove packing item', message:`Remove "<strong>${h.label}</strong>"?`, confirmLabel:'Remove', onConfirm(){ travelData.packing.splice(i,1); saveTravelData(); renderTRVPacking(); updateTRVStats(); } }); };
        row.appendChild(emojiEl); row.appendChild(cb); row.appendChild(labelEl); row.appendChild(delBtn);
        list.appendChild(row);
    });
    updateTRVStats();
}

function saveTRVPack() {
    const emoji = (document.getElementById('trvp-emoji')?.value || '').trim() || '🧳';
    const label = (document.getElementById('trvp-label')?.value || '').trim();
    if (!label) { document.getElementById('trvp-label')?.focus(); return; }
    travelData.packing.push({ key:'p'+Date.now(), emoji, label, done:false });
    saveTravelData();
    ['trvp-emoji','trvp-label'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideTRVForm('pack'); renderTRVPacking(); updateTRVStats();
}

function resetTRVPack() {
    travelData.packing.forEach(p => p.done = false);
    saveTravelData(); renderTRVPacking(); updateTRVStats();
    toast('🔄 Packing list reset');
}

// ── TRIP PREP HABITS
function renderTRVHabits() {
    const list = document.getElementById('trv-habits-list');
    if (!list) return;
    list.innerHTML = '';
    const total = travelData.habits.length;
    const done  = travelData.habits.filter(h => h.done).length;
    const pct   = total ? Math.round((done/total)*100) : 0;
    const bar   = document.getElementById('trv-habits-bar'); if (bar) bar.style.width = pct + '%';
    const pctEl = document.getElementById('trv-habits-pct'); if (pctEl) pctEl.textContent = pct + '%';
    travelData.habits.forEach((h, i) => {
        const row = document.createElement('div');
        row.className = `ir ${h.done ? 'ir-y8' : ''}`;
        const emojiEl = document.createElement('div');
        emojiEl.className = 'icon-26';
        emojiEl.textContent = h.emoji || '✈️';
        const cb = document.createElement('div');
        cb.style.cssText = chk('#fbbf24',h.done);
        cb.textContent = h.done ? '✓' : '';
        const labelEl = document.createElement('div');
        labelEl.className = `done-label done-y ${h.done ? 'done' : ''}`;
        labelEl.textContent = h.label;
        const toggle = () => { travelData.habits[i].done = !h.done; saveTravelData(); renderTRVHabits(); updateTRVStats(); };
        [row, cb, labelEl].forEach(el => el.onclick = toggle);
        const pushBtn = document.createElement('button');
        pushBtn.className = 'pill pill-y';
        pushBtn.textContent = '📋'; pushBtn.title = 'Push to tasks';
        pushBtn.onclick = e => { e.stopPropagation(); trvQuickTask(h.emoji||'✈️', h.label, 'Trip prep'); };
        const delBtn = document.createElement('button');
        delBtn.className = 'mini-btn';
        delBtn.textContent = '✕';
        delBtn.onmouseover = () => { delBtn.style.color='#f87171'; delBtn.style.borderColor='rgba(248,113,113,0.3)'; };
        delBtn.onmouseout  = () => { delBtn.style.color='#475569'; delBtn.style.borderColor='rgba(255,255,255,0.07)'; };
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title:'Remove prep habit', message:`Remove "<strong>${h.label}</strong>"?`, confirmLabel:'Remove', onConfirm(){ travelData.habits.splice(i,1); saveTravelData(); renderTRVHabits(); updateTRVStats(); } }); };
        row.appendChild(emojiEl); row.appendChild(cb); row.appendChild(labelEl); row.appendChild(pushBtn); row.appendChild(delBtn);
        list.appendChild(row);
    });
    updateTRVStats();
}

function saveTRVHabit() {
    const emoji = (document.getElementById('trvh-emoji')?.value || '').trim() || '✈️';
    const label = (document.getElementById('trvh-label')?.value || '').trim();
    if (!label) { document.getElementById('trvh-label')?.focus(); return; }
    travelData.habits.push({ key:'h'+Date.now(), emoji, label, done:false });
    saveTravelData();
    ['trvh-emoji','trvh-label'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideTRVForm('habit'); renderTRVHabits(); updateTRVStats();
}

function resetTRVHabits() {
    travelData.habits.forEach(h => h.done = false);
    saveTravelData(); renderTRVHabits(); updateTRVStats();
    toast('🔄 Prep habits reset');
}

// ── TRIP LOG
const TRV_LOG_TYPE = {
    memory:   { emoji:'📸', label:'Memory',      color:'#22d3ee' },
    tip:      { emoji:'💡', label:'Travel tip',  color:'#34d399' },
    research: { emoji:'🔍', label:'Research',    color:'#a78bfa' },
    budget:   { emoji:'💰', label:'Budget note', color:'#fbbf24' },
    issue:    { emoji:'⚠️', label:'Issue',        color:'#f87171' },
    note:     { emoji:'📝', label:'Note',         color:'#94a3b8' },
};

function renderTRVLog() {
    const list = document.getElementById('trv-log-list');
    if (!list) return;
    list.innerHTML = '';
    if (!travelData.log.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No entries yet. Log memories, tips, and research.</div>';
        updateTRVStats(); return;
    }
    [...travelData.log].reverse().forEach((e, revIdx) => {
        const realIdx = travelData.log.length - 1 - revIdx;
        const t = TRV_LOG_TYPE[e.type] || TRV_LOG_TYPE.note;
        const row = document.createElement('div');
        row.className = 'card-p';
        const icon = document.createElement('div');
        icon.className = 'icon-lg';
        icon.textContent = t.emoji;
        const body = document.createElement('div');
        body.className = 'flex-1';
        const topRow = document.createElement('div');
        topRow.className = 'd-row-7w';
        const typeTag = document.createElement('span');
        typeTag.style.cssText = colorTag(t.color);
        typeTag.textContent = t.label;
        topRow.appendChild(typeTag);
        if (e.dest) {
            const db = document.createElement('span');
            db.style.cssText = 'font-size:0.7em;font-weight:800;padding:2px 7px;border-radius:99px;background:rgba(34,211,238,0.1);color:#22d3ee;border:1px solid rgba(34,211,238,0.2);';
            db.textContent = '📍 ' + e.dest;
            topRow.appendChild(db);
        }
        body.appendChild(topRow);
        if (e.text) { const textEl = document.createElement('div'); textEl.className='note-text'; textEl.textContent=e.text; body.appendChild(textEl); }
        const right = document.createElement('div');
        right.className = 'd-flex-gs0';
        const pushBtn = document.createElement('button');
        pushBtn.title = 'Push to tasks';
        pushBtn.className='pill pill-c';
        pushBtn.textContent = '📋';
        pushBtn.onclick = ev => { ev.stopPropagation(); trvQuickTask(t.emoji, t.label+(e.dest?' — '+e.dest:''), e.text?.slice(0,40)||''); };
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️';
        delBtn.onclick = ev => { ev.stopPropagation(); showConfirm({ title:'Remove log entry', message:`Remove this <strong>${t.label}</strong> entry?`, confirmLabel:'Remove', onConfirm(){ travelData.log.splice(realIdx,1); saveTravelData(); renderTRVLog(); updateTRVStats(); } }); };
        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateTRVStats();
}

function saveTRVLog() {
    const type = document.getElementById('trvl-type')?.value || 'note';
    const dest = (document.getElementById('trvl-dest')?.value || '').trim();
    const text = (document.getElementById('trvl-text')?.value || '').trim();
    if (!text) { document.getElementById('trvl-text')?.focus(); return; }
    travelData.log.push({ id:'l'+Date.now(), type, dest, text });
    saveTravelData();
    ['trvl-dest','trvl-text'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideTRVForm('log'); renderTRVLog(); updateTRVStats();
}

// ── QUICK TASK
function trvQuickTask(emoji, title, desc) {
    if (!gTasksAll['travel-list']) gTasksAll['travel-list'] = [];
    const already = gTasksAll['travel-list'].find(t => (t.text === title || t.title === title) && !t.done);
    if (already) { toast('Task already exists'); return; }
    gTasksAll['travel-list'].push({ id: 'trvqt_' + Date.now(), emoji, text: title, notes: desc || '', done: false, accentColor: '#22d3ee' });
    saveGTasksAll(); renderTRVTasks();
    toast('📌 Task added');
}

// ── TASKS
function renderTRVTasks() {
    renderGTasks('travel-list');
    try { ['r1','r2','r3'].forEach(slot => { if(rSlots&&rSlots[slot]==='travel-list') renderRTasks(slot); }); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e) {}
}

function saveTRVTask() { showGTask('travel-list'); }

function removeTRVTask() { /* collapsed — tasks managed via renderGTasks */ }

function initTravelListSection() {
    if (!document.getElementById('resp-section-travel-list')) return;
    // One-time migration from travelData.tasks → gTasksAll['travel-list']
    if ((travelData.tasks || []).length && !(gTasksAll['travel-list'] || []).length) {
        gTasksAll['travel-list'] = travelData.tasks.map(t => ({
            id: t.id || ('trvqt_' + Date.now() + '_' + Math.random()),
            emoji: t.emoji || '',
            text: t.title || t.text || '',
            notes: t.desc || '',
            done: !!t.done,
            accentColor: '#22d3ee'
        }));
        saveGTasksAll();
    }
    renderTRVDestinations();
    renderTRVPacking();
    renderTRVHabits();
    renderTRVLog();
    renderTRVTasks();
    updateTRVStats();
}

