let roomData = loadData('roomData');

ensureArrays(roomData, 'cleaning', 'upgrades', 'items', 'log', 'tasks');
if (!roomData._seeded) roomData._seeded = false;

if (!roomData.cleaning.length && !roomData._seeded) {
    roomData.cleaning = [
        { key:'vacuum',  emoji:'🧹', label:'Vacuum / sweep floor',          done:false },
        { key:'desk',    emoji:'🖥️', label:'Clean and organise desk',        done:false },
        { key:'dust',    emoji:'🪟', label:'Dust surfaces and shelves',      done:false },
        { key:'laundry', emoji:'👕', label:'Do laundry / change bed sheets', done:false },
        { key:'trash',   emoji:'🗑️', label:'Empty trash',                    done:false },
        { key:'windows', emoji:'🪟', label:'Clean windows / mirrors',        done:false },
    ];
}
if (!roomData.tasks.length && !roomData._seeded) {
    roomData.tasks = [
        { id:'rm_clean', emoji:'🧹', title:'Weekly room clean', desc:'Go through full cleaning checklist.' },
    ];
}
roomData._seeded = true;

