// ── UPGRADE WISHLIST
const RM_PRIORITY = {
    high:   { emoji:'🔥', label:'High',   color:'#f87171' },
    medium: { emoji:'🟡', label:'Medium', color:'#fbbf24' },
    low:    { emoji:'🟢', label:'Low',    color:'#34d399' },
};
const RM_UPGRADE_STATUS = {
    want:   { emoji:'⭐', label:'Want',    color:'#fbbf24' },
    saving: { emoji:'💰', label:'Saving',  color:'#38bdf8' },
    done:   { emoji:'✅', label:'Done',   color:'#34d399' },
};

function renderRMUpgrades() {
    const list = document.getElementById('rm-upgrades-list');
    if (!list) return;
    list.innerHTML = '';
    if (!roomData.upgrades.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No upgrades yet — add things you want for your room.</div>';
        updateRMStats(); return;
    }
    roomData.upgrades.forEach((u, i) => {
        const pr = RM_PRIORITY[u.priority || 'medium'] || RM_PRIORITY.medium;
        const st = RM_UPGRADE_STATUS[u.status || 'want'] || RM_UPGRADE_STATUS.want;
        const row = document.createElement('div');
        row.style.cssText = irColor(st.color);
        const icon = document.createElement('div');
        icon.className = 'icon-26';
        icon.textContent = u.emoji || '⭐';
        const body = document.createElement('div');
        body.className = 'flex-1';
        const nameEl = document.createElement('div');
        nameEl.className = 'item-label';
        nameEl.textContent = u.name;
        body.appendChild(nameEl);
        const meta = document.createElement('div');
        meta.className = 'd-row-6w';
        const prBadge = document.createElement('span');
        prBadge.style.cssText = colorTagSm(pr.color);
        prBadge.textContent = pr.emoji + ' ' + pr.label;
        meta.appendChild(prBadge);
        const stBadge = document.createElement('span');
        stBadge.style.cssText = colorTagSm(st.color);
        stBadge.textContent = st.emoji + ' ' + st.label;
        meta.appendChild(stBadge);
        if (u.cost) { const cb = document.createElement('span'); cb.className='meta-xs'; cb.textContent='~'+u.cost; meta.appendChild(cb); }
        body.appendChild(meta);
        const nextStatus = { want:'saving', saving:'done', done:'want' };
        row.onclick = () => { roomData.upgrades[i].status = nextStatus[u.status||'want']; saveRoomData(); renderRMUpgrades(); updateRMStats(); };
        const right = document.createElement('div');
        right.className = 'd-flex-gs0';
        const pushBtn = document.createElement('button');
        pushBtn.className = 'pill pill-y';
        pushBtn.textContent = '📋'; pushBtn.title = 'Push to tasks';
        pushBtn.onclick = e => { e.stopPropagation(); rmQuickTask(u.emoji||'⭐', 'Buy: '+u.name, u.cost?'Est. '+u.cost:''); };
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title:'Remove upgrade', message:`Remove "<strong>${u.name}</strong>"?`, confirmLabel:'Remove', onConfirm(){ roomData.upgrades.splice(i,1); saveRoomData(); renderRMUpgrades(); updateRMStats(); } }); };
        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateRMStats();
}

function saveRMUpgrade() {
    const emoji    = (document.getElementById('rmu-emoji')?.value    || '').trim() || '⭐';
    const name     = (document.getElementById('rmu-name')?.value     || '').trim();
    const priority = document.getElementById('rmu-priority')?.value  || 'medium';
    const cost     = (document.getElementById('rmu-cost')?.value     || '').trim();
    if (!name) { document.getElementById('rmu-name')?.focus(); return; }
    roomData.upgrades.push({ id:'u'+Date.now(), emoji, name, priority, cost, status:'want' });
    saveRoomData();
    ['rmu-emoji','rmu-name','rmu-cost'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideRMForm('upgrade'); renderRMUpgrades(); updateRMStats();
}

