        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title:'Remove item', message:`Remove "<strong>${it.name}</strong>"?`, confirmLabel:'Remove', onConfirm(){ roomData.items.splice(i,1); saveRoomData(); renderRMItems(); updateRMStats(); } }); };
        right.appendChild(pushBtn); right.appendChild(delBtn);
