// ── LOG
const RM_LOG_TYPE = {
    change:  { emoji:'🔧', label:'Change made',  color:'#38bdf8' },
    fix:     { emoji:'✅', label:'Fixed',         color:'#34d399' },
    idea:    { emoji:'💡', label:'Idea',          color:'#fbbf24' },
    bought:  { emoji:'🛍️', label:'Bought',        color:'#a78bfa' },
    issue:   { emoji:'⚠️', label:'Issue',         color:'#f87171' },
    note:    { emoji:'📝', label:'Note',           color:'#94a3b8' },
};

function renderRMLog() {
    const list = document.getElementById('rm-log-list');
    if (!list) return;
    list.innerHTML = '';
    if (!roomData.log.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No entries yet. Log changes, fixes, and room ideas.</div>';
        updateRMStats(); return;
    }
    [...roomData.log].reverse().forEach((e, revIdx) => {
        const realIdx = roomData.log.length - 1 - revIdx;
        const t = RM_LOG_TYPE[e.type] || RM_LOG_TYPE.note;
        const row = document.createElement('div');
        row.className = 'card-p';
        const icon = document.createElement('div');
        icon.className = 'icon-lg';
        icon.textContent = t.emoji;
        const body = document.createElement('div');
        body.className = 'flex-1';
        const topRow = document.createElement('div');
        topRow.className = 'd-row-7w';
        const typeTag = document.createElement('span');
        typeTag.style.cssText = colorTag(t.color);
        typeTag.textContent = t.label;
        topRow.appendChild(typeTag);
        if (e.date) { const db = document.createElement('span'); db.className='meta-dim'; db.textContent='📅 '+e.date; topRow.appendChild(db); }
        body.appendChild(topRow);
        if (e.text) { const textEl = document.createElement('div'); textEl.className='note-text'; textEl.textContent=e.text; body.appendChild(textEl); }
        const right = document.createElement('div');
        right.className = 'd-flex-gs0';
        const pushBtn = document.createElement('button');
        pushBtn.title = 'Push to tasks';
        pushBtn.style.cssText = 'padding:5px 9px;border-radius:8px;border:1px solid rgba(251,113,133,0.3);background:rgba(251,113,133,0.07);color:#fb7185;font-size:0.72em;font-weight:700;cursor:pointer;';
        pushBtn.textContent = '📋';
        pushBtn.onclick = ev => { ev.stopPropagation(); rmQuickTask(t.emoji, t.label+(e.date?' — '+e.date:''), e.text?.slice(0,40)||''); };
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️';
        delBtn.onclick = ev => { ev.stopPropagation(); showConfirm({ title:'Remove log entry', message:`Remove this <strong>${t.label}</strong> entry?`, confirmLabel:'Remove', onConfirm(){ roomData.log.splice(realIdx,1); saveRoomData(); renderRMLog(); updateRMStats(); } }); };
        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateRMStats();
}

function saveRMLog() {
    const type = document.getElementById('rml-type')?.value || 'note';
    const date = (document.getElementById('rml-date')?.value || '').trim();
    const text = (document.getElementById('rml-text')?.value || '').trim();
    if (!text) { document.getElementById('rml-text')?.focus(); return; }
    roomData.log.push({ id:'l'+Date.now(), type, date, text });
    saveRoomData();
    ['rml-date','rml-text'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideRMForm('log'); renderRMLog(); updateRMStats();
}

// ── QUICK TASK
function rmQuickTask(emoji, title, desc) {
    if (!gTasksAll['room']) gTasksAll['room'] = [];
    const already = gTasksAll['room'].find(t => (t.text === title || t.title === title) && !t.done);
    if (already) { toast('Task already exists'); return; }
    gTasksAll['room'].push({ id: 'rmqt_' + Date.now(), emoji, text: title, notes: desc || '', done: false, accentColor: '#fb7185' });
    saveGTasksAll(); renderRMTasks();
    toast('📌 Task added');
}

// ── TASKS
function renderRMTasks() {
    renderGTasks('room');
    try { ['r1','r2','r3'].forEach(slot => { if(rSlots&&rSlots[slot]==='room') renderRTasks(slot); }); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e) {}
}

function saveRMTask() { showGTask('room'); }

function removeRMTask() { /* collapsed — tasks managed via renderGTasks */ }

function initRoomSection() {
    if (!document.getElementById('resp-section-room')) return;
    // One-time migration from roomData.tasks → gTasksAll['room']
    if ((roomData.tasks || []).length && !(gTasksAll['room'] || []).length) {
        gTasksAll['room'] = roomData.tasks.map(t => ({
            id: t.id || ('rmqt_' + Date.now() + '_' + Math.random()),
            emoji: t.emoji || '',
            text: t.title || t.text || '',
            notes: t.desc || '',
            done: !!t.done,
            accentColor: '#fb7185'
        }));
        saveGTasksAll();
    }
    renderRMCleaning();
    renderRMUpgrades();
    renderRMItems();
    renderRMLog();
    renderRMTasks();
    updateRMStats();
}

