        const titleInp = document.createElement('input');
        titleInp.type = 'text'; titleInp.value = f.title;
        titleInp.style.cssText = 'width:100%;padding:7px 10px;background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.1);border-radius:8px;color:#e2e8f0;font-size:0.84em;box-sizing:border-box;';
