function saveUAFeature() {
    const p = _projGet(); if (!p) return;
    const area     = document.getElementById('uaf-area')?.value     || 'feature';
    const priority = document.getElementById('uaf-priority')?.value || 'medium';
    const title    = (document.getElementById('uaf-title')?.value   || '').trim();
    if (!title) { document.getElementById('uaf-title')?.focus(); return; }
    if (!Array.isArray(p.features)) p.features = [];
    p.features.push({ id:'f'+Date.now(), area, priority, title, status:'idea' });
    saveProjectsData();
    document.getElementById('uaf-title').value = '';
    hideUAForm('feature'); renderUABacklog(); updateUAStats();
}

