        editBtn.textContent = '✏️'; editBtn.title = 'Edit bug';
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title:'Remove bug', message:`Remove "<strong>${b.desc.slice(0,60)}</strong>"?<br><span style="color:#94a3b8;font-size:0.85em;">Any linked task will also be removed.</span>`, confirmLabel:'Remove', onConfirm(){ const proj=_projGet(); if(!proj) return; proj.bugs.splice(i,1); saveProjectsData(); renderUABugs(); updateUAStats(); const lIdx=(gTasksAll['update-app']||[]).findIndex(t=>t.linkedType==='bug'&&t.linkedId===b.id); if(lIdx!==-1){gTasksAll['update-app'].splice(lIdx,1);saveGTasksAll();renderUATasks();} } }); };
        right.appendChild(pushBtn); right.appendChild(editBtn); right.appendChild(delBtn);
