function showPHForm(kind) {
    const el = document.getElementById('ph-form-' + kind);
    if (!el) return;
    el.classList.add('visible');
    const f = el.querySelector('input,textarea,select');
    if (f) setTimeout(() => f.focus(), 60);
}
function hidePHForm(kind) {
    const el = document.getElementById('ph-form-' + kind);
    if (el) el.classList.remove('visible');
}

// ── STATS
function updatePHStats() {
    const g = id => document.getElementById(id);
    if (g('ph-stat-apps'))  g('ph-stat-apps').textContent  = phoneData.apps.length;
    const mDone = phoneData.maint.filter(m => m.done).length;
    const mPct  = phoneData.maint.length ? Math.round((mDone/phoneData.maint.length)*100) : 0;
    if (g('ph-stat-maint')) g('ph-stat-maint').textContent = mPct + '%';
    if (g('ph-stat-info'))  g('ph-stat-info').textContent  = phoneData.info.filter(s => s.value).length;
    if (g('ph-stat-log'))   g('ph-stat-log').textContent   = phoneData.log.length;
}

