        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove App', message: `Remove "${a.name}" from your app list?`, confirmLabel: 'Remove', onConfirm: () => { phoneData.apps.splice(i,1); savePhoneData(); renderPHApps(); updatePHStats(); } }); };
        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
