// ── MAINTENANCE CHECKLIST
function renderPHMaint() {
    const list = document.getElementById('ph-maint-list');
    if (!list) return;
    list.innerHTML = '';
    const total = phoneData.maint.length;
    const done  = phoneData.maint.filter(m => m.done).length;
    const pct   = total ? Math.round((done/total)*100) : 0;
    const bar   = document.getElementById('ph-maint-bar'); if (bar) bar.style.width = pct + '%';
    const pctEl = document.getElementById('ph-maint-pct'); if (pctEl) pctEl.textContent = pct + '%';
    phoneData.maint.forEach((h, i) => {
        const row = document.createElement('div');
        row.className = `ir ${h.done ? 'ir-b' : ''}`;
        const emojiEl = document.createElement('div');
        emojiEl.className = 'icon-26';
        emojiEl.textContent = h.emoji || '📱';
        const cb = document.createElement('div');
        cb.style.cssText = chk('#38bdf8',h.done);
        cb.textContent = h.done ? '✓' : '';
        const labelEl = document.createElement('div');
        labelEl.className = `done-label done-b ${h.done ? 'done' : ''}`;
        labelEl.textContent = h.label;
        const toggle = () => { phoneData.maint[i].done = !h.done; savePhoneData(); renderPHMaint(); updatePHStats(); };
        [row, cb, labelEl].forEach(el => el.onclick = toggle);
        const pushBtn = document.createElement('button');
        pushBtn.className = 'pill pill-b';
        pushBtn.textContent = '📋'; pushBtn.title = 'Push to tasks';
        pushBtn.onclick = e => { e.stopPropagation(); phQuickTask(h.emoji||'📱', h.label, 'Maintenance task'); };
        const delBtn = document.createElement('button');
        delBtn.className = 'mini-btn';
        delBtn.textContent = '✕';
        delBtn.onmouseover = () => { delBtn.style.color='#f87171'; delBtn.style.borderColor='rgba(248,113,113,0.3)'; };
        delBtn.onmouseout  = () => { delBtn.style.color='#475569'; delBtn.style.borderColor='rgba(255,255,255,0.07)'; };
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove Task', message: `Remove "${h.label}" from maintenance checklist?`, confirmLabel: 'Remove', onConfirm: () => { phoneData.maint.splice(i,1); savePhoneData(); renderPHMaint(); updatePHStats(); } }); };
        row.appendChild(emojiEl); row.appendChild(cb); row.appendChild(labelEl); row.appendChild(pushBtn); row.appendChild(delBtn);
        list.appendChild(row);
    });
    updatePHStats();
}

