let pcData = loadData('pcData');

ensureArrays(pcData, 'apps', 'maint', 'specs', 'log', 'tasks');
if (!pcData._seeded) pcData._seeded = false;

if (!pcData.maint.length && !pcData._seeded) {
    pcData.maint = [
        { key:'updates',  emoji:'🔄', label:'Run OS & software updates',         done:false },
        { key:'backup',   emoji:'💾', label:'Backup important files',             done:false },
        { key:'cleanup',  emoji:'🧹', label:'Disk cleanup / remove temp files',   done:false },
        { key:'antivirus',emoji:'🛡️', label:'Run antivirus / malware scan',       done:false },
        { key:'browser',  emoji:'🌐', label:'Clear browser cache & cookies',      done:false },
    ];
}
if (!pcData.specs.length && !pcData._seeded) {
    pcData.specs = [
        { key:'os',  emoji:'🖥️', label:'OS',  value:'Windows 11' },
        { key:'cpu', emoji:'⚡', label:'CPU', value:'' },
        { key:'ram', emoji:'💾', label:'RAM', value:'' },
        { key:'gpu', emoji:'🎮', label:'GPU', value:'' },
        { key:'ssd', emoji:'💿', label:'SSD', value:'' },
    ];
}
if (!pcData.tasks.length && !pcData._seeded) {
    pcData.tasks = [
        { id:'pc_maint', emoji:'💻', title:'Monthly computer maintenance', desc:'Updates, backup, cleanup.' },
    ];
}
pcData._seeded = true;

const savePcData = () => saveData('pcData', pcData);
savePcData();

function showPCForm(kind) {
    const el = document.getElementById('pc-form-' + kind);
    if (!el) return;
    el.classList.add('visible');
    const f = el.querySelector('input,textarea,select');
    if (f) setTimeout(() => f.focus(), 60);
}
function hidePCForm(kind) {
    const el = document.getElementById('pc-form-' + kind);
    if (el) el.classList.remove('visible');
}

// ── STATS
function updatePCStats() {
    const g = id => document.getElementById(id);
    if (g('pc-stat-apps'))  g('pc-stat-apps').textContent  = pcData.apps.length;
    const mDone = pcData.maint.filter(m => m.done).length;
    const mPct  = pcData.maint.length ? Math.round((mDone/pcData.maint.length)*100) : 0;
    if (g('pc-stat-maint')) g('pc-stat-maint').textContent = mPct + '%';
    if (g('pc-stat-specs')) g('pc-stat-specs').textContent = pcData.specs.filter(s => s.value).length;
    if (g('pc-stat-log'))   g('pc-stat-log').textContent   = pcData.log.length;
}

// ── APP CATEGORY MAP
const PC_APP_CAT = {
    dev:          { emoji:'💻', label:'Dev',         color:'#60a5fa' },
    productivity: { emoji:'📋', label:'Productivity', color:'#34d399' },
    media:        { emoji:'🎵', label:'Media',        color:'#a78bfa' },
    security:     { emoji:'🔒', label:'Security',     color:'#f87171' },
    utility:      { emoji:'🔧', label:'Utility',      color:'#fbbf24' },
    game:         { emoji:'🎮', label:'Game',          color:'#fb923c' },
    other:        { emoji:'⚙️', label:'Other',         color:'#94a3b8' },
};
const PC_APP_STATUS = {
    ok:      { emoji:'✅', label:'Up to date', color:'#34d399' },
    update:  { emoji:'🔄', label:'Needs update', color:'#fbbf24' },
    issue:   { emoji:'⚠️', label:'Has issue',   color:'#f87171' },
    unused:  { emoji:'📦', label:'Unused',      color:'#475569' },
};

// ── APPS
function renderPCApps() {
    const list = document.getElementById('pc-apps-list');
    if (!list) return;
    list.innerHTML = '';
    if (!pcData.apps.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No apps yet — add your key software.</div>';
        updatePCStats(); return;
    }
    pcData.apps.forEach((a, i) => {
        const cat = PC_APP_CAT[a.cat] || PC_APP_CAT.other;
        const st  = PC_APP_STATUS[a.status || 'ok'] || PC_APP_STATUS.ok;
        const row = document.createElement('div');
        row.style.cssText = irColor(st.color);

        const icon = document.createElement('div');
        icon.className = 'icon-26';
        icon.textContent = a.emoji || cat.emoji;

        const body = document.createElement('div');
        body.className = 'flex-1';
        const nameEl = document.createElement('div');
        nameEl.className = 'item-label';
        nameEl.textContent = a.name;
        body.appendChild(nameEl);
        const meta = document.createElement('div');
        meta.className = 'd-row-6w';
        const catBadge = document.createElement('span');
        catBadge.style.cssText = colorTagSm(cat.color);
        catBadge.textContent = cat.label;
        meta.appendChild(catBadge);
        const stBadge = document.createElement('span');
        stBadge.style.cssText = colorTagSm(st.color);
        stBadge.textContent = st.emoji + ' ' + st.label;
        meta.appendChild(stBadge);
        if (a.notes) { const nb = document.createElement('span'); nb.className='meta-xs'; nb.textContent=a.notes; meta.appendChild(nb); }
        body.appendChild(meta);

        const nextStatus = { ok:'update', update:'issue', issue:'unused', unused:'ok' };
        row.onclick = () => { pcData.apps[i].status = nextStatus[a.status||'ok']; savePcData(); renderPCApps(); };

        const right = document.createElement('div');
        right.className = 'd-flex-gs0';
        const pushBtn = document.createElement('button');
        pushBtn.className='pill pill-sky';
        pushBtn.textContent = '📋'; pushBtn.title = 'Push to tasks';
        pushBtn.onclick = e => { e.stopPropagation(); pcQuickTask(a.emoji||cat.emoji, 'Update: '+a.name, a.notes||''); };
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove App', message: `Remove "${a.name}" from your software list?`, confirmLabel: 'Remove', onConfirm: () => { pcData.apps.splice(i,1); savePcData(); renderPCApps(); updatePCStats(); } }); };
        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updatePCStats();
}

function savePCApp() {
    const emoji = (document.getElementById('pca-emoji')?.value || '').trim();
    const name  = (document.getElementById('pca-name')?.value  || '').trim();
    const cat   = document.getElementById('pca-cat')?.value    || 'other';
    const notes = (document.getElementById('pca-notes')?.value || '').trim();
    if (!name) { document.getElementById('pca-name')?.focus(); return; }
    pcData.apps.push({ id:'a'+Date.now(), emoji, name, cat, notes, status:'ok' });
    savePcData();
    ['pca-emoji','pca-name','pca-notes'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hidePCForm('app'); renderPCApps(); updatePCStats();
}

// ── MAINTENANCE CHECKLIST
function renderPCMaint() {
    const list = document.getElementById('pc-maint-list');
    if (!list) return;
    list.innerHTML = '';
    const total = pcData.maint.length;
    const done  = pcData.maint.filter(m => m.done).length;
    const pct   = total ? Math.round((done/total)*100) : 0;
    const bar   = document.getElementById('pc-maint-bar'); if (bar) bar.style.width = pct + '%';
    const pctEl = document.getElementById('pc-maint-pct'); if (pctEl) pctEl.textContent = pct + '%';
    pcData.maint.forEach((h, i) => {
        const row = document.createElement('div');
        row.className = `ir ${h.done ? 'ir-g' : ''}`;
        const emojiEl = document.createElement('div');
        emojiEl.className = 'icon-26';
        emojiEl.textContent = h.emoji || '🔧';
        const cb = document.createElement('div');
        cb.style.cssText = chk('#34d399',h.done);
        cb.textContent = h.done ? '✓' : '';
        const labelEl = document.createElement('div');
        labelEl.className = `done-label done-g ${h.done ? 'done' : ''}`;
        labelEl.textContent = h.label;
        const toggle = () => { pcData.maint[i].done = !h.done; savePcData(); renderPCMaint(); updatePCStats(); };
        [row, cb, labelEl].forEach(el => el.onclick = toggle);
        const pushBtn = document.createElement('button');
        pushBtn.className = 'pill pill-g';
        pushBtn.textContent = '📋'; pushBtn.title = 'Push to tasks';
        pushBtn.onclick = e => { e.stopPropagation(); pcQuickTask(h.emoji||'🔧', h.label, 'Maintenance task'); };
        const delBtn = document.createElement('button');
        delBtn.className = 'mini-btn';
        delBtn.textContent = '✕';
        delBtn.onmouseover = () => { delBtn.style.color='#f87171'; delBtn.style.borderColor='rgba(248,113,113,0.3)'; };
        delBtn.onmouseout  = () => { delBtn.style.color='#475569'; delBtn.style.borderColor='rgba(255,255,255,0.07)'; };
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove Task', message: `Remove "${h.label}" from maintenance checklist?`, confirmLabel: 'Remove', onConfirm: () => { pcData.maint.splice(i,1); savePcData(); renderPCMaint(); updatePCStats(); } }); };
        row.appendChild(emojiEl); row.appendChild(cb); row.appendChild(labelEl); row.appendChild(pushBtn); row.appendChild(delBtn);
        list.appendChild(row);
    });
    updatePCStats();
}

function savePCMaint() {
    const emoji = (document.getElementById('pcm-emoji')?.value || '').trim() || '🔧';
    const label = (document.getElementById('pcm-label')?.value || '').trim();
    if (!label) { document.getElementById('pcm-label')?.focus(); return; }
    pcData.maint.push({ key:'m'+Date.now(), emoji, label, done:false });
    savePcData();
    ['pcm-emoji','pcm-label'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hidePCForm('maint'); renderPCMaint(); updatePCStats();
}

function resetPCMaint() {
    pcData.maint.forEach(m => m.done = false);
    savePcData(); renderPCMaint(); updatePCStats();
    toast('🔄 Checklist reset');
}

// ── HARDWARE & SPECS
function renderPCSpecs() {
    const list = document.getElementById('pc-specs-list');
    if (!list) return;
    list.innerHTML = '';
    if (!pcData.specs.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No specs yet — add your hardware components.</div>';
        updatePCStats(); return;
    }
    pcData.specs.forEach((s, i) => {
        const row = document.createElement('div');
        row.style.cssText = 'display:flex;align-items:center;gap:10px;padding:10px 13px;border-radius:12px;border:1px solid rgba(251,191,36,0.15);background:rgba(251,191,36,0.04);';
        const icon = document.createElement('div');
        icon.className='icon-sm';
        icon.textContent = s.emoji || '🔧';
        const labelEl = document.createElement('div');
        labelEl.style.cssText = 'font-size:0.8em;font-weight:800;color:#fbbf24;min-width:50px;flex-shrink:0;text-transform:uppercase;letter-spacing:0.5px;';
        labelEl.textContent = s.label;
        const valueEl = document.createElement('div');
        valueEl.style.cssText = 'flex:1;font-size:0.85em;font-weight:600;color:' + (s.value ? '#e2e8f0' : '#475569') + ';';
        valueEl.textContent = s.value || '—';
        // Make value editable inline
        valueEl.contentEditable = 'true';
        valueEl.style.outline = 'none';
        valueEl.addEventListener('blur', function() {
            pcData.specs[i].value = valueEl.textContent.trim();
            savePcData(); updatePCStats();
            valueEl.style.color = valueEl.textContent.trim() ? '#e2e8f0' : '#475569';
        });
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove Spec', message: `Remove "${s.label}" from specs?`, confirmLabel: 'Remove', onConfirm: () => { pcData.specs.splice(i,1); savePcData(); renderPCSpecs(); updatePCStats(); } }); };
        row.appendChild(icon); row.appendChild(labelEl); row.appendChild(valueEl); row.appendChild(delBtn);
        list.appendChild(row);
    });
    updatePCStats();
}

function savePCSpec() {
    const emoji = (document.getElementById('pcs-emoji')?.value || '').trim() || '🔧';
    const label = (document.getElementById('pcs-label')?.value || '').trim();
    const value = (document.getElementById('pcs-value')?.value || '').trim();
    if (!label) { document.getElementById('pcs-label')?.focus(); return; }
    pcData.specs.push({ key:'sp'+Date.now(), emoji, label, value });
    savePcData();
    ['pcs-emoji','pcs-label','pcs-value'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hidePCForm('spec'); renderPCSpecs(); updatePCStats();
}

