function updateEMUStats() {
    const g = id => document.getElementById(id);
    if (g('emu-stat-games'))     g('emu-stat-games').textContent     = emuData.games.length;
    if (g('emu-stat-emulators')) g('emu-stat-emulators').textContent = emuData.setup.filter(s => s.active).length;
    if (g('emu-stat-wishlist'))  g('emu-stat-wishlist').textContent  = emuData.wishlist.length;
    if (g('emu-stat-log'))       g('emu-stat-log').textContent       = emuData.log.length;
}

// ── SYSTEM MAP
const EMU_SYSTEM = {
    gba:   { emoji:'🟣', label:'GBA',    color:'#a78bfa' },
    nds:   { emoji:'🔵', label:'NDS',    color:'#38bdf8' },
    psx:   { emoji:'🔴', label:'PS1',    color:'#f87171' },
    ps2:   { emoji:'🔴', label:'PS2',    color:'#f87171' },
    n64:   { emoji:'🟡', label:'N64',    color:'#fbbf24' },
    snes:  { emoji:'🟢', label:'SNES',   color:'#34d399' },
    nes:   { emoji:'🟢', label:'NES',    color:'#34d399' },
    psp:   { emoji:'🟠', label:'PSP',    color:'#fb923c' },
    nds3:  { emoji:'🔵', label:'3DS',    color:'#38bdf8' },
    other: { emoji:'⚪', label:'Other',  color:'#94a3b8' },
};
const EMU_GAME_STATUS = {
    backlog:   { emoji:'📥', label:'Backlog',   color:'#94a3b8' },
    playing:   { emoji:'▶️',  label:'Playing',  color:'#34d399' },
    completed: { emoji:'✅', label:'Completed', color:'#a78bfa' },
    dropped:   { emoji:'❌', label:'Dropped',   color:'#475569' },
};

// ── GAMES LIBRARY
function renderEMUGames() {
    const list = document.getElementById('emu-games-list');
    if (!list) return;
    list.innerHTML = '';
    if (!emuData.games.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No games yet — add your ROM collection.</div>';
        updateEMUStats(); return;
    }
    emuData.games.forEach((g, i) => {
        const sys = EMU_SYSTEM[g.system] || EMU_SYSTEM.other;
        const st  = EMU_GAME_STATUS[g.status || 'backlog'] || EMU_GAME_STATUS.backlog;
        const row = document.createElement('div');
        row.style.cssText = irColor(st.color);

        const icon = document.createElement('div');
        icon.className = 'icon-26';
        icon.textContent = sys.emoji;

        const body = document.createElement('div');
        body.className = 'flex-1';
        const titleEl = document.createElement('div');
        titleEl.className = 'item-label';
        titleEl.textContent = g.title;
        body.appendChild(titleEl);
        const meta = document.createElement('div');
        meta.className = 'd-row-6w';
        const sysBadge = document.createElement('span');
        sysBadge.style.cssText = colorTagSm(sys.color);
        sysBadge.textContent = sys.label;
        meta.appendChild(sysBadge);
        const stBadge = document.createElement('span');
        stBadge.style.cssText = colorTagSm(st.color);
        stBadge.textContent = st.emoji + ' ' + st.label;
        meta.appendChild(stBadge);
        if (g.notes) { const nb = document.createElement('span'); nb.className='meta-xs'; nb.textContent=g.notes; meta.appendChild(nb); }
        body.appendChild(meta);

        const nextStatus = { backlog:'playing', playing:'completed', completed:'dropped', dropped:'backlog' };
        row.onclick = () => { emuData.games[i].status = nextStatus[g.status||'backlog']; saveEmuData(); renderEMUGames(); };

        const right = document.createElement('div');
        right.className = 'd-flex-gs0';
        const pushBtn = document.createElement('button');
        pushBtn.className='pill pill-v';
        pushBtn.textContent = '📋'; pushBtn.title = 'Push to tasks';
        pushBtn.onclick = e => { e.stopPropagation(); emuQuickTask('🎮', 'Play: '+g.title+' ('+sys.label+')', g.notes||''); };
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove Game', message: `Remove "${g.title}" from your library?`, confirmLabel: 'Remove', onConfirm: () => { emuData.games.splice(i,1); saveEmuData(); renderEMUGames(); updateEMUStats(); } }); };
        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateEMUStats();
}

function saveEMUGame() {
    const title  = (document.getElementById('emug-title')?.value  || '').trim();
    const system = document.getElementById('emug-system')?.value  || 'other';
    const status = document.getElementById('emug-status')?.value  || 'backlog';
    const notes  = (document.getElementById('emug-notes')?.value  || '').trim();
    if (!title) { document.getElementById('emug-title')?.focus(); return; }
    emuData.games.push({ id:'g'+Date.now(), title, system, status, notes });
    saveEmuData();
    ['emug-title','emug-notes'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideEMUForm('game'); renderEMUGames(); updateEMUStats();
}

// ── EMULATORS & SETUP
function renderEMUSetup() {
    const list = document.getElementById('emu-setup-list');
    if (!list) return;
    list.innerHTML = '';
    if (!emuData.setup.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No emulators added yet.</div>';
        updateEMUStats(); return;
    }
    emuData.setup.forEach((s, i) => {
        const active = s.active !== false;
        const row = document.createElement('div');
        row.className = `ir ${active ? 'ir-ga' : ''}`;

        const icon = document.createElement('div');
        icon.className = 'icon-26';
        icon.textContent = s.emoji || '🕹️';

        const body = document.createElement('div');
        body.className = 'flex-1';
        const nameEl = document.createElement('div');
        nameEl.className = `active-label ${active ? 'on' : ''}`;
        nameEl.textContent = s.name;
        body.appendChild(nameEl);
        const meta = document.createElement('div');
        meta.className='d-row-6-mt3-fc';
        if (s.systems) { const sb = document.createElement('span'); sb.style.cssText='font-size:0.72em;color:#64748b;'; sb.textContent=s.systems; meta.appendChild(sb); }
        if (s.notes) { const nb = document.createElement('span'); nb.className='meta-xs'; nb.textContent=s.notes; meta.appendChild(nb); }
        const abadge = document.createElement('span');
        abadge.className = `badge-active ${active ? 'on' : ''}`;
        abadge.textContent = active ? '✅ Active' : '⏸ Inactive';
        meta.appendChild(abadge);
        body.appendChild(meta);

        row.onclick = () => { emuData.setup[i].active = !active; saveEmuData(); renderEMUSetup(); updateEMUStats(); };

        const right = document.createElement('div');
        right.className = 'd-flex-gs0';
        const pushBtn = document.createElement('button');
        pushBtn.className = 'pill pill-g';
        pushBtn.textContent = '📋'; pushBtn.title = 'Push to tasks';
        pushBtn.onclick = e => { e.stopPropagation(); emuQuickTask(s.emoji||'🕹️', 'Configure: '+s.name, s.notes||''); };
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove Emulator', message: `Remove "${s.name}" from your setup?`, confirmLabel: 'Remove', onConfirm: () => { emuData.setup.splice(i,1); saveEmuData(); renderEMUSetup(); updateEMUStats(); } }); };
        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateEMUStats();
}

function saveEMUSetup() {
    const emoji   = (document.getElementById('emus-emoji')?.value   || '').trim() || '🕹️';
    const name    = (document.getElementById('emus-name')?.value    || '').trim();
    const systems = (document.getElementById('emus-system')?.value  || '').trim();
    const notes   = (document.getElementById('emus-notes')?.value   || '').trim();
    if (!name) { document.getElementById('emus-name')?.focus(); return; }
    emuData.setup.push({ id:'s'+Date.now(), emoji, name, systems, notes, active:true });
    saveEmuData();
    ['emus-emoji','emus-name','emus-system','emus-notes'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideEMUForm('setup'); renderEMUSetup(); updateEMUStats();
}

