// ── SESSION LOG
const EMU_LOG_TYPE = {
    session: { emoji:'🎮', label:'Session',    color:'#a78bfa' },
    bug:     { emoji:'🐛', label:'Bug/Glitch', color:'#f87171' },
    cheat:   { emoji:'🔑', label:'Cheat/Code', color:'#fbbf24' },
    tip:     { emoji:'💡', label:'Tip/Trick',  color:'#34d399' },
    setup:   { emoji:'⚙️', label:'Setup fix',  color:'#38bdf8' },
    note:    { emoji:'📝', label:'Note',        color:'#94a3b8' },
};

function renderEMULog() {
    const list = document.getElementById('emu-log-list');
    if (!list) return;
    list.innerHTML = '';
    if (!emuData.log.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No entries yet. Log sessions, cheats, bugs, or setup fixes.</div>';
        updateEMUStats(); return;
    }
    [...emuData.log].reverse().forEach((e, revIdx) => {
        const realIdx = emuData.log.length - 1 - revIdx;
        const t = EMU_LOG_TYPE[e.type] || EMU_LOG_TYPE.note;
        const row = document.createElement('div');
        row.style.cssText = 'display:flex;align-items:flex-start;gap:10px;padding:12px 14px;border-radius:13px;background:rgba(248,113,113,0.03);border:1px solid rgba(248,113,113,0.1);';
        const icon = document.createElement('div');
        icon.className = 'icon-lg';
        icon.textContent = t.emoji;
        const body = document.createElement('div');
        body.className = 'flex-1';
        const topRow = document.createElement('div');
        topRow.className = 'd-row-7w';
        const typeTag = document.createElement('span');
        typeTag.style.cssText = colorTag(t.color);
        typeTag.textContent = t.label;
        topRow.appendChild(typeTag);
        if (e.game) {
            const gb = document.createElement('span');
            gb.style.cssText = 'font-size:0.7em;font-weight:700;padding:2px 7px;border-radius:99px;background:rgba(167,139,250,0.1);color:#a78bfa;border:1px solid rgba(167,139,250,0.2);';
            gb.textContent = '🎮 ' + e.game;
            topRow.appendChild(gb);
        }
        body.appendChild(topRow);
        if (e.text) { const textEl = document.createElement('div'); textEl.className='note-text'; textEl.textContent=e.text; body.appendChild(textEl); }
        const right = document.createElement('div');
        right.className = 'd-flex-gs0';
        const pushBtn = document.createElement('button');
        pushBtn.title = 'Push to tasks';
        pushBtn.className='pill pill-v';
        pushBtn.textContent = '📋';
        pushBtn.onclick = ev => { ev.stopPropagation(); emuQuickTask(t.emoji, t.label+(e.game?' — '+e.game:''), e.text?.slice(0,40)||''); };
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️';
        delBtn.onclick = ev => { ev.stopPropagation(); showConfirm({ title: 'Delete Log Entry', message: 'Delete this log entry?', confirmLabel: 'Delete', onConfirm: () => { emuData.log.splice(realIdx,1); saveEmuData(); renderEMULog(); updateEMUStats(); } }); };
        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateEMUStats();
}

function saveEMULog() {
    const type = document.getElementById('emul-type')?.value || 'session';
    const game = (document.getElementById('emul-game')?.value || '').trim();
    const text = (document.getElementById('emul-text')?.value || '').trim();
    if (!text) { document.getElementById('emul-text')?.focus(); return; }
    emuData.log.push({ id:'l'+Date.now(), type, game, text });
    saveEmuData();
    ['emul-game','emul-text'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideEMUForm('log'); renderEMULog(); updateEMUStats();
}

// ── QUICK TASK
function emuQuickTask(emoji, title, desc) {
    if (!gTasksAll['emulator']) gTasksAll['emulator'] = [];
    const already = gTasksAll['emulator'].find(t => (t.text === title || t.title === title) && !t.done);
    if (already) { toast('Task already exists'); return; }
    gTasksAll['emulator'].push({ id: 'emuqt_' + Date.now(), emoji, text: title, notes: desc || '', done: false, accentColor: '#a78bfa' });
    saveGTasksAll(); renderGTasks('emulator');
    toast('📌 Task added');
}

// ── TASKS (now handled by gTasksAll + renderGTasks)
function renderEMUTasks() { renderGTasks('emulator'); }
function saveEMUTask()    { showGTask('emulator'); }
function removeEMUTask()  { /* no-op: gTasksAll handles deletion */ }

function initEmulatorSection() {
    if (!document.getElementById('resp-section-emulator')) return;
    if ((emuData.tasks || []).length && !(gTasksAll['emulator'] || []).length) {
        gTasksAll['emulator'] = emuData.tasks.map(t => ({
            id: t.id || ('emuqt_' + Date.now() + '_' + Math.random()),
            emoji: t.emoji || '🕹️',
            text: t.title || t.text || '',
            notes: t.desc || '',
            done: !!t.done,
            accentColor: '#a78bfa'
        }));
        saveGTasksAll();
    }
    renderEMUGames();
    renderEMUSetup();
    renderEMUWishlist();
    renderEMULog();
    renderGTasks('emulator');
    updateEMUStats();
}

