let socialData = loadData('socialData');

ensureArrays(socialData, 'accounts', 'queue', 'habits', 'log', 'tasks');
if (!socialData._seeded) socialData._seeded = false;

if (!socialData.habits.length && !socialData._seeded) {
    socialData.habits = [
        { key:'post',    emoji:'📸', label:'Post or schedule 1 piece of content',  done:false },
        { key:'engage',  emoji:'💬', label:'Reply to comments / DMs',              done:false },
        { key:'stories', emoji:'⏳', label:'Post to stories',                       done:false },
        { key:'research',emoji:'🔍', label:'Research trending content in niche',   done:false },
        { key:'stats',   emoji:'📊', label:'Check analytics / insights',           done:false },
    ];
}
if (!socialData.tasks.length && !socialData._seeded) {
    socialData.tasks = [
        { id:'sm_content', emoji:'🎬', title:'Create this week content batch', desc:'Film, edit, and schedule posts.' },
    ];
}
socialData._seeded = true;

const saveSocialData = () => saveData('socialData', socialData);
saveSocialData();

function showSMForm(kind) {
    const el = document.getElementById('sm-form-' + kind);
    if (!el) return;
    el.classList.add('visible');
    const f = el.querySelector('input,textarea,select');
    if (f) setTimeout(() => f.focus(), 60);
}
function hideSMForm(kind) {
    const el = document.getElementById('sm-form-' + kind);
    if (el) el.classList.remove('visible');
}

// ── STATS
function updateSMStats() {
    const g = id => document.getElementById(id);
    if (g('sm-stat-accounts')) g('sm-stat-accounts').textContent = socialData.accounts.length;
    const qPending = socialData.queue.filter(q => q.status !== 'posted').length;
    if (g('sm-stat-queue'))    g('sm-stat-queue').textContent    = qPending;
    const hDone = socialData.habits.filter(h => h.done).length;
    const hPct  = socialData.habits.length ? Math.round((hDone/socialData.habits.length)*100) : 0;
    if (g('sm-stat-habits'))   g('sm-stat-habits').textContent   = hPct + '%';
    if (g('sm-stat-log'))      g('sm-stat-log').textContent      = socialData.log.length;
}

