        const active = a.active !== false;
        const row = document.createElement('div');
        row.style.cssText = `display:flex;align-items:center;gap:10px;padding:11px 13px;border-radius:12px;cursor:pointer;transition:all 0.2s;border:1px solid ${active?pl.color+'44':'rgba(255,255,255,0.06)'};background:${active?pl.color+'0a':'rgba(2,8,23,0.35)'};`;

