let investData = loadData('investData');

ensureArrays(investData, 'positions', 'watchlist', 'habits', 'log', 'tasks');
if (!investData._seeded) investData._seeded = false;

if (!investData.habits.length && !investData._seeded) {
    investData.habits = [
        { key:'review',   emoji:'📊', label:'Review portfolio performance',        done:false },
        { key:'news',     emoji:'📰', label:'Read 1 financial news article',        done:false },
        { key:'save',     emoji:'💰', label:'Transfer planned savings amount',      done:false },
        { key:'watchlist',emoji:'👁️', label:'Check watchlist for entry points',     done:false },
        { key:'rebalance',emoji:'⚖️', label:'Review allocation vs target %',        done:false },
    ];
}
if (!investData.tasks.length && !investData._seeded) {
    investData.tasks = [
        { id:'inv_review', emoji:'📈', title:'Monthly portfolio review', desc:'Check performance, rebalance if needed.' },
    ];
}
investData._seeded = true;

const saveInvestData = () => saveData('investData', investData);
saveInvestData();

function showINVForm(kind) {
    const el = document.getElementById('inv-form-' + kind);
    if (!el) return;
    el.classList.add('visible');
    const f = el.querySelector('input,textarea,select');
    if (f) setTimeout(() => f.focus(), 60);
}
function hideINVForm(kind) {
    const el = document.getElementById('inv-form-' + kind);
    if (el) el.classList.remove('visible');
}

// ── STATS
function updateINVStats() {
    const g = id => document.getElementById(id);
    if (g('inv-stat-positions')) g('inv-stat-positions').textContent = investData.positions.length;
    if (g('inv-stat-watchlist')) g('inv-stat-watchlist').textContent = investData.watchlist.length;
    const hDone = investData.habits.filter(h => h.done).length;
    const hPct  = investData.habits.length ? Math.round((hDone/investData.habits.length)*100) : 0;
    if (g('inv-stat-habits'))    g('inv-stat-habits').textContent    = hPct + '%';
    if (g('inv-stat-log'))       g('inv-stat-log').textContent       = investData.log.length;
}

// ── ASSET TYPE MAP
const INV_ASSET_TYPE = {
    stock:  { emoji:'📈', label:'Stock',  color:'#34d399' },
    etf:    { emoji:'🏦', label:'ETF',    color:'#38bdf8' },
    crypto: { emoji:'₿',  label:'Crypto', color:'#fbbf24' },
    fund:   { emoji:'💰', label:'Fund',   color:'#a78bfa' },
    bond:   { emoji:'📜', label:'Bond',   color:'#94a3b8' },
    other:  { emoji:'💳', label:'Other',  color:'#64748b' },
};

