let streamingData = loadData('streamingData');

ensureArrays(streamingData, 'platforms', 'checklist', 'devices', 'log', 'tasks');
if (!streamingData._seeded) streamingData._seeded = false;

if (!streamingData.checklist.length && !streamingData._seeded) {
    streamingData.checklist = [
        { key:'speed',    emoji:'📶', label:'Check internet speed (>25 Mbps)',     done:false },
        { key:'hdmi',     emoji:'🔌', label:'HDMI / cables all connected',          done:false },
        { key:'remote',   emoji:'🎮', label:'Remote batteries OK',                  done:false },
        { key:'updates',  emoji:'🔄', label:'Check for app / firmware updates',     done:false },
        { key:'audio',    emoji:'🔊', label:'Audio output set correctly',           done:false },
    ];
}
if (!streamingData.tasks.length && !streamingData._seeded) {
    streamingData.tasks = [
        { id:'str_setup', emoji:'📺', title:'Review streaming setup', desc:'Check all devices and accounts are up to date.' },
    ];
}
streamingData._seeded = true;

const saveStreamingData = () => saveData('streamingData', streamingData);
saveStreamingData();

function showSTRForm(kind) {
    const el = document.getElementById('str-form-' + kind);
    if (!el) return;
    el.classList.add('visible');
    const f = el.querySelector('input,textarea,select');
    if (f) setTimeout(() => f.focus(), 60);
}
function hideSTRForm(kind) {
    const el = document.getElementById('str-form-' + kind);
    if (el) el.classList.remove('visible');
}

// ── STATS
function updateSTRStats() {
    const g = id => document.getElementById(id);
    if (g('str-stat-platforms'))  g('str-stat-platforms').textContent  = streamingData.platforms.length;
    const cDone = streamingData.checklist.filter(c => c.done).length;
    const cPct  = streamingData.checklist.length ? Math.round((cDone/streamingData.checklist.length)*100) : 0;
    if (g('str-stat-checklist'))  g('str-stat-checklist').textContent  = cPct + '%';
    if (g('str-stat-devices'))    g('str-stat-devices').textContent    = streamingData.devices.length;
    if (g('str-stat-log'))        g('str-stat-log').textContent        = streamingData.log.length;
}

// ── PLATFORMS
function renderSTRPlatforms() {
    const list = document.getElementById('str-platform-list');
    if (!list) return;
    list.innerHTML = '';
    if (!streamingData.platforms.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No platforms yet — add your streaming services.</div>';
        updateSTRStats(); return;
    }
    streamingData.platforms.forEach((p, i) => {
        const active = p.active !== false;
        const row = document.createElement('div');
        row.className = `ir ${active ? 'ir-c' : ''}`;

        const emojiEl = document.createElement('div');
        emojiEl.style.cssText = 'font-size:1.3em;flex-shrink:0;width:26px;text-align:center;';
        emojiEl.textContent = p.emoji || '📺';

        const body = document.createElement('div');
        body.className = 'flex-1';
        const nameEl = document.createElement('div');
        nameEl.className = `active-label ${active ? 'on' : ''}`;
        nameEl.textContent = p.name;
        body.appendChild(nameEl);
        const meta = document.createElement('div');
        meta.className = 'd-row-6-mt3';
        if (p.account) { const ac = document.createElement('span'); ac.className='meta-xs'; ac.textContent=p.account; meta.appendChild(ac); }
        if (p.cost) {
            const cb = document.createElement('span');
            cb.style.cssText = 'font-size:0.68em;font-weight:800;padding:2px 7px;border-radius:99px;background:rgba(34,211,238,0.1);color:#22d3ee;border:1px solid rgba(34,211,238,0.2);';
            cb.textContent = p.cost;
            meta.appendChild(cb);
        }
        const statusBadge = document.createElement('span');
        statusBadge.className = `badge-active ${active ? 'on' : ''}`;
        statusBadge.textContent = active ? '✅ Active' : '⏸ Inactive';
        meta.appendChild(statusBadge);
        body.appendChild(meta);

        const toggle = () => { streamingData.platforms[i].active = !active; saveStreamingData(); renderSTRPlatforms(); };
        [row, body].forEach(el => el.onclick = toggle);

        const right = document.createElement('div');
        right.className = 'd-flex-gs0';
        const pushBtn = document.createElement('button');
        pushBtn.className='pill pill-c';
        pushBtn.textContent = '📋'; pushBtn.title = 'Push to tasks';
        pushBtn.onclick = e => { e.stopPropagation(); strQuickTask(p.emoji||'📺', 'Manage: '+p.name, p.account||''); };
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove Platform', message: `Remove "${p.name}" from streaming platforms?`, confirmLabel: 'Remove', onConfirm: () => { streamingData.platforms.splice(i,1); saveStreamingData(); renderSTRPlatforms(); updateSTRStats(); } }); };
        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(emojiEl); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateSTRStats();
}

function saveSTRPlatform() {
    const emoji   = (document.getElementById('strp-emoji')?.value   || '').trim() || '📺';
    const name    = (document.getElementById('strp-name')?.value    || '').trim();
    const account = (document.getElementById('strp-account')?.value || '').trim();
    const cost    = (document.getElementById('strp-cost')?.value    || '').trim();
    if (!name) { document.getElementById('strp-name')?.focus(); return; }
    streamingData.platforms.push({ id:'p'+Date.now(), emoji, name, account, cost, active:true });
    saveStreamingData();
    ['strp-emoji','strp-name','strp-account','strp-cost'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideSTRForm('platform'); renderSTRPlatforms(); updateSTRStats();
}

