let abletonData = loadData('abletonData');

ensureArrays(abletonData, 'projects', 'habits', 'skills', 'log', 'tasks');
if (!abletonData._seeded) abletonData._seeded = false;

if (!abletonData.habits.length && !abletonData._seeded) {
    abletonData.habits = [
        { key:'open',    emoji:'💻', label:'Open Ableton and work for 20+ min',    done:false },
        { key:'finish',  emoji:'🎯', label:'Finish at least one element per session', done:false },
        { key:'ref',     emoji:'🎧', label:'Reference mix against a pro track',     done:false },
        { key:'save',    emoji:'💾', label:'Save + backup project files',           done:false },
        { key:'learn',   emoji:'📚', label:'Watch/read 1 production tip',           done:false },
    ];
}
if (!abletonData.skills.length && !abletonData._seeded) {
    abletonData.skills = [
        { key:'sidechain', emoji:'🔗', name:'Sidechain compression', status:'todo' },
        { key:'eq',        emoji:'🎚️', name:'EQ fundamentals',        status:'todo' },
        { key:'automation',emoji:'🤖', name:'Automation & envelopes', status:'todo' },
        { key:'sampling',  emoji:'🎵', name:'Sampling & chopping',    status:'todo' },
    ];
}
if (!abletonData.tasks.length && !abletonData._seeded) {
    abletonData.tasks = [
        { id:'abl_session', emoji:'🎛️', title:'Open Ableton production session', desc:'Even 20 min of focused work.' },
    ];
}
abletonData._seeded = true;

const saveAbletonData = () => saveData('abletonData', abletonData);
saveAbletonData();

function showABLForm(kind) {
    const el = document.getElementById('abl-form-' + kind);
    if (!el) return;
    el.classList.add('visible');
    const f = el.querySelector('input,textarea,select');
    if (f) setTimeout(() => f.focus(), 60);
}
function hideABLForm(kind) {
    const el = document.getElementById('abl-form-' + kind);
    if (el) el.classList.remove('visible');
}

// ── STATS
function updateABLStats() {
    const g = id => document.getElementById(id);
    if (g('abl-stat-projects')) g('abl-stat-projects').textContent = abletonData.projects.length;
    if (g('abl-stat-skills'))   g('abl-stat-skills').textContent   = abletonData.skills.length;
    if (g('abl-stat-log'))      g('abl-stat-log').textContent      = abletonData.log.length;
}

// ── MUSIC INLINE-EDIT STATE
let _gtrEditSession=-1,_gtrEditSong=-1;
let _saxEditSession=-1,_saxEditSong=-1;
let _pnoEditSession=-1,_pnoEditSong=-1;
let _ablEditProject=-1,_ablEditSkill=-1;

// ── MUSIC INLINE-EDIT HELPERS
function _mInp(placeholder, val, extraStyle) {
    const el=document.createElement('input');
    el.placeholder=placeholder; el.value=val||'';
    el.style.cssText=`padding:6px 9px;border-radius:8px;border:1px solid rgba(255,255,255,0.1);background:rgba(255,255,255,0.05);color:#e2e8f0;font-size:0.83em;font-weight:600;font-family:'Outfit',sans-serif;${extraStyle||''}`;
    return el;
}
function _mSel(options, selected) {
    const el=document.createElement('select');
    el.style.cssText="padding:6px 9px;border-radius:8px;border:1px solid rgba(255,255,255,0.1);background:rgba(22,28,40,0.95);color:#e2e8f0;font-size:0.83em;font-weight:600;font-family:'Outfit',sans-serif;width:100%;";
    options.forEach(([v,l])=>{ const o=document.createElement('option'); o.value=v; o.textContent=l; if(v===selected) o.selected=true; el.appendChild(o); });
    return el;
}
function _mSvBtn(accent) {
    const el=document.createElement('button'); el.type='button'; el.textContent='✓ Save';
    el.style.cssText=`padding:7px 14px;border-radius:9px;border:none;background:${accent};color:#000;font-size:0.8em;font-weight:800;cursor:pointer;font-family:'Outfit',sans-serif;`;
    return el;
}
function _mCxBtn() {
    const el=document.createElement('button'); el.type='button'; el.textContent='Cancel';
    el.style.cssText="padding:7px 12px;border-radius:9px;border:1px solid rgba(255,255,255,0.07);background:rgba(255,255,255,0.03);color:#475569;font-size:0.8em;font-weight:700;cursor:pointer;font-family:'Outfit',sans-serif;";
    return el;
}
function _mEditBtn(onClick) {
    const el=document.createElement('button'); el.type='button'; el.textContent='✏️'; el.title='Edit';
    el.style.cssText='width:28px;height:28px;border-radius:7px;border:1px solid rgba(255,255,255,0.07);background:rgba(255,255,255,0.03);color:#475569;font-size:0.82em;cursor:pointer;display:flex;align-items:center;justify-content:center;flex-shrink:0;';
    el.onmouseover=()=>{el.style.background='rgba(251,191,36,0.1)';el.style.borderColor='rgba(251,191,36,0.3)';}
    el.onmouseout =()=>{el.style.background='rgba(255,255,255,0.03)';el.style.borderColor='rgba(255,255,255,0.07)';}
    el.onclick = e => { e.stopPropagation(); onClick(); };
    return el;
}
function _buildSessionEditRow(a, typeMap, accent, onSave, onCancel) {
    const wrap=document.createElement('div');
    wrap.style.cssText=`padding:12px 14px;border-radius:13px;background:${accent}0a;border:1px solid ${accent}33;display:flex;flex-direction:column;gap:8px;`;
    const typeOpts=Object.entries(typeMap).map(([k,v])=>[k,v.emoji+' '+v.label]);
    const typeSel=_mSel(typeOpts, a.type);
    const r1=document.createElement('div'); r1.style.cssText='display:flex;gap:8px;';
    const whenInp=_mInp('When (e.g. Tue 19:00)',a.when,'flex:1;');
    const durInp=_mInp('Duration (e.g. 45 min)',a.duration,'flex:1;');
    r1.appendChild(whenInp); r1.appendChild(durInp);
    const notesInp=_mInp('Notes…',a.notes,'width:100%;');
    const acts=document.createElement('div'); acts.style.cssText='display:flex;gap:8px;';
    const sv=_mSvBtn(accent); sv.onclick=()=>onSave({type:typeSel.value,when:whenInp.value.trim(),duration:durInp.value.trim(),notes:notesInp.value.trim()});
    const cx=_mCxBtn(); cx.onclick=onCancel;
    acts.appendChild(sv); acts.appendChild(cx);
    wrap.appendChild(typeSel); wrap.appendChild(r1); wrap.appendChild(notesInp); wrap.appendChild(acts);
    return wrap;
}
function _buildSongEditRow(s, statusMap, accent, onSave, onCancel) {
    const wrap=document.createElement('div');
    wrap.style.cssText=`padding:12px 14px;border-radius:13px;background:${accent}0a;border:1px solid ${accent}33;display:flex;flex-direction:column;gap:8px;`;
    const r1=document.createElement('div'); r1.style.cssText='display:flex;gap:8px;';
    const titleInp=_mInp('Title',s.title,'flex:1;');
    const artistInp=_mInp('Artist',s.artist,'flex:1;');
    r1.appendChild(titleInp); r1.appendChild(artistInp);
    const statusOpts=Object.entries(statusMap).map(([k,v])=>[k,v.emoji+' '+v.label]);
    const statusSel=_mSel(statusOpts, s.status);
    const notesInp=_mInp('Notes…',s.notes,'width:100%;');
    const acts=document.createElement('div'); acts.style.cssText='display:flex;gap:8px;';
    const sv=_mSvBtn(accent); sv.onclick=()=>{if(!titleInp.value.trim()){titleInp.focus();return;} onSave({title:titleInp.value.trim(),artist:artistInp.value.trim(),status:statusSel.value,notes:notesInp.value.trim()});};
    const cx=_mCxBtn(); cx.onclick=onCancel;
    acts.appendChild(sv); acts.appendChild(cx);
    wrap.appendChild(r1); wrap.appendChild(statusSel); wrap.appendChild(notesInp); wrap.appendChild(acts);
    return wrap;
}

// ── PROJECT STATUS MAP
const ABL_PROJECT_STATUS = {
    idea:    { emoji:'💡', label:'Idea',        color:'#94a3b8' },
    wip:     { emoji:'🚧', label:'In progress', color:'#fbbf24' },
    mixing:  { emoji:'🎚️', label:'Mixing',       color:'#38bdf8' },
    done:    { emoji:'✅', label:'Done',         color:'#34d399' },
};
const ABL_GENRE = {
    hiphop:    '🎤', electronic:'⚡', lofi:'🌅', house:'🏠', ambient:'🌊', other:'🎶'
};

// ── PROJECTS
function renderABLProjects() {
    const list = document.getElementById('abl-project-list');
    if (!list) return;
    list.innerHTML = '';
    if (!abletonData.projects.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No projects yet — add your first track.</div>';
        updateABLStats(); return;
    }
    abletonData.projects.forEach((p, i) => {
        if (_ablEditProject === i) {
            const genreOpts=Object.entries(ABL_GENRE).map(([k,v])=>[k,v+' '+k[0].toUpperCase()+k.slice(1)]);
            const statusOpts=Object.entries(ABL_PROJECT_STATUS).map(([k,v])=>[k,v.emoji+' '+v.label]);
            const wrap=document.createElement('div');
            wrap.style.cssText='padding:12px 14px;border-radius:13px;background:rgba(251,191,36,0.05);border:1px solid rgba(251,191,36,0.25);display:flex;flex-direction:column;gap:8px;';
            const titleInp=_mInp('Project title',p.title,'width:100%;');
            const r1=document.createElement('div'); r1.style.cssText='display:flex;gap:8px;';
            const genreSel=_mSel(genreOpts,p.genre); genreSel.style.flex='1';
            const statusSel=_mSel(statusOpts,p.status); statusSel.style.flex='1';
            r1.appendChild(genreSel); r1.appendChild(statusSel);
            const notesInp=_mInp('Notes…',p.notes,'width:100%;');
            const acts=document.createElement('div'); acts.style.cssText='display:flex;gap:8px;';
            const sv=_mSvBtn('#fbbf24'); sv.onclick=()=>{ if(!titleInp.value.trim()){titleInp.focus();return;} Object.assign(abletonData.projects[i],{title:titleInp.value.trim(),genre:genreSel.value,status:statusSel.value,notes:notesInp.value.trim()}); saveAbletonData(); _ablEditProject=-1; renderABLProjects(); updateABLStats(); };
            const cx=_mCxBtn(); cx.onclick=()=>{ _ablEditProject=-1; renderABLProjects(); };
            acts.appendChild(sv); acts.appendChild(cx);
            wrap.appendChild(titleInp); wrap.appendChild(r1); wrap.appendChild(notesInp); wrap.appendChild(acts);
            list.appendChild(wrap); return;
        }
        const st = ABL_PROJECT_STATUS[p.status] || ABL_PROJECT_STATUS.idea;
        const row = document.createElement('div');
        row.style.cssText = irColor(st.color);
        const icon = document.createElement('div');
        icon.className = 'icon-m';
        icon.textContent = ABL_GENRE[p.genre] || '🎶';
        const body = document.createElement('div');
        body.className = 'flex-1';
        const titleEl = document.createElement('div');
        titleEl.className = 'item-label';
        titleEl.textContent = p.title;
        body.appendChild(titleEl);
        const meta = document.createElement('div');
        meta.className = 'd-row-6-mt3';
        const badge = document.createElement('span');
        badge.style.cssText = colorTagSm(st.color);
        badge.textContent = st.emoji + ' ' + st.label;
        meta.appendChild(badge);
        if (p.notes) { const nb = document.createElement('span'); nb.className='meta-xs'; nb.textContent=p.notes; meta.appendChild(nb); }
        body.appendChild(meta);
        const nextStatus = { idea:'wip', wip:'mixing', mixing:'done', done:'idea' };
        row.onclick = () => { abletonData.projects[i].status = nextStatus[p.status||'idea']; saveAbletonData(); renderABLProjects(); updateABLStats(); };
        const right = document.createElement('div');
        right.className = 'd-flex-gs0';
        const pushBtn = document.createElement('button');
        pushBtn.className = 'pill pill-y';
        pushBtn.textContent = '📋'; pushBtn.title = 'Push to tasks';
        pushBtn.onclick = e => { e.stopPropagation(); ablQuickTask(ABL_GENRE[p.genre]||'🎶', 'Work on: '+p.title, p.notes||''); };
        const editBtn=_mEditBtn(()=>{ _ablEditProject=i; renderABLProjects(); });
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title:'Delete Project', message:`Delete "${p.title}"?`, confirmLabel:'Delete', onConfirm:() => { abletonData.projects.splice(i,1); saveAbletonData(); renderABLProjects(); updateABLStats(); } }); };
        right.appendChild(pushBtn); right.appendChild(editBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateABLStats();
}

function saveABLProject() {
    const title  = (document.getElementById('ablp-title')?.value  || '').trim();
    const genre  = document.getElementById('ablp-genre')?.value  || 'other';
    const status = document.getElementById('ablp-status')?.value || 'idea';
    const notes  = (document.getElementById('ablp-notes')?.value  || '').trim();
    if (!title) { document.getElementById('ablp-title')?.focus(); return; }
    abletonData.projects.push({ id:'p'+Date.now(), title, genre, status, notes });
    saveAbletonData();
    ['ablp-title','ablp-notes'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideABLForm('project'); renderABLProjects(); updateABLStats();
}


