    breakthrough: { emoji:'✨', label:'Breakthrough', color:'#34d399' },
    struggle:     { emoji:'💪', label:'Struggle',     color:'#f87171' },
    idea:         { emoji:'💡', label:'Idea',          color:'#fbbf24' },
