// ── QUICK TASK
function saxQuickTask(emoji, title, desc) {
    if (!gTasksAll['music']) gTasksAll['music'] = [];
    const already = gTasksAll['music'].find(t => t.text === title);
    if (already) { toast('Task already exists'); return; }
    gTasksAll['music'].push({ id:'saxqt_'+Date.now(), emoji, text: title, notes: desc||'', done:false, accentColor:'#fbbf24' });
    saveGTasksAll(); renderGTasks('music');
    toast('📌 Task added');
}

// ── TASKS (stubs — rendering handled by renderGTasks)
function renderSAXTasks() { renderGTasks('music'); }
function saveSAXTask() { showGTask('music'); }
function removeSAXTask(taskId) {
    if (!gTasksAll['music']) return;
    gTasksAll['music'] = gTasksAll['music'].filter(t => t.id !== String(taskId||''));
    saveGTasksAll(); renderGTasks('music');
}

function initSaxophoneSection() { /* now handled by initMusicSection */ }

