let guitarData = loadData('guitarData');

ensureArrays(guitarData, 'sessions', 'drills', 'repertoire', 'log', 'tasks');
if (!guitarData._seeded) guitarData._seeded = false;

if (!guitarData.drills.length && !guitarData._seeded) {
    guitarData.drills = [
        { key:'chromatic',  emoji:'🎸', label:'Chromatic warm-up (5 min)',           done:false },
        { key:'scales',     emoji:'🎵', label:'Major / minor scales (10 min)',        done:false },
        { key:'chords',     emoji:'🤘', label:'Chord transitions practice',          done:false },
        { key:'strumming',  emoji:'🥁', label:'Strumming / rhythm patterns',         done:false },
        { key:'song',       emoji:'🎶', label:'Work on current song (15 min)',        done:false },
    ];
}
if (!guitarData.tasks.length && !guitarData._seeded) {
    guitarData.tasks = [
        { id:'gtr_practice', emoji:'🎸', title:'Daily guitar practice session', desc:'Even 15 min counts.' },
    ];
}
guitarData._seeded = true;

const saveGuitarData = () => saveData('guitarData', guitarData);
saveGuitarData();

function showGTRForm(kind) {
    const el = document.getElementById('gtr-form-' + kind);
    if (!el) return;
    el.classList.add('visible');
    const f = el.querySelector('input,textarea,select');
    if (f) setTimeout(() => f.focus(), 60);
}
function hideGTRForm(kind) {
    const el = document.getElementById('gtr-form-' + kind);
    if (el) el.classList.remove('visible');
}

// ── STATS
function updateGTRStats() {
    const g = id => document.getElementById(id);
    if (g('gtr-stat-sessions'))    g('gtr-stat-sessions').textContent    = guitarData.sessions.length;
    if (g('gtr-stat-repertoire'))  g('gtr-stat-repertoire').textContent  = guitarData.repertoire.length;
    if (g('gtr-stat-log'))         g('gtr-stat-log').textContent         = guitarData.log.length;
}

