        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title:'Delete Session', message:`Delete this ${t.label} session?`, confirmLabel:'Delete', onConfirm:() => { guitarData.sessions.splice(i,1); saveGuitarData(); renderGTRSessions(); } }); };
        right.appendChild(pushBtn); right.appendChild(editBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
