// ════════════════════════════════════════════════════════
//  HEALTH SECTION (unified tabbed section)
// ════════════════════════════════════════════════════════

let _activeHealthTab = 'general-doctor';

function switchHealthTab(tab) {
    _activeHealthTab = tab;
    const tabs = ['general-doctor','dentist','ophthalmologist','dermatologist','psychologist'];
    tabs.forEach(t => {
        const panel = document.getElementById('health-panel-' + t);
        const btn   = document.getElementById('health-tab-' + t);
        if (panel) panel.style.display = t === tab ? '' : 'none';
        if (btn) {
            btn.style.background  = t === tab ? 'rgba(56,189,248,0.15)' : 'rgba(255,255,255,0.03)';
            btn.style.color       = t === tab ? '#38bdf8' : '#475569';
            btn.style.borderColor = t === tab ? 'rgba(56,189,248,0.4)'  : 'rgba(255,255,255,0.07)';
        }
    });
    if (tab === 'general-doctor')    { renderGDAppts(); renderGDHabits(); renderGDMeds(); renderGDLog(); updateGDStats(); renderGTasks('general-doctor'); }
    else if (tab === 'dentist')      { renderDentistAppts(); renderDentistRoutine(); renderDentistKit(); renderDentistLog(); updateDentistStats(); renderGTasks('dentist'); }
    else if (tab === 'ophthalmologist') { renderOphAppts(); renderOphHabits(); initOphRx(); renderOphLog(); updateOphStats(); renderGTasks('ophthalmologist'); }
    else if (tab === 'dermatologist'){ renderDRMAppts(); renderDRMHabits(); renderDRMRx(); renderDRMLog(); updateDRMStats(); renderGTasks('dermatologist'); }
    else if (tab === 'psychologist') { renderPSYSessions(); renderPSYHabits(); renderPSYTools(); renderPSYLog(); updatePSYStats(); renderGTasks('psychologist'); }
}

function initHealthSection() {
    if (!document.getElementById('resp-section-health')) return;

    // One-time migration: general-doctor
    if ((generalDoctorData.tasks || []).length && !(gTasksAll['general-doctor'] || []).length) {
        gTasksAll['general-doctor'] = generalDoctorData.tasks.map(t => ({
            id: t.id || ('gdqt_' + Date.now() + '_' + Math.random()),
            emoji: t.emoji || '',
            text: t.title || t.text || '',
            notes: t.desc || '',
            done: !!t.done,
            accentColor: '#38bdf8'
        }));
        saveGTasksAll();
    }

    // One-time migration: dentist
    if ((dentistData.tasks || []).length && !(gTasksAll['dentist'] || []).length) {
        gTasksAll['dentist'] = dentistData.tasks.map(t => ({
            id: t.id || ('dqt_' + Date.now() + '_' + Math.random()),
            emoji: t.emoji || '',
            text: t.title || t.text || '',
            notes: t.desc || '',
            done: !!t.done,
            accentColor: '#60a5fa'
        }));
        saveGTasksAll();
    }

    // One-time migration: ophthalmologist
    if ((ophthalmologistData.tasks || []).length && !(gTasksAll['ophthalmologist'] || []).length) {
        gTasksAll['ophthalmologist'] = ophthalmologistData.tasks.map(t => ({
            id: t.id || ('t' + Date.now() + '_' + Math.random()),
            emoji: t.emoji || '',
            text: t.title || t.text || '',
            notes: t.desc || '',
            done: !!t.done,
            accentColor: '#38bdf8'
        }));
        saveGTasksAll();
    }

    // One-time migration: dermatologist
    if ((dermData.tasks || []).length && !(gTasksAll['dermatologist'] || []).length) {
        gTasksAll['dermatologist'] = dermData.tasks.map(t => ({
            id: t.id || ('drmqt_' + Date.now() + '_' + Math.random()),
            emoji: t.emoji || '',
            text: t.title || t.text || '',
            notes: t.desc || '',
            done: !!t.done,
            accentColor: '#f9a8d4'
        }));
        saveGTasksAll();
    }

    // One-time migration: psychologist
    if ((psyData.tasks || []).length && !(gTasksAll['psychologist'] || []).length) {
        gTasksAll['psychologist'] = psyData.tasks.map(t => ({
            id: t.id || ('psyqt_' + Date.now() + '_' + Math.random()),
            emoji: t.emoji || '',
            text: t.title || t.text || '',
            notes: t.desc || '',
            done: !!t.done,
            accentColor: '#c4b5fd'
        }));
        saveGTasksAll();
    }

    switchHealthTab(_activeHealthTab);
}
window.switchHealthTab = switchHealthTab;
window.initHealthSection = initHealthSection;

// ════════════════════════════════════════════════════════
//  DERMATOLOGIST MODULE
// ════════════════════════════════════════════════════════

let dermData = {};
try {
    const raw = localStorage.getItem('dermData');
    dermData = JSON.parse(raw || '{}') || {};
} catch(e) { dermData = {}; }

ensureArrays(dermData, 'appts', 'habits', 'rx', 'log', 'tasks');
if (!dermData._seeded) dermData._seeded = false;

if (!dermData.habits.length && !dermData._seeded) {
    dermData.habits = [
        { key:'sunscreen',  emoji:'☀️',  label:'Apply sunscreen SPF50+',           done:false },
        { key:'cleanser',   emoji:'🧴',  label:'Gentle cleanser AM + PM',          done:false },
        { key:'moisturise', emoji:'💧',  label:'Moisturiser after cleansing',       done:false },
        { key:'treatment',  emoji:'💊',  label:'Apply prescribed treatment',        done:false },
        { key:'water',      emoji:'🥤',  label:'Stay hydrated (2L water)',          done:false },
        { key:'touch',      emoji:'🙅',  label:'No touching / picking face',        done:false },
    ];
}
if (!dermData.tasks.length && !dermData._seeded) {
    dermData.tasks = [
        { id:'drm_consult', emoji:'🧴', title:'Book dermatologist consultation', desc:'Find a clinic and schedule.' },
    ];
}
dermData._seeded = true;

const saveDermData = () => saveData('dermData', dermData);
saveDermData();

function showDRMForm(kind) {
    const el = document.getElementById('drm-form-' + kind);
    if (!el) return;
    el.classList.add('visible');
    const f = el.querySelector('input,textarea,select');
    if (f) setTimeout(() => f.focus(), 60);
}
function hideDRMForm(kind) {
    const el = document.getElementById('drm-form-' + kind);
    if (el) el.classList.remove('visible');
}

// ── STATS
function updateDRMStats() {
    const g = id => document.getElementById(id);
    if (g('drm-stat-appts'))  g('drm-stat-appts').textContent  = dermData.appts.length;
    const hDone = dermData.habits.filter(h => h.done).length;
    const hPct  = dermData.habits.length ? Math.round((hDone/dermData.habits.length)*100) : 0;
    if (g('drm-stat-habits')) g('drm-stat-habits').textContent = hPct + '%';
    if (g('drm-stat-rx'))     g('drm-stat-rx').textContent     = dermData.rx.length;
    if (g('drm-stat-log'))    g('drm-stat-log').textContent    = dermData.log.length;
}

// ── APPOINTMENT TYPE MAP
const DRM_APPT_TYPE = {
    consult:  { emoji:'🦷', label:'Consultation', color:'#f9a8d4' },
    followup: { emoji:'🔄', label:'Follow-up',    color:'#34d399' },
    biopsy:   { emoji:'🔬', label:'Biopsy',       color:'#f87171' },
    laser:    { emoji:'⚡', label:'Laser / Proc', color:'#a78bfa' },
    allergy:  { emoji:'🧪', label:'Allergy test', color:'#38bdf8' },
    other:    { emoji:'⚙️', label:'Other',        color:'#94a3b8' },
};

// ── APPOINTMENTS
function renderDRMAppts() {
    const list = document.getElementById('drm-appt-list');
    if (!list) return;
    list.innerHTML = '';
    if (!dermData.appts.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No appointments yet — add your next visit.</div>';
        updateDRMStats(); return;
    }
    dermData.appts.forEach((a, i) => {
        const t = DRM_APPT_TYPE[a.type] || DRM_APPT_TYPE.other;
        const row = document.createElement('div');
        row.style.cssText = 'display:flex;align-items:flex-start;gap:10px;padding:12px 14px;border-radius:13px;background:rgba(249,168,212,0.05);border:1px solid rgba(249,168,212,0.15);';

        const icon = document.createElement('div');
        icon.className = 'icon-xl';
        icon.textContent = t.emoji;

        const body = document.createElement('div');
        body.className = 'flex-1';
        const topRow = document.createElement('div');
        topRow.className = 'd-row-7w';

        const typeTag = document.createElement('span');
        typeTag.style.cssText = colorTag(t.color) + ';white-space:nowrap';
        typeTag.textContent = t.label;
        topRow.appendChild(typeTag);

        if (a.when) {
            const wb = document.createElement('span');
            wb.style.cssText = 'font-size:0.7em;font-weight:800;padding:2px 7px;border-radius:99px;background:rgba(249,168,212,0.1);color:#f9a8d4;border:1px solid rgba(249,168,212,0.2);white-space:nowrap;';
            wb.textContent = '📅 ' + a.when;
            topRow.appendChild(wb);
        }
        if (a.where) {
            const we = document.createElement('span');
            we.className = 'item-label';
            we.textContent = a.where;
            topRow.appendChild(we);
        }
        body.appendChild(topRow);
        if (a.notes) {
            const ne = document.createElement('div');
            ne.className = 'text-muted';
            ne.textContent = a.notes;
            body.appendChild(ne);
        }

        const right = document.createElement('div');
        right.className = 'd-flex-gs0';
        const pushBtn = document.createElement('button');
        pushBtn.style.cssText = 'padding:5px 9px;border-radius:8px;border:1px solid rgba(249,168,212,0.3);background:rgba(249,168,212,0.07);color:#f9a8d4;font-size:0.72em;font-weight:700;cursor:pointer;';
        pushBtn.textContent = '📋'; pushBtn.title = 'Push to tasks';
        pushBtn.onclick = e => { e.stopPropagation(); drmQuickTask(t.emoji, (a.where||t.label)+(a.when?' — '+a.when:''), a.notes||''); };
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️'; delBtn.title = 'Remove';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove appointment?', message: 'Delete this appointment? This cannot be undone.', confirmLabel: 'Remove', onConfirm: () => { dermData.appts.splice(i,1); saveDermData(); renderDRMAppts(); } }); };
        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateDRMStats();
}

function saveDRMAppt() {
    const type  = document.getElementById('drm-appt-type')?.value || 'other';
    const date  = (document.getElementById('drm-appt-date')?.value  || '').trim();
    const time  = (document.getElementById('drm-appt-time')?.value  || '').trim();
    const when  = [date, time].filter(Boolean).join(' ');
    const where = (document.getElementById('drm-appt-where')?.value || '').trim();
    const notes = (document.getElementById('drm-appt-notes')?.value || '').trim();
    if (!date && !where) { document.getElementById('drm-appt-date')?.focus(); return; }
    dermData.appts.push({ id:'a'+Date.now(), type, when, date, time, where, notes });
    saveDermData();
    ['drm-appt-date','drm-appt-time','drm-appt-where','drm-appt-notes'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideDRMForm('appt'); renderDRMAppts();
}

// ── SKIN CARE HABITS
function renderDRMHabits() {
    const list = document.getElementById('drm-habits-list');
    if (!list) return;
    list.innerHTML = '';
    const total = dermData.habits.length;
    const done  = dermData.habits.filter(h => h.done).length;
    const pct   = total ? Math.round((done/total)*100) : 0;
    const bar   = document.getElementById('drm-habits-bar'); if (bar) bar.style.width = pct + '%';
    const pctEl = document.getElementById('drm-habits-pct'); if (pctEl) pctEl.textContent = pct + '%';

    dermData.habits.forEach((h, i) => {
        const row = document.createElement('div');
        row.className = `ir ${h.done ? 'ir-g' : ''}`;

        const emojiEl = document.createElement('div');
        emojiEl.className = 'icon-26';
        emojiEl.textContent = h.emoji || '🧴';

        const cb = document.createElement('div');
        cb.style.cssText = chk('#34d399',h.done);
        cb.textContent = h.done ? '✓' : '';

        const labelEl = document.createElement('div');
        labelEl.className = `done-label done-g ${h.done ? 'done' : ''}`;
        labelEl.textContent = h.label;

        const toggle = () => { dermData.habits[i].done = !h.done; saveDermData(); renderDRMHabits(); updateDRMStats(); };
        [row, cb, labelEl].forEach(el => el.onclick = toggle);

        const pushBtn = document.createElement('button');
        pushBtn.className = 'pill pill-g';
        pushBtn.textContent = '📋'; pushBtn.title = 'Push to tasks';
        pushBtn.onclick = e => { e.stopPropagation(); drmQuickTask(h.emoji||'🧴', h.label, 'Skin care routine'); };

        const delBtn = document.createElement('button');
        delBtn.className = 'mini-btn';
        delBtn.textContent = '✕';
        delBtn.onmouseover = () => { delBtn.style.color='#f87171'; delBtn.style.borderColor='rgba(248,113,113,0.3)'; };
        delBtn.onmouseout  = () => { delBtn.style.color='#475569'; delBtn.style.borderColor='rgba(255,255,255,0.07)'; };
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove habit?', message: 'Delete this skincare habit?', confirmLabel: 'Remove', onConfirm: () => { dermData.habits.splice(i,1); saveDermData(); renderDRMHabits(); updateDRMStats(); } }); };

        row.appendChild(emojiEl); row.appendChild(cb); row.appendChild(labelEl); row.appendChild(pushBtn); row.appendChild(delBtn);
        list.appendChild(row);
    });
    updateDRMStats();
}

function saveDRMHabit() {
    const emoji = (document.getElementById('drmh-emoji')?.value || '').trim() || '🧴';
    const label = (document.getElementById('drmh-label')?.value || '').trim();
    if (!label) { document.getElementById('drmh-label')?.focus(); return; }
    dermData.habits.push({ key:'h'+Date.now(), emoji, label, done:false });
    saveDermData();
    ['drmh-emoji','drmh-label'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideDRMForm('habit'); renderDRMHabits(); updateDRMStats();
}

function resetDRMHabits() {
    dermData.habits.forEach(h => h.done = false);
    saveDermData(); renderDRMHabits(); updateDRMStats();
    toast('🔄 Routine reset');
}

// ── TREATMENTS & PRESCRIPTIONS
function renderDRMRx() {
    const list = document.getElementById('drm-rx-list');
    if (!list) return;
    list.innerHTML = '';
    if (!dermData.rx.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No treatments added yet.</div>';
        updateDRMStats(); return;
    }
    dermData.rx.forEach((m, i) => {
        const row = document.createElement('div');
        row.className = `ir ${m.taken ? 'ir-y' : ''}`;

        const emojiEl = document.createElement('div');
        emojiEl.className = 'icon-26';
        emojiEl.textContent = m.emoji || '🧴';

        const cb = document.createElement('div');
        cb.style.cssText = chk('#fbbf24',m.taken);
        cb.textContent = m.taken ? '✓' : '';

        const body = document.createElement('div');
        body.className = 'flex-1';
        const nameEl = document.createElement('div');
        nameEl.style.cssText = `font-size:0.87em;font-weight:${m.taken?700:600};color:${m.taken?'#fbbf24':'#cbd5e1'};text-decoration:${m.taken?'line-through':'none'};`;
        nameEl.textContent = m.name;
        body.appendChild(nameEl);
        if (m.freq) {
            const freqEl = document.createElement('div');
            freqEl.style.marginTop = '3px';
            freqEl.innerHTML = `<span style="font-size:0.68em;font-weight:800;padding:2px 7px;border-radius:99px;background:rgba(251,191,36,0.1);color:#fbbf24;border:1px solid rgba(251,191,36,0.2);text-transform:uppercase;letter-spacing:0.6px;">${m.freq}</span>`;
            body.appendChild(freqEl);
        }

        const toggle = () => { dermData.rx[i].taken = !m.taken; saveDermData(); renderDRMRx(); };
        [row, cb, body].forEach(el => el.onclick = toggle);

        const delBtn = document.createElement('button');
        delBtn.className = 'mini-btn';
        delBtn.textContent = '✕';
        delBtn.onmouseover = () => { delBtn.style.color='#f87171'; delBtn.style.borderColor='rgba(248,113,113,0.3)'; };
        delBtn.onmouseout  = () => { delBtn.style.color='#475569'; delBtn.style.borderColor='rgba(255,255,255,0.07)'; };
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title: 'Remove prescription?', message: 'Delete this prescription item?', confirmLabel: 'Remove', onConfirm: () => { dermData.rx.splice(i,1); saveDermData(); renderDRMRx(); updateDRMStats(); } }); };

        row.appendChild(emojiEl); row.appendChild(cb); row.appendChild(body); row.appendChild(delBtn);
        list.appendChild(row);
    });
    updateDRMStats();
}

function saveDRMRx() {
    const emoji = (document.getElementById('drmrx-emoji')?.value || '').trim() || '🧴';
    const name  = (document.getElementById('drmrx-name')?.value  || '').trim();
    const freq  = (document.getElementById('drmrx-freq')?.value  || '').trim();
    if (!name) { document.getElementById('drmrx-name')?.focus(); return; }
    dermData.rx.push({ key:'rx'+Date.now(), emoji, name, freq, taken:false });
    saveDermData();
    ['drmrx-emoji','drmrx-name','drmrx-freq'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideDRMForm('rx'); renderDRMRx(); updateDRMStats();
}

function resetDRMRx() {
    dermData.rx.forEach(m => m.taken = false);
    saveDermData(); renderDRMRx();
    toast('🔄 Treatments reset');
}

// ── SKIN LOG
const DRM_LOG_TYPE = {
    flareup:  { emoji:'🔥', label:'Flare-up',  color:'#f87171' },
    reaction: { emoji:'⚠️', label:'Reaction',  color:'#fb923c' },
    question: { emoji:'❓', label:'Question',  color:'#38bdf8' },
    rxupdate: { emoji:'💊', label:'Rx update', color:'#fbbf24' },
    progress: { emoji:'✨', label:'Progress',  color:'#34d399' },
    note:     { emoji:'📝', label:'Note',      color:'#94a3b8' },
};

function renderDRMLog() {
    const list = document.getElementById('drm-log-list');
    if (!list) return;
    list.innerHTML = '';
    if (!dermData.log.length) {
        list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No entries yet. Log flare-ups, reactions, or questions for your next visit.</div>';
        updateDRMStats(); return;
    }
    [...dermData.log].reverse().forEach((e, revIdx) => {
        const realIdx = dermData.log.length - 1 - revIdx;
        const t = DRM_LOG_TYPE[e.type] || DRM_LOG_TYPE.note;
        const row = document.createElement('div');
        row.className = 'card-p';

        const icon = document.createElement('div');
        icon.className = 'icon-lg';
        icon.textContent = t.emoji;

        const body = document.createElement('div');
        body.className = 'flex-1';
        const topRow = document.createElement('div');
        topRow.className = 'd-row-7w';

        const typeTag = document.createElement('span');
        typeTag.style.cssText = colorTag(t.color);
        typeTag.textContent = t.label;
        topRow.appendChild(typeTag);

        if (e.date) {
            const dateBadge = document.createElement('span');
            dateBadge.className = 'meta-dim';
            dateBadge.textContent = '📅 ' + e.date;
            topRow.appendChild(dateBadge);
        }
        body.appendChild(topRow);
        if (e.text) {
            const textEl = document.createElement('div');
            textEl.className = 'note-text';
            textEl.textContent = e.text;
            body.appendChild(textEl);
        }

        const right = document.createElement('div');
        right.className = 'd-flex-gs0';
        const pushBtn = document.createElement('button');
        pushBtn.title = 'Push to tasks';
        pushBtn.className = 'pill pill-p';
        pushBtn.textContent = '📋';
        pushBtn.onclick = ev => { ev.stopPropagation(); drmQuickTask(t.emoji, t.label+(e.date?' — '+e.date:''), e.text?.slice(0,40)||''); };
        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️'; delBtn.title = 'Remove';
        delBtn.onclick = ev => { ev.stopPropagation(); showConfirm({ title: 'Remove log entry?', message: 'Delete this log entry?', confirmLabel: 'Remove', onConfirm: () => { dermData.log.splice(realIdx,1); saveDermData(); renderDRMLog(); updateDRMStats(); } }); };
        right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(icon); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    updateDRMStats();
}

function saveDRMLog() {
    const type = document.getElementById('drml-type')?.value || 'note';
    const date = (document.getElementById('drml-date')?.value || '').trim();
    const text = (document.getElementById('drml-text')?.value || '').trim();
    if (!text) { document.getElementById('drml-text')?.focus(); return; }
    dermData.log.push({ id:'l'+Date.now(), type, date, text });
    saveDermData();
    ['drml-date','drml-text'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    hideDRMForm('log'); renderDRMLog(); updateDRMStats();
}

// ── QUICK TASK
function drmQuickTask(emoji, title, desc) {
    if (!gTasksAll['dermatologist']) gTasksAll['dermatologist'] = [];
    const already = gTasksAll['dermatologist'].find(t => (t.text === title || t.title === title) && !t.done);
    if (already) { toast('Task already exists'); return; }
    gTasksAll['dermatologist'].push({ id: 'drmqt_' + Date.now(), emoji, text: title, notes: desc || '', done: false, accentColor: '#f9a8d4' });
    saveGTasksAll(); renderDRMTasks();
    toast('📌 Task added');
}

// ── TASKS
function renderDRMTasks() {
    renderGTasks('dermatologist');
    try { ['r1','r2','r3'].forEach(slot => { if(rSlots&&(rSlots[slot]==='dermatologist'||rSlots[slot]==='health')) renderRTasks(slot); }); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e) {}
}

function saveDRMTask() { hideDRMForm('task'); showGTask('dermatologist'); }
function removeDRMTask() { renderDRMTasks(); }

function initDermatologistSection() {
    if (!document.getElementById('resp-section-dermatologist')) return;
    // One-time migration from dermData.tasks → gTasksAll['dermatologist']
    if ((dermData.tasks || []).length && !(gTasksAll['dermatologist'] || []).length) {
        gTasksAll['dermatologist'] = dermData.tasks.map(t => ({
            id: t.id || ('drmqt_' + Date.now() + '_' + Math.random()),
            emoji: t.emoji || '',
            text: t.title || t.text || '',
            notes: t.desc || '',
            done: !!t.done,
            accentColor: '#f9a8d4'
        }));
        saveGTasksAll();
    }
    renderDRMAppts();
    renderDRMHabits();
    renderDRMRx();
    renderDRMLog();
    renderDRMTasks();
    updateDRMStats();
}

// ════════════════════════════════════════════════════════
//  SHOPPING MODULE (Buy List + Wishlist + Gifts + Tasks)
// ════════════════════════════════════════════════════════

let __shoppingFirstLoad = false;
// ════════════════════════════════════════════════════════
//  SHOPPING MODULE  (Buy List + Wishlist + Gifts + Tasks)
// ════════════════════════════════════════════════════════

let shoppingData = {};
try {
    const raw = localStorage.getItem('shoppingData');
    __shoppingFirstLoad = (raw === null);
    shoppingData = JSON.parse(raw || '{}') || {};
} catch(e) {
    __shoppingFirstLoad = true;
    shoppingData = {};
}

ensureArrays(shoppingData, 'buy', 'wishlist', 'tasks');

const saveShoppingData = () => saveData('shoppingData', shoppingData);

function showShoppingForm(kind){
    const el = document.getElementById('shopping-form-' + kind);
    if (el) { el.classList.add('visible'); const f = el.querySelector('input'); if(f) f.focus(); }
}
function hideShoppingForm(kind){
    const el = document.getElementById('shopping-form-' + kind);
    if (el) el.classList.remove('visible');
}

// ── STATS ────────────────────────────────────────────────
function updateShoppingStats(){
    const g = id => document.getElementById(id);
    const pending = (shoppingData.buy || []).filter(x => !x.done).length;
    const done    = (shoppingData.buy || []).filter(x =>  x.done).length;
    if (g('shop-stat-buy'))   g('shop-stat-buy').textContent   = pending;
    if (g('shop-stat-wish'))  g('shop-stat-wish').textContent  = (shoppingData.wishlist || []).length;
    if (g('shop-stat-done'))  g('shop-stat-done').textContent  = done;
}

// ── BUY FILTER ───────────────────────────────────────────
let _shopBuyFilter = 'all';
function setShopBuyFilter(f) { _shopBuyFilter = f; renderShoppingBuy(); }
function cancelShopBuyFilter() { _shopBuyFilter = 'all'; renderShoppingBuy(); }

function _renderShopBuyFilters() {
    const row = document.getElementById('shop-buy-filter-row');
    if (!row) return;
    const FILTERS = [
        { key:'all',     label:'All',     c:'#fbbf24', bg:'rgba(251,191,36,0.18)', bd:'rgba(251,191,36,0.45)' },
        { key:'pending', label:'Pending', c:'#fbbf24', bg:'rgba(251,191,36,0.10)', bd:'rgba(251,191,36,0.25)' },
        { key:'bought',  label:'Bought',  c:'#34d399', bg:'rgba(52,211,153,0.10)', bd:'rgba(52,211,153,0.25)' },
    ];
    row.innerHTML = '';
    FILTERS.forEach(f => {
        const active = _shopBuyFilter === f.key;
        const btn = document.createElement('button');
        btn.style.cssText = `padding:5px 12px;border-radius:99px;font-size:0.75em;font-weight:800;cursor:pointer;border:1px solid ${active ? f.bd : 'rgba(255,255,255,0.07)'};background:${active ? f.bg : 'rgba(255,255,255,0.03)'};color:${active ? f.c : '#475569'};transition:all 0.15s;font-family:'Outfit',sans-serif;`;
        btn.textContent = f.label;
        btn.onclick = () => setShopBuyFilter(f.key);
        row.appendChild(btn);
    });
}

function _renderShopBuySummary() {
    const el = document.getElementById('shop-buy-summary');
    if (!el) return;
    const items = shoppingData.buy || [];
    if (!items.length) { el.innerHTML = ''; return; }
    const pending = items.filter(x => !x.done).length;
    const bought  = items.filter(x =>  x.done).length;
    let html = '';
    if (pending) html += `<span style="font-size:0.72em;font-weight:800;padding:3px 9px;border-radius:20px;background:rgba(251,191,36,0.1);color:#fbbf24;border:1px solid rgba(251,191,36,0.25);">🛒 ${pending} pending</span>`;
    if (bought)  html += `<span style="font-size:0.72em;font-weight:800;padding:3px 9px;border-radius:20px;background:rgba(52,211,153,0.1);color:#34d399;border:1px solid rgba(52,211,153,0.25);">✓ ${bought} bought</span>`;
    el.innerHTML = html;
}

function clearShoppingBought() {
    showConfirm({ title:'Clear bought items', message:'Remove all <strong>bought</strong> items from your buy list?', confirmLabel:'Clear', confirmColor:'#ef4444', onConfirm() { shoppingData.buy = shoppingData.buy.filter(x => !x.done); saveShoppingData(); renderShoppingBuy(); } });
}

// ── WISH FILTER ──────────────────────────────────────────
let _shopWishFilter = 'all';
function setShopWishFilter(f) { _shopWishFilter = f; renderShoppingWish(); }

function _renderShopWishFilters() {
    const row = document.getElementById('shop-wish-filter-row');
    if (!row) return;
    const FILTERS = [
        { key:'all',    label:'All',       c:'#38bdf8', bg:'rgba(56,189,248,0.18)', bd:'rgba(56,189,248,0.45)' },
        { key:'High',   label:'🔴 High',   c:'#f87171', bg:'rgba(248,113,113,0.12)', bd:'rgba(248,113,113,0.35)' },
        { key:'Medium', label:'🟡 Medium', c:'#fbbf24', bg:'rgba(251,191,36,0.12)',  bd:'rgba(251,191,36,0.35)'  },
        { key:'Low',    label:'🔵 Low',    c:'#38bdf8', bg:'rgba(56,189,248,0.12)',  bd:'rgba(56,189,248,0.35)'  },
    ];
    row.innerHTML = '';
    FILTERS.forEach(f => {
        const active = _shopWishFilter === f.key;
        const btn = document.createElement('button');
        btn.style.cssText = `padding:5px 12px;border-radius:99px;font-size:0.75em;font-weight:800;cursor:pointer;border:1px solid ${active ? f.bd : 'rgba(255,255,255,0.07)'};background:${active ? f.bg : 'rgba(255,255,255,0.03)'};color:${active ? f.c : '#475569'};transition:all 0.15s;font-family:'Outfit',sans-serif;`;
        btn.textContent = f.label;
        btn.onclick = () => setShopWishFilter(f.key);
        row.appendChild(btn);
    });
}

function _renderShopWishSummary() {
    const el = document.getElementById('shop-wish-summary');
    if (!el) return;
    const items = shoppingData.wishlist || [];
    if (!items.length) { el.innerHTML = ''; return; }
    const high   = items.filter(x => x.priority === 'High').length;
    const medium = items.filter(x => x.priority === 'Medium').length;
    const low    = items.filter(x => (x.priority || 'Low') === 'Low').length;
    let html = '';
    if (high)   html += `<span style="font-size:0.72em;font-weight:800;padding:3px 9px;border-radius:20px;background:rgba(248,113,113,0.1);color:#f87171;border:1px solid rgba(248,113,113,0.25);">🔴 ${high} High</span>`;
    if (medium) html += `<span style="font-size:0.72em;font-weight:800;padding:3px 9px;border-radius:20px;background:rgba(251,191,36,0.1);color:#fbbf24;border:1px solid rgba(251,191,36,0.25);">🟡 ${medium} Medium</span>`;
    if (low)    html += `<span style="font-size:0.72em;font-weight:800;padding:3px 9px;border-radius:20px;background:rgba(56,189,248,0.1);color:#38bdf8;border:1px solid rgba(56,189,248,0.25);">🔵 ${low} Low</span>`;
    el.innerHTML = html;
}

function moveWishToBuy(itemId) {
    const idx = shoppingData.wishlist.findIndex(x => x.id === itemId);
    const it  = shoppingData.wishlist[idx];
    if (!it) return;
    shoppingData.buy.push({ id:'b'+Date.now(), emoji: it.emoji||'🛒', title: it.title, store:'', notes: it.notes||'', link:'', done:false });
    shoppingData.wishlist.splice(idx, 1);
    saveShoppingData(); renderShoppingBuy(); renderShoppingWish();
    toast('🛒 Moved to Buy List');
}

// ── QUICK TASK ───────────────────────────────────────────
function shoppingQuickTask(emoji, title, desc){
    if (!gTasksAll['shopping']) gTasksAll['shopping'] = [];
    const already = gTasksAll['shopping'].find(t => (t.text === title || t.title === title) && !t.done);
    if (already) { toast('Task already exists'); return; }
    gTasksAll['shopping'].push({ id: 'sqt_' + Date.now(), emoji, text: title, notes: desc || '', done: false, accentColor: '#fbbf24' });
    saveGTasksAll(); renderShoppingTasks();
    toast('📌 Task added');
}

// ── BUY LIST ─────────────────────────────────────────────
function renderShoppingBuy(){
    _renderShopBuyFilters();
    _renderShopBuySummary();
    const list = document.getElementById('shopping-buy-list');
    if (!list) return;
    list.innerHTML = '';

    const allItems = shoppingData.buy || [];
    const boughtExist = allItems.some(x => x.done);

    // Clear bought button — appears below the list when bought items exist
    const clearBoughtBtn = document.getElementById('shop-clear-bought-btn');
    if (clearBoughtBtn) clearBoughtBtn.style.display = boughtExist ? '' : 'none';

    const items = _shopBuyFilter === 'all' ? allItems
        : _shopBuyFilter === 'pending' ? allItems.filter(x => !x.done)
        : allItems.filter(x => x.done);

    if (!items.length) {
        list.innerHTML = `<div style="color:#475569;font-size:0.88em;padding:8px 2px;">${_shopBuyFilter !== 'all' ? 'No ' + _shopBuyFilter + ' items.' : 'No items yet. Add what you need to buy.'}</div>`;
        updateShoppingStats(); return;
    }

    items.forEach((it, _) => {
        const idx = allItems.indexOf(it);
        const row = document.createElement('div');
        row.className = 'shop-buy-item';
        row.setAttribute('data-bidx', idx);
        row.style.cssText = `display:flex;align-items:center;gap:8px;padding:11px 13px;border-radius:12px;transition:all 0.2s;border:1px solid ${it.done ? 'rgba(52,211,153,0.3)' : 'rgba(251,191,36,0.18)'};background:${it.done ? 'rgba(52,211,153,0.06)' : 'rgba(251,191,36,0.05)'};`;

        // drag handle
        const handle = document.createElement('span');
        handle.className = 'dnd-handle';
        handle.title = 'Drag to reorder';
        handle.innerHTML = '&#8942;&#8942;';

        // emoji (inline-editable)
        const emojiEl = document.createElement('div');
        emojiEl.contentEditable = 'true';
        emojiEl.spellcheck = false;
        emojiEl.style.cssText = 'font-size:1.3em;flex-shrink:0;width:28px;text-align:center;outline:none;cursor:text;';
        emojiEl.textContent = it.emoji || '🛒';
        emojiEl.addEventListener('click', e => e.stopPropagation());
        emojiEl.addEventListener('keydown', e => { if (e.key === 'Enter') { e.preventDefault(); emojiEl.blur(); } });
        emojiEl.addEventListener('blur', () => {
            shoppingData.buy[idx].emoji = emojiEl.textContent.trim() || '🛒';
            saveShoppingData();
        });

        // body
        const body = document.createElement('div');
        body.className = 'flex-1';

        const titleEl = document.createElement('div');
        titleEl.contentEditable = 'true';
        titleEl.spellcheck = false;
        titleEl.style.cssText = `font-weight:800;font-size:0.92em;color:${it.done?'#34d399':'#e2e8f0'};text-decoration:${it.done?'line-through':'none'};outline:none;cursor:text;`;
        titleEl.textContent = it.title || '';
        titleEl.addEventListener('click', e => e.stopPropagation());
        titleEl.addEventListener('keydown', e => { if (e.key === 'Enter') { e.preventDefault(); titleEl.blur(); } });
        titleEl.addEventListener('blur', () => {
            const v = titleEl.textContent.trim();
            if (v) { shoppingData.buy[idx].title = v; saveShoppingData(); }
        });
        body.appendChild(titleEl);

        const storeEl = document.createElement('div');
        storeEl.contentEditable = 'true';
        storeEl.spellcheck = false;
        storeEl.style.cssText = 'color:#64748b;font-size:0.8em;margin-top:3px;outline:none;cursor:text;min-height:1em;';
        storeEl.textContent = [it.store ? '📍 '+it.store : '', it.notes].filter(Boolean).join(' · ');
        storeEl.dataset.placeholder = '📍 Store · notes...';
        storeEl.addEventListener('click', e => e.stopPropagation());
        storeEl.addEventListener('keydown', e => { if (e.key === 'Enter') { e.preventDefault(); storeEl.blur(); } });
        storeEl.addEventListener('blur', () => {
            const raw = storeEl.textContent.trim();
            const m = raw.match(/^📍\s*([^·]+?)(?:\s*·\s*(.*))?$/s);
            if (m) { shoppingData.buy[idx].store = m[1].trim(); shoppingData.buy[idx].notes = (m[2]||'').trim(); }
            else { shoppingData.buy[idx].store = ''; shoppingData.buy[idx].notes = raw; }
            saveShoppingData();
        });
        body.appendChild(storeEl);

        if (it.link) {
            const link = document.createElement('a');
            link.href = it.link; link.target = '_blank';
            link.style.cssText = 'display:inline-block;margin-top:3px;font-size:0.75em;color:#38bdf8;text-decoration:none;';
            link.textContent = '🔗 Link';
            link.addEventListener('click', e => e.stopPropagation());
            body.appendChild(link);
        }

        // right actions
        const right = document.createElement('div');
        right.className = 'd-flex-ai-gs0';

        const doneBtn = document.createElement('button');
        doneBtn.title = it.done ? 'Mark as pending' : 'Mark as bought';
        doneBtn.style.cssText = `padding:5px 9px;border-radius:8px;font-size:0.8em;font-weight:800;cursor:pointer;transition:all 0.15s;border:1px solid ${it.done ? 'rgba(52,211,153,0.4)' : 'rgba(251,191,36,0.3)'};background:${it.done ? 'rgba(52,211,153,0.12)' : 'rgba(251,191,36,0.08)'};color:${it.done ? '#34d399' : '#fbbf24'};`;
        doneBtn.textContent = it.done ? '✓' : '○';
        doneBtn.onclick = e => {
            e.stopPropagation();
            shoppingData.buy[idx].done = !shoppingData.buy[idx].done;
            saveShoppingData(); renderShoppingBuy();
        };

        if (!it.done) {
            const pushBtn = document.createElement('button');
            pushBtn.title = 'Push to tasks';
            pushBtn.className = 'pill pill-y';
            pushBtn.textContent = '📋';
            pushBtn.onclick = e => { e.stopPropagation(); shoppingQuickTask(it.emoji||'🛒','Buy: '+it.title, it.store||''); };
            right.appendChild(pushBtn);
        }

        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn';
        delBtn.textContent = '🗑️'; delBtn.title = 'Remove';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title:'Remove item', message:`Remove "<strong>${it.title}</strong>" from your buy list?`, confirmLabel:'Remove', confirmColor:'#ef4444', onConfirm(){ shoppingData.buy.splice(idx,1); saveShoppingData(); renderShoppingBuy(); } }); };

        right.appendChild(doneBtn);
        right.appendChild(delBtn);
        row.appendChild(handle); row.appendChild(emojiEl); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    _initShopBuyDnd(list);
    updateShoppingStats();
}

function saveShoppingBuy(){
    const title = (document.getElementById('sb-title')?.value || '').trim();
    if (!title) { document.getElementById('sb-title')?.focus(); return; }
    const emoji = (document.getElementById('sb-emoji')?.value || '').trim() || '🛒';
    const store = (document.getElementById('sb-store')?.value || '').trim();
    const notes = (document.getElementById('sb-notes')?.value || '').trim();
    const link  = (document.getElementById('sb-link')?.value || '').trim();
    shoppingData.buy.push({ id:'b'+Date.now(), emoji, title, store, notes, link, done:false });
    ['sb-emoji','sb-title','sb-store','sb-notes','sb-link'].forEach(i => { const el=document.getElementById(i); if(el) el.value=''; });
    saveShoppingData(); renderShoppingBuy(); hideShoppingForm('buy');
}

// ── WISHLIST ─────────────────────────────────────────────
const WISH_PRIORITY = {
    Low:    { label:'🔵 Low',    bg:'rgba(56,189,248,0.1)',  bd:'rgba(56,189,248,0.3)',  c:'#38bdf8' },
    Medium: { label:'🟡 Medium', bg:'rgba(251,191,36,0.1)', bd:'rgba(251,191,36,0.35)', c:'#fbbf24' },
    High:   { label:'🔴 High',   bg:'rgba(248,113,113,0.1)',bd:'rgba(248,113,113,0.35)',c:'#f87171' },
};

function renderShoppingWish(){
    _renderShopWishFilters();
    _renderShopWishSummary();
    const list = document.getElementById('shopping-wishlist');
    if (!list) return;
    list.innerHTML = '';

    const allItems = shoppingData.wishlist || [];
    const items = _shopWishFilter === 'all' ? allItems : allItems.filter(x => (x.priority || 'Low') === _shopWishFilter);

    if (!items.length) {
        list.innerHTML = `<div style="color:#475569;font-size:0.88em;padding:8px 2px;">${_shopWishFilter !== 'all' ? 'No ' + _shopWishFilter + ' priority items.' : 'No wishlist items yet. Capture what you want to buy eventually.'}</div>`;
        updateShoppingStats(); return;
    }

    items.forEach((it, _) => {
        const idx = allItems.indexOf(it);
        const p   = WISH_PRIORITY[it.priority] || WISH_PRIORITY.Low;
        const row = document.createElement('div');
        row.className = 'shop-wish-item';
        row.setAttribute('data-widx', idx);
        row.style.cssText = 'display:flex;align-items:center;gap:8px;padding:11px 13px;border-radius:12px;background:rgba(56,189,248,0.04);border:1px solid rgba(56,189,248,0.12);transition:all 0.15s;';

        // drag handle
        const handle = document.createElement('span');
        handle.className = 'dnd-handle';
        handle.title = 'Drag to reorder';
        handle.innerHTML = '&#8942;&#8942;';

        // emoji (inline-editable)
        const emojiEl = document.createElement('div');
        emojiEl.contentEditable = 'true';
        emojiEl.spellcheck = false;
        emojiEl.style.cssText = 'font-size:1.3em;flex-shrink:0;width:28px;text-align:center;outline:none;cursor:text;';
        emojiEl.textContent = it.emoji || '⭐';
        emojiEl.addEventListener('click', e => e.stopPropagation());
        emojiEl.addEventListener('keydown', e => { if (e.key === 'Enter') { e.preventDefault(); emojiEl.blur(); } });
        emojiEl.addEventListener('blur', () => {
            shoppingData.wishlist[idx].emoji = emojiEl.textContent.trim() || '⭐';
            saveShoppingData();
        });

        const body = document.createElement('div');
        body.className = 'flex-1';

        const titleEl = document.createElement('div');
        titleEl.contentEditable = 'true';
        titleEl.spellcheck = false;
        titleEl.style.cssText = 'font-weight:800;font-size:0.92em;color:#e2e8f0;outline:none;cursor:text;';
        titleEl.textContent = it.title || '';
        titleEl.addEventListener('click', e => e.stopPropagation());
        titleEl.addEventListener('keydown', e => { if (e.key === 'Enter') { e.preventDefault(); titleEl.blur(); } });
        titleEl.addEventListener('blur', () => {
            const v = titleEl.textContent.trim();
            if (v) { shoppingData.wishlist[idx].title = v; saveShoppingData(); }
        });
        body.appendChild(titleEl);

        const notesEl = document.createElement('div');
        notesEl.contentEditable = 'true';
        notesEl.spellcheck = false;
        notesEl.style.cssText = 'color:#64748b;font-size:0.8em;margin-top:3px;outline:none;cursor:text;min-height:1em;';
        notesEl.textContent = it.notes || '';
        notesEl.dataset.placeholder = 'Notes...';
        notesEl.addEventListener('click', e => e.stopPropagation());
        notesEl.addEventListener('keydown', e => { if (e.key === 'Enter') { e.preventDefault(); notesEl.blur(); } });
        notesEl.addEventListener('blur', () => {
            shoppingData.wishlist[idx].notes = notesEl.textContent.trim();
            saveShoppingData();
        });
        body.appendChild(notesEl);

        const right = document.createElement('div');
        right.className = 'd-flex-ai-gs0';

        // priority pill — click cycles
        const pill = document.createElement('button');
        pill.style.cssText = `cursor:pointer;border-radius:99px;padding:4px 10px;font-weight:800;font-size:0.72em;border:1px solid ${p.bd};background:${p.bg};color:${p.c};white-space:nowrap;transition:all 0.15s;`;
        pill.textContent = p.label;
        pill.title = 'Tap to cycle priority';
        pill.onclick = e => {
            e.stopPropagation();
            const o = ['Low','Medium','High'];
            const cur = o.indexOf(it.priority || 'Low');
            shoppingData.wishlist[idx].priority = o[(cur+1)%o.length];
            saveShoppingData(); renderShoppingWish();
        };

        const moveBtn = document.createElement('button');
        moveBtn.title = 'Move to Buy List';
        moveBtn.style.cssText = 'padding:4px 10px;border-radius:99px;font-size:0.72em;font-weight:800;cursor:pointer;border:1px solid rgba(251,191,36,0.35);background:rgba(251,191,36,0.08);color:#fbbf24;white-space:nowrap;transition:all 0.15s;';
        moveBtn.textContent = '→ Buy';
        moveBtn.onclick = e => { e.stopPropagation(); moveWishToBuy(it.id); };

        const pushBtn = document.createElement('button');
        pushBtn.title = 'Push to tasks';
        pushBtn.className = 'pill pill-b';
        pushBtn.textContent = '📋';
        pushBtn.onclick = e => { e.stopPropagation(); shoppingQuickTask(it.emoji||'⭐','Research: '+it.title, it.notes||''); };

        const delBtn = document.createElement('button');
        delBtn.className = 'house-delete-btn';
        delBtn.textContent = '🗑️'; delBtn.title = 'Remove';
        delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title:'Remove wishlist item', message:`Remove "<strong>${it.title}</strong>" from your wishlist?`, confirmLabel:'Remove', confirmColor:'#ef4444', onConfirm(){ shoppingData.wishlist.splice(idx,1); saveShoppingData(); renderShoppingWish(); } }); };

        right.appendChild(pill); right.appendChild(moveBtn); right.appendChild(pushBtn); right.appendChild(delBtn);
        row.appendChild(handle); row.appendChild(emojiEl); row.appendChild(body); row.appendChild(right);
        list.appendChild(row);
    });
    _initShopWishDnd(list);
    updateShoppingStats();
}

function saveShoppingWish(){
    const title = (document.getElementById('sw-title')?.value || '').trim();
    if (!title) { document.getElementById('sw-title')?.focus(); return; }
    const emoji    = (document.getElementById('sw-emoji')?.value    || '').trim() || '⭐';
    const notes    = (document.getElementById('sw-notes')?.value    || '').trim();
    const priority = (document.getElementById('sw-priority')?.value || 'Low').trim();
    shoppingData.wishlist.push({ id:'w'+Date.now(), emoji, title, notes, priority });
    ['sw-emoji','sw-title','sw-notes'].forEach(i => { const el=document.getElementById(i); if(el) el.value=''; });
    saveShoppingData(); renderShoppingWish(); hideShoppingForm('wish');
}

// ── SHOPPING DnD ─────────────────────────────────────────
function _initShopBuyDnd(container) {
    if (!container) return;
    var getAllItems = function() { return Array.from(container.querySelectorAll('.shop-buy-item[data-bidx]')); };
    getAllItems().forEach(function(itemEl) {
        var getIdx    = function() { return parseInt(itemEl.getAttribute('data-bidx')); };
        var getListId = function() { return 'shop-buy'; };
        _wireDrag(itemEl, getIdx, getListId, getAllItems, function(from, to) {
            var moved = shoppingData.buy.splice(from, 1)[0];
            shoppingData.buy.splice(to, 0, moved);
            saveShoppingData(); renderShoppingBuy();
        });
    });
}

function _initShopWishDnd(container) {
    if (!container) return;
    var getAllItems = function() { return Array.from(container.querySelectorAll('.shop-wish-item[data-widx]')); };
    getAllItems().forEach(function(itemEl) {
        var getIdx    = function() { return parseInt(itemEl.getAttribute('data-widx')); };
        var getListId = function() { return 'shop-wish'; };
        _wireDrag(itemEl, getIdx, getListId, getAllItems, function(from, to) {
            var moved = shoppingData.wishlist.splice(from, 1)[0];
            shoppingData.wishlist.splice(to, 0, moved);
            saveShoppingData(); renderShoppingWish();
        });
    });
}

// ── TASKS ────────────────────────────────────────────────
function renderShoppingTasks(){
    renderGTasks('shopping');
    try { ['r1','r2','r3'].forEach(slot => { if(rSlots&&rSlots[slot]==='shopping') renderRTasks(slot); }); bindScheduleRTasks(); updateSummaryPills(); updateProgress(); } catch(e) {}
}

function saveShoppingTask(){ showGTask('shopping'); }

function removeShoppingTask(){ /* collapsed — tasks managed via renderGTasks */ }

function initShoppingSection(){
    if (!document.getElementById('resp-section-shopping')) return;
    // One-time migration from shoppingData.tasks → gTasksAll['shopping']
    if ((shoppingData.tasks || []).length && !(gTasksAll['shopping'] || []).length) {
        gTasksAll['shopping'] = shoppingData.tasks.map(t => ({
            id: t.id || ('sqt_' + Date.now() + '_' + Math.random()),
            emoji: t.emoji || '',
            text: t.title || t.text || '',
            notes: t.desc || '',
            done: !!t.done,
            accentColor: '#fbbf24'
        }));
        saveGTasksAll();
    }
    // One-time cleanup: remove any default/placeholder seeded tasks
    if (!shoppingData._cleanedDefaultTasks) {
        const DEFAULT_TEXTS = ['pick outfit for tomorrow', 'prep clothes', 'shopping list'];
        if (gTasksAll['shopping']) {
            const before = gTasksAll['shopping'].length;
            gTasksAll['shopping'] = gTasksAll['shopping'].filter(t => {
                const txt = (t.text || t.title || '').toLowerCase();
                return !DEFAULT_TEXTS.some(d => txt.includes(d));
            });
            if (gTasksAll['shopping'].length !== before) saveGTasksAll();
        }
        shoppingData._cleanedDefaultTasks = true;
        saveShoppingData();
    }
    renderShoppingBuy();
    renderShoppingWish();
    renderShoppingTasks();
    updateShoppingStats();
}



// ════════════════════════════════════════════════════════
//  LOOK MODULE (Outfit Plan + Essentials + Kit + Tasks)
// ════════════════════════════════════════════════════════

let __lookFirstLoad = false;
// ════════════════════════════════════════════════════════
//  LOOK MODULE  (Outfits + Essentials + Kit + Upgrades + Tasks)
// ════════════════════════════════════════════════════════

let lookData = {};
try {
    const raw = localStorage.getItem('lookData');
    __lookFirstLoad = (raw === null);
    lookData = JSON.parse(raw || '{}') || {};
} catch(e) {
    __lookFirstLoad = true;
    lookData = {};
}

ensureArrays(lookData, 'outfits', 'essentials', 'kit', 'tasks', 'upgrades', 'grooming');

const saveLookData = () => saveData('lookData', lookData);

function showLookForm(kind){
    const el = document.getElementById('look-form-' + kind);
    if (el) { el.classList.add('visible'); const f = el.querySelector('input'); if(f) f.focus(); }
}
function hideLookForm(kind){
    const el = document.getElementById('look-form-' + kind);
    if (el) el.classList.remove('visible');
}

// ── DEFAULTS ────────────────────────────────────────────

function ensureLookTaskDefaults(){
    if (!__lookFirstLoad) return;
    if (lookData._seededTasks) return;
    if (Array.isArray(lookData.tasks) && lookData.tasks.length) { lookData._seededTasks = true; saveLookData(); return; }
    lookData.tasks = [
        { id:'pick_outfit',   emoji:'👔', title:'Pick outfit for tomorrow',          desc:'Quick decision = less stress.' },
        { id:'prep_clothes',  emoji:'🧺', title:'Prep clothes (iron / steam / fold)', desc:'Do it in 10 minutes.' },
    ];
    lookData._seededTasks = true;
    saveLookData();
}

// ── STATS ────────────────────────────────────────────────
function updateLookStats() {
    const g = id => document.getElementById(id);
    if (g('look-stat-outfits'))  g('look-stat-outfits').textContent  = lookData.outfits.length;
    if (g('look-stat-upgrades')) g('look-stat-upgrades').textContent = lookData.upgrades.length;
    const today = new Date(); today.setHours(0,0,0,0);
    const grooming = lookData.grooming || [];
    let overdue = 0;
    grooming.forEach(it => {
        if (!it.lastDate || !it.freqWeeks) return;
        const next = new Date(it.lastDate);
        next.setDate(next.getDate() + it.freqWeeks * 7);
        if (next < today) overdue++;
    });
    if (g('look-stat-grooming')) g('look-stat-grooming').textContent = grooming.length;
    if (g('look-stat-overdue'))  g('look-stat-overdue').textContent  = overdue;
}

// ── QUICK TASK ───────────────────────────────────────────
function lookQuickTask(emoji, title, desc) {
    if (!gTasksAll['look']) gTasksAll['look'] = [];
    const already = gTasksAll['look'].find(t => (t.text === title || t.title === title) && !t.done);
    if (already) { toast('Task already exists'); return; }
    gTasksAll['look'].push({ id: 'lqt_' + Date.now(), emoji, text: title, notes: desc || '', done: false, accentColor: '#a78bfa' });
    saveGTasksAll(); renderLookTasks();
    toast('📌 Task added');
}

