let _lookOutfitFilter = 'all';
let _lookEditOutfitId = null;
function cancelLookOutfitEdit() { _lookEditOutfitId = null; renderLookOutfits(); }
function setLookOutfitFilter(f) { _lookOutfitFilter = f; renderLookOutfits(); }
function _renderLookOutfitFilters() {
    const row = document.getElementById('look-outfit-filter-row');
    if (!row) return;
    const CATS = [
        { key:'all',    label:'All',     c:'#a78bfa', bg:'rgba(139,92,246,0.18)', bd:'rgba(139,92,246,0.45)' },
        { key:'casual', label:'Casual',  c:'#a78bfa', bg:'rgba(139,92,246,0.10)', bd:'rgba(139,92,246,0.22)' },
        { key:'smart',  label:'Smart',   c:'#60a5fa', bg:'rgba(96,165,250,0.10)',  bd:'rgba(96,165,250,0.22)'  },
        { key:'formal', label:'Formal',  c:'#fbbf24', bg:'rgba(251,191,36,0.10)',  bd:'rgba(251,191,36,0.22)'  },
        { key:'sport',  label:'Sport',   c:'#34d399', bg:'rgba(52,211,153,0.10)',  bd:'rgba(52,211,153,0.22)'  },
        { key:'other',  label:'Other',   c:'#94a3b8', bg:'rgba(148,163,184,0.10)', bd:'rgba(148,163,184,0.22)' },
    ];
    row.innerHTML = '';
    CATS.forEach(cat => {
        const active = _lookOutfitFilter === cat.key;
        const btn = document.createElement('button');
        btn.style.cssText = `padding:5px 12px;border-radius:99px;font-size:0.75em;font-weight:800;cursor:pointer;border:1px solid ${active ? cat.bd : 'rgba(255,255,255,0.07)'};background:${active ? cat.bg : 'rgba(255,255,255,0.03)'};color:${active ? cat.c : '#475569'};transition:all 0.15s;font-family:'Outfit',sans-serif;`;
        btn.textContent = cat.label;
        btn.onclick = () => setLookOutfitFilter(cat.key);
        row.appendChild(btn);
    });
}

