function saveLookOutfitEdit(id) {
    const o = lookData.outfits.find(x => x.id === id);
    if (!o) return;
    const title = (document.getElementById('loe-title')?.value || '').trim();
    if (!title) { document.getElementById('loe-title')?.focus(); return; }
    o.emoji    = (document.getElementById('loe-emoji')?.value || '').trim() || '🧥';
    o.title    = title;
    o.when     = (document.getElementById('loe-when')?.value || '').trim();
    o.category = document.getElementById('loe-cat')?.value || 'casual';
    o.notes    = (document.getElementById('loe-notes')?.value || '').trim();
    _lookEditOutfitId = null;
    saveLookData(); renderLookOutfits();
}

function saveLookOutfit(){
    const emoji    = (document.getElementById('lo-emoji')?.value || '').trim() || '🧥';
    const title    = (document.getElementById('lo-title')?.value || '').trim();
    const when     = (document.getElementById('lo-when')?.value || '').trim();
    const notes    = (document.getElementById('lo-notes')?.value || '').trim();
    const category = (document.getElementById('lo-cat')?.value || 'casual');
    if (!title) { document.getElementById('lo-title')?.focus(); return; }
    lookData.outfits.push({ id: 'o_' + Date.now(), emoji, title, when, notes, category, worn: false });
    saveLookData();
    ['lo-emoji','lo-title','lo-when','lo-notes'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
    const catEl = document.getElementById('lo-cat'); if (catEl) catEl.value = 'casual';
    hideLookForm('outfit');
    renderLookOutfits();
}

function removeLookOutfit(outfitId){
    const o = (lookData.outfits || []).find(x => x.id === String(outfitId));
    showConfirm({ title:'Remove outfit', message:`Remove "<strong>${o ? o.title : 'this outfit'}</strong>"?`, confirmLabel:'Remove', confirmColor:'#ef4444', onConfirm(){ lookData.outfits = lookData.outfits.filter(x => x.id !== String(outfitId)); saveLookData(); renderLookOutfits(); } });
}


