        // Live-tick the timers every second without full re-render
        setInterval(function() {
            const now = Date.now();
            limitsV2.forEach(lim => {
                if (!lim.showTimer) return;
                const el = document.getElementById('lv2timer-' + lim.id);
                if (!el) return;
                if (!lim.lastUsed) { el.textContent = '⏱ not used yet'; return; }
                const elapsed = _lv2FormatElapsed(now - lim.lastUsed);
                el.textContent = elapsed ? '⏱ ' + elapsed + ' since last' : '';
            });
        }, 1000);

        function lv2ResetTimer(id) {
            const lim = limitsV2.find(l => l.id === id);
            if (!lim) return;
            delete lim.lastUsed;
            saveLimitsV2();
            lv2Render();
        }

        function lv2Change(id, delta) {
            const lim = limitsV2.find(l => l.id === id);
            if (!lim) return;
            lim.current = Math.max(0, (lim.current||0) + delta);
            if (delta > 0) lim.lastUsed = Date.now();   // record time of last increment
            saveLimitsV2();
            lv2Render();
        }

