        // ── LIVE CLOCK ──────────────────────────────────────────────────────────
        function updateLiveClock() {
            const now = new Date();
            const hh = String(now.getHours()).padStart(2, '0');
            const mm = String(now.getMinutes()).padStart(2, '0');
            const ss = String(now.getSeconds()).padStart(2, '0');
            const clockEl = document.getElementById('liveClock');
            // Compact: HH:MM with blinking colon on even seconds
            if (clockEl) {
                const sep = now.getSeconds() % 2 === 0 ? ':' : '·';
                clockEl.textContent = `${hh}${sep}${mm}`;
            }
        }

        function updateLiveDateBadge() {
            const now = new Date();
            const daysEN = ['SUNDAY','MONDAY','TUESDAY','WEDNESDAY','THURSDAY','FRIDAY','SATURDAY'];
            const monthsEN = ['JANUARY','FEBRUARY','MARCH','APRIL','MAY','JUNE','JULY','AUGUST','SEPTEMBER','OCTOBER','NOVEMBER','DECEMBER'];
            const daysPT = ['DOMINGO','SEGUNDA','TERÇA','QUARTA','QUINTA','SEXTA','SÁBADO'];
            const monthsPT = ['JANEIRO','FEVEREIRO','MARÇO','ABRIL','MAIO','JUNHO','JULHO','AGOSTO','SETEMBRO','OUTUBRO','NOVEMBRO','DEZEMBRO'];
            const isPT = _appLanguage === 'pt';
            const dayName = (isPT ? daysPT : daysEN)[now.getDay()];
            const date = now.getDate();
            const month = (isPT ? monthsPT : monthsEN)[now.getMonth()];
            const connector = isPT ? 'DE' : 'OF';
            const el = document.getElementById('liveDateBadge');
            if (el) el.textContent = `🔴 ${dayName} ${date} ${connector} ${month}`;
        }

        // ── AUTO-HIGHLIGHT CURRENT TIME BLOCK ───────────────────────────────────
        function parseTimeToMinutes(timeStr) {
            // accepts "HH:MM" → total minutes since midnight
            const [h, m] = timeStr.trim().split(':').map(Number);
            return h * 60 + m;
        }

        function highlightCurrentBlock() {
            // NOW/completed highlights only make sense on today's schedule
            if (schedDay !== _dateKey(new Date())) {
                document.querySelectorAll('#schedule .hour-block').forEach(b => {
                    b.classList.remove('now', 'completed');
                    const nl = b.querySelector('.now-label');
                    if (nl) nl.remove();
                });
                return;
            }
            const now = new Date();
            const currentMin = now.getHours() * 60 + now.getMinutes();

            const blocks = document.querySelectorAll('#schedule .hour-block');
            let activeBlock = null;

            blocks.forEach(block => {
                block.classList.remove('now', 'completed');
                const badge = block.querySelector('.time-badge');
                const existingNowLabel = block.querySelector('.now-label');
                if (existingNowLabel) existingNowLabel.remove();
                if (!badge) return;

                const rangeText = badge.textContent.trim(); // e.g. "07:45 - 09:00"
                const parts = rangeText.split('-').map(s => s.trim());
                if (parts.length < 2) return;

                const startMin = parseTimeToMinutes(parts[0]);
                let endMin = parseTimeToMinutes(parts[1]);

                // Handle overnight blocks (e.g. 23:30 - 00:15 or 00:15 - 02:00)
                // A block is "current" if currentMin is between start and end
                // For overnight handling: if end < start, the block crosses midnight
                let isCurrent = false;
                let isPast = false;

                if (endMin < startMin) {
                    // Crosses midnight
                    isCurrent = currentMin >= startMin || currentMin < endMin;
                    isPast = false; // don't dim overnight blocks
                } else {
                    isCurrent = currentMin >= startMin && currentMin < endMin;
                    isPast = currentMin >= endMin;
                }

                if (isCurrent) {
                    block.classList.add('now');
                    // Add NOW label next to time badge
                    const nowLabel = document.createElement('span');
                    nowLabel.className = 'now-label';
                    nowLabel.textContent = '● NOW';
                    badge.appendChild(nowLabel);
                    activeBlock = block;
                } else if (isPast) {
                    block.classList.add('completed');
                }
            });

            // Show/hide jump-to-now button based on schedule tab visibility
            const jumpBtn = document.getElementById('jumpNowBtn');
            const scheduleTab = document.getElementById('schedule');
            if (jumpBtn) {
                if (activeBlock && scheduleTab && scheduleTab.classList.contains('active')) {
                    jumpBtn.classList.remove('hidden');
                } else {
                    jumpBtn.classList.add('hidden');
                }
            }
        }

        // ── JUMP TO NOW ─────────────────────────────────────────────────────────
        function jumpToNow() {
            const nowBlock = document.querySelector('#schedule .hour-block.now');
            if (nowBlock) {
                nowBlock.scrollIntoView({ behavior: 'smooth', block: 'center' });
            }
        }

        // ── TOAST NOTIFICATION ──────────────────────────────────────────────────
        let _toastTimeout = null;
        function showToast(msg) {
            let toast = document.getElementById('appToast');
            if (!toast) {
                toast = document.createElement('div');
                toast.id = 'appToast';
                toast.className = 'toast';
                document.body.appendChild(toast);
            }
            toast.textContent = msg;
            // prevent flash if already showing
            if (_toastTimeout) clearTimeout(_toastTimeout);
            // force reflow
            toast.classList.remove('show');
            void toast.offsetWidth;
            toast.classList.add('show');
            _toastTimeout = setTimeout(() => toast.classList.remove('show'), 3000);
        }

