        // ── DAY SNAPSHOT (backfills task.done into schedBlocksPerDay on day change) ─
        function saveDaySnapshot(dateStr) {
            if (!dateStr) return;
            let history = {};
            try { history = JSON.parse(localStorage.getItem('dailyHistory') || '{}'); } catch(e) {}

            // Use the blocks for the specific day being snapshot, not today's blocks
            let dayKey = null;
            try { dayKey = _dateKey(new Date(dateStr)); } catch(e) {}

            // Backfill task.done from global tasks[] into the day's block objects.
            // This fixes legacy data where toggleTask didn't sync back to the block.
            if (dayKey && schedBlocksPerDay && Array.isArray(schedBlocksPerDay[dayKey])) {
                let dirty = false;
                schedBlocksPerDay[dayKey].forEach(b => {
                    (b.tasks || []).forEach(t => {
                        if (tasks && t.id && tasks[t.id] !== undefined) {
                            const correct = !!tasks[t.id];
                            if (t.done !== correct) { t.done = correct; dirty = true; }
                        }
                    });
                });
                if (dirty) localStorage.setItem('schedBlocksPerDay', JSON.stringify(schedBlocksPerDay));
            }

            const srcBlocks = (dayKey && schedBlocksPerDay && Array.isArray(schedBlocksPerDay[dayKey]) && schedBlocksPerDay[dayKey].length)
                ? schedBlocksPerDay[dayKey]
                : (schedBlocks || []);

            const snapshot = {
                date: dateStr,
                savedAt: new Date().toISOString(),
                blocks: srcBlocks.map(b => ({
                    time:  b.time  || '',
                    title: b.title || '',
                    tasks: (b.tasks || []).map(t => ({
                        text:      t.text || t.title || '',
                        done:      !!(t.done || (tasks && tasks[t.id])),
                        subtasks:  (t.subtasks || []).map(s => ({ text: s.text || '', done: !!s.done }))
                    })).filter(t => t.text)
                })).filter(b => b.tasks.length),
            };

            let total = 0, done = 0;
            snapshot.blocks.forEach(b => b.tasks.forEach(t => {
                total++; if (t.done) done++;
                (t.subtasks || []).forEach(s => { total++; if (s.done) done++; });
            }));
            snapshot.stats = { done, total };
        }

        // ── DAILY AUTO-RESET CHECK ───────────────────────────────────────────────
        function checkDailyReset() {
            const todayStr = new Date().toDateString();
            const lastDate = localStorage.getItem('lastAppDate');
            // Set today's date FIRST so a crash/reload mid-function can't re-trigger snapshot
            localStorage.setItem('lastAppDate', todayStr);
            if (lastDate && lastDate !== todayStr) {
                // Always snapshot the previous day first, regardless of reset choice
                saveDaySnapshot(lastDate);

                // ── Streak break check: if either streak wasn't logged yesterday, reset it ──
                (function() {
                    const _yest = new Date();
                    _yest.setDate(_yest.getDate() - 1);
                    const _ymd = _yest.getFullYear() + '-' + String(_yest.getMonth()+1).padStart(2,'0') + '-' + String(_yest.getDate()).padStart(2,'0');
                })();

                showConfirm({
                    icon: '🌅',
                    title: 'New day — ' + todayStr,
                    message: 'Reset all tasks for today? Your previous day has been saved to <strong>Day History</strong>.',
                    confirmLabel: 'Reset for today',
                    confirmColor: '#ef4444',
                    onConfirm: () => {
                        tasks = {};
                        localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
                        schedBlocks.forEach(block => {
                            block.tasks.forEach(task => {
                                task.done = false;
                                if (Array.isArray(task.subtasks)) task.subtasks.forEach(s => s.done = false);
                            });
                        });
                        saveSchedBlocks();
                        limitsV2.forEach(l => { l.current = 0; });
                        saveLimitsV2();
                        const GENERIC_SECTIONS = [
                            'dermatologist','psychologist','music','martial-arts','streaming',
                            'doutor-finan-as','invest','social-media','emulator','computer','phone',
                            'calendar','update-app','lenses','room','travel-list'
                        ];
                        GENERIC_SECTIONS.forEach(sid => {
                            if (gTasksAll[sid]) gTasksAll[sid].forEach(t => {
                                t.done = false;
                                if (Array.isArray(t.subtasks)) t.subtasks.forEach(s => s.done = false);
                            });
                        });
                        IMP_SECTIONS.forEach(sid => {
                            if (gTasksAll[sid]) gTasksAll[sid].forEach(t => {
                                t.done = false;
                                if (Array.isArray(t.subtasks)) t.subtasks.forEach(s => s.done = false);
                            });
                        });
                        saveGTasksAll();
                        localStorage.removeItem('orgChecksDate');
                        showToast('✅ Tasks reset for the new day!');
                        renderSchedule();
                    },
                    onCancel: () => {
                        showToast('Keeping previous tasks — history saved.');
                    }
                });
            }
        }

