        // ── STATS
        function updateMAStats(){
            const g = id => document.getElementById(id);
            const done  = maData.disciplines.filter(d => d.weekDone).length;
            const goal  = maData.weeklyGoal ?? 3;

            // Auto-increment streak as soon as goal is met, once per week
            if (done >= goal) {
                const sd = maData.weekStreakData || { lastWeek:'', streak:0 };
                const currentWeek = _gymCurrentWeekKey();
                if (sd.lastWeek !== currentWeek) {
                    sd.streak = (sd.streak || 0) + 1;
                    sd.lastWeek = currentWeek;
                    maData.weekStreakData = sd;
                    saveMAData();
                    toast('🔥 Weekly goal hit! Streak: ' + sd.streak + ' week' + (sd.streak === 1 ? '' : 's') + '!');
                }
            }

            if (g('ma-stat-week'))   g('ma-stat-week').textContent   = done + '/' + goal;
            if (g('ma-stat-streak')) g('ma-stat-streak').textContent = (maData.weekStreakData && maData.weekStreakData.streak) || 0;
            if (g('ma-stat-total'))  g('ma-stat-total').textContent  = maData.logs.length;
        }

