        function maEsc(s){ try { return (typeof escHtml==='function') ? escHtml(String(s)) : String(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); } catch(e){ return String(s); } }

        function renderMALogs(){
            const list = document.getElementById('ma-log-list');
            if (!list) return;
            list.innerHTML = '';
            if (!maData.logs.length) {
                list.innerHTML = '<div style="color:#475569;font-size:0.88em;padding:8px 2px;">No sessions logged yet. Every class is a step forward.</div>';
                updateMAStats(); return;
            }
            const energyEmoji = {1:'😴',2:'😐',3:'🙂',4:'💪',5:'🔥'};
            [...maData.logs].reverse().forEach((l, revIdx) => {
                const realIdx = maData.logs.length - 1 - revIdx;
                const disc = maData.disciplines.find(d => d.id === l.discId);
                const row = document.createElement('div');
                row.style.cssText = 'display:flex;align-items:flex-start;gap:10px;padding:12px 14px;border-radius:13px;background:rgba(168,85,247,0.05);border:1px solid rgba(168,85,247,0.15);';

                const icon = document.createElement('div');
                icon.className = 'icon-xl';
                icon.textContent = disc ? (disc.emoji||'🥋') : '🥋';

                const body = document.createElement('div');
                body.className = 'flex-1';

                const titleRow = document.createElement('div');
                titleRow.className = 'd-row-7w';

                const nameEl = document.createElement('span');
                nameEl.style.cssText = 'font-weight:800;font-size:0.92em;color:#e2e8f0;';
                nameEl.textContent = l.discName || (disc ? disc.name : 'Session');
                titleRow.appendChild(nameEl);

                if (l.when) {
                    const badge = document.createElement('span');
                    badge.style.cssText = 'font-size:0.7em;font-weight:800;padding:2px 7px;border-radius:99px;background:rgba(56,189,248,0.12);color:#38bdf8;border:1px solid rgba(56,189,248,0.22);white-space:nowrap;';
                    badge.textContent = '📅 ' + l.when;
                    titleRow.appendChild(badge);
                }
                if (l.duration) {
                    const badge = document.createElement('span');
                    badge.className = 'badge-y';
                    badge.textContent = '⏱ ' + l.duration;
                    titleRow.appendChild(badge);
                }
                if (l.energy) {
                    const enEl = document.createElement('span');
                    enEl.style.cssText = 'font-size:0.85em;';
                    enEl.textContent = energyEmoji[l.energy] || '';
                    titleRow.appendChild(enEl);
                }
                body.appendChild(titleRow);

                if (l.notes) {
                    const notesEl = document.createElement('div');
                    notesEl.style.cssText = 'color:#64748b;font-size:0.8em;line-height:1.5;white-space:pre-wrap;';
                    notesEl.textContent = l.notes;
                    body.appendChild(notesEl);
                }

                const right = document.createElement('div');
                right.className = 'd-flex-gs0';

                const pushBtn = document.createElement('button');
                pushBtn.title = 'Push to tasks';
                pushBtn.className = 'pill pill-p';
                pushBtn.textContent = '📋';
                pushBtn.onclick = e => { e.stopPropagation(); maQuickTask(icon.textContent, nameEl.textContent + ' session', l.when||''); };

                const delBtn = document.createElement('button');
                delBtn.className = 'house-delete-btn'; delBtn.textContent = '🗑️'; delBtn.title = 'Remove';
                delBtn.onclick = e => { e.stopPropagation(); showConfirm({ title:'Delete Log', message:'Delete this session log?', confirmLabel:'Delete', onConfirm:() => { maData.logs.splice(realIdx,1); saveMAData(); renderMALogs(); } }); };

                right.appendChild(pushBtn); right.appendChild(delBtn);
                row.appendChild(icon); row.appendChild(body); row.appendChild(right);
                list.appendChild(row);
            });
            updateMAStats();
        }

        function saveMALog(){
            const discId   = (document.getElementById('mal-discipline')?.value || '').trim();
            const when     = (document.getElementById('mal-when')?.value      || '').trim();
            const duration = (document.getElementById('mal-duration')?.value  || '').trim();
            const notes    = (document.getElementById('mal-notes')?.value     || '').trim();
            if (!discId && !when && !notes) { document.getElementById('mal-discipline')?.focus(); return; }
            const disc = maData.disciplines.find(d => d.id === discId);
            maData.logs.push({ ts:Date.now(), discId, discName: disc ? disc.name : (discId==='custom'?'Custom':discId), when, duration, energy: _maEnergy||null, notes });
            if (disc) disc.weekDone = true;
            saveMAData();
            ['mal-discipline','mal-when','mal-duration','mal-notes'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
            _maEnergy = 0;
            document.querySelectorAll('.ma-en-btn').forEach(b => { b.style.opacity='0.3'; b.style.background='none'; });
            const lbl = document.getElementById('ma-energy-label'); if(lbl) lbl.textContent='';
            hideMAForm('log'); renderMADisciplines(); renderMALogs();
        }

