        function saveLiquidSettings() {
            const i = _liquidSettingsIdx;
            if (i < 0 || !liquidsInventory[i]) return;
            const refillEl = document.getElementById('liquid-settings-refillat');
            const doseEl = document.getElementById('liquid-settings-dose');
            const courseDaysEl = document.getElementById('liquid-settings-coursedays');
            const courseStartEl = document.getElementById('liquid-settings-coursestart');
            const refillAt = parseFloat(refillEl ? refillEl.value : 10);
            const doseAmount = parseFloat(doseEl ? doseEl.value : 1);
            if (!isNaN(refillAt) && refillAt >= 0) liquidsInventory[i].refillAt = Math.round(refillAt * 10) / 10;
            if (!isNaN(doseAmount) && doseAmount > 0) liquidsInventory[i].doseAmount = Math.round(doseAmount * 10) / 10;
            const cd = parseInt(courseDaysEl ? courseDaysEl.value : 0);
            liquidsInventory[i].courseDays = (!isNaN(cd) && cd > 0) ? cd : 0;
            liquidsInventory[i].courseStart = (courseStartEl && courseStartEl.value) ? courseStartEl.value : null;
            saveLiquidsInventory();
            renderLiquidsInventory();
            closeLiquidSettings();
        }

