            saveGTasksAll();
            renderGTasks('pills');
            updateSummaryPills(); updateProgress();

            if (!expected.length) { showToast('No active liquids with schedules — nothing to sync', '#fbbf24'); return; }
            const parts = [];
            if (added)   parts.push(`+${added} added`);
            if (removed) parts.push(`−${removed} removed`);
