        // Called when a "Take X" pills task is toggled (from any source) ─────────
        function pillHandleTaskToggle(taskText, newState) {
            // Extract optional dose + pill name from "Take [N] {name}" (may have emoji prefix like "💊 Take 2 Lamdbapil")
            const match = taskText.match(/Take (?:(\d+) )?(.+)/i);
            if (!match) return;
            const dose = match[1] ? parseInt(match[1]) : 1;
            const pillName = match[2].trim();
            const pill = pillsInventory.find(p => p.name.trim().toLowerCase() === pillName.toLowerCase());
            if (!pill) return;
            if (newState) {
                pill.count = Math.max(0, pill.count - dose);
                showToast(`💊 ${pill.name}: ${pill.count} left`, '#38bdf8');
            } else {
                // Unchecked → put dose back, cap at bottle size
                pill.count = Math.min(pill.bottleSize || 60, pill.count + dose);
                showToast(`↩️ ${pill.name} unchecked — count restored to ${pill.count}`, '#38bdf8');
            }
            savePillsInventory();
            updatePillInventoryDisplay();
            renderPillsLowStockBanner();
        }

        function liquidHandleTaskToggle(taskText, newState) {
            const match = taskText.match(/Apply (.+)/i);
            if (!match) return;
            const liquidName = match[1].trim();
            const liquid = liquidsInventory.find(p => p.name.trim().toLowerCase() === liquidName.toLowerCase());
            if (!liquid) return;
            const doseAmount = liquid.doseAmount != null ? liquid.doseAmount : 1;
            if (newState) {
                liquid.count = Math.max(0, Math.round((liquid.count - doseAmount) * 10) / 10);
                showToast(`🧴 ${liquid.name}: ${liquid.count} ml left`, '#60a5fa');
            } else {
                // Unchecked → put dose back, cap at bottle size
                liquid.count = Math.min(liquid.bottleSize || 60, Math.round((liquid.count + doseAmount) * 10) / 10);
                showToast(`↩️ ${liquid.name} unchecked — volume restored to ${liquid.count} ml`, '#60a5fa');
            }
            saveLiquidsInventory();
            updatePillInventoryDisplay();
            renderLiquidsLowStockBanner();
        }
        // ── Finance Balance Accounts CRUD ─────────────────────────────────────
        const FIN_ACCOUNTS_DEF = [];
        let finAccounts = [];
        try { finAccounts = JSON.parse(localStorage.getItem('finAccounts') || 'null') || FIN_ACCOUNTS_DEF; } catch(e) { finAccounts = FIN_ACCOUNTS_DEF; }

        const saveFinAccounts = () => saveData('finAccounts', finAccounts);

        function renderFinAccounts() {
            const grid = document.getElementById('finance-money-grid');
            if (!grid) return;
            if (!finAccounts.length) {
                grid.innerHTML = '<p style="color:#475569;font-size:0.85em;padding:8px 2px;">No accounts yet. Add one below.</p>';
                updateFinTotal();
                return;
            }
            grid.innerHTML = finAccounts.map((acc, i) => {
                const val = parseFloat(acc.value) || 0;
                const isNeg = val < 0;
                const valColor = isNeg ? '#f87171' : '#34d399';
                return '<div style="display:flex;align-items:center;gap:10px;background:rgba(2,8,23,0.5);border:1px solid rgba(52,211,153,0.12);border-left:3px solid ' + (isNeg ? 'rgba(248,113,113,0.5)' : 'rgba(52,211,153,0.4)') + ';border-radius:12px;padding:12px 14px;">'
                    + '<span contenteditable="true" spellcheck="false" style="font-size:1.2em;flex-shrink:0;outline:none;cursor:text;" onblur="saveFinAccount(' + i + ',\'ic\',this.textContent.trim())">' + escapeHtml(acc.ic) + '</span>'
                    + '<span contenteditable="true" spellcheck="false" style="color:#e2e8f0;font-size:0.9em;font-weight:700;flex:1;outline:none;cursor:text;" onblur="saveFinAccount(' + i + ',\'label\',this.textContent.trim())">' + escapeHtml(acc.label) + '</span>'
                    + '<div style="display:flex;align-items:center;gap:3px;flex-shrink:0;">'
                    + '<input type="number" step="0.01" name="fin-account-value-' + i + '" value="' + (acc.value || 0) + '" '
                    + 'onkeydown="_numOnly(event)" onchange="saveFinAccount(' + i + ',\'value\',parseFloat(this.value)||0)" '
                    + 'style="width:100px;text-align:right;background:transparent;color:' + valColor + ';border:none;font-weight:900;font-family:\'DM Mono\',monospace;font-size:0.95em;outline:none;padding:0;" />'
                    + '<span style="font-size:0.8em;color:#475569;font-weight:700;">€</span>'
                    + '</div>'
                    + '<button onclick="deleteFinAccount(' + i + ')" style="background:none;border:none;color:#334155;font-size:0.9em;cursor:pointer;padding:4px 6px;flex-shrink:0;transition:color 0.15s;" onmouseover="this.style.color=\'#f87171\'" onmouseout="this.style.color=\'#334155\'">✕</button>'
                    + '</div>';
            }).join('');
            updateFinTotal();
        }

        function addFinanceRow() {
            finAccounts.push({ id:'acc'+Date.now(), ic:'💰', label:'New Account', value:0 });
            saveFinAccounts();
            renderFinAccounts();
            setTimeout(() => {
                const rows = document.querySelectorAll('#finance-money-grid > div');
                if (rows.length) {
                    const labelEl = rows[rows.length-1].querySelectorAll('[contenteditable]')[1];
                    if (labelEl) { labelEl.focus(); selectAllText(labelEl); }
                }
            }, 50);
        }

        function deleteFinAccount(i) {
            const removedId = finAccounts[i] && finAccounts[i].id;
            finAccounts.splice(i, 1);
            saveFinAccounts();
            renderFinAccounts();
            if (removedId) {
                finTx.forEach(tx => {
                    if (tx.accountId === removedId) tx.accountId = '';
                });
                saveFinTx();
                renderFinTx();
            }
        }

        function saveFinAccount(i, field, val) {
            if (!finAccounts[i]) return;
            if (!val && field !== 'value') { renderFinAccounts(); return; }
            finAccounts[i][field] = val;
            saveFinAccounts();
            if (field === 'value') updateFinTotal();
        }

        function updateFinTotal() {
            const total = finAccounts.reduce((sum, acc) => sum + (parseFloat(acc.value) || 0), 0);
            const el = document.getElementById('money-total');
            if (el) el.textContent = total.toFixed(2).replace('.', ',') + '€';
        }

        // ── Debts ─────────────────────────────────────────────────
        let finDebts = [];
        try { finDebts = JSON.parse(localStorage.getItem('finDebts') || '[]') || []; } catch(e) { finDebts = []; }
        const saveFinDebts = () => saveData('finDebts', finDebts);

        function renderFinDebts() {
            const list  = document.getElementById('fin-debts-list');
            const empty = document.getElementById('fin-debts-empty');
            const sumEl = document.getElementById('fin-debts-summary');
            if (!list) return;

            list.innerHTML = '';
            if (!finDebts.length) {
                if (empty) empty.style.display = 'block';
                if (sumEl) sumEl.style.display = 'none';
                return;
            }
            if (empty) empty.style.display = 'none';
            if (sumEl) sumEl.style.display = 'flex';

            finDebts.forEach(function(d, i) {
                const isOwe   = d.dir === 'owe';
                const accent  = isOwe ? '#f87171' : '#34d399';
                const bgColor = isOwe ? 'rgba(248,113,113,0.06)' : 'rgba(52,211,153,0.06)';
                const border  = isOwe ? 'rgba(248,113,113,0.2)'  : 'rgba(52,211,153,0.2)';
                const tag     = isOwe ? '😬 I owe' : '🤑 Owes me';

                const row = document.createElement('div');
                row.style.cssText = `display:flex;align-items:center;gap:8px;padding:10px 12px;background:${bgColor};border-radius:11px;border:1px solid ${border};`;
                row.innerHTML = `
                    <span style="font-size:0.65em;font-weight:800;padding:2px 7px;border-radius:20px;background:${accent}18;border:1px solid ${accent}44;color:${accent};flex-shrink:0;">${tag}</span>
                    <input value="${escHtml(d.person||'')}" placeholder="Person…" maxlength="40"
                        style="flex:1;min-width:60px;background:transparent;border:none;outline:none;color:#e2e8f0;font-family:'Outfit',sans-serif;font-size:0.85em;font-weight:700;"
                        onchange="saveFinDebt(${i},'person',this.value)" oninput="saveFinDebt(${i},'person',this.value)">
                    <input value="${escHtml(d.desc||'')}" placeholder="Note…" maxlength="80"
                        style="flex:2;min-width:60px;background:transparent;border:none;outline:none;color:#64748b;font-family:'Outfit',sans-serif;font-size:0.78em;"
                        onchange="saveFinDebt(${i},'desc',this.value)" oninput="saveFinDebt(${i},'desc',this.value)">
                    <input value="${d.amount > 0 ? String(d.amount).replace('.',',') : ''}" placeholder="0,00" inputmode="decimal" maxlength="10"
                        style="width:70px;text-align:right;background:transparent;border:none;outline:none;color:${accent};font-family:'DM Mono',monospace;font-size:0.95em;font-weight:900;"
                        onkeydown="_numOnly(event)"
                        onchange="saveFinDebt(${i},'amount',this.value)"
                        oninput="saveFinDebt(${i},'amount',this.value)">
                    <span style="color:#475569;font-size:0.8em;font-weight:700;">€</span>
                    <button onclick="addDebtReminderTask(${i})" data-tooltip="${isOwe ? 'Add task to pay' : 'Add task to ask for money'}"
                        style="background:none;border:none;font-size:0.9em;cursor:pointer;padding:2px 4px;flex-shrink:0;opacity:0.45;transition:opacity 0.15s;"
                        onmouseover="this.style.opacity='1'" onmouseout="this.style.opacity='0.45'">📋</button>
                    <button onclick="deleteFinDebt(${i})"
                        style="background:none;border:none;color:#334155;cursor:pointer;font-size:1em;padding:2px 4px;flex-shrink:0;transition:color 0.15s;"
                        onmouseover="this.style.color='#f87171'" onmouseout="this.style.color='#334155'">×</button>`;
                list.appendChild(row);
            });

            // Totals
            const oweTotal  = finDebts.filter(d => d.dir === 'owe' ).reduce((s, d) => s + (parseFloat(d.amount) || 0), 0);
            const owedTotal = finDebts.filter(d => d.dir === 'owed').reduce((s, d) => s + (parseFloat(d.amount) || 0), 0);
            const net       = owedTotal - oweTotal;
            const fmt = v => v.toFixed(2).replace('.', ',') + '€';
            const oweTotEl  = document.getElementById('fin-debts-owe-total');
            const owedTotEl = document.getElementById('fin-debts-owed-total');
            const netEl     = document.getElementById('fin-debts-net');
            const netRow    = document.getElementById('fin-debts-net-row');
            if (oweTotEl)  oweTotEl.textContent  = fmt(oweTotal);
            if (owedTotEl) owedTotEl.textContent = fmt(owedTotal);
            if (netEl) {
                netEl.textContent = (net >= 0 ? '+' : '') + fmt(Math.abs(net));
                netEl.style.color = net > 0 ? '#34d399' : net < 0 ? '#f87171' : '#94a3b8';
            }
            if (netRow) netRow.style.borderColor = net > 0 ? 'rgba(52,211,153,0.3)' : net < 0 ? 'rgba(248,113,113,0.3)' : 'rgba(255,255,255,0.08)';
        }

        function addFinDebt(dir) {
            finDebts.push({ id: 'debt' + Date.now(), dir: dir, person: '', amount: 0, desc: '' });
            saveFinDebts();
            renderFinDebts();
            // Focus the person input of the new row
            setTimeout(function() {
                const rows = document.querySelectorAll('#fin-debts-list > div');
                const last = rows[rows.length - 1];
                if (last) { const inp = last.querySelector('input'); if (inp) inp.focus(); }
            }, 50);
        }

        function deleteFinDebt(i) {
            finDebts.splice(i, 1);
            saveFinDebts();
            renderFinDebts();
        }

        function addDebtReminderTask(i) {
            const d = finDebts[i];
            if (!d) return;
            const person = (d.person || '').trim() || 'someone';
            const amountStr = (parseFloat(d.amount) > 0) ? ' (' + String(d.amount).replace('.', ',') + '€)' : '';
            const isOwe = d.dir === 'owe';
            const taskText = (isOwe ? 'Pay ' : 'Ask ') + person + (isOwe ? '' : ' for money') + amountStr;
            if (!gTasksAll['finance']) gTasksAll['finance'] = [];
            if (gTasksAll['finance'].some(t => t.text === taskText && !t.done)) {
                showToast('Already in Today\'s Tasks', '#fbbf24'); return;
            }
            gTasksAll['finance'].push({
                id: Date.now() + Math.random(), emoji: isOwe ? '😬' : '🤑',
                text: taskText, notes: d.desc || '', done: false
            });
            saveGTasksAll();
            renderGTasks('finance');
            showToast('📋 Task added', '#34d399');
        }

        function saveFinDebt(i, field, val) {
            if (!finDebts[i]) return;
            if (field === 'amount') {
                finDebts[i].amount = parseFloat(String(val).replace(',', '.')) || 0;
            } else {
                finDebts[i][field] = val;
            }
            saveFinDebts();
            // Re-render totals only (avoid full re-render while typing)
            const oweTotal  = finDebts.filter(d => d.dir === 'owe' ).reduce((s, d) => s + (parseFloat(d.amount) || 0), 0);
            const owedTotal = finDebts.filter(d => d.dir === 'owed').reduce((s, d) => s + (parseFloat(d.amount) || 0), 0);
            const net       = owedTotal - oweTotal;
            const fmt = v => v.toFixed(2).replace('.', ',') + '€';
            const oweTotEl  = document.getElementById('fin-debts-owe-total');
            const owedTotEl = document.getElementById('fin-debts-owed-total');
            const netEl     = document.getElementById('fin-debts-net');
            const netRow    = document.getElementById('fin-debts-net-row');
            const sumEl     = document.getElementById('fin-debts-summary');
            if (sumEl)     sumEl.style.display = finDebts.length ? 'flex' : 'none';
            if (oweTotEl)  oweTotEl.textContent  = fmt(oweTotal);
            if (owedTotEl) owedTotEl.textContent = fmt(owedTotal);
            if (netEl) {
                netEl.textContent = (net >= 0 ? '+' : '') + fmt(Math.abs(net));
                netEl.style.color = net > 0 ? '#34d399' : net < 0 ? '#f87171' : '#94a3b8';
            }
            if (netRow) netRow.style.borderColor = net > 0 ? 'rgba(52,211,153,0.3)' : net < 0 ? 'rgba(248,113,113,0.3)' : 'rgba(255,255,255,0.08)';
        }

        // ═══════════════════════════════════════════════════════════
        //  DYNAMIC SCHEDULE SYSTEM
        // ═══════════════════════════════════════════════════════════

        const SCHED_DEFAULT = [];

        // ── Per-day schedule ──
        const _SCHED_DAYS       = ['mon','tue','wed','thu','fri','sat','sun'];
        const _SCHED_DAY_LABELS = ['Mo','Tu','We','Th','Fr','Sa','Su'];
        const _MONTH_NAMES      = ['January','February','March','April','May','June','July','August','September','October','November','December'];

        // Helper: Date → 'YYYY-MM-DD'
        function _dateKey(d) {
            var dt = new Date(d);
            return dt.getFullYear() + '-' + String(dt.getMonth()+1).padStart(2,'0') + '-' + String(dt.getDate()).padStart(2,'0');
        }
        // Helper: 'YYYY-MM-DD' → weekday abbr ('mon'…'sun') — used for rSlotsPerDay
        function _dayAbbr(dateKey) {
            var d = new Date(dateKey + 'T00:00:00');
            return _SCHED_DAYS[d.getDay() === 0 ? 6 : d.getDay() - 1];
        }

        // Today's key as YYYY-MM-DD
        let schedDay = _dateKey(new Date());

        // Calendar navigation state
        let _schedCalYear  = new Date().getFullYear();
        let _schedCalMonth = new Date().getMonth(); // 0-11

        let schedBlocksPerDay = {};
        try {
            const _spd = JSON.parse(localStorage.getItem('schedBlocksPerDay') || '{}');
            if (_spd && typeof _spd === 'object' && !Array.isArray(_spd)) schedBlocksPerDay = _spd;
        } catch(e) {}

        // Migrate old 'mon'/'tue'/... keys → YYYY-MM-DD keys for this week
        (function() {
            var _OLD = ['mon','tue','wed','thu','fri','sat','sun'];
            var _hasOld = _OLD.some(function(d) { return Array.isArray(schedBlocksPerDay[d]) && schedBlocksPerDay[d].length; });
            if (!_hasOld) return;
            var _now = new Date(); _now.setHours(0,0,0,0);
            var _dow = _now.getDay();
            var _monday = new Date(_now); _monday.setDate(_now.getDate() - (_dow === 0 ? 6 : _dow - 1));
            _OLD.forEach(function(d, i) {
                if (!Array.isArray(schedBlocksPerDay[d]) || !schedBlocksPerDay[d].length) { delete schedBlocksPerDay[d]; return; }
                var _date = new Date(_monday); _date.setDate(_monday.getDate() + i);
                var _dk = _dateKey(_date);
                if (!schedBlocksPerDay[_dk] || !schedBlocksPerDay[_dk].length) schedBlocksPerDay[_dk] = schedBlocksPerDay[d];
                delete schedBlocksPerDay[d];
            });
            localStorage.setItem('schedBlocksPerDay', JSON.stringify(schedBlocksPerDay));
        })();

        // Migrate legacy schedBlocks2 → today's slot (once, only if today's key is truly absent)
        (function() {
            if (schedDay in schedBlocksPerDay) return; // key exists (even empty) — don't overwrite
            try {
                const _leg = JSON.parse(localStorage.getItem('schedBlocks2') || 'null');
                if (_leg && Array.isArray(_leg) && _leg.length) {
                    schedBlocksPerDay[schedDay] = _leg;
                    localStorage.setItem('schedBlocksPerDay', JSON.stringify(schedBlocksPerDay));
                }
            } catch(e) {}
        })();

        let schedBlocks = [];

        function _loadSchedDay(day) {
            schedBlocks = JSON.parse(JSON.stringify(
                Array.isArray(schedBlocksPerDay[day]) ? schedBlocksPerDay[day] : []
            ));
            schedBlocks = schedBlocks.filter(b => b != null).map(function(b) {
                b.tasks = (b.tasks || []).filter(t => t != null);
                return b;
            });
        }
        _loadSchedDay(schedDay);
        saveSchedBlocks();

        function saveSchedBlocks() {
            schedBlocksPerDay[schedDay] = schedBlocks;
            localStorage.setItem('schedBlocksPerDay', JSON.stringify(schedBlocksPerDay));
            // Only keep schedBlocks2 in sync when editing today — future days must not pollute it
            if (schedDay === _dateKey(new Date())) {
                localStorage.setItem('schedBlocks2', JSON.stringify(schedBlocks));
            }
        }

        function schedSwitchDay(day) {
            if (day === schedDay) return;
            schedDay = day;
            _loadSchedDay(day);
            rSlots = Object.assign({}, R_DEFAULTS, rSlotsPerDay[day] || {});
            ['r1','r2','r3'].forEach(function(slot) {
                var sel = document.getElementById(slot + '-select');
                if (sel) sel.value = rSlots[slot] || 'none';
                if (typeof renderRSection === 'function') renderRSection(slot);
                if (typeof updateRTaskCount === 'function') updateRTaskCount(slot);
            });
            if (typeof updateRLabels === 'function') updateRLabels();
            if (typeof bindScheduleRTasks === 'function') bindScheduleRTasks();
            initSchedCalendar();
            renderSchedule();
            highlightCurrentBlock();
            _updateSchedFab();
            updateSummaryPills();
            updateProgress();
        }

        function schedCalNav(dir) {
            _schedCalMonth += dir;
            if (_schedCalMonth < 0)  { _schedCalMonth = 11; _schedCalYear--; }
            if (_schedCalMonth > 11) { _schedCalMonth = 0;  _schedCalYear++; }
            initSchedCalendar();
        }

        function initSchedDaySelector() { initSchedCalendar(); } // compat alias

        function initSchedCalendar() {
            var wrap = document.getElementById('sched-cal-wrap');
            if (!wrap) return;
            var todayKey   = _dateKey(new Date());
            var firstDay   = new Date(_schedCalYear, _schedCalMonth, 1);
            var lastDay    = new Date(_schedCalYear, _schedCalMonth + 1, 0);
            var startOffset = firstDay.getDay() === 0 ? 6 : firstDay.getDay() - 1;

            var h = '<div class="sched-cal">';
            // Header
            h += '<div class="sched-cal-hdr">'
               + '<button class="sched-cal-nav" onclick="schedCalNav(-1)">&#8249;</button>'
               + '<span class="sched-cal-title">' + _MONTH_NAMES[_schedCalMonth] + ' ' + _schedCalYear + '</span>'
               + '<button class="sched-cal-nav" onclick="schedCalNav(1)">&#8250;</button>'
               + '</div>';
            // Day-of-week headers + day cells
            h += '<div class="sched-cal-grid">';
            _SCHED_DAY_LABELS.forEach(function(l) { h += '<div class="sched-cal-dow">' + l + '</div>'; });
            // Prev-month padding cells
            for (var b = 0; b < startOffset; b++) {
                var pd = new Date(_schedCalYear, _schedCalMonth, 1 - startOffset + b);
                var pk = _dateKey(pd);
                var pdot = schedBlocksPerDay[pk] && schedBlocksPerDay[pk].length;
                h += '<button class="sched-cal-day other-month' + (pk === schedDay ? ' selected' : '') + '" onclick="schedSwitchDay(\'' + pk + '\')">'
                   + '<span class="sched-cal-num">' + pd.getDate() + '</span>'
                   + (pdot ? '<span class="sched-cal-dot"></span>' : '')
                   + '</button>';
            }
            // Current month
            for (var d = 1; d <= lastDay.getDate(); d++) {
                var dk  = _dateKey(new Date(_schedCalYear, _schedCalMonth, d));
                var cls = 'sched-cal-day'
                        + (dk === todayKey  ? ' today'    : '')
                        + (dk === schedDay  ? ' selected' : '');
                var dot = schedBlocksPerDay[dk] && schedBlocksPerDay[dk].length;
                h += '<button class="' + cls + '" onclick="schedSwitchDay(\'' + dk + '\')">'
                   + '<span class="sched-cal-num">' + d + '</span>'
                   + (dot ? '<span class="sched-cal-dot"></span>' : '')
                   + '</button>';
            }
            // Next-month padding
            var filled = startOffset + lastDay.getDate();
            var remainder = filled % 7 === 0 ? 0 : 7 - (filled % 7);
            for (var n = 1; n <= remainder; n++) {
                var nk  = _dateKey(new Date(_schedCalYear, _schedCalMonth + 1, n));
                var ndot = schedBlocksPerDay[nk] && schedBlocksPerDay[nk].length;
                h += '<button class="sched-cal-day other-month' + (nk === schedDay ? ' selected' : '') + '" onclick="schedSwitchDay(\'' + nk + '\')">'
                   + '<span class="sched-cal-num">' + n + '</span>'
                   + (ndot ? '<span class="sched-cal-dot"></span>' : '')
                   + '</button>';
            }
            h += '</div></div>';
            wrap.innerHTML = h;
        }

        // ── Migrate: backfill subtasks on existing imported gTask block tasks ──
        // Runs once after load to fix tasks imported before subtask support was added.
        (function _migrateSchedSubtasks() {
            if (typeof gTasksAll === 'undefined') return;
            let changed = false;
            schedBlocks.forEach(function(block) {
                (block.tasks || []).forEach(function(bt) {
                    if (!bt || !bt.id || bt.subtasks != null) return; // null guard + already has subtasks field
                    // bt.id format: 'gtask-{sid}-{numericId}'
                    const m = bt.id.match(/^gtask-([^-]+(?:-[^-]+)*?)-(\d+)$/);
                    if (!m) return;
                    const sid = m[1];
                    const numId = parseInt(m[2], 10);
                    const gtasks = gTasksAll[sid] || [];
                    const src = gtasks.find(function(x){ return x.id === numId; });
                    if (!src) return;
                    if (src.subtasks && src.subtasks.length) {
                        bt.subtasks   = src.subtasks.map(function(s){ return {id:s.id,text:s.text,done:!!s.done}; });
                        bt.accentColor = src.accentColor || null;
                        bt.groupRef    = src.groupRef    || null;
                        changed = true;
                    }
                });
            });
            if (changed) saveSchedBlocks();
        })();

        // ════════════════════════════════════════════════════════════════
        //  SCHEDULE TEMPLATES
        // ════════════════════════════════════════════════════════════════

        let schedTemplates = [];
        try { schedTemplates = JSON.parse(localStorage.getItem('schedTemplates') || '[]') || []; } catch(e) { schedTemplates = []; }
        const saveSchedTemplatesList = () => saveData('schedTemplates', schedTemplates);

        function openTemplatesPanel() {
            renderTemplatesPanel();
            const tb  = document.getElementById('sched-toolbar');
            const fab = document.getElementById('sched-fab-wrap');
            if (tb)  tb.style.display  = 'none';
            if (fab) fab.style.display = 'none';
            document.getElementById('tpl-overlay').style.display = 'block';
            const panel = document.getElementById('tpl-panel');
            panel.style.display = 'flex';
            panel.style.transform = 'translateY(100%)';
            panel.style.transition = 'transform 0.3s cubic-bezier(0.32,0.72,0,1)';
            requestAnimationFrame(() => { panel.style.transform = 'translateY(0)'; });
        }

        function closeTemplatesPanel() {
            const panel = document.getElementById('tpl-panel');
            panel.style.transform = 'translateY(100%)';
            setTimeout(() => {
                document.getElementById('tpl-overlay').style.display = 'none';
                panel.style.display = 'none';
                const tb  = document.getElementById('sched-toolbar');
                const fab = document.getElementById('sched-fab-wrap');
                if (tb)  tb.style.display  = '';
                if (fab) fab.style.display = '';
            }, 280);
        }

        function saveCurrentAsTemplate() {
            const nameEl = document.getElementById('tpl-save-name');
            const name = (nameEl ? nameEl.value : '').trim();
            const hint = document.getElementById('tpl-save-hint');
            if (!name) {
                if (nameEl) { nameEl.focus(); nameEl.style.borderColor = 'rgba(239,68,68,0.6)'; setTimeout(() => nameEl.style.borderColor = 'rgba(251,191,36,0.2)', 1200); }
                return;
            }
            const bc = schedBlocks.length;
            if (!bc) { showToast('Nothing to save — your schedule is empty.', '#f87171'); return; }
            const tpl = {
                id: Date.now(),
                name,
                created: new Date().toLocaleDateString('en-GB'),
                blocks: JSON.parse(JSON.stringify(schedBlocks))
            };
            schedTemplates.unshift(tpl);
            saveSchedTemplatesList();
            if (nameEl) nameEl.value = '';
            if (hint) { hint.textContent = `✓ "${name}" saved!`; hint.style.color = '#34d399'; setTimeout(() => { if (hint) { hint.textContent = ''; updateTplSaveHint(); } }, 2500); }
            renderTemplatesPanel();
        }

        function updateTplSaveHint() {
            const hint = document.getElementById('tpl-save-hint');
            if (!hint || hint.textContent) return;
            const bc = schedBlocks.length;
            const tc = schedBlocks.reduce((s,b) => s+(b.tasks||[]).length, 0);
            hint.textContent = `Current: ${bc} block${bc!==1?'s':''} · ${tc} task${tc!==1?'s':''}`;
            hint.style.color = '#334155';
        }

        function loadTemplate(id) {
            const tpl = schedTemplates.find(t => t.id === id);
            if (!tpl) return;
            showConfirm({
                title: '📋 Load Template?',
                message: `Replace your current schedule with <strong style="color:#fbbf24;">"${escapeHtml(tpl.name)}"</strong>?<br><small style="color:#64748b;">${tpl.blocks.length} blocks · saved ${tpl.created}</small>`,
                confirmLabel: '▶ Load',
                confirmColor: '#f59e0b',
                onConfirm: () => {
                    schedBlocks = JSON.parse(JSON.stringify(tpl.blocks));
                    // Reset done states and strip tasks that no longer exist in gTasksAll
                    // Build a flat lookup: gtask-key → source task
                    const _gtaskLookup = {};
                    if (typeof gTasksAll !== 'undefined') {
                        Object.entries(gTasksAll).forEach(([sid, arr]) => {
                            (arr || []).forEach(t => { _gtaskLookup['gtask-' + sid + '-' + t.id] = t; });
                        });
                    }
                    schedBlocks.forEach(block => {
                        block.tasks = (block.tasks || []).filter(task => {
                            const id = String(task.id || '');
                            // Keep plain schedule tasks (manually typed, not linked to a section)
                            if (!id.startsWith('gtask-')) return true;
                            // For linked tasks: source must exist and not be done
                            const src = _gtaskLookup[id];
                            return !!src && !src.done;
                        });
                        block.tasks.forEach(task => {
                            task.done = false;
                            if (Array.isArray(task.subtasks)) task.subtasks.forEach(s => s.done = false);
                        });
                    });
                    saveSchedBlocks();
                    renderSchedule();
                    closeTemplatesPanel();
                    showToast(`✓ Loaded "${tpl.name}"`, '#fbbf24');
                }
            });
        }

        function duplicateTemplate(id) {
            const tpl = schedTemplates.find(t => t.id === id);
            if (!tpl) return;
            const copy = { id: Date.now(), name: tpl.name + ' (copy)', created: new Date().toLocaleDateString('en-GB'), blocks: JSON.parse(JSON.stringify(tpl.blocks)) };
            const idx = schedTemplates.findIndex(t => t.id === id);
            schedTemplates.splice(idx + 1, 0, copy);
            saveSchedTemplatesList();
            renderTemplatesPanel();
        }

        function overwriteTemplate(id) {
            const tpl = schedTemplates.find(t => t.id === id);
            if (!tpl) return;
            const bc = schedBlocks.length;
            if (!bc) { showToast('Nothing to save — your schedule is empty.', '#f87171'); return; }
            showConfirm({
                title: '↺ Overwrite Template?',
                message: `Replace <strong style="color:#fbbf24;">"${escapeHtml(tpl.name)}"</strong> with your current schedule?<br><small style="color:#64748b;">Current: ${bc} block${bc!==1?'s':''} · ${schedBlocks.reduce((s,b)=>s+(b.tasks||[]).length,0)} tasks</small>`,
                confirmLabel: '↺ Overwrite',
                confirmColor: '#f59e0b',
                onConfirm: () => {
                    tpl.blocks   = JSON.parse(JSON.stringify(schedBlocks));
                    tpl.created  = new Date().toLocaleDateString('en-GB');
                    saveSchedTemplatesList();
                    renderTemplatesPanel();
                    showToast(`↺ Updated "${tpl.name}"`, '#fbbf24');
                }
            });
        }

        function deleteTemplate(id) {
            const tpl = schedTemplates.find(t => t.id === id);
            if (!tpl) return;
            showConfirm({
                title: '🗑 Delete Template?',
                message: `Delete <strong style="color:#e2e8f0;">"${escapeHtml(tpl.name)}"</strong>? This cannot be undone.`,
                confirmLabel: '🗑 Delete',
                confirmColor: '#ef4444',
                onConfirm: () => {
                    schedTemplates = schedTemplates.filter(t => t.id !== id);
                    saveSchedTemplatesList();
                    renderTemplatesPanel();
                }
            });
        }

        function moveTemplate(id, dir) {
            const idx = schedTemplates.findIndex(t => t.id === id);
            if (idx < 0) return;
            const swapIdx = dir === 'up' ? idx - 1 : idx + 1;
            if (swapIdx < 0 || swapIdx >= schedTemplates.length) return;
            [schedTemplates[idx], schedTemplates[swapIdx]] = [schedTemplates[swapIdx], schedTemplates[idx]];
            saveSchedTemplatesList();
            renderTemplatesPanel();
        }

        function renderTemplatesPanel() {
            const body = document.getElementById('tpl-body');
            if (!body) return;
            updateTplSaveHint();

            if (!schedTemplates.length) {
                body.innerHTML = `<div style="padding:40px 20px;text-align:center;color:#334155;font-size:0.9em;">
                    <div style="font-size:2.4em;margin-bottom:12px;">📋</div>
                    No templates saved yet.<br>
                    <span style="font-size:0.85em;color:#1e293b;">Type a name above and hit 💾 Save to create your first one.</span>
                </div>`;
                return;
            }

            body.innerHTML = `<div style="padding:12px 16px 6px;font-size:0.72em;color:#334155;font-weight:800;text-transform:uppercase;letter-spacing:0.07em;">
                ${schedTemplates.length} Template${schedTemplates.length!==1?'s':''}
            </div>` + schedTemplates.map((t, i) => {
                const tbc = (t.blocks||[]).length;
                const ttc = (t.blocks||[]).reduce((s,b) => s+(b.tasks||[]).length, 0);
                const isFirst = i === 0;
                const isLast = i === schedTemplates.length - 1;
                const btnBase = "border-radius:8px;padding:7px 10px;font-family:'Outfit',sans-serif;font-size:0.78em;cursor:pointer;transition:all 0.15s;";
                return `<div style="display:flex;align-items:center;gap:10px;padding:13px 16px;
                           border-bottom:1px solid rgba(255,255,255,0.04);
                           transition:background 0.15s;"
                       onmouseover="this.style.background='rgba(255,255,255,0.025)'"
                       onmouseout="this.style.background=''">
                    <div style="display:flex;flex-direction:column;gap:3px;flex-shrink:0;">
                        <button onclick="moveTemplate(${t.id},'up')"
                            data-tooltip="Move up"
                            ${isFirst ? 'disabled' : ''}
                            style="${btnBase}background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.1);color:${isFirst?'#1e293b':'#94a3b8'};padding:3px 8px;font-size:0.7em;${isFirst?'cursor:default;':''}"
                            ${isFirst ? '' : `onmouseover="this.style.background='rgba(255,255,255,0.1)'" onmouseout="this.style.background='rgba(255,255,255,0.04)'"`}>▲</button>
                        <button onclick="moveTemplate(${t.id},'down')"
                            data-tooltip="Move down"
                            ${isLast ? 'disabled' : ''}
                            style="${btnBase}background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.1);color:${isLast?'#1e293b':'#94a3b8'};padding:3px 8px;font-size:0.7em;${isLast?'cursor:default;':''}"
                            ${isLast ? '' : `onmouseover="this.style.background='rgba(255,255,255,0.1)'" onmouseout="this.style.background='rgba(255,255,255,0.04)'"`}>▼</button>
                    </div>
                    <div style="flex:1;min-width:0;">
                        <div style="font-weight:800;color:#e2e8f0;font-size:0.92em;
                                    overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${escapeHtml(t.name)}</div>
                        <div style="font-size:0.72em;color:#475569;margin-top:3px;">
                            ${tbc} block${tbc!==1?'s':''} · ${ttc} task${ttc!==1?'s':''}
                            ${t.created ? `<span style="color:#1e293b;"> · ${t.created}</span>` : ''}
                        </div>
                    </div>
                    <div style="display:flex;gap:6px;flex-shrink:0;">
                        <button onclick="loadTemplate(${t.id})"
                            style="background:rgba(251,191,36,0.1);border:1px solid rgba(251,191,36,0.3);color:#fbbf24;
                            border-radius:8px;padding:7px 14px;font-family:'Outfit',sans-serif;font-size:0.78em;font-weight:800;cursor:pointer;
                            transition:all 0.15s;"
                            onmouseover="this.style.background='rgba(251,191,36,0.2)'"
                            onmouseout="this.style.background='rgba(251,191,36,0.1)'">▶ Load</button>
                        <button onclick="overwriteTemplate(${t.id})"
                            data-tooltip="Overwrite with current schedule"
                            style="background:rgba(251,191,36,0.06);border:1px solid rgba(251,191,36,0.2);color:#92400e;
                            border-radius:8px;padding:7px 10px;font-family:'Outfit',sans-serif;font-size:0.78em;cursor:pointer;
                            transition:all 0.15s;"
                            onmouseover="this.style.background='rgba(251,191,36,0.16)';this.style.color='#fbbf24'"
                            onmouseout="this.style.background='rgba(251,191,36,0.06)';this.style.color='#92400e'">↺</button>
                        <button onclick="duplicateTemplate(${t.id})"
                            data-tooltip="Duplicate"
                            style="background:rgba(99,102,241,0.08);border:1px solid rgba(99,102,241,0.2);color:#818cf8;
                            border-radius:8px;padding:7px 10px;font-family:'Outfit',sans-serif;font-size:0.78em;cursor:pointer;
                            transition:all 0.15s;"
                            onmouseover="this.style.background='rgba(99,102,241,0.18)'"
                            onmouseout="this.style.background='rgba(99,102,241,0.08)'">⧉</button>
                        <button onclick="deleteTemplate(${t.id})"
                            data-tooltip="Delete"
                            style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.18);color:#f87171;
                            border-radius:8px;padding:7px 10px;font-family:'Outfit',sans-serif;font-size:0.78em;cursor:pointer;
                            transition:all 0.15s;"
                            onmouseover="this.style.background='rgba(239,68,68,0.16)'"
                            onmouseout="this.style.background='rgba(239,68,68,0.06)'">🗑</button>
                    </div>
                </div>`;
            }).join('');
        }

        // ════════════════════════════════════════════════════════════════
        //  SCHEDULE FILE EXPORT / IMPORT
        // ════════════════════════════════════════════════════════════════

        function exportScheduleAsFile() {
            const bc = schedBlocks.length;
            if (!bc) { showToast('Nothing to export — your schedule is empty.', '#f87171'); return; }
            const data = { _type: 'jn-schedule-template', _version: 1, _exported: new Date().toISOString(), blocks: schedBlocks };
            _downloadJson(data, `schedule-${_dateStr()}.json`);
            showToast(`📤 Schedule exported (${bc} blocks)`, '#34d399');
        }

        function importScheduleFile(input) {
            const file = input.files[0];
            input.value = '';
            if (!file) return;
            const reader = new FileReader();
            reader.onload = (ev) => {
                try {
                    const data = JSON.parse(ev.target.result);
                    let blocks = null;
                    if (data._type === 'jn-schedule-template' && Array.isArray(data.blocks)) {
                        blocks = data.blocks;
                    } else if (data._app === 'JN-Life-App' && data.data && data.data.schedBlocks2) {
                        try { blocks = JSON.parse(data.data.schedBlocks2); } catch(e) {}
                    }
                    if (!blocks || !Array.isArray(blocks) || !blocks.length) {
                        showToast('No valid schedule found in this file.', '#f87171'); return;
                    }
                    const suggestedName = file.name.replace(/\.json$/,'').replace(/^schedule-/,'').replace(/-/g,' ').trim() || 'Imported';
                    showConfirm({
                        title: '📥 Import Schedule',
                        message: `Found <strong style="color:#fbbf24;">${blocks.length} blocks</strong> in <em>${escapeHtml(file.name)}</em>.<br>
                                  Will also be saved as template <strong>"${escapeHtml(suggestedName)}"</strong>.<br><br>
                                  <small style="color:#64748b;">Your current schedule will be replaced.</small>`,
                        confirmLabel: '▶ Load & Save',
                        confirmColor: '#f59e0b',
                        onConfirm: () => {
                            schedBlocks = JSON.parse(JSON.stringify(blocks));
                            saveSchedBlocks();
                            renderSchedule();
                            schedTemplates.unshift({ id: Date.now(), name: suggestedName, created: new Date().toLocaleDateString('en-GB'), blocks: JSON.parse(JSON.stringify(blocks)) });
                            saveSchedTemplatesList();
                            renderTemplatesPanel();
                            showToast(`✓ Loaded & saved as "${suggestedName}"`, '#34d399');
                        }
                    });
                } catch(err) { showToast('Failed to read file: ' + err.message, '#f87171'); }
            };
            reader.readAsText(file);
        }

        // ════════════════════════════════════════════════════════════════
        //  FULL APP BACKUP / RESTORE
        // ════════════════════════════════════════════════════════════════

        const BACKUP_KEYS = [
            // Schedule
            'schedBlocks2','schedTemplates','schedBlocksPerDay',
            // Tasks & slots
            'wednesdayTasks','gTasksAll','respTasks','rSlots','rSlotsPerDay',
            // App state
            'limits','limitsV2','lastAppDate','catCollapsed','customRespItems',
            'scheduleFocusCardOrder','dailyFocusOpen',
            // Organize
            'orgMode','orgModes','orgChecksDate','impOrgNightGroups',
            // Important – Work / Info
            'impWorkProjects','impWorkTimeLog','impBInfo','bGifts',
            // Finance
            'financeMoney','financeSubscriptions','finAccounts',
            'finBudgetIncome','finCategories','finTx','finDebts',
            // Pills
            'pillInventory','pillsInventory','liquidsInventory',
            // Responsibilities
            'houseData','lostData','famData','friData','praxeData',
            'lookData','shoppingData','travelData',
            'dentistData','dentistAppointments',
            'ophthalmologistData','generalDoctorData','dermData','psyData','guitarData','saxData','pianoData','abletonData','streamingData','investData','socialData','emuData','pcData','phoneData','calData','uaData','lensData','roomData',
            // Gym & Martial Arts
            // Projects (update-app)
            'projectsData',
            // Gym & Martial Arts
            'gym123Data','gymWeeklySessions','maData','maTaskDefs',
            // Love
            'loveData','loveMemories',
            // Recipes
            'recipesData',
        ];

        function exportAllData() {
            const backup = { _app: 'JN-Life-App', _version: 2, _exported: new Date().toISOString(), data: {} };
            let count = 0;
            // Static keys
            BACKUP_KEYS.forEach(k => {
                const v = localStorage.getItem(k);
                if (v !== null) { backup.data[k] = v; count++; }
            });
            // Dynamic Organize mode keys (impOrgData_<id>)
            Object.keys(localStorage).filter(k => k.startsWith('impOrgData_')).forEach(k => {
                const v = localStorage.getItem(k);
                if (v !== null) { backup.data[k] = v; count++; }
            });
            if (!count) { showToast('Nothing to export yet.', '#f87171'); return; }
            _downloadJson(backup, `jn-life-backup-${_dateStr()}.json`);
            showToast(`📤 Backup exported (${count} data stores)`, '#34d399');
        }

        function importBackupFile() {
            const input = document.createElement('input');
            input.type = 'file';
            input.accept = '.json,application/json';
            input.onchange = (e) => {
                const file = e.target.files[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = (ev) => {
                    try {
                        const backup = JSON.parse(ev.target.result);
                        if (!backup._app || !backup.data || typeof backup.data !== 'object') {
                            showToast('Invalid backup file.', '#f87171'); return;
                        }
                        const keys = Object.keys(backup.data);
                        const dateStr = backup._exported ? backup._exported.slice(0,10) : 'unknown date';
                        showConfirm({
                            title: '📥 Restore Backup?',
                            message: `Restore backup from <strong style="color:#60a5fa;">${dateStr}</strong>?<br>
                                      Contains <strong>${keys.length} data stores</strong>.<br><br>
                                      <strong style="color:#f87171;">This will overwrite all your current data.</strong><br>
                                      <small style="color:#64748b;">The page will reload after restore.</small>`,
                            confirmLabel: '✓ Restore Everything',
                            confirmColor: '#3b82f6',
                            onConfirm: () => {
                                Object.entries(backup.data).forEach(([k, v]) => {
                                    try { localStorage.setItem(k, v); } catch(err) {}
                                });
                                // Migrate old backups: if schedBlocks2 present but schedBlocksPerDay absent,
                                // inject blocks into this week's Wednesday using a real date key.
                                if (backup.data['schedBlocks2'] && !backup.data['schedBlocksPerDay']) {
                                    try {
                                        const _migBlocks = JSON.parse(backup.data['schedBlocks2']);
                                        if (Array.isArray(_migBlocks) && _migBlocks.length) {
                                            const _mn = new Date(); _mn.setHours(0,0,0,0);
                                            const _dw = _mn.getDay();
                                            const _mo = new Date(_mn); _mo.setDate(_mn.getDate() - (_dw === 0 ? 6 : _dw - 1));
                                            const _we = new Date(_mo); _we.setDate(_mo.getDate() + 2);
                                            const _wk = _we.getFullYear() + '-' + String(_we.getMonth()+1).padStart(2,'0') + '-' + String(_we.getDate()).padStart(2,'0');
                                            localStorage.setItem('schedBlocksPerDay', JSON.stringify({ [_wk]: _migBlocks }));
                                            localStorage.setItem('schedBlocks2', '[]');
                                        }
                                    } catch(e) {}
                                }
                                // rSlotsPerDay is now date-keyed — old weekday-keyed rSlots are not migrated
                                // so each date starts with clean R slots (no stale data from old backups).
                                location.reload();
                            }
                        });
                    } catch(err) { showToast('Failed to parse backup: ' + err.message, '#f87171'); }
                };
                reader.readAsText(file);
            };
            input.click();
        }

        // ════════════════════════════════════════════════════════════════
        //  FILE SYSTEM ACCESS — persistent save/load next to the HTML file
        // ════════════════════════════════════════════════════════════════

        // IndexedDB helpers — store the FileSystemFileHandle across sessions
        function _fsaOpenDB() {
            return new Promise((res, rej) => {
                const req = indexedDB.open('jnlife-fsa', 1);
                req.onupgradeneeded = e => e.target.result.createObjectStore('handles');
                req.onsuccess = e => res(e.target.result);
                req.onerror   = e => rej(e.target.error);
            });
        }
        async function _fsaSaveHandle(handle) {
            const db = await _fsaOpenDB();
            return new Promise((res, rej) => {
                const tx = db.transaction('handles', 'readwrite');
                tx.objectStore('handles').put(handle, 'saveFileHandle');
                tx.oncomplete = res; tx.onerror = rej;
            });
        }
        async function _fsaLoadHandle() {
            const db = await _fsaOpenDB();
            return new Promise((res, rej) => {
                const tx = db.transaction('handles', 'readonly');
                const req = tx.objectStore('handles').get('saveFileHandle');
                req.onsuccess = e => res(e.target.result || null);
                req.onerror   = e => rej(e.target.error);
            });
        }
        async function _fsaPermission(handle, mode) {
            if (!handle) return false;
            try {
                if (await handle.queryPermission({ mode }) === 'granted') return true;
                return await handle.requestPermission({ mode }) === 'granted';
            } catch(e) { return false; }
        }
        function _fsaUpdateStatus(name) {
            const el = document.getElementById('save-file-status');
            if (!el) return;
            el.textContent  = name ? `Linked: ${name}` : '';
            el.style.display = name ? 'block' : 'none';
        }
        async function _fsaInitStatus() {
            if (_isNativeApp()) return; // file links don't exist in the native app
            try {
                const h = await _fsaLoadHandle();
                if (h) _fsaUpdateStatus(h.name);
            } catch(e) {}
        }

        // Build the backup payload (same data as exportAllData)
        function _buildBackup() {
            const backup = { _app: 'JN-Life-App', _version: 2, _exported: new Date().toISOString(), data: {} };
            let count = 0;
            BACKUP_KEYS.forEach(k => {
                const v = localStorage.getItem(k);
                if (v !== null) { backup.data[k] = v; count++; }
            });
            Object.keys(localStorage).filter(k => k.startsWith('impOrgData_')).forEach(k => {
                const v = localStorage.getItem(k);
                if (v !== null) { backup.data[k] = v; count++; }
            });
            return { backup, count };
        }

        // True when running inside the Capacitor native shell (Android/iOS app)
        function _isNativeApp() {
            try { return !!(window.Capacitor && window.Capacitor.isNativePlatform && window.Capacitor.isNativePlatform()); }
            catch(e) { return false; }
        }

        // Native save: write the backup to app cache, then open the Android/iOS
        // share sheet so the user saves it to Files / Drive / sends it anywhere.
        async function _capSaveBackup(backup, count) {
            try {
                if (!window.Capacitor || !window.Capacitor.Plugins) throw new Error('Capacitor not available');
                const { Filesystem, Share } = window.Capacitor.Plugins;
                if (!Filesystem || !Share) throw new Error('Filesystem or Share plugin not loaded');

                const fname = 'jn-life-data.json';
                const data = JSON.stringify(backup, null, 2);

                // Write to cache directory
                await Filesystem.writeFile({ path: fname, data, directory: 'CACHE', encoding: 'utf8' });

                // Get URI and share
                const result = await Filesystem.getUri({ path: fname, directory: 'CACHE' });
                const uri = result.uri;
                if (!uri) throw new Error('Failed to get file URI');

                await Share.share({ title: 'JN Life backup', files: [uri] });
                showToast(`💾 Backup ready (${count} stores)`, '#34d399');
            } catch(err) {
                throw new Error(err.message || err);
            }
        }

        // Save to the linked file (or pick a new one the first time)
        async function saveDataFile() {
            const { backup, count } = _buildBackup();
            if (!count) { showToast('Nothing to save yet.', '#f87171'); return; }

            // Native app: the File System Access API is broken inside WebView —
            // use the native share sheet instead.
            if (_isNativeApp()) {
                try { await _capSaveBackup(backup, count); }
                catch(err) {
                    if (err && err.message && /cancel/i.test(err.message)) return; // user closed share sheet
                    showToast('Save failed: ' + (err && err.message || err), '#f87171');
                }
                return;
            }

            if (!window.showSaveFilePicker) {
                // Fallback for browsers that don't support FSA (Firefox, etc.)
                exportAllData(); return;
            }
            try {
                let handle = await _fsaLoadHandle();
                const hasWrite = await _fsaPermission(handle, 'readwrite');

                if (!handle || !hasWrite) {
                    handle = await window.showSaveFilePicker({
                        suggestedName: 'jn-life-data.json',
                        types: [{ description: 'JN Life data file', accept: { 'application/json': ['.json'] } }]
                    });
                    await _fsaSaveHandle(handle);
                }

                const writable = await handle.createWritable();
                await writable.write(JSON.stringify(backup, null, 2));
                await writable.close();

                _fsaUpdateStatus(handle.name);
                showToast(`💾 Saved to ${handle.name} (${count} stores)`, '#34d399');
            } catch(err) {
                if (err.name === 'AbortError') return;
                // Stale/unusable file link (moved, deleted, or unsupported here) —
                // unlink it and fall back to a plain download so the save still happens.
                try { await _fsaSaveHandle(null); } catch(e2) {}
                _fsaUpdateStatus(null);
                exportAllData();
            }
        }

        // Load from a picked file (always shows file picker so you can choose any file)
        async function loadDataFile() {
            if (_isNativeApp() || !window.showOpenFilePicker) {
                // Native app or browsers without FSA: use the classic file input,
                // which opens the platform's standard file picker.
                importBackupFile(); return;
            }
            try {
                let handle;
                [handle] = await window.showOpenFilePicker({
                    types: [{ description: 'JN Life data file', accept: { 'application/json': ['.json'] } }]
                });

                const file = await handle.getFile();
                const backup = JSON.parse(await file.text());
                if (!backup._app || !backup.data || typeof backup.data !== 'object') {
                    showToast('Invalid data file.', '#f87171'); return;
                }

                await _fsaSaveHandle(handle);
                _fsaUpdateStatus(handle.name);

                const keys = Object.keys(backup.data);
                const dateStr = backup._exported ? backup._exported.slice(0,10) : 'unknown date';
                showConfirm({
                    title: '📥 Restore Data?',
                    message: `Restore from <strong style="color:#60a5fa;">${escapeHtml(handle.name)}</strong> (${dateStr})?<br>
                              Contains <strong>${keys.length} data stores</strong>.<br><br>
                              <strong style="color:#f87171;">This will overwrite all your current data.</strong><br>
                              <small style="color:#64748b;">The page will reload after restore.</small>`,
                    confirmLabel: '✓ Restore Everything',
                    confirmColor: '#3b82f6',
                    onConfirm: () => {
                        Object.entries(backup.data).forEach(([k, v]) => {
                            try { localStorage.setItem(k, v); } catch(e2) {}
                        });
                        if (backup.data['schedBlocks2'] && !backup.data['schedBlocksPerDay']) {
                            try {
                                const _mb = JSON.parse(backup.data['schedBlocks2']);
                                if (Array.isArray(_mb) && _mb.length) {
                                    const _mn = new Date(); _mn.setHours(0,0,0,0);
                                    const _dw = _mn.getDay();
                                    const _mo = new Date(_mn); _mo.setDate(_mn.getDate() - (_dw === 0 ? 6 : _dw - 1));
                                    const _we = new Date(_mo); _we.setDate(_mo.getDate() + 2);
                                    const _wk = _we.getFullYear() + '-' + String(_we.getMonth()+1).padStart(2,'0') + '-' + String(_we.getDate()).padStart(2,'0');
                                    localStorage.setItem('schedBlocksPerDay', JSON.stringify({ [_wk]: _mb }));
                                    localStorage.setItem('schedBlocks2', '[]');
                                }
                            } catch(e2) {}
                        }
                        location.reload();
                    }
                });
            } catch(err) {
                if (err.name !== 'AbortError') showToast('Load failed: ' + err.message, '#f87171');
            }
        }

        // ── Shared helpers ─────────────────────────────────────────────

        function _dateStr() { return new Date().toISOString().slice(0, 10); }

        function _downloadJson(obj, filename) {
            const json = JSON.stringify(obj, null, 2);
            const blob = new Blob([json], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url; a.download = filename; a.click();
            setTimeout(() => URL.revokeObjectURL(url), 1000);
        }

        function showToast(msg, color) {
            let t = document.getElementById('_jn_toast');
            if (!t) {
                t = document.createElement('div');
                t.id = '_jn_toast';
                t.style.cssText = `position:fixed;bottom:90px;left:50%;transform:translateX(-50%) translateY(20px);
                    background:rgba(8,12,24,0.97);border:1.5px solid rgba(255,255,255,0.08);
                    border-radius:14px;padding:11px 22px;font-family:'Outfit',sans-serif;
                    font-size:0.87em;font-weight:700;z-index:9999;pointer-events:none;
                    opacity:0;transition:opacity 0.25s,transform 0.25s;white-space:nowrap;
                    box-shadow:0 8px 32px rgba(0,0,0,0.6);max-width:90vw;text-align:center;`;
                document.body.appendChild(t);
            }
            t.textContent = msg;
            t.style.color = color || '#e2e8f0';
            t.style.opacity = '1'; t.style.transform = 'translateX(-50%) translateY(0)';
            clearTimeout(t._timeout);
            t._timeout = setTimeout(() => { t.style.opacity = '0'; t.style.transform = 'translateX(-50%) translateY(10px)'; }, 3000);
        }

        var schedEditMode = false;
        var _sbmInsertIdx = -1; // index to insert new block at
        let _sbmEditId = null;  // block id being edited (null = new)
        let _moveTaskInfo = null; // {blockId, taskIdx}
        let _schedTaskEditInfo = null; // {blockId, tIdx}

        function _isSchedPastDay() { return schedDay < _dateKey(new Date()); }

        // ── Daily Focus collapse ────────────────────────────────────────────────
        let _dailyFocusOpen = true;
        try { _dailyFocusOpen = localStorage.getItem('dailyFocusOpen') !== 'false'; } catch(e) {}

        function toggleDailyFocus() {
            _dailyFocusOpen = !_dailyFocusOpen;
            try { localStorage.setItem('dailyFocusOpen', _dailyFocusOpen); } catch(e) {}
            _applyDailyFocusState();
        }

        function _applyDailyFocusState() {
            const body     = document.getElementById('daily-focus-body');
            const chevron  = document.getElementById('daily-focus-chevron');
            const miniPills = document.getElementById('daily-focus-mini-pills');
            if (!body) return;
            if (_dailyFocusOpen) {
                body.style.maxHeight = '1200px';
                if (chevron) { chevron.textContent = '▲'; chevron.style.transform = ''; }
                if (miniPills) miniPills.style.display = 'none';
            } else {
                body.style.maxHeight = '0';
                if (chevron) { chevron.textContent = '▼'; chevron.style.transform = ''; }
                // Build mini summary pills from existing summary pill states
                if (miniPills) {
                    miniPills.innerHTML = '';
                    const pills = [
                        { id:'summary-pill-pills',    emoji:'💊', color:'#38bdf8' },
                        { id:'summary-pill-organize', emoji:'🗂️', color:'#fbbf24' },
                        { id:'summary-pill-music',    emoji:'🎵', color:'#e879f9' },
                        { id:'summary-pill-work',     emoji:'💼', color:'#60a5fa' },
                        { id:'summary-pill-finance',  emoji:'💰', color:'#34d399' },
                    ];
                    pills.forEach(p => {
                        const src = document.getElementById(p.id);
                        const badge = src ? src.querySelector('.imp-card-badge, [class*="badge"], .summary-badge') : null;
                        const dot = document.createElement('span');
                        dot.textContent = p.emoji;
                        dot.style.cssText = 'font-size:1em;cursor:pointer;';
                        dot.title = p.id.replace('summary-pill-','');
                        dot.onclick = e => { e.stopPropagation(); toggleDailyFocus(); };
                        miniPills.appendChild(dot);
                    });
                    miniPills.style.display = 'flex';
                }
            }
        }

        // ── Schedule FAB ────────────────────────────────────────────────────────
        let _schedFabOpen = false;

        function toggleSchedFab() {
            if (schedEditMode) {
                // In edit mode: ✓ tap exits edit mode
                toggleSchedEdit();
                _schedFabOpen = false;
            } else {
                // Not in edit mode: toggle the menu
                _schedFabOpen = !_schedFabOpen;
            }
            _updateSchedFab();
        }

        function _updateSchedFab() {
            const fab    = document.getElementById('sched-fab-btn');
            const menu   = document.getElementById('sched-fab-menu');
            const importBtn = document.getElementById('sched-fab-import');
            if (!fab) return;
            // In edit mode: show ✓ to exit. Otherwise: ☰ to open menu.
            if (schedEditMode) {
                fab.textContent = '✓';
                fab.style.background = 'rgba(99,102,241,0.35)';
                fab.style.borderColor = 'rgba(165,180,252,0.7)';
                fab.style.color = '#a5b4fc';
            } else {
                fab.textContent = '☰';
                fab.style.background = 'rgba(15,23,42,0.97)';
                fab.style.borderColor = 'rgba(129,140,248,0.5)';
                fab.style.color = '#818cf8';
            }
            // Menu: visible only when open and not in edit mode. All options on all days.
            if (menu) {
                menu.style.display = (!schedEditMode && _schedFabOpen) ? 'flex' : 'none';
                if (importBtn) importBtn.style.display = '';
            }
        }

        function schedFabAction(action) {
            _schedFabOpen = false;
            _updateSchedFab();
            if (action === 'edit')           toggleSchedEdit();
            else if (action === 'import')    openSchedImportPanel();
            else if (action === 'templates') openTemplatesPanel();
            else if (action === 'clear')     clearAllSchedBlocks();
        }

        // Close FAB menu when clicking elsewhere
        document.addEventListener('click', function(e) {
            if (_schedFabOpen && !e.target.closest('#sched-fab-wrap')) {
                _schedFabOpen = false;
                _updateSchedFab();
            }
        });

        function toggleSchedEdit() {
            schedEditMode = !schedEditMode;
            const btn = document.getElementById('sched-edit-btn');
            const hint = document.getElementById('sched-edit-hint');
            if (btn) {
                btn.textContent = schedEditMode ? '✓ Done Editing' : '✏️ Edit Schedule';
                btn.style.background = schedEditMode ? 'rgba(99,102,241,0.25)' : 'rgba(99,102,241,0.1)';
                btn.style.color = schedEditMode ? '#a5b4fc' : '#818cf8';
            }
            if (hint) hint.style.display = schedEditMode ? 'block' : 'none';
            _schedFabOpen = false;
            _updateSchedFab();
            renderSchedule();
        }

        // ── RENDER ──────────────────────────────────────────────────────────────
        function renderSchedule() {
            const container = document.getElementById('sched-container');
            if (!container) return;
            container.className = schedEditMode ? 'edit-mode' : '';
            container.innerHTML = '';
            _updateSchedFab();

            // Toolbar: show all buttons on all days
            const editBtn   = document.getElementById('sched-edit-btn');
            const importBtn = document.getElementById('sched-import-btn');
            const row1      = document.getElementById('sched-toolbar-row1');
            if (editBtn)   editBtn.style.display   = 'flex';
            if (importBtn) importBtn.style.display = 'flex';
            if (row1) row1.style.display = 'flex';
            document.querySelectorAll('#sched-toolbar button:not(#sched-edit-btn):not(#sched-import-btn)').forEach(b => {
                b.style.display = 'flex';
            });

            // Empty state
            if (!schedBlocks.length) {
                container.innerHTML = `
                    <div style="text-align:center;padding:48px 20px 40px;display:flex;flex-direction:column;align-items:center;gap:14px;">
                        <div style="font-size:3em;line-height:1;filter:drop-shadow(0 4px 12px rgba(99,102,241,0.3));">📅</div>
                        <div style="font-size:1.08em;font-weight:900;color:#e2e8f0;margin-top:4px;">No blocks yet</div>
                        <div style="font-size:0.83em;color:#475569;max-width:260px;line-height:1.75;">
                            Break your day into time blocks — sleep, work, gym, meals, wind-down. Each block holds its own tasks.
                        </div>
                        <button onclick="openSchedBlockAdd(0)"
                            style="margin-top:10px;padding:13px 30px;border-radius:14px;border:none;
                                   background:linear-gradient(135deg,#6366f1,#4f46e5);color:#fff;
                                   font-family:'Outfit',sans-serif;font-size:0.88em;font-weight:800;
                                   cursor:pointer;box-shadow:0 4px 24px rgba(99,102,241,0.4);
                                   transition:all 0.18s;">
                            ＋ Add your first block
                        </button>
                    </div>`;
                bindScheduleRTasks();
                return;
            }

            schedBlocks.forEach((block, bIdx) => {
                if (schedEditMode) container.appendChild(_makeAddBlockDivider(bIdx));
                container.appendChild(_buildBlockEl(block, bIdx));
            });

            if (schedEditMode) container.appendChild(_makeAddBlockDivider(schedBlocks.length));

            bindScheduleRTasks();
            highlightCurrentBlock();
            _initSchedBlockDnd();
            _initSchedCrossBlockTaskDnd();
        }

        function _buildBlockEl(block, bIdx) {
            const wrap = document.createElement('div');
            wrap.className = 'hour-block';
            wrap.id = 'sched-block-' + block.id;
            wrap.setAttribute('data-bidx', bIdx);

            wrap.style.position = 'relative';

            const _blockIsPast = schedDay < _dateKey(new Date());

            // Edit control bar (edit mode only) — full controls on all days
            if (schedEditMode) {
                const bar = document.createElement('div');
                bar.className = 'sched-block-edit-bar';
                bar.innerHTML = `
                    <button class="sched-block-ctrl-btn" onclick="openSchedBlockEdit('${block.id}')" data-tooltip="Edit time &amp; title">✏️ Edit</button>
                    ${bIdx > 0 ? `<button class="sched-block-ctrl-btn" onclick="moveSchedBlock(${bIdx},-1)" data-tooltip="Move up">↑</button>` : ''}
                    ${bIdx < schedBlocks.length-1 ? `<button class="sched-block-ctrl-btn" onclick="moveSchedBlock(${bIdx},1)" data-tooltip="Move down">↓</button>` : ''}
                    <div style="flex:1;"></div>
                    <button class="sched-block-ctrl-btn danger" onclick="deleteSchedBlock('${block.id}')" data-tooltip="Delete block">🗑 Delete</button>
                `;
                wrap.appendChild(bar);
            }

            // Time badge row (handle + badge together)
            const badgeRow = document.createElement('div');
            badgeRow.style.cssText = 'display:flex;align-items:center;gap:8px;margin-bottom:0;';

            // Block drag handle — shown in edit mode on all days
            if (!_blockIsPast || schedEditMode) {
                const dragHandle = document.createElement('div');
                dragHandle.className = 'dnd-handle dnd-block-handle';
                dragHandle.title = 'Drag to reorder block';
                dragHandle.innerHTML = '&#8942;&#8942;';
                dragHandle.style.cssText = 'font-size:1.15em;letter-spacing:-2px;padding:4px 3px;border-radius:6px;color:#334155;user-select:none;flex-shrink:0;';
                badgeRow.appendChild(dragHandle);
            }

            const badge = document.createElement('div');
            badge.className = 'time-badge';
            badge.textContent = `${block.start} - ${block.end}`;

            badgeRow.appendChild(badge);

            // Collapse chevron (right side of badge row)
            const collapseBtn = document.createElement('button');
            const _blockCollapsed = !!block.collapsed;
            collapseBtn.style.cssText = 'margin-left:auto;background:none;border:none;color:#475569;font-size:0.75em;'
                + 'font-weight:900;cursor:pointer;padding:4px 6px;flex-shrink:0;transition:color 0.15s,transform 0.2s;'
                + 'transform:' + (_blockCollapsed ? 'rotate(-90deg)' : 'rotate(0deg)') + ';';
            collapseBtn.textContent = '▼';
            collapseBtn.title = _blockCollapsed ? 'Expand block' : 'Collapse block';
            collapseBtn.onclick = e => { e.stopPropagation(); toggleSchedBlock(block.id); };
            badgeRow.appendChild(collapseBtn);

            wrap.appendChild(badgeRow);

            // Title row (title + collapsed summary inline)
            const titleRow = document.createElement('div');
            titleRow.style.cssText = 'display:flex;align-items:center;gap:8px;';
            const title = document.createElement('div');
            title.className = 'hour-title';
            title.style.flex = '1';
            title.textContent = `${block.emoji} ${block.title}`;
            titleRow.appendChild(title);
            // Collapsed summary badge (task count)
            const collapsedSummary = document.createElement('span');
            collapsedSummary.id = 'sched-block-summary-' + block.id;
            const _doneCount = (block.tasks || []).filter(t => t.done).length;
            const _totalCount = (block.tasks || []).length;
            collapsedSummary.style.cssText = 'font-size:0.65em;font-weight:800;padding:2px 7px;border-radius:20px;'
                + 'background:rgba(255,255,255,0.05);color:#475569;border:1px solid rgba(255,255,255,0.07);flex-shrink:0;'
                + 'display:' + (_blockCollapsed && _totalCount ? 'inline-flex' : 'none') + ';align-items:center;';
            collapsedSummary.textContent = _doneCount + '/' + _totalCount;
            titleRow.appendChild(collapsedSummary);
            wrap.appendChild(titleRow);

            // Tasks
            const ul = document.createElement('ul');
            ul.className = 'task-list';
            ul.setAttribute('data-block-id', block.id);
            ul.style.cssText = 'overflow:hidden;transition:max-height 0.3s cubic-bezier(0.4,0,0.2,1),opacity 0.2s;'
                + (_blockCollapsed ? 'max-height:0;opacity:0;margin:0;padding:0;' : 'max-height:2000px;opacity:1;');

            // Sanitize: filter out any null/undefined tasks that may have been saved
            block.tasks = (block.tasks || []).filter(t => t != null);

            block.tasks.forEach((task, tIdx) => {
                ul.appendChild(_buildTaskEl(block, task, tIdx));
            });
            wrap.appendChild(ul);

            // Add-task button (shown via CSS in edit mode, hidden when collapsed)
            const addTaskBtn = document.createElement('button');
            addTaskBtn.className = 'sched-add-task-btn';
            addTaskBtn.innerHTML = '＋ Add task';
            addTaskBtn.onclick = () => showSchedAddTaskForm(block.id);
            if (_blockCollapsed) addTaskBtn.style.display = 'none';
            wrap.appendChild(addTaskBtn);

            // Inline add-task form
            const addForm = document.createElement('div');
            addForm.className = 'sched-inline-task-form';
            addForm.id = `sched-task-form-${block.id}`;
            addForm.style.display = 'none';
            addForm.style.flexDirection = 'column';
            addForm.style.gap = '0';
            addForm.innerHTML = `
                <div class="sched-task-type-picker">
                    <button class="sched-ttpill sel-reg" id="sttp-reg-${block.id}"  onclick="schedSetTaskType('${block.id}','regular')">📝 Regular</button>
                    <button class="sched-ttpill"          id="sttp-meal-${block.id}" onclick="schedSetTaskType('${block.id}','meal')">🍽️ Meal</button>
                </div>
                <div id="sched-reg-form-${block.id}" style="display:flex;flex-direction:column;gap:9px;">
                    <div style="display:flex;gap:8px;">
                        <input id="sched-task-emoji-${block.id}" placeholder="😊" maxlength="4"
                            style="width:52px;text-align:center;font-size:1.2em;
                                   background:rgba(255,255,255,0.04);
                                   border:1.5px solid rgba(255,255,255,0.1);border-radius:11px;
                                   padding:10px 4px;color:#e2e8f0;font-family:'Outfit',sans-serif;outline:none;
                                   transition:border-color 0.15s;"
                            onfocus="this.style.borderColor='rgba(99,102,241,0.55)'"
                            onblur="this.style.borderColor='rgba(255,255,255,0.1)'">
                        <input id="sched-task-input-${block.id}" placeholder="Task title…" maxlength="120"
                            style="flex:1;background:rgba(255,255,255,0.04);
                                   border:1.5px solid rgba(255,255,255,0.1);border-radius:11px;
                                   padding:10px 13px;color:#e2e8f0;font-family:'Outfit',sans-serif;
                                   font-size:0.88em;outline:none;transition:border-color 0.15s;"
                            onfocus="this.style.borderColor='rgba(99,102,241,0.55)'"
                            onblur="this.style.borderColor='rgba(255,255,255,0.1)'">
                    </div>
                    <input id="sched-task-notes-${block.id}" placeholder="Notes (optional)…" maxlength="120"
                        style="width:100%;box-sizing:border-box;
                               background:rgba(255,255,255,0.03);
                               border:1.5px solid rgba(255,255,255,0.07);border-radius:11px;
                               padding:9px 13px;color:#94a3b8;font-family:'Outfit',sans-serif;
                               font-size:0.82em;outline:none;transition:border-color 0.15s;"
                        onfocus="this.style.borderColor='rgba(99,102,241,0.4)'"
                        onblur="this.style.borderColor='rgba(255,255,255,0.07)'">
                    <div style="display:flex;gap:8px;">
                        <button onclick="hideSchedAddTaskForm('${block.id}')"
                            style="flex:1;padding:10px;border-radius:12px;
                                   border:1.5px solid rgba(255,255,255,0.08);
                                   background:rgba(255,255,255,0.04);color:#64748b;
                                   font-size:0.85em;font-weight:800;font-family:'Outfit',sans-serif;
                                   cursor:pointer;transition:all 0.15s;"
                            onmouseover="this.style.background='rgba(255,255,255,0.08)';this.style.color='#94a3b8'"
                            onmouseout="this.style.background='rgba(255,255,255,0.04)';this.style.color='#64748b'">Cancel</button>
                        <button onclick="saveSchedTask('${block.id}')"
                            style="flex:2;padding:10px;border-radius:12px;border:none;
                                   background:linear-gradient(135deg,rgba(99,102,241,0.9),rgba(79,70,229,0.9));
                                   color:#fff;font-size:0.85em;font-weight:900;
                                   font-family:'Outfit',sans-serif;cursor:pointer;
                                   transition:all 0.15s;box-shadow:0 4px 14px rgba(99,102,241,0.3);"
                            onmouseover="this.style.transform='translateY(-1px)'"
                            onmouseout="this.style.transform=''">＋ Add Task</button>
                    </div>
                </div>
                <div id="sched-meal-form-${block.id}" class="sched-meal-subform" style="display:none;">
                    <div class="sched-meal-cat-row" id="sched-mcat-${block.id}">
                        <button class="sched-mcpill sel" data-mcat="breakfast" onclick="schedSetMealCat('${block.id}','breakfast')">🌅 Breakfast</button>
                        <button class="sched-mcpill" data-mcat="brunch"    onclick="schedSetMealCat('${block.id}','brunch')">🥂 Brunch</button>
                        <button class="sched-mcpill" data-mcat="lunch"     onclick="schedSetMealCat('${block.id}','lunch')">☀️ Lunch</button>
                        <button class="sched-mcpill" data-mcat="dinner"    onclick="schedSetMealCat('${block.id}','dinner')">🌙 Dinner</button>
                        <button class="sched-mcpill" data-mcat="snack"     onclick="schedSetMealCat('${block.id}','snack')">🍎 Snack</button>
                        <button class="sched-mcpill" data-mcat="dessert"   onclick="schedSetMealCat('${block.id}','dessert')">🍰 Dessert</button>
                        <button class="sched-mcpill" data-mcat="drink"     onclick="schedSetMealCat('${block.id}','drink')">🥤 Drink</button>
                    </div>
                    <div class="sched-recipe-link-row">
                        <select class="sched-recipe-sel" id="sched-recipe-sel-${block.id}">
                            <option value="">— No recipe linked —</option>
                        </select>
                    </div>
                    <div style="display:flex;gap:7px;">
                        <input id="sched-meal-label-${block.id}" placeholder="Label (optional)" maxlength="60"
                            style="flex:1;background:#0a0f1e;border:1.5px solid rgba(255,255,255,0.1);border-radius:9px;
                                   padding:7px 11px;color:#e2e8f0;font-family:'Outfit',sans-serif;font-size:0.8em;outline:none;">
                        <button onclick="saveSchedMealTask('${block.id}')"
                            style="background:rgba(251,191,36,0.15);border:1px solid rgba(251,191,36,0.3);color:#fbbf24;
                                   border-radius:9px;padding:8px 13px;cursor:pointer;font-size:0.82em;font-weight:700;font-family:'Outfit',sans-serif;">Add</button>
                    </div>
                </div>
            `;
            wrap.appendChild(addForm);

            return wrap;
        }

        function _buildTaskEl(block, task, tIdx) {
            const li = document.createElement('li');
            li.className = 'task-item';
            if (task.mealType) li.classList.add('meal-task');
            // Today: use global tasks[] (live). Past/future days: use task.done from the block.
            const _todayKey = _dateKey(new Date());
            const _isPast = schedDay < _todayKey;
            const _isFuture = schedDay > _todayKey;
            const _isCurrentDay = schedDay === _todayKey;
            const _taskDone = _isCurrentDay ? !!(tasks && tasks[task.id]) : !!task.done;
            if (_taskDone) li.classList.add('checked');
            const isCollapsed = !!task.collapsed;
            const hasSubs = !!(task.subtasks && task.subtasks.length);
            let subsWrapEl = null;
            li.setAttribute('data-task', task.id);
            li.setAttribute('data-tidx', tIdx);
            if (task.summary) li.setAttribute('data-summary', task.summary);
            if (task.sslot)   li.setAttribute('data-sched-slot', task.sslot);
            if (task.srtask)  li.setAttribute('data-sched-rtask', task.srtask);

            const cb = document.createElement('div');
            if (task.subtasks && task.subtasks.length) {
                // Progress badge — not a clickable checkbox
                const taskAccent = task.accentColor || '#fbbf24';
                const doneCount = task.subtasks.filter(function(s){ return s.done; }).length;
                cb.id = 'sched-prog-' + task.id.replace(/[^a-z0-9]/gi,'_');
                cb.style.cssText = 'width:26px;height:26px;min-width:26px;border-radius:8px;flex-shrink:0;'
                    + 'border:3px solid ' + taskAccent + ';'
                    + 'display:flex;align-items:center;justify-content:center;'
                    + 'font-size:0.6em;font-weight:900;transition:all 0.2s;'
                    + (task.done ? 'background:' + taskAccent + ';color:#000;' : 'color:' + taskAccent + ';background:transparent;');
                cb.textContent = task.done ? '✓' : doneCount + '/' + task.subtasks.length;
                // Clickable: select/deselect all subtasks (read-only on future days only)
                cb.style.cursor = _isFuture ? 'default' : 'pointer';
                cb.title = _isFuture ? '' : (task.done ? 'Uncheck all' : 'Check all');
                cb.addEventListener('click', function(e) {
                    e.stopPropagation();
                    if (_isFuture) { showToast('📅 Future days are read-only'); return; }
                    const allDone = task.subtasks.every(function(x){ return x.done; });
                    const newState = !allDone;
                    task.subtasks.forEach(function(x){ x.done = newState; });
                    task.done = newState;
                    if (_isCurrentDay) {
                        if (newState) tasks[task.id] = true; else delete tasks[task.id];
                        localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
                    }
                    saveSchedBlocks();
                    li.classList.toggle('checked', newState);
                    cb.textContent = newState ? '✓' : '0/' + task.subtasks.length;
                    cb.style.background = newState ? taskAccent : 'transparent';
                    cb.style.color = newState ? '#000' : taskAccent;
                    cb.title = newState ? 'Uncheck all' : 'Check all';
                    // Re-render subtask rows via the closure function
                    buildBlockSubs();
                    // Sync to live source only for current day — past day checks stay in the block
                    if (_isCurrentDay) {
                        if (task.id && typeof task.id === 'string' && task.id.startsWith('gtask-')) {
                            var _pRest = task.id.slice(6);
                            var _pLd = _pRest.lastIndexOf('-');
                            if (_pLd > 0) {
                                var _pSid = _pRest.slice(0, _pLd);
                                var _pRawId = _pRest.slice(_pLd + 1);
                                if (typeof gTasksAll !== 'undefined' && gTasksAll[_pSid]) {
                                    var _pGt = gTasksAll[_pSid].find(function(x){ return String(x.id) === _pRawId; });
                                    if (_pGt) {
                                        if (_pGt.subtasks) {
                                            task.subtasks.forEach(function(s, si) {
                                                if (_pGt.subtasks[si] !== undefined) _pGt.subtasks[si].done = newState;
                                            });
                                        }
                                        _pGt.done = newState;
                                        if (typeof saveGTasksAll === 'function') saveGTasksAll();
                                        if (typeof renderGTasks === 'function') renderGTasks(_pSid);
                                    }
                                }
                            }
                        }
                        if (task.groupRef) {
                            if (task.groupRef.isWork && typeof workProjects !== 'undefined') {
                                var _wpProj = workProjects.find(function(p){ return p.id === task.groupRef.projectId; });
                                if (_wpProj) {
                                    if (_wpProj.subtasks) {
                                        task.subtasks.forEach(function(s, si) {
                                            if (_wpProj.subtasks[si] !== undefined) _wpProj.subtasks[si].done = newState;
                                        });
                                    }
                                    _wpProj.status = newState ? 'done' : 'in-progress';
                                    if (typeof saveWorkProjects === 'function') saveWorkProjects();
                                    if (typeof renderWorkProjects === 'function') renderWorkProjects();
                                }
                            } else if (task.groupRef.isGym) {
                                task.subtasks.forEach(function(s, si) {
                                    if (typeof _setGymSessionSubDone === 'function') _setGymSessionSubDone(task.groupRef, si, newState);
                                });
                            } else if (task.groupRef.isMA) {
                                task.subtasks.forEach(function(s, si) {
                                    if (typeof _setMADisciplineSubDone === 'function') _setMADisciplineSubDone(task.groupRef, si, newState);
                                });
                            } else {
                                task.subtasks.forEach(function(s, si) {
                                    if (typeof _setOrgGroupSubDone === 'function') _setOrgGroupSubDone(task.groupRef, si, newState);
                                });
                            }
                        }
                    }
                    updateSummaryPills();
                    updateProgress();
                });
                li.style.cursor = 'default';
            } else {
                cb.className = 'task-checkbox';
            }
            // Expose as progBadge for subtask onclick closures
            var progBadge = cb;

            // When a task has subtasks, the header row (checkbox/handle/title/controls) is
            // kept on its own line so the subtask list below always keeps full width,
            // regardless of how many edit-mode controls the header row is showing.
            let headerRow = li;
            if (hasSubs) {
                li.style.flexDirection = 'column';
                li.style.alignItems = 'stretch';
                headerRow = document.createElement('div');
                headerRow.style.cssText = 'display:flex;align-items:flex-start;gap:14px;width:100%;';
                li.appendChild(headerRow);
            }

            headerRow.appendChild(cb);

            if (hasSubs) {
                const collapseBtn = document.createElement('button');
                collapseBtn.title = isCollapsed ? 'Expand subtasks' : 'Minimize subtasks';
                collapseBtn.textContent = isCollapsed ? '▸' : '▾';
                collapseBtn.className = 'compact-toggle-btn';
                collapseBtn.onclick = function(e) {
                    e.stopPropagation();
                    toggleScheduleGroupedTaskCollapse(task.id);
                };
                headerRow.appendChild(collapseBtn);
            }

            // Drag handle for task reordering — shown in edit mode on all days
            if (!_isPast || schedEditMode) {
                const taskDragHandle = document.createElement('div');
                taskDragHandle.className = 'dnd-handle dnd-sched-task-handle';
                taskDragHandle.title = 'Drag to reorder';
                taskDragHandle.innerHTML = '&#8942;&#8942;';
                taskDragHandle.style.cssText = 'font-size:1.1em;letter-spacing:-2px;padding:4px 6px;border-radius:5px;color:#475569;user-select:none;flex-shrink:0;transition:color 0.15s;touch-action:none;';
                headerRow.appendChild(taskDragHandle);
            }

            const body = document.createElement('div');
            body.className = 'task-text';
            body.style.flex = '1';

            if (task.mealType) {
                // Meal task — badge + label + optional recipe chip
                const MEAL_META = {
                    breakfast:{ label:'Breakfast', emoji:'🌅', col:'rgba(251,191,36,0.15)', tcol:'#fbbf24' },
                    brunch:   { label:'Brunch',    emoji:'🥂', col:'rgba(249,115,22,0.15)', tcol:'#fb923c' },
                    lunch:    { label:'Lunch',     emoji:'☀️', col:'rgba(34,197,94,0.15)',  tcol:'#4ade80' },
                    dinner:   { label:'Dinner',    emoji:'🌙', col:'rgba(99,102,241,0.15)', tcol:'#818cf8' },
                    snack:    { label:'Snack',     emoji:'🍎', col:'rgba(236,72,153,0.15)', tcol:'#f472b6' },
                    dessert:  { label:'Dessert',   emoji:'🍰', col:'rgba(167,139,250,0.15)',tcol:'#c084fc' },
                    drink:    { label:'Drink',     emoji:'🥤', col:'rgba(56,189,248,0.15)', tcol:'#38bdf8' },
                };
                const m = MEAL_META[task.mealType] || { label: task.mealType, emoji:'🍽️', col:'rgba(251,191,36,0.15)', tcol:'#fbbf24' };
                const badge = document.createElement('span');
                badge.className = 'task-meal-badge';
                badge.textContent = m.emoji + ' ' + m.label;
                badge.style.background = m.col;
                badge.style.color = m.tcol;
                body.appendChild(badge);

                const label = document.createElement('div');
                label.style.marginTop = '2px';
                label.style.fontWeight = '700';
                label.textContent = task.text || '';
                body.appendChild(label);

                if (task.recipeId) {
                    const rcp = (window._rcpData || []).find(r => r.id === task.recipeId);
                    if (rcp) {
                        const chip = document.createElement('div');
                        chip.className = 'task-recipe-chip';
                        // Build safely without innerHTML to avoid name-breaking markup
                        const emojiSpan = document.createElement('span');
                        emojiSpan.textContent = rcp.emoji || '🍳';
                        const nameSpan = document.createElement('span');
                        nameSpan.textContent = rcp.name;
                        const arrowSpan = document.createElement('span');
                        arrowSpan.textContent = '→';
                        arrowSpan.style.opacity = '0.45';
                        chip.appendChild(emojiSpan);
                        chip.appendChild(document.createTextNode(' '));
                        chip.appendChild(nameSpan);
                        chip.appendChild(document.createTextNode(' '));
                        chip.appendChild(arrowSpan);
                        chip.onclick = e => { e.stopPropagation(); rcpOpenDetail(task.recipeId, 'schedule'); };
                        body.appendChild(chip);
                    }
                }
                if (task.notes) {
                    const notesNode = document.createElement('div');
                    notesNode.style.cssText = 'font-size:0.78em;color:#475569;margin-top:5px;font-weight:500;';
                    notesNode.textContent = task.notes;
                    body.appendChild(notesNode);
                }
            } else {
                const textNode = document.createElement('div');
                textNode.textContent = task.text;
                body.appendChild(textNode);
                if (task.notes) {
                    const notesNode = document.createElement('div');
                    notesNode.style.cssText = 'font-size:0.78em;color:#475569;margin-top:2px;font-weight:500;';
                    notesNode.textContent = task.notes;
                    body.appendChild(notesNode);
                }
                // Subtasks (from imported Organize groups)
                if (task.subtasks && task.subtasks.length) {
                    const taskAccent = task.accentColor || '#fbbf24';
                    const subsWrap = document.createElement('div');
                    subsWrap.style.cssText = 'display:' + (isCollapsed ? 'none' : 'flex') + ';flex-direction:column;gap:5px;margin-top:8px;';

                    function buildBlockSubs() {
                        subsWrap.innerHTML = '';
                        task.subtasks.forEach(function(s, si) {
                            const done = !!s.done;
                            const row = document.createElement('div');
                            row.style.cssText = 'display:flex;align-items:center;gap:8px;padding:5px 8px;'
                                + 'background:rgba(255,255,255,0.03);border-radius:7px;'
                                + 'border:1px solid rgba(255,255,255,0.07);cursor:pointer;transition:background 0.15s;';
                            row.addEventListener('mouseenter', function(){ row.style.background='rgba(255,255,255,0.06)'; });
                            row.addEventListener('mouseleave', function(){ row.style.background='rgba(255,255,255,0.03)'; });
                            row.addEventListener('click', function(e) {
                                e.stopPropagation();
                                if (_isFuture) { showToast('📅 Future days are read-only'); return; }
                                s.done = !s.done;
                                const newDone = s.done;
                                const allDone = task.subtasks.every(function(x){ return x.done; });
                                task.done = allDone;
                                // Update live tasks map only for current day — past keeps state in block
                                if (_isCurrentDay) {
                                    if (allDone) tasks[task.id] = true; else delete tasks[task.id];
                                    localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
                                }
                                saveSchedBlocks();
                                // Update li checked state
                                li.classList.toggle('checked', allDone);
                                // Update progress badge
                                progBadge.textContent = allDone ? '✓' : task.subtasks.filter(function(x){return x.done;}).length + '/' + task.subtasks.length;
                                progBadge.style.background = allDone ? taskAccent : 'transparent';
                                progBadge.style.color = allDone ? '#000' : taskAccent;
                                buildBlockSubs();
                                // Sync to live source only for current day — past day checks stay in the block
                                if (_isCurrentDay) {
                                    const _syncSid = (function() {
                                        if (!task.id || !task.id.startsWith('gtask-')) return null;
                                        const rest = task.id.slice(6);
                                        const lastDash = rest.lastIndexOf('-');
                                        return lastDash > 0 ? rest.slice(0, lastDash) : null;
                                    })();
                                    if (_syncSid && typeof gTasksAll !== 'undefined') {
                                        const gtasks = gTasksAll[_syncSid] || [];
                                        const _rawId = task.id.slice(6 + _syncSid.length + 1);
                                        const gt = gtasks.find(function(x){ return String(x.id) === _rawId; });
                                        if (gt && gt.subtasks && gt.subtasks[si] !== undefined) {
                                            gt.subtasks[si].done = newDone;
                                            gt.done = allDone;
                                            if (typeof saveGTasksAll === 'function') saveGTasksAll();
                                            if (typeof renderGTasks === 'function') renderGTasks(_syncSid);
                                        }
                                    }
                                    if (task.groupRef) {
                                        if (task.groupRef.isWork) {
                                            if (typeof _setWorkProjectSubDone === 'function') _setWorkProjectSubDone(task.groupRef, si, newDone);
                                            if (typeof _syncWorkProjectStatus === 'function') _syncWorkProjectStatus(task.groupRef, allDone);
                                        } else if (task.groupRef.isGym) {
                                            if (typeof _setGymSessionSubDone === 'function') _setGymSessionSubDone(task.groupRef, si, newDone);
                                        } else if (task.groupRef.isMA) {
                                            if (typeof _setMADisciplineSubDone === 'function') _setMADisciplineSubDone(task.groupRef, si, newDone);
                                        } else if (typeof _setOrgGroupSubDone === 'function') {
                                            _setOrgGroupSubDone(task.groupRef, si, newDone);
                                        }
                                    }
                                }
                                updateSummaryPills();
                                updateProgress();
                            });

                            const chkEl = document.createElement('div');
                            chkEl.style.cssText = 'width:14px;height:14px;min-width:14px;border-radius:4px;'
                                + 'border:1.5px solid ' + (done ? taskAccent : 'rgba(255,255,255,0.25)') + ';'
                                + 'background:' + (done ? taskAccent : 'transparent') + ';'
                                + 'display:flex;align-items:center;justify-content:center;'
                                + 'font-size:0.5em;font-weight:900;color:#000;flex-shrink:0;';
                            chkEl.textContent = done ? '✓' : '';

                            const lblEl = document.createElement('span');
                            lblEl.style.cssText = 'font-size:0.8em;flex:1;color:' + (done ? '#475569' : '#94a3b8') + ';'
                                + (done ? 'text-decoration:line-through;' : '');
                            lblEl.textContent = s.text;

                            const delSubBtn = document.createElement('button');
                            delSubBtn.textContent = '✕';
                            delSubBtn.title = 'Remove';
                            delSubBtn.className = 'compact-del-btn';
                            delSubBtn.style.visibility = schedEditMode ? 'visible' : 'hidden';
                            if (schedEditMode) {
                                delSubBtn.addEventListener('click', function(e) {
                                    e.stopPropagation();
                                    task.subtasks.splice(si, 1);
                                    task.done = task.subtasks.length > 0 ? task.subtasks.every(function(x){ return x.done; }) : false;
                                    if (_isCurrentDay) {
                                        if (task.done) tasks[task.id] = true; else delete tasks[task.id];
                                        localStorage.setItem('wednesdayTasks', JSON.stringify(tasks));
                                    }
                                    saveSchedBlocks();
                                    li.classList.toggle('checked', task.done);
                                    progBadge.textContent = task.subtasks.length ? (task.done ? '✓' : task.subtasks.filter(function(x){return x.done;}).length + '/' + task.subtasks.length) : '✓';
                                    progBadge.style.background = task.done ? taskAccent : 'transparent';
                                    progBadge.style.color = task.done ? '#000' : taskAccent;
                                    if (_isCurrentDay) {
                                        const _syncSid = (function() {
                                            if (!task.id || !task.id.startsWith('gtask-')) return null;
                                            const rest = task.id.slice(6);
                                            const lastDash = rest.lastIndexOf('-');
                                            return lastDash > 0 ? rest.slice(0, lastDash) : null;
                                        })();
                                        if (_syncSid && typeof gTasksAll !== 'undefined') {
                                            const gtasks = gTasksAll[_syncSid] || [];
                                            const _rawId = task.id.slice(6 + _syncSid.length + 1);
                                            const gt = gtasks.find(function(x){ return String(x.id) === _rawId; });
                                            if (gt && gt.subtasks && gt.subtasks[si] !== undefined) {
                                                gt.subtasks.splice(si, 1);
                                                gt.done = task.done;
                                                if (typeof saveGTasksAll === 'function') saveGTasksAll();
                                                if (typeof renderGTasks === 'function') renderGTasks(_syncSid);
                                            }
                                        }
                                        if (task.groupRef && task.groupRef.isWork && typeof _deleteTaskSubFromProject === 'function') {
                                            _deleteTaskSubFromProject(task.groupRef, si);
                                        }
                                    }
                                    buildBlockSubs();
                                    updateSummaryPills();
                                    updateProgress();
                                });
                            }

                            row.appendChild(chkEl);
                            row.appendChild(lblEl);
                            row.appendChild(delSubBtn);
                            subsWrap.appendChild(row);
                        });
                    }
                    buildBlockSubs();
                    subsWrapEl = subsWrap;
                }
            }

            headerRow.appendChild(body);
            if (subsWrapEl) li.appendChild(subsWrapEl);

            if ((tasks && tasks[task.id]) && /^gtask-pills-/.test(task.id || '') && /(?:^|\s)Buy\s+.+/i.test(task.text || '')) {
                const liquidBuyTask = liquidsInventory.some(p =>
                    String(task.text || '').toLowerCase().includes(`buy ${String((p && p.name) || '').trim().toLowerCase()}`)
                );
                const refillBtn = document.createElement('button');
                refillBtn.textContent = liquidBuyTask ? '🧴 Refill' : '📦 Refill';
                refillBtn.style.cssText = 'margin-top:10px;align-self:flex-start;'
                    + 'background:rgba(56,189,248,0.1);border:1px solid rgba(56,189,248,0.28);color:#7dd3fc;'
                    + 'border-radius:10px;padding:7px 12px;cursor:pointer;font-family:\'Outfit\',sans-serif;'
                    + 'font-size:0.75em;font-weight:800;transition:all 0.15s;';
                refillBtn.onclick = e => {
                    e.stopPropagation();
                    showConfirm({
                        title: liquidBuyTask ? '🧴 Refill Liquid?' : '📦 Refill Pills?',
                        message: 'This opens the refill dialog. After you save the refill, this completed Schedule task will be removed.',
                        confirmLabel: 'Open Refill',
                        confirmColor: '#38bdf8',
                        onConfirm: () => openInventoryRefillFromTask(task.text, { source: 'schedule', taskId: task.id })
                    });
                };
                body.appendChild(refillBtn);
            }

            if (_isPast && schedEditMode) {
                // Past day in edit mode — full edit controls
                const ctrl = document.createElement('div');
                ctrl.className = 'sched-task-ctrl';
                ctrl.onclick = e => e.stopPropagation();
                const isFirst = tIdx === 0;
                const isLast  = tIdx === block.tasks.length - 1;
                ctrl.innerHTML = `
                    <button data-tooltip="Move up"   class="reorder${isFirst ? ' disabled' : ''}"
                        onclick="reorderSchedTask('${block.id}',${tIdx},-1)"
                        ${isFirst ? 'disabled' : ''}>▲</button>
                    <button data-tooltip="Move down" class="reorder${isLast ? ' disabled' : ''}"
                        onclick="reorderSchedTask('${block.id}',${tIdx},1)"
                        ${isLast ? 'disabled' : ''}>▼</button>
                    <button class="edit" data-tooltip="Edit task" onclick="openSchedTaskEdit('${block.id}',${tIdx})">✏️</button>
                    <button class="move" data-tooltip="Move to another block" onclick="openSchedMoveModal('${block.id}',${tIdx})">↕</button>
                    <button class="del" data-tooltip="Delete task" onclick="deleteSchedTask('${block.id}',${tIdx})">🗑️</button>
                `;
                headerRow.appendChild(ctrl);
                if (task.subtasks && task.subtasks.length) {
                    li.onclick = e => { e.stopPropagation(); };
                } else {
                    li.onclick = e => {
                        e.stopPropagation();
                        if (e.target.closest('.sched-task-ctrl') || e.target.closest('.task-recipe-chip')) return;
                        const newDone = !task.done;
                        task.done = newDone;
                        li.classList.toggle('checked', newDone);
                        saveSchedBlocks();
                    };
                }
            } else if (_isPast) {
                // Past day not in edit mode — check/uncheck only
                li.style.opacity = '0.78';
                li.style.cursor = 'default';
                if (task.subtasks && task.subtasks.length) {
                    li.onclick = e => { e.stopPropagation(); };
                } else {
                    li.onclick = e => {
                        e.stopPropagation();
                        if (e.target.closest('.task-recipe-chip')) return;
                        const newDone = !task.done;
                        task.done = newDone;
                        li.classList.toggle('checked', newDone);
                        saveSchedBlocks();
                    };
                }
            } else if (schedEditMode) {
                const ctrl = document.createElement('div');
                ctrl.className = 'sched-task-ctrl';
                ctrl.onclick = e => e.stopPropagation();
                const isFirst = tIdx === 0;
                const isLast  = tIdx === block.tasks.length - 1;
                ctrl.innerHTML = `
                    <button data-tooltip="Move up"   class="reorder${isFirst ? ' disabled' : ''}"
                        onclick="reorderSchedTask('${block.id}',${tIdx},-1)"
                        ${isFirst ? 'disabled' : ''}>▲</button>
                    <button data-tooltip="Move down" class="reorder${isLast ? ' disabled' : ''}"
                        onclick="reorderSchedTask('${block.id}',${tIdx},1)"
                        ${isLast ? 'disabled' : ''}>▼</button>
                    <button class="edit" data-tooltip="Edit task" onclick="openSchedTaskEdit('${block.id}',${tIdx})">✏️</button>
                    <button class="move" data-tooltip="Move to another block" onclick="openSchedMoveModal('${block.id}',${tIdx})">↕</button>
                    <button class="del" data-tooltip="Delete task" onclick="deleteSchedTask('${block.id}',${tIdx})">🗑️</button>
                `;
                headerRow.appendChild(ctrl);
                if (task.subtasks && task.subtasks.length) {
                    li.onclick = e => { e.stopPropagation(); };
                } else {
                    li.onclick = e => {
                        if (!e.target.closest('.sched-task-ctrl') && !e.target.closest('.task-recipe-chip')) toggleTask(li);
                    };
                }
            } else if (_isFuture) {
                // Future day — can edit blocks but can't check tasks
                li.style.opacity = '0.65';
                li.style.cursor = 'default';
                li.onclick = e => { e.stopPropagation(); showToast('📅 Future days are read-only'); };
            } else {
                if (task.subtasks && task.subtasks.length) {
                    li.onclick = e => { e.stopPropagation(); };
                } else {
                    li.onclick = e => {
                        if (!e.target.closest('.task-recipe-chip')) toggleTask(li);
                    };
                }
            }

            return li;
        }

        function _makeAddBlockDivider(insertIdx) {
            const div = document.createElement('div');
            div.className = 'sched-add-block-divider';
            div.innerHTML = `
                <div class="sched-add-block-divider-line"></div>
                <button class="sched-add-block-btn" onclick="openSchedBlockAdd(${insertIdx})">＋ Add Block</button>
                <div class="sched-add-block-divider-line"></div>
            `;
            return div;
        }

        // ── BLOCK CRUD ───────────────────────────────────────────────────────────
        function openSchedBlockAdd(insertIdx) {
            _sbmInsertIdx = insertIdx;
            _sbmEditId = null;
            document.getElementById('sched-block-modal-title').textContent = '＋ New Block';
            document.getElementById('sbm-emoji').value = '';
            document.getElementById('sbm-title').value = '';

            // Smart default times: start where the previous block ends
            let defaultStart = '08:00';
            let defaultEnd   = '09:00';
            if (schedBlocks.length > 0) {
                const prevIdx = Math.min(insertIdx, schedBlocks.length) - 1;
                if (prevIdx >= 0 && schedBlocks[prevIdx]) {
                    defaultStart = schedBlocks[prevIdx].end || '08:00';
                    // Default end = start + 1h
                    const [h, m] = defaultStart.split(':').map(Number);
                    const endH = (h + 1) % 24;
                    defaultEnd = String(endH).padStart(2, '0') + ':' + String(m).padStart(2, '0');
                }
            }
            document.getElementById('sbm-start').value = defaultStart;
            document.getElementById('sbm-end').value   = defaultEnd;

            document.getElementById('sched-block-modal-overlay').style.display = 'block';
            document.getElementById('sched-block-modal').style.display = 'block';
            setTimeout(() => {
                const emoji = document.getElementById('sbm-emoji');
                const title = document.getElementById('sbm-title');
                emoji.focus();
                // Tab from emoji → title, Enter from title → save
                emoji.onkeydown = e => { if (e.key === 'Enter' || e.key === 'Tab') { e.preventDefault(); title.focus(); } };
                title.onkeydown = e => { if (e.key === 'Enter') { e.preventDefault(); saveSchedBlockModal(); } };
            }, 80);
        }

        function openSchedBlockEdit(blockId) {
            const block = schedBlocks.find(b => b.id === blockId);
            if (!block) return;
            _sbmEditId = blockId;
            _sbmInsertIdx = -1;
            document.getElementById('sched-block-modal-title').textContent = '✏️ Edit Block';
            document.getElementById('sbm-emoji').value = block.emoji;
            document.getElementById('sbm-title').value = block.title;
            document.getElementById('sbm-start').value = block.start;
            document.getElementById('sbm-end').value = block.end;
            document.getElementById('sched-block-modal-overlay').style.display = 'block';
            document.getElementById('sched-block-modal').style.display = 'block';
            setTimeout(() => {
                const title = document.getElementById('sbm-title');
                title.focus();
                title.onkeydown = e => { if (e.key === 'Enter') { e.preventDefault(); saveSchedBlockModal(); } };
            }, 80);
        }

        function closeSchedBlockModal() {
            document.getElementById('sched-block-modal-overlay').style.display = 'none';
            document.getElementById('sched-block-modal').style.display = 'none';
        }

        function saveSchedBlockModal() {
            const emoji = document.getElementById('sbm-emoji').value.trim() || '🕐';
            const title = document.getElementById('sbm-title').value.trim() || 'New Block';
            const start = document.getElementById('sbm-start').value || '00:00';
            const end   = document.getElementById('sbm-end').value   || '01:00';

            if (_sbmEditId) {
                // Edit existing
                const block = schedBlocks.find(b => b.id === _sbmEditId);
                if (block) { block.emoji = emoji; block.title = title; block.start = start; block.end = end; }
            } else {
                // Add new
                const newBlock = { id: 'sb_' + Date.now(), start, end, emoji, title, tasks:[] };
                if (_sbmInsertIdx >= schedBlocks.length) {
                    schedBlocks.push(newBlock);
                } else {
                    schedBlocks.splice(_sbmInsertIdx, 0, newBlock);
                }
            }
            saveSchedBlocks();
            closeSchedBlockModal();
            renderSchedule();
        }

        function toggleSchedBlock(blockId) {
            const block = schedBlocks.find(b => b.id === blockId);
            if (!block) return;
            block.collapsed = !block.collapsed;
            saveSchedBlocks();
            // Update DOM directly — no full re-render needed
            const wrap = document.getElementById('sched-block-' + blockId);
            if (!wrap) return;
            const ul = wrap.querySelector('.task-list');
            const chevron = wrap.querySelector('button[title*="ollapse"], button[title*="xpand"]');
            const summary = document.getElementById('sched-block-summary-' + blockId);
            const addBtn = wrap.querySelector('.sched-add-task-btn');
            const addForm = document.getElementById('sched-task-form-' + blockId);
            if (block.collapsed) {
                if (ul)      { ul.style.maxHeight = '0'; ul.style.opacity = '0'; ul.style.margin = '0'; ul.style.padding = '0'; }
                if (chevron) { chevron.style.transform = 'rotate(-90deg)'; chevron.title = 'Expand block'; }
                if (summary) {
                    const done = (block.tasks||[]).filter(t=>t.done).length;
                    const total = (block.tasks||[]).length;
                    summary.textContent = done + '/' + total;
                    if (total) summary.style.display = 'inline-flex';
                }
                if (addBtn)  addBtn.style.display = 'none';
                if (addForm) addForm.style.display = 'none';
            } else {
                if (ul)      { ul.style.maxHeight = '2000px'; ul.style.opacity = '1'; ul.style.margin = ''; ul.style.padding = ''; }
                if (chevron) { chevron.style.transform = 'rotate(0deg)'; chevron.title = 'Collapse block'; }
                if (summary) summary.style.display = 'none';
                if (addBtn)  addBtn.style.display = '';
            }
        }

        function deleteSchedBlock(blockId) {
            const block = schedBlocks.find(b => b.id === blockId);
            if (!block) return;
            if (block.tasks.length && !confirm(`Delete "${block.emoji} ${block.title}" and all its ${block.tasks.length} task(s)?`)) return;
            schedBlocks = schedBlocks.filter(b => b.id !== blockId);
            saveSchedBlocks();
            renderSchedule();
        }

        function moveSchedBlock(idx, dir) {
            const newIdx = idx + dir;
            if (newIdx < 0 || newIdx >= schedBlocks.length) return;
            const tmp = schedBlocks[idx];
            schedBlocks[idx] = schedBlocks[newIdx];
            schedBlocks[newIdx] = tmp;
            saveSchedBlocks();
            renderSchedule();
        }

        // ── TASK CRUD ────────────────────────────────────────────────────────────
        function showSchedAddTaskForm(blockId) {
            const form = document.getElementById(`sched-task-form-${blockId}`);
            if (!form) return;
            form.style.display = 'flex';
            // Populate recipe selector
            const sel = document.getElementById(`sched-recipe-sel-${blockId}`);
            if (sel) {
                sel.innerHTML = '<option value="">— No recipe linked —</option>';
                (window._rcpData || []).forEach(r => {
                    const o = document.createElement('option');
                    o.value = r.id;
                    o.textContent = (r.emoji || '🍳') + ' ' + r.name;
                    sel.appendChild(o);
                });
            }
            // Default to regular type, focus input
            schedSetTaskType(blockId, 'regular');
            const input = document.getElementById(`sched-task-input-${blockId}`);
            if (input) {
                setTimeout(() => input.focus(), 60);
                input.onkeydown = e => {
                    if (e.key === 'Enter') saveSchedTask(blockId);
                    if (e.key === 'Escape') hideSchedAddTaskForm(blockId);
                };
            }
        }

        function schedSetTaskType(blockId, type) {
            const regBtn  = document.getElementById(`sttp-reg-${blockId}`);
            const mealBtn = document.getElementById(`sttp-meal-${blockId}`);
            const regForm  = document.getElementById(`sched-reg-form-${blockId}`);
            const mealForm = document.getElementById(`sched-meal-form-${blockId}`);
            if (!regBtn) return;
            regBtn.className  = 'sched-ttpill' + (type === 'regular' ? ' sel-reg'  : '');
            mealBtn.className = 'sched-ttpill' + (type === 'meal'    ? ' sel-meal' : '');
            regForm.style.display  = type === 'regular' ? 'flex'  : 'none';
            mealForm.style.display = type === 'meal'    ? 'flex'  : 'none';
            if (type === 'meal') {
                // ensure first cat is selected
                const cats = document.querySelectorAll(`#sched-mcat-${blockId} .sched-mcpill`);
                let hasSel = false;
                cats.forEach(c => { if (c.classList.contains('sel')) hasSel = true; });
                if (!hasSel && cats.length) { cats[0].classList.add('sel'); }
            }
        }

        function schedSetMealCat(blockId, cat) {
            const row = document.getElementById(`sched-mcat-${blockId}`);
            if (!row) return;
            row.querySelectorAll('.sched-mcpill').forEach(btn => {
                btn.classList.toggle('sel', btn.getAttribute('data-mcat') === cat);
            });
        }

        function saveSchedMealTask(blockId) {
            const block = schedBlocks.find(b => b.id === blockId);
            if (!block) return;
            // Get meal category
            const row = document.getElementById(`sched-mcat-${blockId}`);
            let mealType = 'breakfast';
            if (row) {
                const sel = row.querySelector('.sched-mcpill.sel');
                if (sel) mealType = sel.getAttribute('data-mcat') || 'breakfast';
            }
            // Get linked recipe
            const rcpSel = document.getElementById(`sched-recipe-sel-${blockId}`);
            const recipeId = rcpSel ? rcpSel.value : '';
            // Custom label
            const labelInput = document.getElementById(`sched-meal-label-${blockId}`);
            const customLabel = labelInput ? labelInput.value.trim() : '';
            // Build display text
            const MEAL_LABELS = _schedMealLabels();
            const text = customLabel || MEAL_LABELS[mealType] || mealType;
            const newTask = {
                id: 'st_' + Date.now(),
                text,
                mealType,
                recipeId: recipeId || null,
                summary: null, sslot: null, srtask: null
            };
            block.tasks.push(newTask);
            saveSchedBlocks();
            if (labelInput) labelInput.value = '';
            renderSchedule();
            // Don't auto-reopen for meal tasks — one meal per add is natural
        }

        function hideSchedAddTaskForm(blockId) {
            const form = document.getElementById('sched-task-form-' + blockId);
            if (form) form.style.display = 'none';
            // Guard: elements may not exist if renderSchedule just ran
            const regBtn = document.getElementById('sttp-reg-' + blockId);
            if (regBtn) schedSetTaskType(blockId, 'regular');
        }

        function saveSchedTask(blockId) {
            const emojiEl = document.getElementById(`sched-task-emoji-${blockId}`);
            const input   = document.getElementById(`sched-task-input-${blockId}`);
            const notesEl = document.getElementById(`sched-task-notes-${blockId}`);
            const emoji = (emojiEl?.value || '').trim();
            const raw   = (input?.value || '').trim();
            const notes = (notesEl?.value || '').trim();
            if (!raw) { input?.focus(); return; }
            const text = emoji ? emoji + ' ' + raw : raw;
            const block = schedBlocks.find(b => b.id === blockId);
            if (!block) return;
            const newTask = { id: 'st_' + Date.now(), text, notes: notes || null, summary:null, sslot:null, srtask:null };
            block.tasks.push(newTask);
            saveSchedBlocks();
            if (input)   input.value   = '';
            if (emojiEl) emojiEl.value = '';
            if (notesEl) notesEl.value = '';
            renderSchedule();
            setTimeout(() => showSchedAddTaskForm(blockId), 60);
        }

        function _schedMealLabels() {
            return {
                breakfast:'Breakfast', brunch:'Brunch', lunch:'Lunch', dinner:'Dinner',
                snack:'Snack', dessert:'Dessert', drink:'Drink'
            };
        }

        function _schedTaskAllowsTypeChange(task) {
            return !(task && task.subtasks && task.subtasks.length);
        }

        function schedEditSetTaskType(type) {
            const regBtn  = document.getElementById('sched-edit-type-regular');
            const mealBtn = document.getElementById('sched-edit-type-meal');
            const regWrap = document.getElementById('sched-edit-regular-wrap');
            const mealWrap = document.getElementById('sched-edit-meal-wrap');
            if (!regBtn || !mealBtn || !regWrap || !mealWrap) return;

            if (_schedTaskEditInfo) {
                const block = schedBlocks.find(b => b.id === _schedTaskEditInfo.blockId);
                const task = block && block.tasks ? block.tasks[_schedTaskEditInfo.tIdx] : null;
                if (task && !_schedTaskAllowsTypeChange(task)) {
                    type = task.mealType ? 'meal' : 'regular';
                }
            }

            regBtn.className  = 'sched-ttpill' + (type === 'regular' ? ' sel-reg'  : '');
            mealBtn.className = 'sched-ttpill' + (type === 'meal'    ? ' sel-meal' : '');
            regWrap.style.display  = type === 'regular' ? 'flex' : 'none';
            mealWrap.style.display = type === 'meal' ? 'flex' : 'none';
        }

        function schedEditSetMealCat(cat) {
            const row = document.getElementById('sched-edit-mcat');
            if (!row) return;
            row.querySelectorAll('.sched-mcpill').forEach(btn => {
                btn.classList.toggle('sel', btn.getAttribute('data-mcat') === cat);
            });
        }

        function openSchedTaskEdit(blockId, tIdx) {
            const block = schedBlocks.find(b => b.id === blockId);
            if (!block || !block.tasks[tIdx]) return;
            const task = block.tasks[tIdx];
            _schedTaskEditInfo = { blockId, tIdx };

            const overlay = document.getElementById('sched-task-edit-overlay');
            const modal = document.getElementById('sched-task-edit-modal');
            const subtitle = document.getElementById('sched-task-edit-subtitle');
            const textEl = document.getElementById('sched-edit-text');
            const notesEl = document.getElementById('sched-edit-notes');
            const recipeSel = document.getElementById('sched-edit-recipe-sel');
            const mealLabelEl = document.getElementById('sched-edit-meal-label');
            const lockHint = document.getElementById('sched-edit-lock-hint');
            const regBtn = document.getElementById('sched-edit-type-regular');
            const mealBtn = document.getElementById('sched-edit-type-meal');
            if (!overlay || !modal || !textEl || !notesEl || !recipeSel || !mealLabelEl || !lockHint || !regBtn || !mealBtn) return;

            subtitle.textContent = `${block.emoji} ${block.start} - ${block.end} · ${block.title}`;
            textEl.value = task.mealType ? '' : (task.text || '');
            notesEl.value = task.notes || '';

            recipeSel.innerHTML = '<option value="">— No recipe linked —</option>';
            (window._rcpData || []).forEach(r => {
                const o = document.createElement('option');
                o.value = r.id;
                o.textContent = (r.emoji || '🍳') + ' ' + r.name;
                recipeSel.appendChild(o);
            });

            if (task.mealType) {
                const labels = _schedMealLabels();
                const defaultLabel = labels[task.mealType] || task.mealType;
                mealLabelEl.value = (task.text && task.text !== defaultLabel) ? task.text : '';
                recipeSel.value = task.recipeId || '';
                schedEditSetMealCat(task.mealType || 'breakfast');
                schedEditSetTaskType('meal');
            } else {
                mealLabelEl.value = '';
                recipeSel.value = '';
                schedEditSetMealCat('breakfast');
                schedEditSetTaskType('regular');
            }

            const allowTypeChange = _schedTaskAllowsTypeChange(task);
            [regBtn, mealBtn].forEach(btn => {
                btn.disabled = !allowTypeChange;
                btn.style.opacity = allowTypeChange ? '1' : '0.45';
                btn.style.cursor = allowTypeChange ? 'pointer' : 'default';
            });
            if (allowTypeChange) {
                lockHint.style.display = 'none';
                lockHint.textContent = '';
            } else {
                lockHint.style.display = 'block';
                lockHint.textContent = 'Task type is locked for imported grouped tasks with subtasks.';
            }

            [textEl, notesEl, mealLabelEl].forEach(el => {
                el.onkeydown = function(e) {
                    if (e.key === 'Enter') saveSchedTaskEdit();
                    if (e.key === 'Escape') closeSchedTaskEdit();
                };
            });

            overlay.style.display = 'block';
            modal.style.display = 'block';
            document.body.style.overflow = 'hidden';
            setTimeout(() => {
                const activeType = task.mealType ? 'meal' : 'regular';
                const focusEl = activeType === 'meal' ? mealLabelEl : textEl;
                focusEl && focusEl.focus();
                if (focusEl && typeof focusEl.select === 'function' && focusEl.value) focusEl.select();
            }, 60);
        }

        function closeSchedTaskEdit() {
            _schedTaskEditInfo = null;
            const overlay = document.getElementById('sched-task-edit-overlay');
            const modal = document.getElementById('sched-task-edit-modal');
            if (overlay) overlay.style.display = 'none';
            if (modal) modal.style.display = 'none';
            document.body.style.overflow = '';
        }

        function saveSchedTaskEdit() {
            if (!_schedTaskEditInfo) return;
            const block = schedBlocks.find(b => b.id === _schedTaskEditInfo.blockId);
            if (!block || !block.tasks[_schedTaskEditInfo.tIdx]) return;
            const task = block.tasks[_schedTaskEditInfo.tIdx];

            const notesEl = document.getElementById('sched-edit-notes');
            const notes = (notesEl?.value || '').trim();
            const allowTypeChange = _schedTaskAllowsTypeChange(task);
            const mealBtn = document.getElementById('sched-edit-type-meal');
            const type = allowTypeChange
                ? (mealBtn && mealBtn.classList.contains('sel-meal') ? 'meal' : 'regular')
                : (task.mealType ? 'meal' : 'regular');

            if (type === 'meal') {
                const row = document.getElementById('sched-edit-mcat');
                let mealType = 'breakfast';
                if (row) {
                    const sel = row.querySelector('.sched-mcpill.sel');
                    if (sel) mealType = sel.getAttribute('data-mcat') || 'breakfast';
                }
                const recipeSel = document.getElementById('sched-edit-recipe-sel');
                const mealLabelEl = document.getElementById('sched-edit-meal-label');
                const recipeId = recipeSel ? recipeSel.value : '';
                const customLabel = (mealLabelEl?.value || '').trim();
                const labels = _schedMealLabels();
                task.text = customLabel || labels[mealType] || mealType;
                task.mealType = mealType;
                task.recipeId = recipeId || null;
                task.notes = notes || null;
            } else {
                const textEl = document.getElementById('sched-edit-text');
                const text = (textEl?.value || '').trim();
                if (!text) { textEl?.focus(); return; }
                task.text = text;
                task.notes = notes || null;
                delete task.mealType;
                delete task.recipeId;
            }

            saveSchedBlocks();
            closeSchedTaskEdit();
            renderSchedule();
            showToast('✓ Task updated', '#a5b4fc');
        }

        function deleteSchedTask(blockId, tIdx) {
            const block = schedBlocks.find(b => b.id === blockId);
            if (!block || !block.tasks[tIdx]) return;
            block.tasks.splice(tIdx, 1);
            saveSchedBlocks();
            renderSchedule();
        }

        function reorderSchedTask(blockId, tIdx, dir) {
            const block = schedBlocks.find(b => b.id === blockId);
            if (!block) return;
            const newIdx = tIdx + dir;
            if (newIdx < 0 || newIdx >= block.tasks.length) return;
            // Swap
            const tmp = block.tasks[tIdx];
            block.tasks[tIdx] = block.tasks[newIdx];
            block.tasks[newIdx] = tmp;
            saveSchedBlocks();
            renderSchedule();
        }

        // ── MOVE TASK MODAL ──────────────────────────────────────────────────────
        function openSchedMoveModal(blockId, tIdx) {
            const block = schedBlocks.find(b => b.id === blockId);
            if (!block || !block.tasks[tIdx]) return;
            _moveTaskInfo = { blockId, tIdx };
            const task = block.tasks[tIdx];
            document.getElementById('sched-move-task-label').textContent = `"${task.text}"`;
            const list = document.getElementById('sched-move-block-list');
            list.innerHTML = '';
            schedBlocks.forEach(b => {
                if (b.id === blockId) return; // skip current block
                const opt = document.createElement('div');
                opt.className = 'sched-move-block-opt';
                opt.textContent = `${b.emoji} ${b.start}–${b.end} ${b.title}`;
                opt.onclick = () => executeSchedMove(b.id);
                list.appendChild(opt);
            });
            document.getElementById('sched-move-overlay').style.display = 'block';
            document.getElementById('sched-move-modal').style.display = 'block';
        }

        function executeSchedMove(targetBlockId) {
            if (!_moveTaskInfo) return;
            const { blockId, tIdx } = _moveTaskInfo;
            const srcBlock = schedBlocks.find(b => b.id === blockId);
            const dstBlock = schedBlocks.find(b => b.id === targetBlockId);
            if (!srcBlock || !dstBlock) return;
            const [task] = srcBlock.tasks.splice(tIdx, 1);
            dstBlock.tasks.push(task);
            saveSchedBlocks();
            closeSchedMoveModal();
            renderSchedule();
        }

        function closeSchedMoveModal() {
            _moveTaskInfo = null;
            document.getElementById('sched-move-overlay').style.display = 'none';
            document.getElementById('sched-move-modal').style.display = 'none';
        }

        // ── IMPORT PANEL ─────────────────────────────────────────────────────────

        function openSchedImportPanel() {
            const panel = document.getElementById('sched-import-panel');
            const overlay = document.getElementById('sched-import-overlay');
            if (!panel || !overlay) return;
            buildImportBody();
            panel.style.display = 'flex';
            overlay.style.display = 'block';
            const tb  = document.getElementById('sched-toolbar');
            const fab = document.getElementById('sched-fab-wrap');
            if (tb)  tb.style.display  = 'none';
            if (fab) fab.style.display = 'none';
        }

        function closeSchedImportPanel() {
            document.getElementById('sched-import-panel').style.display = 'none';
            document.getElementById('sched-import-overlay').style.display = 'none';
            const tb  = document.getElementById('sched-toolbar');
            const fab = document.getElementById('sched-fab-wrap');
            if (tb)  tb.style.display  = '';
            if (fab) fab.style.display = '';
        }

        // Gather tasks for a given responsibility ID — reads directly from data stores.
        // useTasksMap: when true, merges today's checked state into .done (only valid for today's view)
        function _getTasksForResp(respId, useTasksMap) {
            const results = [];

            function pushModuleTasks(arr, rid) {
                (arr || []).forEach(t => {
                    const taskKey = 'resp-' + rid + '-' + t.id;
                    const text = ((t.emoji ? t.emoji + ' ' : '') + (t.title || t.text || '')).trim();
                    if (!text) return;
                    results.push({
                        id: taskKey,
                        text,
                        notes: t.desc || t.notes || '',
                        done: (useTasksMap ? !!(tasks && tasks[taskKey]) : false) || !!(t.done),
                    });
                });
            }

            function pushGTasks(arr, rid) {
                (arr || []).forEach(t => {
                    const taskKey = 'gtask-' + rid + '-' + t.id;
                    results.push({
                        id: taskKey,
                        emoji: t.emoji || '',
                        text: t.title || t.text || '',
                        notes: t.desc || t.notes || '',
                        done: !!(t.done),
                        collapsed: !!t.collapsed,
                        subtasks: t.subtasks ? t.subtasks.map(s => ({id:s.id, text:s.text, done:s.done})) : null,
                        accentColor: t.accentColor || null,
                        groupRef: t.groupRef || null,
                    });
                });
            }

            // Fitness aggregates gym + martial-arts (no gTasksAll['fitness'] key exists)
            if (respId === 'fitness' && typeof gTasksAll !== 'undefined') {
                pushGTasks(gTasksAll['gym-1-2-3'] || [], 'gym-1-2-3');
                pushGTasks(gTasksAll['martial-arts'] || [], 'martial-arts');
                return results;
            }

            // All sections use gTasksAll as the single source of truth.
            if (typeof gTasksAll !== 'undefined' && gTasksAll[respId] && gTasksAll[respId].length) {
                pushGTasks(gTasksAll[respId], respId);
            }
            return results;
        }

        function buildImportBody() {
            const body = document.getElementById('sched-import-body');
            if (!body) return;
            body.innerHTML = '';

            // Block select options
            const blockOpts = schedBlocks.map(b =>
                `<option value="${escHtml(b.id)}">${escHtml(b.emoji + ' ' + b.start + ' ' + b.title)}</option>`
            ).join('');

            // Helper — builds a task row and appends it to a container
            function _buildTaskRow(container, t, summaryId, color, sourceLabel) {
                const row = document.createElement('div');
                row.className = 'sched-imp-task-row';

                const textEl = document.createElement('div');
                textEl.className = 'flex-1';

                // Label: emoji + text, exactly like Tasks
                const taskNameEl = document.createElement('div');
                taskNameEl.className = 'sched-imp-task-text';
                taskNameEl.textContent = (t.emoji ? t.emoji + ' ' : '') + (t.text || '');

                // Notes line
                const notesEl = document.createElement('div');
                notesEl.style.cssText = 'font-size:0.75em;color:#475569;margin-top:2px;';
                if (t.notes) notesEl.textContent = t.notes;

                // Source label
                const taskSrcEl = document.createElement('div');
                taskSrcEl.className = 'sched-imp-task-section';
                taskSrcEl.style.color = color || '#818cf8';
                taskSrcEl.textContent = sourceLabel;

                textEl.appendChild(taskNameEl);
                if (t.notes) textEl.appendChild(notesEl);
                textEl.appendChild(taskSrcEl);

                const sel = document.createElement('select');
                sel.className = 'sched-imp-block-select';
                sel.style.colorScheme = 'dark';
                sel.innerHTML = blockOpts;

                const addBtn = document.createElement('button');
                addBtn.className = 'sched-imp-add-btn';

                // Check if already imported in ANY block
                const alreadyImported = schedBlocks.some(b => b.tasks.some(bt => bt.id === t.id));
                if (alreadyImported) {
                    addBtn.textContent = '✓ Added';
                    addBtn.disabled = true;
                    addBtn.style.opacity = '0.4';
                    row.style.opacity = '0.5';
                } else {
                    addBtn.textContent = 'Add →';
                }

                addBtn.addEventListener('click', () => {
                    const blockId = sel.value;
                    const block = schedBlocks.find(b => b.id === blockId);
                    if (!block) return;
                    // Re-check uniqueness across all blocks at click time
                    if (schedBlocks.some(b => b.tasks.some(bt => bt.id === t.id))) {
                        showToast('Already in schedule');
                        return;
                    }
                    block.tasks.push({
                        id: t.id,
                        text: (t.emoji ? t.emoji + ' ' : '') + (t.text || ''),
                        notes: t.notes || null,
                        done: false,
                        summary: summaryId,
                        sslot: null,
                        srtask: null,
                        collapsed: !!t.collapsed,
                        subtasks: t.subtasks ? t.subtasks.map(s => ({id:s.id, text:s.text, done: false})) : null,
                        accentColor: t.accentColor || null,
                        groupRef: t.groupRef || null,
                    });
                    saveSchedBlocks();
                    renderSchedule();
                    showToast('✓ Added to ' + block.emoji + ' ' + block.title);
                    row.style.opacity = '0.5';
                    addBtn.textContent = '✓ Added';
                    addBtn.disabled = true;
                    addBtn.style.opacity = '0.4';
                });

                row.appendChild(textEl);
                row.appendChild(sel);
                row.appendChild(addBtn);
                container.appendChild(row);
            }

            // ── SECTION 1: R1 / R2 / R3 responsibilities ──────────────────────
            let hasR = false;
            ['r1', 'r2', 'r3'].forEach(slot => {
                const respId = rSlots && rSlots[slot];
                if (!respId || respId === 'none') return;
                const meta = getRespMeta(respId);
                const rTasks = _getTasksForResp(respId, false); // don't filter by today's map — each day is independent
                if (!rTasks.length) return;
                hasR = true;
                const hdr = document.createElement('div');
                hdr.className = 'sched-imp-section-hdr';
                hdr.textContent = slot.toUpperCase() + ' — ' + meta.emoji + ' ' + meta.title;
                body.appendChild(hdr);
                rTasks.forEach(t => _buildTaskRow(body, t, slot, meta.color || '#818cf8', meta.title));
            });

            // ── SECTION 2: Today's Progress — Important sections ───────────────
            // Each entry: { pill summary ID, gTasksAll storage key, display info }
            const IMP_SECTIONS = [
                { summary: 'pills',    gtaskSid: 'pills',    emoji: '💊', label: 'Pills',    color: '#38bdf8' },
                { summary: 'work',     gtaskSid: 'imp-work', emoji: '💼', label: 'Work',     color: '#60a5fa' },
                { summary: 'finance',  gtaskSid: 'finance',  emoji: '💰', label: 'Finance',  color: '#34d399' },
                { summary: 'b',        gtaskSid: 'b',        emoji: '❤️', label: 'Love',     color: '#f43f5e' },
                { summary: 'organize', gtaskSid: 'organize', emoji: '🗂️', label: 'Organize', color: '#fbbf24' },
                { summary: 'music',    gtaskSid: 'music',    emoji: '🎵', label: 'Music',    color: '#a78bfa' },
            ];

            let hasImp = false;
            const impRows = []; // collect first, add divider only if there's something

            IMP_SECTIONS.forEach(sec => {
                const gtList = (typeof gTasksAll !== 'undefined' && gTasksAll[sec.gtaskSid]) || [];
                // Show all tasks — each day's blocks are independent.
                // The per-day "alreadyImported" check (✓ Added) is the only guard needed.
                const pending = gtList;
                if (!pending.length) return;
                hasImp = true;

                // Section header
                const hdr = document.createElement('div');
                hdr.className = 'sched-imp-section-hdr';
                hdr.textContent = sec.emoji + ' ' + sec.label;
                impRows.push(hdr);

                pending.forEach(t => {
                    // Build the task descriptor matching gTasksAll key format
                    const taskDescriptor = {
                        id:         'gtask-' + sec.gtaskSid + '-' + t.id,
                        emoji:      t.emoji || '',
                        text:       t.text,
                        notes:      t.notes || '',
                        subtasks:   t.subtasks ? t.subtasks.map(s => ({id:s.id, text:s.text, done:!!s.done})) : null,
                        accentColor: t.accentColor || null,
                        groupRef:   t.groupRef || null,
                    };
                    const container = document.createElement('div'); // temp wrapper
                    _buildTaskRow(container, taskDescriptor, sec.summary, sec.color, sec.label);
                    // pull the row out of the wrapper
                    while (container.firstChild) impRows.push(container.removeChild(container.firstChild));
                });
            });

            if (hasImp) {
                // Divider between sections (only if R section also had content)
                if (hasR) {
                    const div = document.createElement('div');
                    div.style.cssText = 'border-top:1px solid rgba(255,255,255,0.06);margin:14px 0 2px;';
                    body.appendChild(div);
                }
                // Section group label
                const grpHdr = document.createElement('div');
                grpHdr.style.cssText = 'font-size:0.68em;font-weight:900;text-transform:uppercase;letter-spacing:0.8px;color:#334155;padding:10px 0 4px;font-family:"Outfit",sans-serif;';
                grpHdr.textContent = '📊 Today\'s Progress';
                body.appendChild(grpHdr);
                impRows.forEach(el => body.appendChild(el));
            }

            if (!hasR && !hasImp) {
                body.innerHTML = `<div style="color:#475569;font-size:0.85em;padding:28px 0;text-align:center;line-height:1.8;">
                    No pending tasks found.<br>
                    <span style="font-size:0.88em;">Add tasks in the Important or Responsibilities sections first.</span>
                </div>`;
            }
        }

        // Init schedule on load
        function initSchedule() { initSchedDaySelector(); renderSchedule(); }

// ══════════════════════════════════════════════════════════════════════
        //  RECIPE SYSTEM — enhanced
        // ══════════════════════════════════════════════════════════════════════
        (function() {
            // ── data ─────────────────────────────────────────────────────────
            let _data = [];
            try { _data = JSON.parse(localStorage.getItem('recipesData') || '[]') || []; } catch(e) {}
            window._rcpData = _data;

            function _save() {
                localStorage.setItem('recipesData', JSON.stringify(_data));
                window._rcpData = _data;
            }

            // ── filter + search state ────────────────────────────────────────
            let _filter = 'all';
            let _search = '';

            window.rcpSetFilter = function(cat) {
                _filter = cat;
                document.querySelectorAll('.rcp-fpill').forEach(p => {
                    p.classList.toggle('on', p.getAttribute('data-cat') === cat);
                });
                _renderGrid();
            };

            window.rcpSetSearch = function(val) {
                _search = val.trim().toLowerCase();
                _renderGrid();
            };

            // ── category meta ────────────────────────────────────────────────
            const CAT_META = {
                breakfast:{ label:'Breakfast', emoji:'🌅', cls:'cat-breakfast' },
                brunch:   { label:'Brunch',    emoji:'🥂', cls:'cat-brunch'    },
                lunch:    { label:'Lunch',     emoji:'☀️', cls:'cat-lunch'     },
                dinner:   { label:'Dinner',    emoji:'🌙', cls:'cat-dinner'    },
                snack:    { label:'Snack',     emoji:'🍎', cls:'cat-snack'     },
                dessert:  { label:'Dessert',   emoji:'🍰', cls:'cat-dessert'   },
                drink:    { label:'Drink',     emoji:'🥤', cls:'cat-drink'     },
                other:    { label:'Other',     emoji:'📦', cls:'cat-other'     },
            };
            function _catMeta(cat) { return CAT_META[cat] || CAT_META.other; }

            // ── last cooked label ────────────────────────────────────────────
            function _lastCookedLabel(dateStr) {
                if (!dateStr) return null;
                const d = new Date(dateStr);
                const now = new Date();
                const days = Math.floor((now - d) / 86400000);
                if (days === 0) return { label: 'Cooked today', recent: true };
                if (days === 1) return { label: 'Cooked yesterday', recent: true };
                if (days < 7)  return { label: `Cooked ${days}d ago`, recent: true };
                return { label: `Last cooked ${d.toLocaleDateString('en-GB', { day:'numeric', month:'short' })}`, recent: false };
            }

            function _syncDetailCookedState(recipe) {
                const lc = document.getElementById('rcp-d-last-cooked');
                const lcInfo = _lastCookedLabel(recipe.lastCooked);
                if (lc) lc.textContent = lcInfo ? lcInfo.label : '';

                const markBtn = document.getElementById('rcp-d-mark-btn');
                if (markBtn) {
                    const cookedToday = !!recipe.lastCooked && recipe.lastCooked === new Date().toISOString().slice(0, 10);
                    markBtn.textContent = cookedToday ? '↺ Unmark Cooked' : '✓ Mark Cooked';
                    markBtn.classList.toggle('active', cookedToday);
                }
            }

            // ── render grid ──────────────────────────────────────────────────
            function _renderGrid() {
                const grid  = document.getElementById('rcp-grid');
                const empty = document.getElementById('rcp-empty');
                if (!grid) return;

                let list = _filter === '__fav__' ? _data.filter(r => r.fav) :
                           _filter === 'all'     ? _data :
                           _data.filter(r => r.category === _filter);

                if (_search) {
                    list = list.filter(r => r.name.toLowerCase().includes(_search) ||
                        (r.notes || '').toLowerCase().includes(_search) ||
                        (r.ingredients || []).some(i => (i.name || '').toLowerCase().includes(_search)));
                }

                // Update count label
                const cl = document.getElementById('rcp-count-label');
                if (cl) cl.textContent = _data.length
                    ? `${_data.length} recipe${_data.length!==1?'s':''} · ${_data.filter(r=>r.fav).length} ❤️`
                    : 'Your personal cookbook.';

                grid.innerHTML = '';
                if (!list.length) {
                    grid.style.display = 'none';
                    if (empty) {
                        empty.style.display = 'flex';
                        const ttl = document.getElementById('rcp-empty-ttl');
                        const sub = document.getElementById('rcp-empty-sub');
                        const btn = document.getElementById('rcp-empty-add-btn');
                        if (_search || _filter !== 'all') {
                            if (ttl) ttl.textContent = 'No matches';
                            if (sub) sub.textContent = 'Try a different search or category.';
                            if (btn) btn.style.display = 'none';
                        } else {
                            if (ttl) ttl.textContent = 'No recipes yet';
                            if (sub) sub.textContent = 'Add your first recipe — ingredients, steps, timing, everything in one place.';
                            if (btn) btn.style.display = '';
                        }
                    }
                    return;
                }
                grid.style.display = 'grid';
                if (empty) empty.style.display = 'none';
                list.forEach(r => {
                    const m = _catMeta(r.category);
                    const card = document.createElement('div');
                    card.className = 'rcp-card';
                    card.style.position = 'relative';
                    const metaParts = [];
                    if (r.prepTime) metaParts.push('⏱ ' + r.prepTime);
                    if (r.cookTime) metaParts.push('🔥 ' + r.cookTime);
                    if (r.servings) metaParts.push('🍽 ' + r.servings);
                    const lc = _lastCookedLabel(r.lastCooked);
                    card.innerHTML = `
                        <button class="rcp-card-fav" onclick="event.stopPropagation();rcpToggleFav('${r.id}')" data-tooltip="${r.fav?'Remove from favourites':'Add to favourites'}">${r.fav ? '❤️' : '🤍'}</button>
                        <button class="rcp-card-edbtn" onclick="event.stopPropagation();rcpOpenEditor('${r.id}')">✏️</button>
                        <div class="rcp-card-emoji">${r.emoji || '🍳'}</div>
                        <div class="rcp-card-name">${_esc(r.name)}</div>
                        <div class="rcp-card-cat ${m.cls}">${m.emoji} ${m.label}</div>
                        ${metaParts.length ? `<div class="rcp-card-meta">${metaParts.join(' · ')}</div>` : ''}
                        ${lc ? `<div class="rcp-card-last-cooked${lc.recent?' cooked-recent':''}">${lc.label}</div>` : ''}
                    `;
                    card.addEventListener('click', () => rcpOpenDetail(r.id, 'recipes'));
                    grid.appendChild(card);
                });
            }

            // ── favourite toggle ─────────────────────────────────────────────
            window.rcpToggleFav = function(id) {
                const r = _data.find(x => x.id === id);
                if (!r) return;
                r.fav = !r.fav;
                _save();
                _renderGrid();
                if (typeof showToast === 'function') showToast(r.fav ? '❤️ Added to favourites' : '🤍 Removed from favourites');
            };

            // ── detail view ──────────────────────────────────────────────────
            let _detailId = null;
            let _rcpOriginTab = 'recipes';

            window.rcpOpenDetail = function(id, originTab) {
                _rcpOriginTab = originTab || 'recipes';
                const r = _data.find(x => x.id === id);
                if (!r) return;
                _detailId = id;
                const m = _catMeta(r.category);
                document.getElementById('rcp-d-emoji').textContent = r.emoji || '🍳';
                document.getElementById('rcp-d-name').textContent  = r.name;
                const catEl = document.getElementById('rcp-d-cat');
                catEl.textContent = m.emoji + ' ' + m.label;
                catEl.className   = 'rcp-detail-cat ' + m.cls;
                document.getElementById('rcp-d-prep').textContent = r.prepTime || '—';
                document.getElementById('rcp-d-cook').textContent = r.cookTime || '—';
                document.getElementById('rcp-d-serv').textContent = r.servings || '—';

                // Last cooked
                _syncDetailCookedState(r);

                // Fav button state
                const favBtn = document.getElementById('rcp-d-fav-btn');
                if (favBtn) {
                    favBtn.textContent = r.fav ? '❤️ Favourited' : '❤️ Favourite';
                    favBtn.classList.toggle('active', !!r.fav);
                }

                const body = document.getElementById('rcp-detail-body');
                body.innerHTML = '';

                if (r.ingredients && r.ingredients.length) {
                    const sec = document.createElement('div');
                    sec.className = 'rcp-section-card';
                    sec.innerHTML = `<div class="rcp-section-lbl">🛒 Ingredients</div>` +
                        r.ingredients.map(ing =>
                            `<div class="rcp-ing-row">
                                <span class="rcp-ing-amt">${_esc(ing.amount || '')}</span>
                                <span class="rcp-ing-name">${_esc(ing.name || '')}</span>
                             </div>`
                        ).join('');
                    body.appendChild(sec);
                }

                if (r.steps && r.steps.length) {
                    const sec = document.createElement('div');
                    sec.className = 'rcp-section-card';
                    sec.innerHTML = `<div class="rcp-section-lbl">📋 Steps</div>` +
                        r.steps.map((s, i) =>
                            `<div class="rcp-step-row">
                                <div class="rcp-step-num">${i + 1}</div>
                                <div class="rcp-step-txt">${_esc(s)}</div>
                             </div>`
                        ).join('');
                    body.appendChild(sec);
                }

                if (r.notes && r.notes.trim()) {
                    const sec = document.createElement('div');
                    sec.className = 'rcp-section-card';
                    sec.innerHTML = `<div class="rcp-section-lbl">💡 Notes & Tips</div>
                        <div class="rcp-notes-txt">${_esc(r.notes)}</div>`;
                    body.appendChild(sec);
                }

                document.getElementById('rcp-detail-ov').style.display = 'block';
                document.body.style.overflow = 'hidden';
            };

            window.rcpCloseDetail = function() {
                document.getElementById('rcp-detail-ov').style.display = 'none';
                document.body.style.overflow = '';
                _detailId = null;
                if (_rcpOriginTab === 'schedule') { _activateTab('schedule'); }
            };

            window.rcpEditFromDetail = function() {
                if (_detailId) { const id = _detailId; rcpCloseDetail(); rcpOpenEditor(id); }
            };

            window.rcpDeleteFromDetail = function() {
                if (!_detailId) return;
                const r = _data.find(x => x.id === _detailId);
                if (!r) return;
                showConfirm({
                    title: '🗑 Delete Recipe?',
                    message: `Delete <strong style="color:#e2e8f0;">"${_esc(r.name)}"</strong>? This cannot be undone.`,
                    confirmLabel: '🗑 Delete',
                    confirmColor: '#ef4444',
                    onConfirm: () => {
                        _data = _data.filter(x => x.id !== _detailId);
                        _save();
                        rcpCloseDetail();
                        _renderGrid();
                    }
                });
            };

            window.rcpToggleFavFromDetail = function() {
                if (!_detailId) return;
                rcpToggleFav(_detailId);
                const r = _data.find(x => x.id === _detailId);
                if (!r) return;
                const favBtn = document.getElementById('rcp-d-fav-btn');
                if (favBtn) {
                    favBtn.textContent = r.fav ? '❤️ Favourited' : '❤️ Favourite';
                    favBtn.classList.toggle('active', !!r.fav);
                }
            };

            window.rcpMarkCooked = function() {
                if (!_detailId) return;
                const r = _data.find(x => x.id === _detailId);
                if (!r) return;
                const today = new Date().toISOString().slice(0, 10);
                const cookedToday = r.lastCooked === today;
                r.lastCooked = cookedToday ? null : today;
                _save();
                _syncDetailCookedState(r);
                _renderGrid();
                if (typeof showToast === 'function') {
                    showToast(cookedToday ? '↺ Removed cooked mark.' : '✓ Marked as cooked today!', '#34d399');
                }
            };

            // ── Export single recipe ────────────────────────────────────────
            window.rcpExportSingle = function() {
                if (!_detailId) return;
                const r = _data.find(x => x.id === _detailId);
                if (!r) return;
                const data = { _type: 'jn-recipes', _version: 1, _exported: new Date().toISOString(), recipes: [r] };
                _rcpDownload(data, `recipe-${r.name.toLowerCase().replace(/\s+/g,'-').replace(/[^a-z0-9-]/g,'')}.json`);
                if (typeof showToast === 'function') showToast(`📤 Exported "${r.name}"`, '#34d399');
            };

            // ── Export all ──────────────────────────────────────────────────
            window.rcpExportAll = function() {
                if (!_data.length) { if (typeof showToast==='function') showToast('No recipes to export.', '#f87171'); return; }
                const data = { _type: 'jn-recipes', _version: 1, _exported: new Date().toISOString(), recipes: _data };
                _rcpDownload(data, `recipes-${new Date().toISOString().slice(0,10)}.json`);
                if (typeof showToast === 'function') showToast(`📤 Exported ${_data.length} recipes`, '#34d399');
            };

            // ── Import ──────────────────────────────────────────────────────
            window.rcpImportFile = function(input) {
                const file = input.files[0];
                input.value = '';
                if (!file) return;
                const reader = new FileReader();
                reader.onload = (ev) => {
                    try {
                        const data = JSON.parse(ev.target.result);
                        let imported = [];
                        if (data._type === 'jn-recipes' && Array.isArray(data.recipes)) {
                            imported = data.recipes;
                        } else if (Array.isArray(data)) {
                            imported = data;
                        }
                        if (!imported.length) { if(typeof showToast==='function') showToast('No valid recipes found.', '#f87171'); return; }
                        showConfirm({
                            title: '📥 Import Recipes?',
                            message: `Import <strong style="color:#fbbf24;">${imported.length} recipe${imported.length!==1?'s':''}</strong> from <em>${_esc(file.name)}</em>?<br>
                                      <small style="color:#64748b;">Existing recipes with the same ID will be updated.</small>`,
                            confirmLabel: `📥 Import ${imported.length}`,
                            confirmColor: '#3b82f6',
                            onConfirm: () => {
                                let added = 0, updated = 0;
                                imported.forEach(r => {
                                    if (!r.id) r.id = 'rcp_' + Date.now() + Math.random().toString(36).slice(2);
                                    const idx = _data.findIndex(x => x.id === r.id);
                                    if (idx >= 0) { _data[idx] = r; updated++; } else { _data.unshift(r); added++; }
                                });
                                _save();
                                _renderGrid();
                                if (typeof showToast==='function') showToast(`✓ ${added} added, ${updated} updated`, '#34d399');
                            }
                        });
                    } catch(err) { if(typeof showToast==='function') showToast('Failed to read file.', '#f87171'); }
                };
                reader.readAsText(file);
            };

            function _rcpDownload(obj, filename) {
                const blob = new Blob([JSON.stringify(obj, null, 2)], { type:'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url; a.download = filename; a.click();
                setTimeout(() => URL.revokeObjectURL(url), 1000);
            }

            // ═══════════════════════════════════════════════════════════════
            //  COOK MODE
            // ═══════════════════════════════════════════════════════════════
            let _cookRecipe = null;
            let _cookServMult = 1;
            let _cookBaseServ = 1;
            let _cookMode = 'ingredients'; // 'ingredients' | 'steps'
            let _cookStep = 0;
            let _cookIngChecked = [];

            function _parseServings(str) {
                if (!str) return 1;
                const n = parseFloat(str);
                return isNaN(n) || n < 1 ? 1 : n;
            }

            function _scaleAmt(amtStr, mult) {
                if (!amtStr) return amtStr;
                // Try to parse leading number
                const m = amtStr.match(/^([\d.,\/\s]+)(.*)/);
                if (!m) return amtStr;
                let numStr = m[1].trim();
                let rest = m[2];
                // Handle fractions like 1/2
                let num;
                if (numStr.includes('/')) {
                    const parts = numStr.split('/');
                    num = parseFloat(parts[0]) / parseFloat(parts[1]);
                } else {
                    num = parseFloat(numStr.replace(',', '.'));
                }
                if (isNaN(num)) return amtStr;
                const scaled = num * mult;
                // Format nicely
                const formatted = scaled % 1 === 0 ? scaled.toString() :
                    Math.round(scaled * 4) % 4 === 0 ? (Math.round(scaled * 4) / 4).toFixed(2).replace('.00','').replace('.50','.5').replace('.25','¼').replace('.75','¾') :
                    parseFloat(scaled.toFixed(1)).toString();
                return formatted + rest;
            }

            window.rcpOpenCookMode = function() {
                if (!_detailId) return;
                const r = _data.find(x => x.id === _detailId);
                if (!r) return;
                _cookRecipe = r;
                _cookBaseServ = _parseServings(r.servings);
                _cookServMult = 1;
                _cookMode = 'ingredients';
                _cookStep = 0;
                _cookIngChecked = (r.ingredients || []).map(() => false);

                document.getElementById('rcp-cook-title').textContent = r.emoji + ' ' + r.name;
                document.getElementById('rcp-cook-serv-val').textContent = _cookBaseServ;
                const baseEl = document.getElementById('rcp-cook-serv-base');
                if (baseEl) baseEl.textContent = `(base: ${_cookBaseServ})`;

                _rcpCookRender();
                document.getElementById('rcp-cook-ov').style.display = 'block';
                document.body.style.overflow = 'hidden';
            };

            window.rcpCloseCookMode = function() {
                document.getElementById('rcp-cook-ov').style.display = 'none';
                document.body.style.overflow = 'hidden'; // detail is still open
            };

            window.rcpCookAdjServ = function(delta) {
                const newServ = Math.max(0.5, _cookBaseServ * _cookServMult + delta * _cookBaseServ * 0.5);
                // Snap to multiples of 0.5 base
                _cookServMult = Math.max(0.5, Math.round((newServ / _cookBaseServ) * 2) / 2);
                const displayServ = _cookBaseServ * _cookServMult;
                document.getElementById('rcp-cook-serv-val').textContent =
                    displayServ % 1 === 0 ? displayServ : displayServ.toFixed(1);
                _rcpCookRender();
            };

            window.rcpCookToggleMode = function() {
                _cookMode = _cookMode === 'ingredients' ? 'steps' : 'ingredients';
                _cookStep = 0;
                _rcpCookRender();
            };

            window.rcpCookToggleIng = function(i) {
                _cookIngChecked[i] = !_cookIngChecked[i];
                const rows = document.querySelectorAll('.rcp-cook-ing-row');
                if (rows[i]) {
                    rows[i].classList.toggle('checked', _cookIngChecked[i]);
                    const cb = rows[i].querySelector('.rcp-cook-ing-cb');
                    if (cb) cb.innerHTML = _cookIngChecked[i] ? '✓' : '';
                }
            };

            window.rcpCookNextStep = function() {
                const steps = _cookRecipe.steps || [];
                if (_cookStep < steps.length - 1) {
                    _cookStep++;
                    _rcpCookRenderStep();
                } else {
                    // Done!
                    _cookRecipe.lastCooked = new Date().toISOString().slice(0,10);
                    _save();
                    _renderGrid();
                    rcpCloseCookMode();
                    if (typeof showToast==='function') showToast('🎉 Recipe complete! Marked as cooked today.', '#34d399');
                    _syncDetailCookedState(_cookRecipe);
                }
            };

            window.rcpCookPrevStep = function() {
                if (_cookStep > 0) { _cookStep--; _rcpCookRenderStep(); }
            };

            function _rcpCookRender() {
                const modeBtn = document.getElementById('rcp-cook-mode-btn');
                const modeLabel = document.getElementById('rcp-cook-mode-label');
                if (_cookMode === 'ingredients') {
                    if (modeBtn) modeBtn.textContent = '📋 Steps';
                    if (modeLabel) modeLabel.textContent = 'Ingredients checklist — tap to tick off';
                    document.getElementById('rcp-cook-step-nav').style.display = 'none';
                    _rcpCookRenderIngredients();
                } else {
                    if (modeBtn) modeBtn.textContent = '🛒 Ingredients';
                    if (modeLabel) modeLabel.textContent = 'Step-by-step guide';
                    document.getElementById('rcp-cook-step-nav').style.display = 'flex';
                    _rcpCookRenderStep();
                }
            }

            function _rcpCookRenderIngredients() {
                const body = document.getElementById('rcp-cook-body');
                if (!body) return;
                const ings = _cookRecipe.ingredients || [];
                if (!ings.length) {
                    body.innerHTML = '<div style="text-align:center;color:#334155;padding:40px;">No ingredients listed for this recipe.</div>';
                    return;
                }
                body.innerHTML = `
                    <div class="rcp-section-card" style="padding:16px 18px;">
                        <div class="rcp-cook-section-lbl">🛒 Ingredients (tap to tick off)</div>
                        ${ings.map((ing, i) => `
                            <div class="rcp-cook-ing-row ${_cookIngChecked[i]?'checked':''}" onclick="rcpCookToggleIng(${i})">
                                <div class="rcp-cook-ing-cb">${_cookIngChecked[i]?'✓':''}</div>
                                <span class="rcp-cook-ing-amt">${_esc(_scaleAmt(ing.amount, _cookServMult))}</span>
                                <span class="rcp-cook-ing-name">${_esc(ing.name || '')}</span>
                            </div>
                        `).join('')}
                    </div>
                    ${_cookRecipe.notes ? `<div class="rcp-section-card" style="padding:14px 18px;">
                        <div class="rcp-cook-section-lbl">💡 Notes</div>
                        <div class="rcp-notes-txt">${_esc(_cookRecipe.notes)}</div>
                    </div>` : ''}
                    <div style="padding:8px 0 20px;text-align:center;">
                        <button onclick="rcpCookToggleMode()"
                            style="background:linear-gradient(135deg,#3b82f6,#2563eb);border:none;color:#fff;
                            border-radius:14px;padding:14px 32px;cursor:pointer;font-family:'Outfit',sans-serif;
                            font-size:0.92em;font-weight:900;width:100%;max-width:320px;">
                            Ready to cook → Step-by-step guide
                        </button>
                    </div>
                `;
            }

            function _rcpCookRenderStep() {
                const body = document.getElementById('rcp-cook-body');
                const steps = _cookRecipe.steps || [];
                if (!steps.length) {
                    if (body) body.innerHTML = '<div style="text-align:center;color:#334155;padding:40px;">No steps listed for this recipe.</div>';
                    return;
                }
                const counter = document.getElementById('rcp-cook-step-counter');
                const prevBtn = document.getElementById('rcp-cook-prev-btn');
                const nextBtn = document.getElementById('rcp-cook-next-btn');

                if (counter) counter.textContent = `${_cookStep + 1} / ${steps.length}`;
                if (prevBtn) prevBtn.disabled = _cookStep === 0;
                if (prevBtn) prevBtn.style.opacity = _cookStep === 0 ? '0.3' : '1';
                if (nextBtn) {
                    const isDone = _cookStep === steps.length - 1;
                    nextBtn.textContent = isDone ? '🎉 Done!' : 'Next →';
                    nextBtn.classList.toggle('done', isDone);
                }

                if (body) {
                    // Progress bar
                    const progress = Math.round((_cookStep / (steps.length - 1)) * 100);
                    body.innerHTML = `
                        <div style="height:3px;background:rgba(255,255,255,0.05);border-radius:99px;margin:0 0 20px;overflow:hidden;">
                            <div style="height:100%;width:${progress}%;background:linear-gradient(90deg,#3b82f6,#60a5fa);border-radius:99px;transition:width 0.3s;"></div>
                        </div>
                        <div class="rcp-cook-step-card">
                            <div class="rcp-cook-step-num-badge">${_cookStep + 1}</div>
                            <div class="rcp-cook-step-text">${_esc(steps[_cookStep])}</div>
                        </div>
                        ${_cookRecipe.ingredients && _cookRecipe.ingredients.length ? `
                        <div class="rcp-section-card" style="padding:12px 16px;margin-top:8px;">
                            <div class="rcp-cook-section-lbl" style="margin-bottom:7px;">🛒 Quick reference</div>
                            ${_cookRecipe.ingredients.slice(0,6).map(ing =>
                                `<div style="display:flex;gap:10px;padding:5px 0;border-bottom:1px solid rgba(255,255,255,0.03);">
                                    <span style="font-size:0.77em;color:#fbbf24;font-weight:700;min-width:70px;">${_esc(_scaleAmt(ing.amount, _cookServMult))}</span>
                                    <span style="font-size:0.8em;color:#64748b;">${_esc(ing.name||'')}</span>
                                </div>`
                            ).join('')}
                            ${_cookRecipe.ingredients.length > 6 ? `<div style="font-size:0.72em;color:#1e293b;margin-top:5px;">+${_cookRecipe.ingredients.length-6} more ingredients</div>` : ''}
                        </div>` : ''}
                    `;
                }
            }

            // ── editor ───────────────────────────────────────────────────────
            let _editId  = null;
            let _ingRows = [];
            let _stepRows = [];

            window.rcpOpenEditor = function(id) {
                _editId = id || null;
                const r = id ? _data.find(x => x.id === id) : null;
                document.getElementById('rcp-editor-title').textContent = r ? 'Edit Recipe' : 'New Recipe';
                document.getElementById('rcp-e-emoji').value = r ? (r.emoji || '') : '';
                document.getElementById('rcp-e-name').value  = r ? r.name  : '';
                document.getElementById('rcp-e-cat').value   = r ? (r.category || 'breakfast') : 'breakfast';
                document.getElementById('rcp-e-prep').value  = r ? (r.prepTime || '') : '';
                document.getElementById('rcp-e-cook').value  = r ? (r.cookTime || '') : '';
                document.getElementById('rcp-e-serv').value  = r ? (r.servings || '') : '';
                document.getElementById('rcp-e-notes').value = r ? (r.notes || '') : '';
                _ingRows = r && r.ingredients ? r.ingredients.map(i => ({...i})) : [];
                if (!_ingRows.length) _ingRows = [{ amount: '', name: '' }];
                _renderIngList();
                _stepRows = r && r.steps ? [...r.steps] : [];
                if (!_stepRows.length) _stepRows = [''];
                _renderStepList();
                document.getElementById('rcp-editor-ov').style.display = 'block';
                document.body.style.overflow = 'hidden';
                setTimeout(() => document.getElementById('rcp-e-emoji').focus(), 80);
            };

            window.rcpCloseEditor = function() {
                document.getElementById('rcp-editor-ov').style.display = 'none';
                document.body.style.overflow = '';
            };

            function _renderIngList() {
                const list = document.getElementById('rcp-ing-list');
                if (!list) return;
                list.innerHTML = '';
                _ingRows.forEach((ing, i) => {
                    const row = document.createElement('div');
                    row.className = 'rcp-dyn-row';
                    row.innerHTML = `
                        <input class="rcp-dyn-amt" name="rcp-ing-amount-${i}" placeholder="Amount" value="${_esc(ing.amount || '')}"
                            oninput="_rcpIngChange(${i},'amount',this.value)">
                        <input class="rcp-dyn-name" name="rcp-ing-name-${i}" placeholder="Ingredient" value="${_esc(ing.name || '')}"
                            oninput="_rcpIngChange(${i},'name',this.value)"
                            onkeydown="if(event.key==='Enter'){event.preventDefault();rcpAddIngredient();}">
                        <button class="rcp-dyn-del" onclick="_rcpDelIng(${i})" data-tooltip="Remove">✕</button>
                    `;
                    list.appendChild(row);
                });
            }

            window._rcpIngChange = function(i, field, val) { if (_ingRows[i]) _ingRows[i][field] = val; };
            window._rcpDelIng    = function(i) { _ingRows.splice(i, 1); _renderIngList(); };
            window.rcpAddIngredient = function() {
                _ingRows.push({ amount: '', name: '' });
                _renderIngList();
                const inputs = document.getElementById('rcp-ing-list').querySelectorAll('.rcp-dyn-amt');
                if (inputs.length) inputs[inputs.length - 1].focus();
            };

            function _renderStepList() {
                const list = document.getElementById('rcp-step-list');
                if (!list) return;
                list.innerHTML = '';
                _stepRows.forEach((step, i) => {
                    const row = document.createElement('div');
                    row.className = 'rcp-dyn-row';
                    row.style.alignItems = 'flex-start';
                    row.innerHTML = `
                        <div style="min-width:24px;height:24px;border-radius:50%;
                            background:linear-gradient(135deg,#3b82f6,#2563eb);color:#fff;
                            font-size:0.7em;font-weight:900;display:flex;align-items:center;
                            justify-content:center;flex-shrink:0;margin-top:8px;">${i + 1}</div>
                        <textarea class="rcp-dyn-step" name="rcp-step-${i}" rows="2" placeholder="Describe this step…"
                            oninput="_rcpStepChange(${i},this.value)"
                            onkeydown="if(event.key==='Enter'&&!event.shiftKey){event.preventDefault();rcpAddStep();}"
                            >${_esc(step)}</textarea>
                        <button class="rcp-dyn-del" onclick="_rcpDelStep(${i})" data-tooltip="Remove">✕</button>
                    `;
                    list.appendChild(row);
                });
            }

            window._rcpStepChange = function(i, val) { if (_stepRows[i] !== undefined) _stepRows[i] = val; };
            window._rcpDelStep    = function(i) { _stepRows.splice(i, 1); _renderStepList(); };
            window.rcpAddStep     = function() {
                _stepRows.push('');
                _renderStepList();
                const tas = document.getElementById('rcp-step-list').querySelectorAll('.rcp-dyn-step');
                if (tas.length) tas[tas.length - 1].focus();
            };

            window.rcpSave = function() {
                const name = document.getElementById('rcp-e-name').value.trim();
                if (!name) { document.getElementById('rcp-e-name').focus(); return; }
                const ingInputs = document.getElementById('rcp-ing-list').querySelectorAll('.rcp-dyn-row');
                _ingRows = [];
                ingInputs.forEach(row => {
                    const [amt, nm] = row.querySelectorAll('input');
                    const a = amt ? amt.value.trim() : '';
                    const n = nm  ? nm.value.trim()  : '';
                    if (a || n) _ingRows.push({ amount: a, name: n });
                });
                const stepTAs = document.getElementById('rcp-step-list').querySelectorAll('textarea');
                _stepRows = [];
                stepTAs.forEach(ta => { const v = ta.value.trim(); if (v) _stepRows.push(v); });

                const existing = _editId ? _data.find(x => x.id === _editId) : null;
                const rec = {
                    id:          _editId || ('rcp_' + Date.now()),
                    emoji:       document.getElementById('rcp-e-emoji').value.trim() || '🍳',
                    name,
                    category:    document.getElementById('rcp-e-cat').value,
                    prepTime:    document.getElementById('rcp-e-prep').value.trim(),
                    cookTime:    document.getElementById('rcp-e-cook').value.trim(),
                    servings:    document.getElementById('rcp-e-serv').value.trim(),
                    ingredients: _ingRows,
                    steps:       _stepRows,
                    notes:       document.getElementById('rcp-e-notes').value.trim(),
                    fav:         existing ? (existing.fav || false) : false,
                    lastCooked:  existing ? (existing.lastCooked || null) : null,
                };

                if (_editId) {
                    const idx = _data.findIndex(x => x.id === _editId);
                    if (idx >= 0) _data[idx] = rec; else _data.push(rec);
                } else {
                    _data.unshift(rec);
                }
                _save();
                rcpCloseEditor();
                _renderGrid();
                if (typeof showToast === 'function') showToast((_editId ? '✏️ Updated: ' : '✓ Saved: ') + name);
            };

            // ── tab helper ───────────────────────────────────────────────────
            function _activateTab(name) {
                document.querySelectorAll('.tab-content').forEach(t => t.classList.remove('active'));
                const tab = document.getElementById(name);
                if (tab) tab.classList.add('active');
                document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
                const btn = document.querySelector(`button[onclick*="${name}"]`);
                if (btn) btn.classList.add('active');
            }

            // ── escape helper ────────────────────────────────────────────────
            function _esc(s) {
                return String(s || '')
                    .replace(/&/g,'&amp;').replace(/</g,'&lt;')
                    .replace(/>/g,'&gt;').replace(/"/g,'&quot;');
            }

            // ── init ─────────────────────────────────────────────────────────
            window.initRecipes = function() { _renderGrid(); };

        })(); // end recipe IIFE


        // ════════════════════════════════════════════════════════
        //  DRAG & DROP — schedule blocks + section task lists
        // ════════════════════════════════════════════════════════

        // ── Shared drag state ─────────────────────────────────
        // ════════════════════════════════════════════════════════
        //  DRAG & DROP ENGINE  (handle-flag approach)
        //  Items are always draggable=true; dragstart is cancelled
        //  unless the mousedown came from the ⋮⋮ handle.
        // ════════════════════════════════════════════════════════

        const _dnd = { dragIdx: null, listId: null, fromHandle: false };

        // Reset fromHandle on any mouseup so stray clicks never enable drags
        document.addEventListener('mouseup', function() { _dnd.fromHandle = false; }, true);

        // ════════════════════════════════════════════════════
        //  TOUCH DnD engine (ghost + hit-test approach)
        // ════════════════════════════════════════════════════
        var _touch = {
            active: false, ghost: null, srcEl: null,
            getAllEls: null, onDrop: null,
            fromIdx: null, offsetX: 0, offsetY: 0, lastOver: null
        };

        function _touchCleanup() {
            if (_touch.ghost) { _touch.ghost.remove(); _touch.ghost = null; }
            if (_touch.srcEl)  { _touch.srcEl.classList.remove('dnd-dragging'); _touch.srcEl.classList.remove('sub-row-dragging'); }
            if (_touch.lastOver) { _touch.lastOver.classList.remove('dnd-over'); _touch.lastOver.classList.remove('sub-row-over'); }
            _touch.active = false; _touch.srcEl = null;
            _touch.getAllEls = null; _touch.onDrop = null;
            _touch.fromIdx = null; _touch.lastOver = null;
        }

        document.addEventListener('touchmove', function(e) {
            if (!_touch.active) return;
            e.preventDefault();
            var t = e.touches[0];
            _touch.ghost.style.left = (t.clientX - _touch.offsetX) + 'px';
            _touch.ghost.style.top  = (t.clientY - _touch.offsetY) + 'px';
            // Hit-test: hide ghost briefly to find element beneath finger
            _touch.ghost.style.display = 'none';
            var under = document.elementFromPoint(t.clientX, t.clientY);
            _touch.ghost.style.display = '';
            var target = null, els = _touch.getAllEls(), node = under;
            while (node && !target) {
                if (els.indexOf(node) !== -1) target = node;
                node = node.parentElement;
            }
            var overClass = (_touch.srcEl && _touch.srcEl.hasAttribute('data-sub-idx')) ? 'sub-row-over' : 'dnd-over';
            if (_touch.lastOver && _touch.lastOver !== target) { _touch.lastOver.classList.remove('dnd-over'); _touch.lastOver.classList.remove('sub-row-over'); }
            if (target && target !== _touch.srcEl) { target.classList.add(overClass); _touch.lastOver = target; }
            else if (!target) _touch.lastOver = null;
        }, { passive: false });

        document.addEventListener('touchend', function(e) {
            if (!_touch.active) return;
            var t = e.changedTouches[0];
            _touch.ghost.style.display = 'none';
            var under = document.elementFromPoint(t.clientX, t.clientY);
            _touch.ghost.style.display = '';
            var target = null, els = _touch.getAllEls(), node = under;
            while (node && !target) {
                if (els.indexOf(node) !== -1) target = node;
                node = node.parentElement;
            }
            if (target && target !== _touch.srcEl) {
                var attr = target.getAttribute('data-bidx') || target.getAttribute('data-tidx') || target.getAttribute('data-sub-idx');
                var toIdx = parseInt(attr, 10);
                if (!isNaN(toIdx) && _touch.fromIdx !== null && toIdx !== _touch.fromIdx) {
                    _touch.onDrop(_touch.fromIdx, toIdx);
                }
            }
            _touchCleanup();
        });

        document.addEventListener('touchcancel', _touchCleanup);

        // ════════════════════════════════════════════════════
        //  DOM-REORDER TOUCH DnD (for focus cards & love items)
        //  Works with direct insertBefore-style reorder, not index swapping.
        //  Call once per container.
        // ════════════════════════════════════════════════════
        function _initDomTouchDnd(container, itemSel, handleSel, shouldInsertBefore, onEnd) {
            if (!container || container.dataset.touchDndBound === '1') return;
            container.dataset.touchDndBound = '1';

            var _dragged = null, _ghost = null, _lastOver = null;

            function cleanup() {
                if (_ghost)   { _ghost.remove(); _ghost = null; }
                if (_dragged) { _dragged.classList.remove('dragging'); _dragged = null; }
                if (_lastOver){ _lastOver.classList.remove('dnd-over'); _lastOver = null; }
            }

            container.addEventListener('touchstart', function(e) {
                var handle = e.target.closest(handleSel);
                if (!handle || !container.contains(handle)) return;
                var item = handle.closest(itemSel);
                if (!item) return;
                e.stopPropagation();
                var t = e.touches[0];
                var rect = item.getBoundingClientRect();
                _dragged = item;
                item.classList.add('dragging');
                var ghost = item.cloneNode(true);
                ghost.style.cssText = 'position:fixed;pointer-events:none;z-index:9999;opacity:0.85;' +
                    'box-shadow:0 8px 24px rgba(0,0,0,0.25);border-radius:10px;transform:scale(1.03);' +
                    'width:' + rect.width + 'px;left:' + rect.left + 'px;top:' + rect.top + 'px;';
                document.body.appendChild(ghost);
                _ghost = ghost;
                _ghost._offsetX = t.clientX - rect.left;
                _ghost._offsetY = t.clientY - rect.top;
            }, { passive: true });

            container.addEventListener('touchmove', function(e) {
                if (!_dragged || !_ghost) return;
                e.preventDefault();
                var t = e.touches[0];
                _ghost.style.left = (t.clientX - _ghost._offsetX) + 'px';
                _ghost.style.top  = (t.clientY - _ghost._offsetY) + 'px';
                // Hit-test
                _ghost.style.display = 'none';
                var under = document.elementFromPoint(t.clientX, t.clientY);
                _ghost.style.display = '';
                var target = under ? under.closest(itemSel) : null;
                if (target && container.contains(target) && target !== _dragged) {
                    if (_lastOver && _lastOver !== target) _lastOver.classList.remove('dnd-over');
                    target.classList.add('dnd-over'); _lastOver = target;
                    // Live reorder (same feel as mouse version)
                    var fakeE = { clientY: t.clientY, clientX: t.clientX };
                    var before = shouldInsertBefore ? shouldInsertBefore(fakeE, target) : (t.clientY < target.getBoundingClientRect().top + target.getBoundingClientRect().height / 2);
                    container.insertBefore(_dragged, before ? target : target.nextSibling);
                } else {
                    if (_lastOver) { _lastOver.classList.remove('dnd-over'); _lastOver = null; }
                }
            }, { passive: false });

            function onTouchEnd() {
                if (!_dragged) return;
                if (onEnd) onEnd();
                cleanup();
            }
            container.addEventListener('touchend', onTouchEnd);
            container.addEventListener('touchcancel', cleanup);
        }

        function _wireTouchDrag(el, getIdx, getAllEls, onDrop) {
            var handle = el.querySelector('.dnd-handle');
            if (!handle) return;
            var _wtTimer = null, _wtTouchRef = null;
            handle.addEventListener('touchstart', function(e) {
                e.stopPropagation();
                var t = e.touches[0];
                _wtTouchRef = { x: t.clientX, y: t.clientY };
                _wtTimer = setTimeout(function() {
                    _wtTimer = null;
                    if (!_wtTouchRef) return;
                    var rect = el.getBoundingClientRect();
                    var ghost = el.cloneNode(true);
                    ghost.style.cssText = 'position:fixed;pointer-events:none;z-index:9999;opacity:0.85;' +
                        'box-shadow:0 8px 24px rgba(0,0,0,0.25);border-radius:10px;transform:scale(1.03);' +
                        'width:' + rect.width + 'px;left:' + rect.left + 'px;top:' + rect.top + 'px;';
                    document.body.appendChild(ghost);
                    _touch.ghost    = ghost;
                    _touch.srcEl    = el;
                    _touch.active   = true;
                    _touch.getAllEls = getAllEls;
                    _touch.onDrop   = onDrop;
                    _touch.fromIdx  = getIdx();
                    _touch.offsetX  = _wtTouchRef.x - rect.left;
                    _touch.offsetY  = _wtTouchRef.y - rect.top;
                    el.classList.add('dnd-dragging');
                }, 300);
            }, { passive: true });
            handle.addEventListener('touchmove', function(e) {
                if (_wtTimer && _wtTouchRef) {
                    var t = e.touches[0];
                    if (Math.abs(t.clientX - _wtTouchRef.x) > 8 || Math.abs(t.clientY - _wtTouchRef.y) > 8) {
                        clearTimeout(_wtTimer); _wtTimer = null; _wtTouchRef = null;
                    }
                }
            }, { passive: true });
            handle.addEventListener('touchend', function() {
                if (_wtTimer) { clearTimeout(_wtTimer); _wtTimer = null; }
                _wtTouchRef = null;
            });
            handle.addEventListener('touchcancel', function() {
                if (_wtTimer) { clearTimeout(_wtTimer); _wtTimer = null; }
                _wtTouchRef = null;
            });
        }

        // ── generic mouse drag wiring ─────────────────────────
        function _wireDrag(el, getIdx, getListId, getAllEls, onDrop) {
            // item is ALWAYS draggable; dragstart is gated by fromHandle flag
            el.setAttribute('draggable', 'true');

            const handle = el.querySelector('.dnd-handle');
            if (handle) {
                handle.addEventListener('mousedown', function(e) {
                    e.stopPropagation();
                    _dnd.fromHandle = true;
                }, true);
            }

            // Wire touch DnD alongside mouse DnD
            _wireTouchDrag(el, getIdx, getAllEls, onDrop);

            el.addEventListener('dragstart', function(e) {
                if (!_dnd.fromHandle) { e.preventDefault(); return; }
                _dnd.dragIdx = getIdx();
                _dnd.listId  = getListId();
                e.dataTransfer.effectAllowed = 'move';
                e.dataTransfer.setData('text/plain', String(_dnd.dragIdx));
                setTimeout(function() { el.classList.add('dnd-dragging'); }, 0);
            });

            el.addEventListener('dragend', function() {
                el.classList.remove('dnd-dragging');
                getAllEls().forEach(function(r) { r.classList.remove('dnd-over'); });
                _dnd.dragIdx = null; _dnd.listId = null; _dnd.fromHandle = false;
            });

            el.addEventListener('dragover', function(e) {
                // If a task is being dragged, allow the drop (preventDefault) but don't
                // highlight this block or interfere — the cross-block handler manages it.
                if (_dnd.listId === 'sched-task') { e.preventDefault(); return; }
                if (_dnd.listId !== getListId()) return;
                e.preventDefault();
                e.stopPropagation();
                e.dataTransfer.dropEffect = 'move';
                getAllEls().forEach(function(r) { r.classList.remove('dnd-over'); });
                el.classList.add('dnd-over');
            });

            el.addEventListener('dragleave', function(e) {
                if (!el.contains(e.relatedTarget)) el.classList.remove('dnd-over');
            });

            el.addEventListener('drop', function(e) {
                // Let task cross-block handler deal with task drops
                if (_dnd.listId === 'sched-task') return;
                e.preventDefault();
                e.stopPropagation();
                el.classList.remove('dnd-over');
                var fromIdx = _dnd.dragIdx;
                var toIdx   = getIdx();
                if (_dnd.listId !== getListId()) return;
                if (fromIdx === null || fromIdx === toIdx) return;
                onDrop(fromIdx, toIdx);
            });
        }

        // ── Schedule-block DnD ────────────────────────────────
        function _initSchedBlockDnd() {
            if (_isSchedPastDay()) return;
            var container = document.getElementById('sched-container');
            if (!container) return;
            var getAllBlocks = function() { return Array.from(container.querySelectorAll('.hour-block[data-bidx]')); };

            getAllBlocks().forEach(function(blockEl) {
                var getIdx     = function() { return parseInt(blockEl.getAttribute('data-bidx')); };
                var getListId  = function() { return 'sched-blocks'; };
                _wireDrag(blockEl, getIdx, getListId, getAllBlocks, function(from, to) {
                    var moved = schedBlocks.splice(from, 1)[0];
                    schedBlocks.splice(to, 0, moved);
                    saveSchedBlocks();
                    renderSchedule();
                });
            });
        }

        // ── Cross-block Schedule task DnD ─────────────────────
        var _stDnd = { fromBlockId: null, fromIdx: null };

        function _doSchedTaskMove(fromBlockId, fromIdx, toBlockId, toIdx) {
            if (!fromBlockId || fromIdx === null) return;
            if (fromBlockId === toBlockId && fromIdx === toIdx) return;
            var fromBlock = schedBlocks.find(function(b) { return b.id === fromBlockId; });
            var toBlock   = schedBlocks.find(function(b) { return b.id === toBlockId; });
            if (!fromBlock || !toBlock) return;
            var moved = fromBlock.tasks.splice(fromIdx, 1)[0];
            if (!moved) return;
            fromBlock.tasks = fromBlock.tasks.filter(function(t) { return t != null; });
            if (fromBlockId === toBlockId) {
                var adj = fromIdx < toIdx ? toIdx - 1 : toIdx;
                fromBlock.tasks.splice(adj, 0, moved);
            } else {
                toBlock.tasks = (toBlock.tasks || []).filter(function(t) { return t != null; });
                toBlock.tasks.splice(toIdx, 0, moved);
            }
            saveSchedBlocks();
            renderSchedule();
        }

        function _initSchedCrossBlockTaskDnd() {
            if (_isSchedPastDay()) return;
            var container = document.getElementById('sched-container');
            if (!container) return;

            function getAllTaskEls() {
                return Array.from(container.querySelectorAll('.task-item[data-tidx]'));
            }
            function getAllBlockEls() {
                return Array.from(container.querySelectorAll('.hour-block[data-bidx]'));
            }
            function getBlockIdOf(el) {
                var ul = el.closest ? el.closest('ul[data-block-id]') : null;
                return ul ? ul.getAttribute('data-block-id') : null;
            }

            // ── MOUSE ─────────────────────────────────────────────────
            getAllTaskEls().forEach(function(liEl) {
                liEl.setAttribute('draggable', 'true');
                liEl.style.cursor = 'grab';

                // Whole task row is the drag handle — no need to hit the ⋮⋮ dots
                liEl.addEventListener('mousedown', function(e) {
                    // Don't interfere with clicks on buttons or checkboxes
                    if (e.target.closest('button, input, .house-task-check, .task-checkbox')) return;
                    _dnd.fromHandle = true;
                }, true);

                liEl.addEventListener('dragstart', function(e) {
                    if (!_dnd.fromHandle) { e.preventDefault(); return; }
                    e.stopPropagation();
                    _stDnd.fromBlockId = getBlockIdOf(liEl);
                    _stDnd.fromIdx     = parseInt(liEl.getAttribute('data-tidx'));
                    _dnd.listId = 'sched-task';
                    e.dataTransfer.effectAllowed = 'move';
                    e.dataTransfer.setData('text/plain', _stDnd.fromBlockId + ':' + _stDnd.fromIdx);
                    // Disable block dragging while task drag is active
                    getAllBlockEls().forEach(function(b) { b.setAttribute('draggable', 'false'); });
                    setTimeout(function() { liEl.classList.add('dnd-dragging'); }, 0);
                });

                liEl.addEventListener('dragend', function(e) {
                    e.stopPropagation();
                    liEl.classList.remove('dnd-dragging');
                    getAllTaskEls().forEach(function(r) { r.classList.remove('dnd-over'); });
                    getAllBlockEls().forEach(function(b) {
                        b.classList.remove('dnd-over');
                        b.setAttribute('draggable', 'true'); // re-enable block dragging
                    });
                    _dnd.listId = null; _dnd.fromHandle = false;
                    _stDnd.fromBlockId = null; _stDnd.fromIdx = null;
                });

                liEl.addEventListener('dragover', function(e) {
                    if (_dnd.listId !== 'sched-task') return;
                    e.preventDefault(); e.stopPropagation();
                    getAllTaskEls().forEach(function(r) { r.classList.remove('dnd-over'); });
                    getAllBlockEls().forEach(function(b) { b.classList.remove('dnd-over'); });
                    liEl.classList.add('dnd-over');
                });

                liEl.addEventListener('dragleave', function(e) {
                    if (!liEl.contains(e.relatedTarget)) liEl.classList.remove('dnd-over');
                });

                liEl.addEventListener('drop', function(e) {
                    e.preventDefault(); e.stopPropagation();
                    liEl.classList.remove('dnd-over');
                    if (_dnd.listId !== 'sched-task') return;
                    _doSchedTaskMove(
                        _stDnd.fromBlockId, _stDnd.fromIdx,
                        getBlockIdOf(liEl), parseInt(liEl.getAttribute('data-tidx'))
                    );
                });
            });

            // Drop target: each block (covers empty blocks + between tasks)
            getAllBlockEls().forEach(function(blockEl) {
                var ul = blockEl.querySelector('ul[data-block-id]');
                var blockId = ul ? ul.getAttribute('data-block-id') : null;
                if (!blockId) return;

                blockEl.addEventListener('dragover', function(e) {
                    if (_dnd.listId !== 'sched-task') return;
                    if (e.target.closest('.task-item')) return; // task handles its own highlight
                    e.preventDefault();
                    getAllTaskEls().forEach(function(r) { r.classList.remove('dnd-over'); });
                    getAllBlockEls().forEach(function(b) { b.classList.remove('dnd-over'); });
                    blockEl.classList.add('dnd-over');
                });

                blockEl.addEventListener('dragleave', function(e) {
                    if (!blockEl.contains(e.relatedTarget)) blockEl.classList.remove('dnd-over');
                });

                blockEl.addEventListener('drop', function(e) {
                    if (_dnd.listId !== 'sched-task') return;
                    if (e.target.closest('.task-item')) return; // handled by task's own drop
                    e.preventDefault(); e.stopPropagation();
                    blockEl.classList.remove('dnd-over');
                    var toBlock = schedBlocks.find(function(b) { return b.id === blockId; });
                    if (!toBlock) return;
                    _doSchedTaskMove(_stDnd.fromBlockId, _stDnd.fromIdx, blockId, (toBlock.tasks || []).length);
                });
            });

            // ── TOUCH ─────────────────────────────────────────────────
            var _tt = { active: false, ghost: null, srcEl: null, srcBlockId: null, fromIdx: null, lastOver: null, ox: 0, oy: 0 };

            function _ttCleanup() {
                if (_tt.ghost)    { _tt.ghost.remove(); _tt.ghost = null; }
                if (_tt.srcEl)    _tt.srcEl.classList.remove('dnd-dragging');
                if (_tt.lastOver) _tt.lastOver.classList.remove('dnd-over');
                _tt.active = false; _tt.srcEl = null; _tt.srcBlockId = null;
                _tt.fromIdx = null; _tt.lastOver = null;
            }

            getAllTaskEls().forEach(function(liEl) {
                // Touch drag activates ONLY from the ⁞⁞ handle (requires edit mode where handle is visible)
                var handle = liEl.querySelector('.dnd-sched-task-handle');
                if (!handle) return;
                var _ttTimer = null, _ttTouchRef = null;
                handle.addEventListener('touchstart', function(e) {
                    e.stopPropagation();
                    var t = e.touches[0];
                    _ttTouchRef = { x: t.clientX, y: t.clientY };
                    // Long-press delay — gives user time to scroll without triggering drag
                    _ttTimer = setTimeout(function() {
                        _ttTimer = null;
                        if (!_ttTouchRef) return;
                        var rect = liEl.getBoundingClientRect();
                        var ghost = liEl.cloneNode(true);
                        ghost.style.cssText = 'position:fixed;pointer-events:none;z-index:9999;opacity:0.85;' +
                            'box-shadow:0 8px 24px rgba(0,0,0,0.25);border-radius:10px;transform:scale(1.03);' +
                            'width:' + rect.width + 'px;left:' + rect.left + 'px;top:' + rect.top + 'px;';
                        document.body.appendChild(ghost);
                        _tt.ghost      = ghost;
                        _tt.srcEl      = liEl;
                        _tt.srcBlockId = getBlockIdOf(liEl);
                        _tt.fromIdx    = parseInt(liEl.getAttribute('data-tidx'));
                        _tt.active     = true;
                        _tt.ox = _ttTouchRef.x - rect.left;
                        _tt.oy = _ttTouchRef.y - rect.top;
                        liEl.classList.add('dnd-dragging');
                    }, 300);
                }, { passive: true });
                handle.addEventListener('touchmove', function(e) {
                    if (_ttTimer && _ttTouchRef) {
                        var t = e.touches[0];
                        if (Math.abs(t.clientX - _ttTouchRef.x) > 8 || Math.abs(t.clientY - _ttTouchRef.y) > 8) {
                            clearTimeout(_ttTimer); _ttTimer = null; _ttTouchRef = null;
                        }
                    }
                }, { passive: true });
                handle.addEventListener('touchend', function() {
                    if (_ttTimer) { clearTimeout(_ttTimer); _ttTimer = null; }
                    _ttTouchRef = null;
                });
                handle.addEventListener('touchcancel', function() {
                    if (_ttTimer) { clearTimeout(_ttTimer); _ttTimer = null; }
                    _ttTouchRef = null;
                });
            });

            container.addEventListener('touchmove', function(e) {
                if (!_tt.active) return;
                e.preventDefault();
                var t = e.touches[0];
                _tt.ghost.style.left = (t.clientX - _tt.ox) + 'px';
                _tt.ghost.style.top  = (t.clientY - _tt.oy) + 'px';
                _tt.ghost.style.display = 'none';
                var under = document.elementFromPoint(t.clientX, t.clientY);
                _tt.ghost.style.display = '';
                // Find task or block under finger
                var targetTask  = under ? under.closest('.task-item[data-tidx]') : null;
                var targetBlock = under ? under.closest('.hour-block[data-bidx]') : null;
                var newOver = targetTask || targetBlock || null;
                if (_tt.lastOver && _tt.lastOver !== newOver) _tt.lastOver.classList.remove('dnd-over');
                if (newOver && newOver !== _tt.srcEl) { newOver.classList.add('dnd-over'); _tt.lastOver = newOver; }
                else if (!newOver) _tt.lastOver = null;
            }, { passive: false });

            container.addEventListener('touchend', function(e) {
                if (!_tt.active) return;
                var t = e.changedTouches[0];
                _tt.ghost.style.display = 'none';
                var under = document.elementFromPoint(t.clientX, t.clientY);
                _tt.ghost.style.display = '';
                var targetTask  = under ? under.closest('.task-item[data-tidx]') : null;
                var targetBlock = under ? under.closest('.hour-block[data-bidx]') : null;
                if (targetTask && targetTask !== _tt.srcEl) {
                    _doSchedTaskMove(_tt.srcBlockId, _tt.fromIdx,
                        getBlockIdOf(targetTask), parseInt(targetTask.getAttribute('data-tidx')));
                } else if (targetBlock && !targetTask) {
                    var ul = targetBlock.querySelector('ul[data-block-id]');
                    var bid = ul ? ul.getAttribute('data-block-id') : null;
                    if (bid) {
                        var tb = schedBlocks.find(function(b) { return b.id === bid; });
                        if (tb) _doSchedTaskMove(_tt.srcBlockId, _tt.fromIdx, bid, (tb.tasks || []).length);
                    }
                }
                _ttCleanup();
            });

            container.addEventListener('touchcancel', _ttCleanup);
        }
        // ── Section task-list DnD ─────────────────────────────
        function _initTaskListDnd(listEl, sid) {
            if (!listEl) return;
            var getAllRows = function() { return Array.from(listEl.querySelectorAll('.house-task-item[data-tidx]')); };

            getAllRows().forEach(function(rowEl) {
                var getIdx    = function() { return parseInt(rowEl.getAttribute('data-tidx')); };
                var getListId = function() { return 'gtask-' + sid; };
                _wireDrag(rowEl, getIdx, getListId, getAllRows, function(from, to) {
                    if (!gTasksAll[sid]) return;
                    var moved = gTasksAll[sid].splice(from, 1)[0];
                    gTasksAll[sid].splice(to, 0, moved);
                    saveGTasksAll();
                    renderGTasks(sid);
                });
            });
        }


        // ════════════════════════════════════════════════════════════════
        //  SHARED SUBTASK DRAG-AND-DROP
        //  Call after rendering a subtask list container.
        //  container: DOM element wrapping the sub rows
        //  getArr: () => the live array of subtasks
        //  saveAndRender: () => save + re-render after reorder
        // ════════════════════════════════════════════════════════════════
        function _wireSubDnd(container, getArr, saveAndRender) {
            let dragEl = null, dragIdx = -1, fromHandle = false;

            const rows = () => Array.from(container.querySelectorAll('[data-sub-idx]'));

            container.querySelectorAll('[data-sub-idx]').forEach(row => {
                const handle = row.querySelector('.sub-drag-handle');
                if (!handle) return;
                const idx = parseInt(row.getAttribute('data-sub-idx'));

                // Always draggable; dragstart is gated by fromHandle flag (mirrors _wireDrag)
                row.setAttribute('draggable', 'true');

                // ── Mouse
                handle.addEventListener('mousedown', e => {
                    e.stopPropagation();
                    fromHandle = true;
                    dragEl = row;
                    dragIdx = idx;
                }, true);

                row.addEventListener('dragstart', e => {
                    if (!fromHandle || dragEl !== row) { e.preventDefault(); return; }
                    e.stopPropagation(); // prevent parent card's dragstart from cancelling this drag
                    e.dataTransfer.effectAllowed = 'move';
                    e.dataTransfer.setData('text/plain', String(dragIdx));
                    setTimeout(() => row.classList.add('sub-row-dragging'), 0);
                });

                row.addEventListener('dragend', () => {
                    row.classList.remove('sub-row-dragging');
                    rows().forEach(r => r.classList.remove('sub-row-over'));
                    dragEl = null; dragIdx = -1; fromHandle = false;
                });

                row.addEventListener('dragover', e => {
                    if (!dragEl || dragEl === row) return;
                    e.preventDefault();
                    e.stopPropagation(); // prevent parent card from handling this
                    e.dataTransfer.dropEffect = 'move';
                    rows().forEach(r => r.classList.remove('sub-row-over'));
                    row.classList.add('sub-row-over');
                });

                row.addEventListener('drop', e => {
                    e.preventDefault();
                    e.stopPropagation(); // prevent parent card's drop handler from firing
                    row.classList.remove('sub-row-over');
                    if (!dragEl || dragEl === row) return;
                    const toIdx = parseInt(row.getAttribute('data-sub-idx'));
                    if (toIdx === dragIdx) return;
                    const arr = getArr();
                    const [item] = arr.splice(dragIdx, 1);
                    arr.splice(toIdx, 0, item);
                    saveAndRender();
                });

                // ── Touch (uses global _touch engine same as _wireTouchDrag)
                handle.addEventListener('touchstart', function(e) {
                    e.stopPropagation();
                    var t = e.touches[0];
                    var rect = row.getBoundingClientRect();
                    var ghost = row.cloneNode(true);
                    ghost.style.cssText = 'position:fixed;pointer-events:none;z-index:9999;opacity:0.8;'
                        + 'box-shadow:0 6px 20px rgba(0,0,0,0.4);border-radius:9px;'
                        + 'width:' + rect.width + 'px;left:' + rect.left + 'px;top:' + rect.top + 'px;';
                    document.body.appendChild(ghost);
                    _touch.ghost     = ghost;
                    _touch.srcEl     = row;
                    _touch.active    = true;
                    _touch.getAllEls = rows;
                    _touch.onDrop    = function(fromIdx, toIdx) {
                        var arr = getArr();
                        var item = arr.splice(fromIdx, 1)[0];
                        arr.splice(toIdx, 0, item);
                        saveAndRender();
                    };
                    _touch.fromIdx  = idx;
                    _touch.offsetX  = t.clientX - rect.left;
                    _touch.offsetY  = t.clientY - rect.top;
                    row.classList.add('sub-row-dragging');
                }, { passive: true });
            });
        }

        
        // ══════════════════════════════════════════════════════════
        //  FAMILY MEMBER MODAL
        // ══════════════════════════════════════════════════════════
        let _famModalMId = null;
        let _famModalType = null;

        function openFamModal(type, mId) {
            _famModalMId = mId;
            _famModalType = type;
            // Hide member row unless called with null mId (global open)
            if (mId !== null) {
                document.getElementById('fam-modal-member-row').style.display = 'none';
            }
            const titles = { date:'🎂 Add Important Date', promise:'🤝 Add Promise', log:'💬 Log a Moment' };
            document.getElementById('fam-modal-title').textContent = titles[type] || 'Add';
            document.getElementById('fam-modal-date-fields').style.display    = type === 'date'    ? 'block' : 'none';
            document.getElementById('fam-modal-promise-fields').style.display = type === 'promise' ? 'block' : 'none';
            document.getElementById('fam-modal-log-fields').style.display     = type === 'log'     ? 'block' : 'none';
            // clear
            ['fam-modal-label','fam-modal-promise','fam-modal-log'].forEach(id => { const el = document.getElementById(id); if(el) el.value=''; });
            const dateEl = document.getElementById('fam-modal-date'); if(dateEl) dateEl.value='';
            const dtypeEl = document.getElementById('fam-modal-dtype'); if(dtypeEl) dtypeEl.selectedIndex=0;
            // save button
            document.getElementById('fam-modal-save').onclick = () => saveFamModal();
            const colors = { date:'linear-gradient(135deg,#fbbf24,#d97706)', promise:'linear-gradient(135deg,#34d399,#059669)', log:'linear-gradient(135deg,#fb7185,#f43f5e)' };
            document.getElementById('fam-modal-save').style.background = colors[type] || colors.log;
            document.getElementById('fam-modal-overlay').style.display = 'block';
            document.getElementById('fam-modal').style.display = 'block';
            // focus first input
            setTimeout(() => {
                const inp = { date:'fam-modal-label', promise:'fam-modal-promise', log:'fam-modal-log' }[type];
                const el = document.getElementById(inp); if(el) el.focus();
            }, 120);
        }

        function closeFamModal() {
            document.getElementById('fam-modal-overlay').style.display = 'none';
            document.getElementById('fam-modal').style.display = 'none';
            document.getElementById('fam-modal-member-row').style.display = 'none';
            _famModalMId = null; _famModalType = null;
        }

        function openFamModalGlobal(type) {
            // Populate member select
            const sel = document.getElementById('fam-modal-member-select');
            if (sel) {
                sel.innerHTML = '';
                if (!famData.members || !famData.members.length) {
                    const opt = document.createElement('option');
                    opt.value = '__general__';
                    opt.textContent = '👨‍👩‍👧‍👦 General (no member)';
                    sel.appendChild(opt);
                } else {
                    famData.members.forEach(m => {
                        const opt = document.createElement('option');
                        opt.value = m.id;
                        opt.textContent = (m.emoji || '👤') + ' ' + m.name + (m.role ? ' · ' + m.role : '');
                        sel.appendChild(opt);
                    });
                }
            }
            document.getElementById('fam-modal-member-row').style.display = 'block';
            openFamModal(type, null);
        }

        function openFamTaskModal() {
            _famModalMId = '__task__';
            _famModalType = 'task';
            document.getElementById('fam-modal-title').textContent = '📌 Add Task';
            document.getElementById('fam-modal-date-fields').style.display    = 'none';
            document.getElementById('fam-modal-promise-fields').style.display = 'none';
            document.getElementById('fam-modal-log-fields').style.display     = 'none';
            document.getElementById('fam-modal-task-fields').style.display    = 'block';
            ['fam-modal-task-emoji','fam-modal-task-title','fam-modal-task-desc'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
            document.getElementById('fam-modal-save').style.background = 'linear-gradient(135deg,#fb7185,#f43f5e)';
            document.getElementById('fam-modal-overlay').style.display = 'block';
            document.getElementById('fam-modal').style.display = 'block';
            setTimeout(() => { const el=document.getElementById('fam-modal-task-title'); if(el) el.focus(); }, 120);
        }

        function saveFamModal() {
            if (!_famModalType) return;
            const type = _famModalType;
            // Resolve mId: if null, read from member select
            let mId = _famModalMId;
            if (mId === null && (type === 'date' || type === 'promise' || type === 'log')) {
                const sel = document.getElementById('fam-modal-member-select');
                mId = sel ? sel.value : '__general__';
            }
            if (type === 'task') {
                const emoji = (document.getElementById('fam-modal-task-emoji')?.value||'').trim();
                const title = (document.getElementById('fam-modal-task-title')?.value||'').trim();
                const desc  = (document.getElementById('fam-modal-task-desc')?.value||'').trim();
                if (!title) { document.getElementById('fam-modal-task-title').focus(); return; }
                if (!gTasksAll['family']) gTasksAll['family'] = [];
                gTasksAll['family'].push({ id: Date.now()+Math.random(), emoji, text: title, notes: desc, done: false, accentColor: '#fb7185' });
                saveGTasksAll();
                closeFamModal();
                renderGTasks('family');
                return;
            }
            if (type === 'date') {
                const label = (document.getElementById('fam-modal-label')?.value||'').trim();
                if (!label) { document.getElementById('fam-modal-label').focus(); return; }
                famData.dates.push({ memberId:mId, label,
                    date:  document.getElementById('fam-modal-date')?.value||'',
                    type:  document.getElementById('fam-modal-dtype')?.value||'birthday',
                    emoji: '' });
            } else if (type === 'promise') {
                const text = (document.getElementById('fam-modal-promise')?.value||'').trim();
                if (!text) { document.getElementById('fam-modal-promise').focus(); return; }
                famData.promises.push({ memberId:mId, text, done:false });
            } else if (type === 'log') {
                const text = (document.getElementById('fam-modal-log')?.value||'').trim();
                if (!text) { document.getElementById('fam-modal-log').focus(); return; }
                const date = new Date().toLocaleDateString('pt-PT',{day:'2-digit',month:'short',year:'numeric'});
                famData.log.push({ memberId:mId, text, date });
            }
            saveFamData();
            closeFamModal();
            renderFamMembers();
            updateFamStats();
        }

        // ── Tooltip system ────────────────────────────────────────────────────
        (function() {
            const tip = document.getElementById('jn-tooltip');
            if (!tip) return;
            let activeEl = null;

            function show(el) {
                const text = el.getAttribute('data-tooltip');
                if (!text) return;
                activeEl = el;
                tip.textContent = text;
                requestAnimationFrame(() => {
                    const r = el.getBoundingClientRect();
                    const tw = tip.offsetWidth;
                    const th = tip.offsetHeight;
                    let left = r.left + r.width / 2 - tw / 2;
                    let top  = r.top - th - 6;
                    left = Math.max(6, Math.min(left, window.innerWidth - tw - 6));
                    if (top < 6) top = r.bottom + 6;
                    tip.style.left = left + 'px';
                    tip.style.top  = top + 'px';
                    tip.style.opacity = '1';
                });
            }

            function hide() {
                activeEl = null;
                tip.style.opacity = '0';
            }

            document.addEventListener('mouseover', function(e) {
                const el = e.target.closest('[data-tooltip]');
                if (el) show(el); else hide();
            });
            document.addEventListener('mouseout', function(e) {
                if (!e.relatedTarget || !e.relatedTarget.closest('[data-tooltip]')) hide();
            });
            document.addEventListener('scroll', hide, true);
            document.addEventListener('click', hide);
        })();
